// Raices CRM - Backend del Agente IA + Webhook WhatsApp
const express = require('express');
const Anthropic = require('@anthropic-ai/sdk');
const { createClient } = require('@supabase/supabase-js');
// crypto a nivel modulo: necesario para validar el secreto del webhook de WhatsApp (~L3088), que se
// ejecuta MUCHO antes del require local de crypto que vive mas abajo (TDZ). Es el mismo modulo nativo.
const crypto = require('crypto');

const app = express();
// ADITIVO (multicanal Meta): capturar el body crudo SIN cambiar el parseo JSON existente.
// Solo se usa para validar la firma X-Hub-Signature-256 de los webhooks de Meta (HMAC sobre
// los bytes exactos recibidos). NO afecta a WhatsApp ni a ningun otro endpoint: solo agrega
// la propiedad req.rawBody. El parseo a req.body sigue identico a antes.
// LIMITE DEL BODY JSON: subido de 2mb -> 12mb. Motivo (bug A1 SOPORTE imagen): el adjunto del ticket viaja
// como data URL base64 dentro del JSON, y el base64 pesa ~33% MAS que los bytes reales. Con el limite viejo de
// 2mb, una captura/foto de ~1.5MB ya superaba el limite y Express devolvia 413 (PayloadTooLargeError) ANTES de
// entrar al handler -> el front lo veia como "error de conexion". Con 12mb entra comodo una imagen de ~8MB reales
// (~11MB en base64), que es el tope que valida subirImagenSoporte. No habilita uploads sin control: el tope duro
// de tamano de imagen sigue en subirImagenSoporte (8MB) y subirMediaEquipo (25MB). NO afecta el gasto de IA.
app.use(express.json({ limit: '12mb', verify: function(req, res, buf){ try { req.rawBody = buf; } catch(e){} } }));

// MANEJADOR DE BODY DEMASIADO GRANDE (bug A1 SOPORTE imagen): si el JSON supera el limite (12mb), express.json
// lanza un error 413 'entity.too.large' que, sin este handler, se devolvia como un 500/413 crudo SIN cabeceras
// CORS -> el navegador lo mostraba como "error de conexion" generico. Aca lo capturamos y devolvemos un 413 con
// CORS y un mensaje claro para que el front pueda explicar "la imagen es demasiado grande". Cualquier otro error
// de parseo (JSON malformado) -> 400 claro. Va ANTES del middleware de CORS, asi que setea las cabeceras el mismo.
app.use(function(err, req, res, next){
  if (!err) return next();
  try {
    var origin = req.headers && req.headers.origin;
    var permitidos = ['https://raices-crm.vercel.app','https://www.raicescrm.com','https://raicescrm.com','http://localhost:3000'];
    if (origin && permitidos.indexOf(origin) !== -1) res.header('Access-Control-Allow-Origin', origin);
    res.header('Access-Control-Allow-Headers', 'Content-Type, apikey, Authorization');
  } catch (eCors) {}
  var tipo = err.type || '';
  var status = err.status || err.statusCode;
  if (tipo === 'entity.too.large' || status === 413) {
    return res.status(413).json({ error: 'El archivo adjunto es demasiado grande. Probá con una imagen más liviana (hasta ~8MB).' });
  }
  if (tipo === 'entity.parse.failed' || status === 400) {
    return res.status(400).json({ error: 'No se pudo leer la solicitud (formato inválido).' });
  }
  // Cualquier otro error de middleware temprano: 500 controlado (no rompe el proceso).
  console.error('error middleware temprano:', err && err.message);
  return res.status(500).json({ error: 'Error procesando la solicitud' });
});

app.use((req, res, next) => {
  // Lista blanca de origenes permitidos (solo la app de Raices CRM)
  const ORIGENES_PERMITIDOS = [
    'https://raices-crm.vercel.app',
    'https://www.raicescrm.com',
    'https://raicescrm.com',
    'http://localhost:3000'
  ];
  const origin = req.headers.origin;
  // Peticiones sin origin (server-to-server, ej webhook de Evolution) pasan sin restriccion CORS
  if (origin && ORIGENES_PERMITIDOS.indexOf(origin) !== -1) {
    res.header('Access-Control-Allow-Origin', origin);
  }
  res.header('Access-Control-Allow-Headers', 'Content-Type, apikey, Authorization');
  // Incluye PATCH y DELETE: sin ellos el navegador bloquea por CORS (preflight) esos metodos -> editar/borrar
  // fallaban en silencio (ej. borrar/editar una Oportunidad quedaba "pausada"; "Quitar aviso" del Maestro).
  res.header('Access-Control-Allow-Methods', 'GET,POST,PATCH,PUT,DELETE,OPTIONS');
  if (req.method === 'OPTIONS') return res.sendStatus(200);
  next();
});

// === SEGURIDAD: rate limiting casero en memoria (sin dependencias) ===
// Limite generoso: protege de abuso/ataques sin molestar el uso normal.
// El webhook de Evolution queda EXENTO (puede mandar muchos mensajes legitimos).
const _rlHits = new Map();
const _RL_VENTANA_MS = 60 * 1000;
const _RL_MAX = 200;

// === DEBOUNCE POR CONVERSACION (FIX bug doble-presentacion) ===
// Cuando un lead manda 2+ mensajes seguidos rapidos, llegan webhooks concurrentes y la IA
// respondia/se presentaba 2 veces. Solucion (sin migracion, instancia unica): por cada conv.id
// agrupamos la rafaga. Cada mensaje entrante SE GUARDA igual (no se pierde nada); solo la
// GENERACION de respuesta se debouncea: el ultimo mensaje reinicia un timer, y al vencer
// DEBOUNCE_MS se genera UNA sola respuesta que re-lee TODO el historial (contempla la rafaga).
// _genEnCurso evita que dos disparos solapados generen dos respuestas para la misma conv.
const _debounceConv = new Map(); // conv.id -> timeout handle
const _genEnCurso = new Set();   // conv.id en generacion ahora mismo
const DEBOUNCE_MS = 6000;
setInterval(() => { _rlHits.clear(); }, _RL_VENTANA_MS);
app.use((req, res, next) => {
  try {
    // el webhook de WhatsApp no se limita
    if (req.path === '/api/webhook/whatsapp') return next();
    if (req.path === '/api/webhook/mercadopago') return next();
    if (req.path === '/api/webhook/meta') return next(); // webhook Meta (Messenger/Instagram): Meta exige <2s y reintenta
    if (req.path === '/api/webhook/cloud-api') return next(); // webhook WhatsApp Cloud API: idem (Meta exige <2s y reintenta)
    if (req.path === '/health') return next();
    const ip = (req.headers['x-forwarded-for'] || req.ip || 'sin-ip').split(',')[0].trim();
    const n = (_rlHits.get(ip) || 0) + 1;
    _rlHits.set(ip, n);
    if (n > _RL_MAX) return res.status(429).json({ error: 'Demasiadas peticiones, intenta en un momento' });
    next();
  } catch (e) { next(); }
});

// === GATE DE SUSCRIPCION SERVER-SIDE (Puerta 2) ===
// Un UNICO guardian (facil de auditar y de revertir: borrar este bloque) que bloquea las rutas de
// DATOS/IA del cliente cuando la cuenta NO esta al dia (debeBloquearAcceso). FAIL-OPEN: nunca corta a
// quien paga (debeBloquearAcceso solo da true con CERTEZA de estado malo; ante error/duda -> false).
// NO gatea: webhooks, /api/suscripcion* (debe poder pagar), /api/soporte* (debe poder pedir ayuda),
// /api/maestro* (auth propia), /health ni rutas publicas (no estan en la lista).
// Si no hay token de usuario valido (uid null) deja pasar: el handler resuelve su propia auth -> no
// rompe endpoints internos/cron ni el flujo sin sesion. Ante CUALQUIER error -> next() (no cortar).
const _PREFIJOS_GATE_SUSCRIPCION = [
  '/api/whatsapp/',       // send, conectar, desconectar, listar-chats, importar-leads, estado (NO el webhook /api/webhook/whatsapp)
  '/api/enviar-media',
  '/api/clasificar-fotos',
  '/api/scrape/',         // lista, detalle, v2, universal (OJO: lista/detalle hoy NO exigen token -> ver hardening aparte)
  '/api/propiedades',
  '/api/scraping-config',
  '/api/scraping-pendientes',
  '/api/probar-agente',
  '/api/agent/',          // /api/agent/respond
  '/api/conversations/',  // /api/conversations/resumen
  '/api/citas'            // ver/crear/actualizar citas (agenda)
  // NOTA: /api/asesores/ NO se gatea: gestionar el equipo (crear/activar usuarios) es CONFIGURACION, no consumo de
  // IA; bloquearlo rompia el onboarding de una cuenta nueva y el setup del dueno impersonando un cliente sin pagar.
];
// P1 (enforcement de plan): prefijos de features que GASTAN IA y NO son la respuesta al lead. Si la cuenta pasó su
// tope de mensajes (sin saldo extra) -> 429 ANTES de gastar. Antes el tope solo frenaba la auto-respuesta al lead;
// estos endpoints seguían consumiendo IA por encima del tope (agujero del pricing). Prefijos ESPECÍFICOS a propósito:
// NO se pone '/api/scrape/' entero porque incluiría /scrape/lista y /scrape/job (estado del job) que NO gastan IA y
// cuyo bloqueo rompería la barra de progreso. Flag-off / plan ilimitado / cortesía SIN override => dentroDelTopeIA=true
// => nunca bloquea. OJO: una cortesía CON limits_override.ai_messages SÍ queda capeada (el override manda sobre la
// cortesía, ver topeEfectivoIA) => esa sí puede recibir 429. Es intencional: el Maestro le puso un tope explícito.
const _PREFIJOS_TOPE_IA = [
  '/api/clasificar-fotos',
  '/api/scrape/lista',         // SI gasta IA: su estrategia (5) es "extraccion con IA" -> listarUrlsIA (Sonnet) y cobra 3 msgs.
  '/api/scrape/detalle',
  '/api/scrape/universal',
  '/api/scrape/v2',
  '/api/scrape/alojamiento',   // /alojamiento, /alojamiento/profundo (cobra hasta 20), /alojamiento/job — todos IA (NO matchea /api/scrape/job)
  '/api/scrape/desarrollo',    // /desarrollo, /desarrollo/actualizar, /desarrollo/job — IA
  '/api/marketing/informe'
  // NO se listan /api/probar-agente (tiene un camino de "agregar instrucción" con 0 tokens que no hay que bloquear)
  // ni /api/agent/ (la respuesta al lead YA está gateada por dentroDelTopeIA en los paths WA/Meta).
];
app.use(async function(req, res, next) {
  try {
    // BYPASS DE MAYUSCULAS (fix 2026-07-14): Express rutea CASE-INSENSITIVE por defecto ('case sensitive routing'
    // viene desactivado), asi que POST /API/WhatsApp/send o /API/CLASIFICAR-FOTOS LLEGAN AL MISMO HANDLER. Este gate
    // comparaba con indexOf (case-SENSITIVE) -> no los veia y los dejaba pasar: bypass total del 403 de no-pago y del
    // 429 de tope (estas rutas NO tienen chequeo propio adentro del handler, el gate es la UNICA barrera). Se compara
    // en minusculas, que es exactamente el criterio con el que Express eligio el handler. Los prefijos ya son
    // minusculas ASCII => bajar el path solo puede hacer que el gate vea MAS rutas (las que Express ya rutea ahi),
    // nunca menos: no puede cortar a nadie que hoy pase.
    const p = (req.path || '').toLowerCase();
    const payGate = _PREFIJOS_GATE_SUSCRIPCION.some(function(pre){ return p === pre || p.indexOf(pre) === 0; });
    const topeGate = _PREFIJOS_TOPE_IA.some(function(pre){ return p === pre || p.indexOf(pre) === 0; });
    if (!payGate && !topeGate) return next();
    const uid = await verificarUsuario(req);
    if (!uid) return next(); // sin sesion valida: que el handler haga su propia auth (no rompe internos/sin-token)
    if (payGate && await debeBloquearAcceso(uid)) return res.status(403).json({ error: 'Suscripcion inactiva. Regulariza tu pago para continuar.' });
    // P1: freno de gasto IA por tope de plan. Resolvemos el DUEÑO (asesor -> admin_id) porque el tope/plan es del tenant.
    if (topeGate) {
      let owner = uid;
      try { const { data: ase } = await supabase.from('asesores').select('admin_id').eq('auth_user_id', uid).maybeSingle(); if (ase && ase.admin_id) owner = ase.admin_id; } catch (eOwn) {}
      if (!(await dentroDelTopeIA(owner))) return res.status(429).json({ error: 'Alcanzaste el tope de mensajes IA de tu plan. Ampliá el plan o esperá al próximo período para usar esta función.', tope_alcanzado: true });
    }
    return next();
  } catch (e) {
    // FAIL-OPEN (disponibilidad): ante cualquier error NO cortamos el servicio. B3: pero ahora LO LOGUEAMOS
    // (antes el catch tragaba la excepcion en silencio) para poder detectar un gate que esta dejando pasar a
    // todos por un bug/caida y no por que paguen. Best-effort: el log/alerta nunca relanza ni corta el next().
    try { console.error('[GATE_SUSCRIPCION] fail-open por excepcion (se deja pasar):', (e && e.message) || e); } catch (eLog) {}
    try { _notifSistema('gate_suscripcion', 'Gate de suscripcion fallo (fail-open)', 'El guardian de suscripcion lanzo una excepcion y dejo pasar la request. Revisar debeBloquearAcceso/verificarUsuario. Detalle: ' + ((e && e.message) || e)); } catch (eNotif) {}
    return next();
  } // FAIL-OPEN: ante cualquier error, no cortar el servicio
});

const PORT = process.env.PORT || 3001;
// FASE 0 failover: el SDK ya reintenta 408/409/429/5xx (incluido 529 Overloaded) y respeta retry-after.
// Subimos de 2 (default) a 4 reintentos para aguantar baches cortos de Anthropic sin caer en el silencio. 0 tokens extra (un reintento fallido no factura).
const anthropic = new Anthropic({ apiKey: process.env.ANTHROPIC_KEY || '', maxRetries: 4 });
const supabase = createClient(process.env.SUPABASE_URL || '', process.env.SUPABASE_SERVICE_KEY || '');

// === Notificaciones push (FCM) via firebase-admin ===
// Se inicializa SOLO si hay credenciales (env FIREBASE_SERVICE_ACCOUNT = JSON del service account).
// Si no esta configurado, enviarPushAsesor no hace nada (no rompe el flujo de mensajes).
let _fcmReady = false;
let _fcmAdmin = null;
try {
  if (process.env.FIREBASE_SERVICE_ACCOUNT) {
    _fcmAdmin = require('firebase-admin');
    if (!_fcmAdmin.apps.length) {
      _fcmAdmin.initializeApp({ credential: _fcmAdmin.credential.cert(JSON.parse(process.env.FIREBASE_SERVICE_ACCOUNT)) });
    }
    _fcmReady = true;
    console.log('FCM listo (firebase-admin inicializado)');
  } else {
    console.log('FCM no configurado (sin FIREBASE_SERVICE_ACCOUNT)');
  }
} catch (e) { console.error('Error init firebase-admin:', e && e.message); }

// ===== PRESENCIA EN VIVO (para NO notificar el chat que el asesor esta MIRANDO) =====
// Map en memoria: authUserId -> { convId, ts }. El front manda un "latido" cada ~20s MIENTRAS tiene una
// conversacion ABIERTA y la ventana VISIBLE; al salir/ocultar/cerrar manda visible:false (o el latido se corta
// y el TTL lo vence). Es EFIMERO: se pierde si el proceso reinicia => FAIL-OPEN (se vuelve a notificar, nunca al
// reves). Asume 1 instancia de backend (si hubiera varias, el que reciba el webhook podria no tener la presencia
// -> manda el push igual = comportamiento de hoy, seguro). CERO IA, CERO DB (todo en memoria).
const _presenciaTTL = 40 * 1000; // 40s sin latido => se considera AUSENTE.
const _presencia = new Map();
function _marcarPresencia(authUserId, convId, visible) {
  if (!authUserId) return;
  const key = String(authUserId);
  if (visible && convId) {
    _presencia.set(key, { convId: String(convId), ts: Date.now() });
  } else {
    // "salí/oculté": limpiar SOLO si la presencia actual es de ESA conv (evita que un latido viejo de la conv A
    // pise la presencia de la conv B a la que el usuario ya se movio -> los POST son async y pueden desordenarse).
    const p = _presencia.get(key);
    if (!convId || (p && p.convId === String(convId))) _presencia.delete(key);
  }
}
// ¿El asesor esta MIRANDO esa conversacion AHORA mismo? (latido fresco y sobre la MISMA conv).
function _estaMirando(authUserId, convId) {
  if (!authUserId || !convId) return false;
  const p = _presencia.get(String(authUserId));
  if (!p || p.convId !== String(convId)) return false;
  return (Date.now() - p.ts) < _presenciaTTL;
}

// ANTI-SPAM de notificaciones (estilo WhatsApp): NO mandar un push por CADA mensaje del lead (30 notis por 3 leads
// = estresante). Combinado con la PRESENCIA (si el asesor está MIRANDO esa conversación, ni se llama a esto), esto
// agrega un DEBOUNCE por conversación: como MÁXIMO 1 push cada 20 min. Así, si el asesor NO está mirando y el lead
// manda una ráfaga de 20 mensajes, le llega UN aviso, no 20; y si el lead reaparece tras un rato, le llega otro.
// Solo cuenta el tiempo cuando SE MANDA un push (si la presencia lo silenció, no consume la ventana → apenas el
// asesor se va, el próximo mensaje avisa). Estado en memoria (se pierde al reiniciar → fail-open: notifica de más,
// nunca de menos). Asume 1 instancia de backend. CERO IA, CERO DB.
const _pushDebounceMs = 20 * 60 * 1000; // máx 1 push por conversación cada 20 min
const _ultimoPushLead = new Map(); // convId -> ts del último push efectivamente enviado
function _debePushearLead(convId) {
  if (!convId) return true;
  const key = String(convId);
  const last = _ultimoPushLead.get(key) || 0;
  if (Date.now() - last >= _pushDebounceMs) { _ultimoPushLead.set(key, Date.now()); return true; }
  return false;
}

// Registro (best-effort, DEPLOY-SAFE) de cada aviso push -> tabla `notificaciones`. Es la PRUEBA con tilde de entrega
// (estado: 'entregado' | 'sin_dispositivo' | 'error'). Fire-and-forget: NO se await desde el push -> nunca lo frena
// ni lo rompe. Si la tabla aun no existe (migracion no corrida), el insert falla en silencio.
function _logNotif(authUserId, titulo, cuerpo, meta, res) {
  try {
    supabase.from('asesores').select('admin_id, nombre').eq('auth_user_id', authUserId).maybeSingle().then(function (r) {
      var ad = (r && r.data && r.data.admin_id) || authUserId; // si no es asesor (es el dueno), se registra a su propio id
      var nom = (r && r.data && r.data.nombre) || null;
      supabase.from('notificaciones').insert({
        admin_id: ad, destinatario_auth_user_id: authUserId, destinatario_nombre: nom,
        tipo: (meta && meta.tipo) || 'aviso', canal: 'push',
        titulo: titulo ? String(titulo).slice(0, 140) : null,
        cuerpo: cuerpo ? String(cuerpo).slice(0, 400) : null,
        conversation_id: (meta && meta.conversation_id) || null,
        tokens_total: res.total || 0, tokens_ok: res.ok || 0, tokens_fail: res.fail || 0, estado: res.estado
      }).then(function () {}, function () {});
    }, function () {});
  } catch (e) {}
}

// Envia un push al/los dispositivo(s) del asesor (identificado por su auth_user_id).
// meta (opcional): { tipo, conversation_id } para enriquecer el registro. Backward-compatible (los callers sin meta funcionan igual).
async function enviarPushAsesor(authUserId, leadNombre, texto, bodyLiteral, meta) {
  if (!authUserId) return;
  // FIX: el push por FCM va en una funcion INTERNA. Sus early-returns (FCM off / usuario sin dispositivo) NO deben
  // saltear el ESPEJO por WhatsApp de abajo. Antes el return de 'sin_dispositivo' salia de TODA la funcion y nunca
  // se llegaba al espejo -> los usuarios SIN dispositivo push (ej. iPhone) no recibian NINGUNA notificacion, aunque
  // el espejo por WhatsApp se hizo justamente para ellos. Ahora el espejo se intenta SIEMPRE.
  const _enviarPushFCM = async () => {
    if (!_fcmReady) return;
    const { data: toks } = await supabase.from('device_tokens').select('token').eq('user_id', authUserId);
    if (!toks || !toks.length) { _logNotif(authUserId, leadNombre, bodyLiteral || texto, meta, { total: 0, ok: 0, fail: 0, estado: 'sin_dispositivo' }); return; }
    const tokens = toks.map(function (t) { return t.token; }).filter(Boolean);
    if (!tokens.length) { _logNotif(authUserId, leadNombre, bodyLiteral || texto, meta, { total: 0, ok: 0, fail: 0, estado: 'sin_dispositivo' }); return; }
    const palabras = String(texto || '').trim().split(/\s+/).slice(0, 3).join(' ');
    // bodyLiteral: para avisos que NO son un mensaje de lead (ej. cupo IA al 80/100%), se respeta el cuerpo tal cual.
    const _body = bodyLiteral ? String(bodyLiteral) : ('Nuevo mensaje · ' + palabras);
    const resp = await _fcmAdmin.messaging().sendEachForMulticast({
      tokens: tokens,
      notification: { title: leadNombre || 'Nuevo lead', body: _body },
      android: { priority: 'high', notification: { channelId: 'mensajes', sound: 'default', priority: 'high' } }
    });
    // Contar entregados/fallidos (para el tilde) + limpiar tokens invalidos (desinstalados / expirados)
    let _ok = 0, _fail = 0;
    if (resp && resp.responses) {
      for (let i = 0; i < resp.responses.length; i++) {
        const r = resp.responses[i];
        if (r && r.success) _ok++; else _fail++;
        const code = (r && r.error && r.error.code) || '';
        if (!r.success && /not-registered|invalid-registration-token|invalid-argument/.test(code)) {
          try { await supabase.from('device_tokens').delete().eq('token', tokens[i]); } catch (eDel) {}
        }
      }
    }
    _logNotif(authUserId, leadNombre, _body, meta, { total: tokens.length, ok: _ok, fail: _fail, estado: _ok > 0 ? 'entregado' : 'error' });
  };
  try { await _enviarPushFCM(); } catch (e) { console.error('Error enviarPushAsesor:', e && e.message); }
  // FASE 2: ESPEJO del push por-usuario a WhatsApp. SIEMPRE se intenta (independiente del push): para los usuarios
  // sin dispositivo push (iPhone) es la UNICA notificacion que reciben. Best-effort, NUNCA rompe nada (gates propios).
  try { await _espejarPushAWhatsApp(authUserId, leadNombre, texto, bodyLiteral); } catch (eDm) { console.error('Error _espejarPushAWhatsApp:', eDm && eDm.message); }
}

// ===== FASE 2: NOTIFICACION INDIVIDUAL POR WHATSAPP (espejo del PUSH por-usuario) =====
// 🔴 ANTI-BAN + GATED OFF por DEFAULT. Cuando el dueno activa business_settings.notif_dm_wa_on
// y el usuario destino tiene asesores.whatsapp_notif cargado, se le manda el MISMO texto del push
// por WhatsApp a SU numero, usando enviarTextoGrupoWA (un POST directo a /message/sendText; el
// numero personal va como `number`, igual de valido que un JID de grupo). Se ESPEJA solo lo que YA
// se manda por push (0 mensajes nuevos). 100% DEFENSIVO: cualquier fallo/columna ausente/instancia
// desconectada => no hace nada y NUNCA lanza (el push ya se envio). CERO IA (0 tokens).
async function _espejarPushAWhatsApp(authUserId, leadNombre, texto, bodyLiteral) {
  try {
    if (!authUserId) return;
    // 1) Resolver la fila del usuario destino en asesores (por auth_user_id): su numero + su dueno (admin_id).
    //    DEFENSIVO: si la columna whatsapp_notif aun no existe (migracion no corrida), el select falla ->
    //    reintentar sin ella (asi no rompe; simplemente no hay numero => no se espeja).
    let ase = null;
    try {
      const { data } = await supabase.from('asesores').select('admin_id, whatsapp_notif').eq('auth_user_id', authUserId).maybeSingle();
      ase = data || null;
    } catch (eSel) {
      try { const { data } = await supabase.from('asesores').select('admin_id').eq('auth_user_id', authUserId).maybeSingle(); ase = data || null; } catch (eSel2) { ase = null; }
    }
    // El OWNER de la cuenta suele NO tener fila en asesores (su auth_user_id ES el user_id del tenant);
    // en ese caso ownerId = authUserId. Si es un asesor, el dueno es su admin_id.
    const ownerId = (ase && ase.admin_id) ? ase.admin_id : authUserId;
    const numero = (ase && ase.whatsapp_notif != null) ? String(ase.whatsapp_notif).trim() : '';
    if (!numero) return; // sin numero cargado => nada que espejar (comportamiento actual)
    // 2) Gate por-tenant: leer el flag del dueno. DEFENSIVO: columna ausente / null / false => OFF.
    let flagOn = false;
    try {
      const { data: bs } = await supabase.from('business_settings').select('notif_dm_wa_on').eq('user_id', ownerId).maybeSingle();
      flagOn = !!(bs && bs.notif_dm_wa_on === true);
    } catch (eBs) { flagOn = false; }
    if (!flagOn) return; // gated OFF (default) => comportamiento actual EXACTO
    // SWITCH POR-USUARIO (asesores.notif_wa_activa): si el usuario apago el aviso por WhatsApp, NO espejar (ej. ya
    // recibe push en Android y no quiere la notif doble). Read SEPARADO y DEFENSIVO: si la columna aun no existe,
    // data viene null => se trata como ON (no bloquea). Default ON.
    try {
      const { data: _nw } = await supabase.from('asesores').select('notif_wa_activa').eq('auth_user_id', authUserId).maybeSingle();
      if (_nw && _nw.notif_wa_activa === false) return;
    } catch (eNW) {}
    // 3) Armar el MISMO texto que ve el usuario en el push (titulo + cuerpo). Reusa la logica del push:
    //    bodyLiteral manda si vino; si no, 'Nuevo mensaje · <primeras 3 palabras>'.
    const palabras = String(texto || '').trim().split(/\s+/).slice(0, 3).join(' ');
    const cuerpo = bodyLiteral ? String(bodyLiteral) : ('Nuevo mensaje · ' + palabras);
    const titulo = leadNombre ? String(leadNombre) : 'Nuevo lead';
    const mensaje = (titulo + (cuerpo ? ('\n' + cuerpo) : '')).trim();
    if (!mensaje) return;
    // 4) Enviar por WhatsApp con la instancia del DUENO (best-effort). enviarTextoGrupoWA ya gatea
    //    instanciaConectada y NUNCA lanza (devuelve bool); el numero personal va como `number`.
    try { await enviarTextoGrupoWA(nombreInstancia(ownerId), numero, mensaje); } catch (eEnv) { console.error('_espejarPushAWhatsApp envio:', eEnv && eEnv.message); }
  } catch (e) { console.error('_espejarPushAWhatsApp:', e && e.message); } // NUNCA lanza
}

// === SEGURIDAD: verificacion de identidad por token JWT de Supabase ===
// Lee el token del header Authorization, lo valida contra Supabase y
// devuelve el user_id REAL del token (o null si no hay token valido).
// Capa 1: definido pero todavia NO aplicado a los endpoints.
// RESILIENCIA (fix 2026-07-01): validar el JWT por FIRMA LOCAL con la llave publica de Supabase (JWKS, ES256/RS256),
// en vez de llamar a supabase.auth.getUser() (round-trip al servicio de Auth) en CADA request. Motivo: cuando el Auth
// (GoTrue) de Supabase se degrada, getUser rechaza tokens VALIDOS con 401 y se cae TODO lo que pasa por el backend
// (departamentos, suscripcion, etc.). PostgREST nunca se cayo porque valida por firma local -> hacemos lo mismo.
// jose cachea el JWKS tras la 1ra bajada y maneja rotacion. Fallback DEFENSIVO a getUser SOLO si la validacion local
// no puede resolver -> nunca somos MENOS robustos que antes. La llave publica no lleva secretos (asimetrica).
let _joseMod = null, _supaJwks = null;
async function _getSupaJwks() {
  if (!_joseMod) _joseMod = await import('jose');
  if (!_supaJwks) {
    const _u = (process.env.SUPABASE_URL || '').replace(/\/+$/, '') + '/auth/v1/.well-known/jwks.json';
    _supaJwks = _joseMod.createRemoteJWKSet(new URL(_u));
  }
  return { jose: _joseMod, jwks: _supaJwks };
}

// ============================================================================
// ACCESO DE USUARIOS (switch Activo/Apagado del dueño). Cuando el dueño APAGA a un usuario (asesores.activo=false),
// ademas de sacarlo del reparto, se le CIERRA la sesion y se le BLOQUEA el ingreso externo (solo el dueño entra a sus
// chats desde el panel). Implementacion SIN costo por-request: un Set en memoria de los auth_user_id SIN acceso
// (activo=false), refrescado cada 60s + actualizado al instante cuando el dueño toca el switch. verificarUsuario corta
// si el uid esta en el Set -> el frontend recibe 401 y cierra la sesion sola. Ademas se banea/desbanea el LOGIN en
// Supabase Auth (defensa extra para el ingreso externo; best-effort). El DUEÑO nunca esta en asesores -> nunca se corta.
// ============================================================================
var _asesoresSinAcceso = new Set(); // auth_user_id SIN acceso: asesores apagados + cuentas eliminadas (dueño y asesores)
async function _refrescarAsesoresSinAcceso() {
  try {
    const s = new Set();
    // 1) Asesores con acceso apagado (activo=false).
    const { data: asDes } = await supabase.from('asesores').select('auth_user_id').eq('activo', false).not('auth_user_id', 'is', null);
    (asDes || []).forEach(function (r) { if (r && r.auth_user_id) s.add(r.auth_user_id); });
    // 2) CUENTAS ELIMINADAS EN PAPELERA (business_settings.eliminado_at != null): el DUEÑO + TODOS sus asesores quedan
    //    SIN acceso (sesion cortada -> verificarUsuario 401). Es RESTORABLE: al restaurar (eliminado_at=null) vuelven.
    //    El dueño NO esta en 'asesores', por eso su uid se agrega aparte. (Diego 2026-07-20: eliminar cuenta = desloguear.)
    const { data: cuentasElim } = await supabase.from('business_settings').select('user_id').not('eliminado_at', 'is', null);
    const ownersElim = (cuentasElim || []).map(function (r) { return r && r.user_id; }).filter(Boolean);
    ownersElim.forEach(function (uid) { s.add(uid); });
    if (ownersElim.length) {
      const { data: asElim } = await supabase.from('asesores').select('auth_user_id').in('admin_id', ownersElim).not('auth_user_id', 'is', null);
      (asElim || []).forEach(function (r) { if (r && r.auth_user_id) s.add(r.auth_user_id); });
    }
    // 3) CUENTAS BORRADAS DEFINITIVO (permanente, no restorable): sus filas ya no existen, se toman del audit para que la
    //    revocacion del dueño SOBREVIVA a este refresco y a reinicios (hasta que su JWT expire; despues es inofensivo).
    try {
      const { data: defs } = await supabase.from('admin_audit').select('target_user_id').eq('accion', 'borrar_definitivo').not('target_user_id', 'is', null);
      (defs || []).forEach(function (r) { if (r && r.target_user_id) s.add(r.target_user_id); });
    } catch (eDef) { /* si admin_audit falla, seguimos con el resto del set */ }
    _asesoresSinAcceso = s;
  } catch (e) { /* defensivo: si falla, dejar el set como esta (no cambiar el estado de acceso por un error puntual) */ }
}
setInterval(_refrescarAsesoresSinAcceso, 60 * 1000);
setTimeout(function () { _refrescarAsesoresSinAcceso().catch(function () {}); }, 3000);
// Auto-saneo de credenciales Meta cruzadas entre inquilinos (def. cerca de _metaCredExclusividad):
// una vez al arrancar (a los 4s, tras conectar supabase) y cada 6h como red de seguridad. Cura el
// estado que la exclusividad reactiva no toca (incidente 2026-07-17: @raicescrm activa en Anton).
setTimeout(function () { try { _sanearCredencialesMetaDuplicadas().catch(function () {}); } catch (e) {} }, 4000);
setInterval(function () { try { _sanearCredencialesMetaDuplicadas().catch(function () {}); } catch (e) {} }, 6 * 60 * 60 * 1000);
