// Banear / desbanear el LOGIN de un usuario en Supabase Auth (best-effort; el corte inmediato ya lo da el Set + verificarUsuario).
async function _setBanUsuario(authUserId, banear) {
  if (!authUserId) return;
  try { await supabase.auth.admin.updateUserById(authUserId, { ban_duration: banear ? '876000h' : 'none' }); } catch (e) { /* best-effort */ }
}

async function verificarUsuario(req) {
  try {
    const auth = req.headers.authorization || req.headers.Authorization || '';
    const token = auth.startsWith('Bearer ') ? auth.slice(7) : null;
    if (!token) return null;
    // 1) Validacion LOCAL por firma (JWKS publico de Supabase, cacheado). NO depende del servicio de Auth.
    try {
      const { jose, jwks } = await _getSupaJwks();
      const { payload } = await jose.jwtVerify(token, jwks, { algorithms: ['ES256', 'RS256'] });
      if (payload && payload.sub) {
        if (_asesoresSinAcceso.has(payload.sub)) return null; // usuario con acceso APAGADO por el dueño -> corta (401)
        return payload.sub;
      }
    } catch (eLocal) { /* cae al fallback defensivo de abajo */ }
    // 2) Fallback DEFENSIVO (por si el JWKS aun no cargo): getUser. Igual de robusto que el comportamiento previo.
    try {
      const { data, error } = await supabase.auth.getUser(token);
      if (error || !data || !data.user) return null;
      if (_asesoresSinAcceso.has(data.user.id)) return null; // acceso APAGADO -> corta
      return data.user.id;
    } catch (e2) { return null; }
  } catch (e) {
    return null;
  }
}
// PERTENENCIA POR TENANT (mismo criterio EXACTO que /api/conversations/cerrar ~L10455):
//   permite al DUEÑO de la conversacion (uid === conv.user_id) Y a un ASESOR de la MISMA cuenta
//   (fila en `asesores` con admin_id === conv.user_id). Devuelve true si pertenece, false si no.
//   No bloquea flujos legitimos: cualquier asesor del tenant dueño de la conversacion pasa.
//   Centraliza el chequeo para reusarlo en los endpoints de envio/insercion de mensajes.
async function convPerteneceAUsuario(convUserId, uid) {
  try {
    if (!convUserId || !uid) return false;
    if (convUserId === uid) return true; // dueño de la cuenta
    var aRes = await supabase.from('asesores').select('admin_id').eq('auth_user_id', uid).maybeSingle();
    return !!(aRes && aRes.data && aRes.data.admin_id === convUserId); // asesor del mismo tenant
  } catch (e) { return false; }
}
