// Mapea el rubro guardado (incluye valores legacy) a la key de DEFAULT_RUBRO. MISMA logica que el viejo if/else.
function _rubroKey(rubro) {
  if (rubro === 'hotel_cabanas' || rubro === 'hotel' || rubro === 'cabanas') return 'hotel_cabanas';
  if (rubro === 'desarrolladora') return 'desarrolladora';
  return 'inmobiliaria';
}
// Devuelve la lista COMPLETA de items (comportamiento + rubro + interna) para la UI y para armar el prompt.
// Si el cliente ya guardo su personalizacion (settings.instrucciones_agente.items) usa esa (garantizando protegidas
// presentes + activas). Si no, devuelve los DEFAULTS (sembrando la interna desde el viejo settings.instructions).
function instruccionesAgenteItems(settings, rubro, perfilOverride) {
  // PERFIL ACTIVO (Fase 3): si el cliente activó un perfil guardado (perfil_activo_id) y existe en instruccion_perfiles
  // con items, la IA usa ESE set. Si no (null / no encontrado / sin migrar) -> comportamiento de SIEMPRE
  // (instrucciones_agente = "Agente principal"). DEFENSIVO: con perfil_activo_id null NADA cambia para el cliente.
  let stored = settings && settings.instrucciones_agente;
  try {
    const _pa = perfilOverride || (settings && settings.perfil_activo_id); // override = perfil del usuario IA; si no, el activo de la cuenta
    if (_pa && Array.isArray(settings.instruccion_perfiles)) {
      const _perfil = settings.instruccion_perfiles.find(function(p){ return p && String(p.id) === String(_pa); });
      if (_perfil && Array.isArray(_perfil.items) && _perfil.items.length) stored = { items: _perfil.items };
    }
  } catch (e) { /* fallback: Agente principal */ }
  if (stored && Array.isArray(stored.items) && stored.items.length) {
    const items = stored.items.map(function(it, i) {
      return {
        id: (it && it.id) ? String(it.id) : ('it-' + i),
        categoria: (it && it.categoria) ? it.categoria : 'interna',
        texto: (it && typeof it.texto === 'string') ? it.texto : '',
        activo: !(it && it.activo === false),
        es_sistema: !!(it && it.es_sistema === true),
        orden: (it && typeof it.orden === 'number') ? it.orden : i
      };
    });
    // Red de seguridad: las de SISTEMA (14 de comportamiento + rubro) NO se eliminan -> re-inyectar si faltan.
    // Se RESPETA el activo (el admin puede DESACTIVARLAS) y el texto editado; solo se garantiza que ESTEN presentes.
    DEFAULT_COMPORTAMIENTO.forEach(function(d) {
      const ex = items.find(function(x) { return x.id === d.id; });
      if (!ex) items.push({ id: d.id, categoria: 'comportamiento', texto: d.texto, activo: true, es_sistema: true, orden: 0 });
      else { ex.es_sistema = true; ex.categoria = 'comportamiento'; if (!ex.texto || !ex.texto.trim()) ex.texto = d.texto; }
    });
    // El item de rubro tampoco se elimina: garantizar que haya al menos uno (re-inyectar el default si falta).
    const k = _rubroKey(rubro);
    if (!items.some(function(x) { return x.categoria === 'rubro'; })) items.push({ id: 'rub-' + k, categoria: 'rubro', texto: DEFAULT_RUBRO[k], activo: true, es_sistema: true, orden: 100 });
    else {
      // Si el item de rubro guardado es un DEFAULT de sistema SIN editar (su texto coincide con ALGUN valor de DEFAULT_RUBRO),
      // refrescarlo al default del rubro ACTUAL de la cuenta -> asi cambiar de rubro corrige el item viejo (ej. quedo el de
      // inmobiliaria en una cuenta que paso a desarrolladora). Si el dueno lo EDITO (texto no coincide con ningun default) NO se toca.
      const _defsRubro = Object.keys(DEFAULT_RUBRO).map(function(kk){ return DEFAULT_RUBRO[kk]; });
      items.forEach(function(x) {
        if (x.categoria !== 'rubro') return;
        x.es_sistema = true;
        if (_defsRubro.indexOf(x.texto) >= 0 && x.texto !== DEFAULT_RUBRO[k]) x.texto = DEFAULT_RUBRO[k];
      });
    }
    return items;
  }
  // DEFAULTS (el cliente nunca personalizo) -> reproduce EXACTAMENTE el comportamiento anterior.
  const out = [];
  DEFAULT_COMPORTAMIENTO.forEach(function(d, i) { out.push({ id: d.id, categoria: 'comportamiento', texto: d.texto, activo: true, es_sistema: true, orden: i }); });
  const k = _rubroKey(rubro);
  out.push({ id: 'rub-' + k, categoria: 'rubro', texto: DEFAULT_RUBRO[k], activo: true, es_sistema: true, orden: 100 });
  const instr = (settings && settings.instructions) || '';
  if (instr) out.push({ id: 'int-legacy', categoria: 'interna', texto: String(instr), activo: true, es_sistema: false, orden: 200 });
  return out;
}
// Arma los bloques de texto que van al system prompt, respetando orden y activo. Con la columna en null devuelve
// EXACTAMENTE: comportamiento = comportamientoSetter.join(' ') ; rubro = instruccionesRubro ; internas = (instructions ? 'Instrucciones internas...: '+instructions : '').
// CORRECCIONES IA (categoria 'correccion', APRENDIZAJE_V2): se devuelven en un bloque SEPARADO (`correcciones`). El
// caller SOLO lo inyecta en el prompt cuando el flag aprendizaje_v2 esta ON; con el flag OFF ese bloque se descarta y
// el prompt queda BYTE-IDENTICO (ademas, una cuenta sin items 'correccion' -> correcciones === '' de todas formas).
function bloquesInstruccionesAgente(settings, rubro, perfilOverride) {
  const items = instruccionesAgenteItems(settings, rubro, perfilOverride);
  const comportamiento = items.filter(function(i) { return i.categoria === 'comportamiento' && i.activo !== false; }).map(function(i) { return i.texto; }).filter(Boolean).join(' ');
  const rub = items.filter(function(i) { return i.categoria === 'rubro' && i.activo !== false; }).map(function(i) { return i.texto; }).filter(Boolean).join(' ');
  const internasTextos = items.filter(function(i) { return i.categoria === 'interna' && i.activo !== false; }).map(function(i) { return i.texto; }).filter(function(s) { return s && String(s).length; });
  const internasJoin = internasTextos.join(' ');
  const internas = internasJoin ? ('Instrucciones internas que SIEMPRE debes seguir: ' + internasJoin) : '';
  // CORRECCIONES IA: correcciones que el dueno le hizo a la IA (ej. "no se dice X, se dice Y"). Alta prioridad.
  const correccionesTextos = items.filter(function(i) { return i.categoria === 'correccion' && i.activo !== false; }).map(function(i) { return i.texto; }).filter(function(s) { return s && String(s).length; });
  const correccionesJoin = correccionesTextos.join(' ');
  const correcciones = correccionesJoin ? ('CORRECCIONES DEL DUENO (tienen PRIORIDAD ALTA: son ajustes que el dueno del negocio te hizo sobre como responder; respetalas SIEMPRE por encima de tu estilo general): ' + correccionesJoin) : '';
  return { comportamiento: comportamiento, rubro: rub, internas: internas, correcciones: correcciones };
}

// ============ SUSCRIPCIONES Y PLANES (MercadoPago) — FASE 1 ============
// Definido pero INERTE (patron "Capa 1"): el gating real se activa con
// SUBSCRIPTIONS_ENABLED=true y requiere la tabla public.subscriptions.
// Mientras este apagado, TODO se permite => no afecta a los tenants actuales.
const SUBSCRIPTIONS_ENABLED = String(process.env.SUBSCRIPTIONS_ENABLED || '').toLowerCase() === 'true';
// Fecha ISO de corte: los clientes creados DESDE aca deben suscribirse; los anteriores quedan grandfathered (gratis). Vacio = nadie obligado.
const TRIAL_DESDE = process.env.TRIAL_DESDE || '';
const MP_TOKEN = process.env.MERCADOPAGO_ACCESS_TOKEN || '';
const MP_BASE = 'https://api.mercadopago.com';
// IDs globales de los planes en MercadoPago (creados 2026-06-16). Son del SaaS, compartidos por todos los tenants.
// enterprise: su id se carga en la env MP_PLAN_ENTERPRISE de Railway (mismo patron; se crea una vez via /api/maestro/mp-crear-plan-enterprise).
const PLANES_MP = { basico: 'a1792acbe2b14721885c3d1b9cb2a867', pro: 'a91c0a95c26f499fb55d9b71ac888b39', premium: 'a320490c4aca402c92e8fa4d12347af7', enterprise: process.env.MP_PLAN_ENTERPRISE || '' };
// Precios mensuales en ARS por nivel (HARDCODE). El preapproval directo (mpCrearSuscripcion) usa ESTE monto en
// auto_recurring.transaction_amount: asi el checkout NO depende del GET del plan en MP (que a veces falla -> MP 500).
// NOTA: ya NO es la fuente del cobro (eso es precioPlanARS, atado al dolar). Queda como mapa de niveles validos
// y precio BASE de referencia (lo usa el guard de aceptar-plan). Mantener en sync con BASE_PESOS.
const PRECIOS_MP = { basico: 55000, pro: 130000, premium: 350000, enterprise: 620000 };

// ============ DOLAR BLUE REF (ratchet / high-water-mark) ============
// Todos los precios nuevos se atan al blue VENTA con un piso que SOLO sube. Se guarda 1 valor GLOBAL en
// app_config.dolar_ref (NO por-tenant). Base inicial 1530 (a ese valor los precios dan exactos los base).
const DOLAR_REF_BASE = 1530;
var _dolarRefCache = DOLAR_REF_BASE; // cache en memoria: el path de COBRO usa esto (NO hace fetch). El cron lo refresca.

// Lee el ref guardado de la DB y lo cachea. DEFENSIVO: si falla o no hay fila/tabla, deja el ultimo cache (o base).
async function obtenerDolarRef() {
  try {
    var r = await supabase.from('app_config').select('dolar_ref').eq('id', 1).maybeSingle();
    var v = r && r.data && Number(r.data.dolar_ref);
    if (v && isFinite(v) && v >= DOLAR_REF_BASE) { _dolarRefCache = v; return v; }
  } catch (e) { console.error('obtenerDolarRef:', e && e.message); }
  return _dolarRefCache;
}
function dolarRefSync() { return _dolarRefCache; } // valor SINCRONICO para el cobro: nunca hace red, usa el cache.

// JOB (corre en el cron, NO en el cobro): fetch blue.venta, ratchea max(ref, venta) y guarda. Best-effort.
async function actualizarDolarRef() {
  try {
    var refActual = await obtenerDolarRef();
    var venta = null;
    try {
      var resp = await fetch('https://dolarapi.com/v1/dolares/blue');
      if (resp && resp.ok) { var j = await resp.json(); var vv = j && Number(j.venta); if (vv && isFinite(vv) && vv > 0) venta = vv; }
    } catch (eF) { console.error('actualizarDolarRef fetch dolarapi:', eF && eF.message); }
    var nuevo = Math.max(refActual, DOLAR_REF_BASE, venta || 0); // RATCHET: solo sube
    if (nuevo > refActual) { await supabase.from('app_config').update({ dolar_ref: nuevo, dolar_ref_updated_at: new Date().toISOString() }).eq('id', 1); }
    _dolarRefCache = nuevo;
  } catch (e) { console.error('actualizarDolarRef:', e && e.message); }
}

// Precios BASE en ARS a dolar_ref=1530 (los 4 planes fijos). A 1530 dan EXACTO estos valores; si el blue sube, suben proporcional.
const BASE_PESOS = { basico: 55000, pro: 130000, premium: 350000, enterprise: 620000 };
function precioPlanARS(nivel) {
  var base = BASE_PESOS[nivel];
  if (typeof base === 'undefined' || base === null) return null;
  var ref = dolarRefSync();
  if (!ref || !isFinite(ref) || ref < DOLAR_REF_BASE) ref = DOLAR_REF_BASE;
  return Math.round(base * ref / DOLAR_REF_BASE);
}

// ===== PLAN PERSONAL (a medida) + RECARGA de mensajes (pago unico) =====
// Personal: suscripcion mensual con volumen ELEGIDO por el cliente (min 15.000 msgs) a USD 0,04 c/u x dolar.
// Recarga: pago UNICO (Checkout Pro) para sumar mensajes al pool, min 200 a USD 0,06 c/u x dolar (requiere plan activo).
// Ambos precios atados al MISMO dolar ratchet (dolarRefSync) que los planes fijos.
const PERSONAL_USD_POR_MSG = 0.04;
const PERSONAL_MIN_MSGS = 15000;
const PERSONAL_MAX_MSGS = 2000000; // tope de cordura: evita montos absurdos por typo/manipulacion
const RECARGA_USD_POR_MSG = 0.06;
const RECARGA_MIN_MSGS = 200;
const RECARGA_MAX_MSGS = 1000000;
// Piso de dolar (mismo guard que precioPlanARS): nunca por debajo del base, ni con un cache corrupto.
function _dolarSeguro() { var ref = dolarRefSync(); return (!ref || !isFinite(ref) || ref < DOLAR_REF_BASE) ? DOLAR_REF_BASE : ref; }
function precioPersonalARS(cantMsgs) {
  var n = parseInt(cantMsgs, 10);
  if (!Number.isSafeInteger(n) || n < PERSONAL_MIN_MSGS || n > PERSONAL_MAX_MSGS) return null;
  return Math.round(n * PERSONAL_USD_POR_MSG * _dolarSeguro());
}
function precioRecargaARS(cantMsgs) {
  var n = parseInt(cantMsgs, 10);
  if (!Number.isSafeInteger(n) || n < RECARGA_MIN_MSGS || n > RECARGA_MAX_MSGS) return null;
  return Math.round(n * RECARGA_USD_POR_MSG * _dolarSeguro());
}

// Topes y features por nivel. (Los precios viven en MercadoPago, no aca.)
const PLAN_LIMITS = {
  trial:      { ai_messages: 100,   asesores: 5,        contactos: Infinity, reportes_ia: true,  audio_traduccion: true,  backup_drive: false, multi_whatsapp: false },
  basico:     { ai_messages: 500,   asesores: 3,        contactos: Infinity, reportes_ia: true,  audio_traduccion: true,  backup_drive: true,  multi_whatsapp: false },
  pro:        { ai_messages: 1800,  asesores: 6,        contactos: Infinity, reportes_ia: true,  audio_traduccion: true,  backup_drive: true,  multi_whatsapp: false },
  premium:    { ai_messages: 4500,  asesores: Infinity, contactos: Infinity, reportes_ia: true,  audio_traduccion: true,  backup_drive: true,  multi_whatsapp: true },
  enterprise: { ai_messages: 8000,  asesores: Infinity, contactos: Infinity, reportes_ia: true,  audio_traduccion: true,  backup_drive: true,  multi_whatsapp: true },
  // 'personal' (a medida): el CUPO real lo fija limits_override.ai_messages = la cantidad elegida (>=15.000) al contratar.
  // Aca ai_messages: 15000 es solo el piso/fallback si por algun motivo no hubiera override.
  personal:   { ai_messages: 15000, asesores: Infinity, contactos: Infinity, reportes_ia: true,  audio_traduccion: true,  backup_drive: true,  multi_whatsapp: true }
};
// SIN grandfathering de topes (Diego 2026-07-20): se ELIMINO. TODOS los clientes (viejos y nuevos) usan los topes
// actuales de PLAN_LIMITS. Ya no hay PLAN_LIMITS_LEGACY ni fecha de corte: nadie conserva topes "viejos" mas altos.
// (El override del Maestro por cliente sigue mandando aparte, ver topeEfectivoIA.)
// Plan por defecto cuando la funcion esta apagada o el tenant no tiene fila: acceso total.
const PLAN_DEFECTO = 'premium';

// Tope de mensajes EFECTIVO de un plan = el de PLAN_LIMITS (mismo para todos; el override del Maestro se aplica aparte).
function topeMensajesPlan(plan, sub) {
  return (PLAN_LIMITS[plan] || PLAN_LIMITS[PLAN_DEFECTO]).ai_messages;
}

// Lee la suscripcion del tenant. Si la tabla no existe o no hay fila, devuelve null (no rompe).
async function getSubscription(user_id) {
  try {
    if (!user_id) return null;
    const { data, error } = await supabase.from('subscriptions').select('*').eq('user_id', user_id).maybeSingle();
    if (error) return null;
    return data || null;
  } catch (e) { return null; }
}

// Plan vigente del tenant (considera estado y vencimiento). DEFAULT-OPEN si la funcion esta apagada.
async function planActual(user_id) {
  if (!SUBSCRIPTIONS_ENABLED) return PLAN_DEFECTO;
  const sub = await getSubscription(user_id);
  if (!sub) return PLAN_DEFECTO; // sin fila todavia: no bloquear
  if (sub.cortesia === true) return PLAN_DEFECTO; // cortesia: acceso libre con features plenas
  const activo = (sub.status === 'active' || sub.status === 'trial');
  const vigente = !sub.current_period_end || new Date(sub.current_period_end).getTime() >= Date.now();
  if (!activo || !vigente) return 'basico'; // suscripcion caida: cae al minimo, no corta del todo
  return PLAN_LIMITS[sub.plan] ? sub.plan : PLAN_DEFECTO;
}

// True si el plan del tenant habilita una feature (reportes_ia, audio_traduccion, backup_drive, multi_whatsapp).
async function planPermite(user_id, feature) {
  if (!SUBSCRIPTIONS_ENABLED) return true;
  const plan = await planActual(user_id);
  const lim = PLAN_LIMITS[plan] || PLAN_LIMITS[PLAN_DEFECTO];
  return !!lim[feature];
}

// Mensajes IA consumidos en el periodo actual (0 si no hay fila).
async function usoMensajesIA(user_id) {
  const sub = await getSubscription(user_id);
  return (sub && typeof sub.ai_messages_this_period === 'number') ? sub.ai_messages_this_period : 0;
}

// M15: TOPE EFECTIVO de mensajes IA del periodo, PURO (sin red). Centraliza la unica definicion CORRECTA del tope
// (la que historicamente vivia inline en dentroDelTopeIA, el gate real) para que registrarUsoIA NO la recalcule
// distinto (antes registrarUsoIA omitia el cap del trial_con_tarjeta -> avisos/split plan-extra mal). Contempla, en
// ESTE orden de precedencia (byte-equivalente al gate): cortesia (ilimitado salvo override del Maestro),
// grandfathering legacy (topeMensajesPlan), cap fijo del trial con tarjeta, y AMBOS overrides (nuevo > compat viejo).
// Devuelve un numero, o Infinity = ILIMITADO. `plan` es el de planActual(user_id) (puede ser null/ignorado en cortesia).
function topeEfectivoIA(sub, plan) {
  if (sub && sub.cortesia === true) {
    // Cortesia: por defecto ILIMITADO. PERO si el Maestro le puso un override de mensajes (limits_override.ai_messages),
    // ESE tope manda aun bajo cortesia (override > cortesia-ilimitado).
    if (sub.limits_override && typeof sub.limits_override.ai_messages === 'number') return sub.limits_override.ai_messages;
    return Infinity; // sin override -> saldo ILIMITADO hasta que se le saque la cortesia
  }
  let tope = topeMensajesPlan(plan, sub); // grandfathering: clientes viejos conservan el tope legacy
  // B1: durante el TRIAL con tarjeta (status 'trial' + trial_con_tarjeta) el cupo es FIJO = PLAN_LIMITS.trial (100),
  // sin importar que plan eligio ni grandfathering. Recien tras el 1er pago real (webhook -> status 'active') se
  // libera el cupo del plan elegido. Un override del Maestro (si existe) sigue mandando sobre este cap.
  if (sub && sub.status === 'trial' && sub.trial_con_tarjeta === true) tope = PLAN_LIMITS.trial.ai_messages;
  if (sub && sub.limits_override && typeof sub.limits_override.ai_messages === 'number') tope = sub.limits_override.ai_messages; // override por cliente (panel maestro)
  else if (sub && typeof sub.ai_messages_limit_override === 'number') tope = sub.ai_messages_limit_override; // compat override viejo
  return tope;
}

// True si el tenant sigue dentro del tope de mensajes IA de su plan. (Usa el tope centralizado topeEfectivoIA.)
async function dentroDelTopeIA(user_id) {
  if (!SUBSCRIPTIONS_ENABLED) return true;
  const sub = await getSubscription(user_id);
  // planActual solo importa fuera de cortesia (grandfathering/plan); en cortesia el tope no depende del plan.
  const plan = (sub && sub.cortesia === true) ? null : await planActual(user_id);
  const tope = topeEfectivoIA(sub, plan);
  if (tope === Infinity) return true;
  const usado = (sub && typeof sub.ai_messages_this_period === 'number') ? sub.ai_messages_this_period : 0;
  return usado < tope || (sub && (sub.mensajes_extra || 0) > 0); // saldo extra (regalo/paquete) extiende el tope del plan
}

// ===== TOPE NOCTURNO (decision d): limite de mensajes IA por cuenta en la franja FUERA de horario de oficina =====
// Motivo: con la IA atendiendo 24/7, las noches (sin humanos) pueden disparar gasto. Este tope SOLO aplica cuando
// estamos FUERA del horario de oficina del tenant y SOLO si el dueno lo configuro. CONFIG (la escribe el front):
//   - business_settings.tope_nocturno_msgs (int): cupo de mensajes IA por noche. null / ausente / 0 / invalido => 100 (FRENO por default).
// El CONTADOR del dia lo maneja SOLO el backend en una jsonb aparte (business_settings.tope_nocturno_uso
// = { dia: 'YYYY-MM-DD' local AR, usado: int }) para no pisar la config del front. DEFAULT 100 (FRENO):
// columnas ausentes o cupo <= 0 => tope 100/noche (Diego 2026-06-27). 0 IA: solo lee/escribe DB.
function _fechaLocalArg() {
  const arg = new Date(Date.now() - 3 * 60 * 60000); // hora AR (leido via getUTC*)
  return arg.toISOString().slice(0, 10);
}
// Hora AR (0-23) usando el MISMO offset UTC-3 ya validado por el resto del codigo. Para la FRANJA de la VOZ V2.
function _horaLocalArg() {
  return new Date(Date.now() - 3 * 60 * 60000).getUTCHours();
}
// Franja del dia en AR para el saludo: 6-12 'manana', 12-20 'tarde', resto 'noche'.
function _franjaArg() {
  const h = _horaLocalArg();
  if (h >= 6 && h < 12) return 'manana';
  if (h >= 12 && h < 20) return 'tarde';
  return 'noche';
}
async function _leerTopeNocturno(user_id) {
  // Devuelve { max, dia, usado, horario }. Diego (2026-06-27): DEFAULT 100 (FRENO de gasto nocturno).
  // null / undefined / 0-invalido / columna ausente / sin fila -> tope = 100 (sigue frenando). El tope
  // se APLICA igual que antes (cap fuera de horario); solo cambia el valor por defecto, no la logica.
  const _DEF_TOPE = 100;
  try {
    let row = null;
    try {
      const { data } = await supabase.from('business_settings').select('tope_nocturno_msgs, tope_nocturno_uso, horario_oficina').eq('user_id', user_id).maybeSingle();
      row = data || null;
    } catch (eCol) {
      // Columna nueva ausente: igual aplicamos el tope por defecto (sin horario -> dentroDelTopeNocturno fail-open).
      return { max: _DEF_TOPE, dia: null, usado: 0, horario: null };
    }
    if (!row) return { max: _DEF_TOPE, dia: null, usado: 0, horario: null };
    const _raw = Number(row.tope_nocturno_msgs);
    let _max = _raw > 0 ? _raw : _DEF_TOPE; // null / undefined / 0 / invalido -> 100 (default freno)
    const uso = row.tope_nocturno_uso && typeof row.tope_nocturno_uso === 'object' ? row.tope_nocturno_uso : {};
    const _dia = (typeof uso.dia === 'string') ? uso.dia : null;
    const _usado = Number(uso.usado);
    return { max: _max, dia: _dia, usado: (_usado >= 0 ? _usado : 0), horario: row.horario_oficina || null };
  } catch (e) { return null; }
}
// True si la cuenta TODAVIA puede responder con IA esta noche (o si el tope nocturno no aplica). FAIL-OPEN.
async function dentroDelTopeNocturno(user_id) {
  try {
    const tn = await _leerTopeNocturno(user_id);
    if (!tn) return true; // sin cupo configurado -> siempre pasa (comportamiento actual)
    // Solo aplica FUERA de horario. Sin horario cargado -> no hay "noche" definida -> no limitar (consistente con (b)).
    if (!tn.horario) return true;
    if (dentroHorarioOficina(tn.horario)) return true; // estamos DENTRO de horario: el tope nocturno no corre
    const hoy = _fechaLocalArg();
    const usadoHoy = (tn.dia === hoy) ? tn.usado : 0; // contador del dia local AR
    return usadoHoy < tn.max;
  } catch (e) { return true; } // fail-open: ante error no cortar el servicio
}
// Suma 1 al contador nocturno del dia (best-effort, 0 IA). Solo cuenta si estamos fuera de horario y hay cupo.
async function registrarMensajeNocturno(user_id) {
  try {
    const tn = await _leerTopeNocturno(user_id);
    if (!tn || !tn.horario || dentroHorarioOficina(tn.horario)) return; // solo de noche y con cupo configurado
    const hoy = _fechaLocalArg();
    const usadoHoy = (tn.dia === hoy) ? tn.usado : 0;
    try { await supabase.from('business_settings').update({ tope_nocturno_uso: { dia: hoy, usado: usadoHoy + 1 } }).eq('user_id', user_id); } catch (eUpd) {}
  } catch (e) {}
}

// Senal AUTORITATIVA de corte por falta de pago. Replica EXACTAMENTE el gate del
// webhook (~1271-1294) + planActual + cortesia + grandfathered, SIN alterarlo: solo
// computa lo mismo de forma reusable. FAIL-OPEN: ante cualquier error o duda -> false.
// TRUE solo cuando: SUBSCRIPTIONS_ENABLED esta activo Y el tenant NO es cortesia Y NO es
// grandfathered Y debe pagar y no lo hizo (status en {cancelled, suspended}
// O no tiene fila de suscripcion y su cuenta es posterior a TRIAL_DESDE).
// En CUALQUIER otro caso (flag apagado, cortesia, grandfathered, trial, active, sin certeza) -> false.
async function debeBloquearAcceso(user_id) {
  try {
    // FIX (Anton, cortesia): si el que pide es un ASESOR (tiene fila en asesores), el estado de suscripcion/bloqueo
    // es el del DUEÑO (admin_id), no el suyo — el asesor NO tiene suscripcion propia. Sin esto, el guardian global
    // (~L130) y todas las rutas devolvian 403 y el asesor no podia enviar ni interactuar. Dueño = sin fila -> queda igual.
    try {
      const _yoB = await supabase.from('asesores').select('admin_id').eq('auth_user_id', user_id).maybeSingle();
      if (_yoB && _yoB.data && _yoB.data.admin_id) user_id = _yoB.data.admin_id;
    } catch (eAse) { /* sin fila -> es el dueño, user_id queda igual */ }
    // PAPELERA (aditivo, independiente de las suscripciones): si el cliente fue eliminado
    // (business_settings.eliminado_at NOT NULL) no puede usar la app, este la funcion de
    // suscripciones encendida o no. Degrada bien si la columna aun no existe (select falla -> no bloquea por esto).
    try {
      const elim = await supabase.from('business_settings').select('eliminado_at').eq('user_id', user_id).maybeSingle();
      if (elim && !elim.error && elim.data && elim.data.eliminado_at) return true;
    } catch (eElim) {}
    if (!SUBSCRIPTIONS_ENABLED) return false; // funcion apagada: no se corta a nadie
    const sub = await getSubscription(user_id);
    const est = sub ? sub.status : null;
    const cortesia = sub && sub.cortesia === true;
    if (cortesia) return false; // cortesia: acceso libre, nunca se bloquea
    // Sin fila de suscripcion: solo se bloquea si la cuenta es NUEVA (creada DESDE TRIAL_DESDE).
    // Los anteriores quedan grandfathered (gratis) -> NO se bloquean. (mismo criterio que el webhook ~1277-1284)
    if (!sub) {
      if (!TRIAL_DESDE) return false; // nadie obligado a suscribirse
      try {
        const u = await supabase.auth.admin.getUserById(user_id);
        const ca = u && u.data && u.data.user && u.data.user.created_at;
        // grandfathered (created_at < TRIAL_DESDE) o sin certeza de la fecha -> NO bloquear (fail-open)
        if (ca && new Date(ca).getTime() >= new Date(TRIAL_DESDE).getTime()) return true;
        return false;
      } catch (eC) { return false; } // sin certeza -> no bloquear
    }
    // Con fila de suscripcion: bloquear SOLO si esta cancelled/suspended (EXACTO como el gate del agente,
    // webhook ~1285). NO se bloquea past_due: el agente sigue atendiendo durante la gracia de 1 dia, y el
    // cron revisarSuscripciones pasa past_due -> suspended tras esa gracia (recien ahi se bloquea aca).
    if (est === 'cancelled' || est === 'suspended') return true;
    // TRIAL: por defecto SIN ACCESO. MercadoPago NUNCA usa el estado "trial": una suscripcion autorizada (aun en su
    // periodo de prueba con tarjeta) queda 'authorized' -> la mapeamos a 'active'. Por eso status 'trial' en
    // nuestra base puede venir de: (a) el trial automatico del registro (sin tarjeta), (b) una preapproval
    // 'pending'/abandonada (el webhook mapea todo lo no-authorized/paused/cancelled a 'trial', y le pone
    // mp_preapproval_id aunque NO este autorizada), o (c) B1: el trial CON TARJETA upfront (start_date = ahora+4d),
    // marcado con trial_con_tarjeta=true. Solo (c) es un suscriptor "real" en prueba -> NO se bloquea (la IA
    // responde, capeada a 100 por dentroDelTopeIA). (a) y (b) NO son suscriptores reales -> se bloquean SIEMPRE.
    // Asi un usuario que solo se registro (o abandono el checkout) queda bloqueado (solo Suscripcion/Ayuda/
    // Soporte/Salir) hasta que cargue tarjeta; y se mata el bypass del boton Dashboard al volver atras.
    if (est === 'trial') return (sub && sub.trial_con_tarjeta === true) ? false : true;
    return false; // active, past_due (en gracia), o estado desconocido -> no bloquear
  } catch (e) { return false; } // ante cualquier error -> fail-open (no cortar el servicio)
}

// M10: dispara los avisos 80%/100% (plan) y "agotado extra" a partir de los valores ANTES/DESPUES (push FCM, NO gasta
// tokens). Centralizado para que tanto la via atomica (RPC) como el fallback usen EXACTAMENTE el mismo criterio de cruce.
async function _avisosUsoIA(user_id, tope, usadoAntes, usadoDespues, extraAntes, extraDespues) {
  try {
    // Cruce del PLAN (solo si hay tope finito > 0). El "agotado" solo si NO quedo saldo extra que lo cubra.
    if (tope !== Infinity && tope > 0 && usadoDespues > usadoAntes) {
      const p80 = Math.floor(tope * 0.8);
      if (usadoAntes < tope && usadoDespues >= tope && extraAntes <= 0) {
        await enviarPushAsesor(user_id, 'Se agoto tu cupo de mensajes IA', '', 'El agente dejo de responder automaticamente este mes. Podes mejorar tu plan para reactivarlo o esperar al proximo periodo.');
      } else if (usadoAntes < p80 && usadoDespues >= p80) {
        await enviarPushAsesor(user_id, 'Cupo de mensajes IA al 80%', '', 'Usaste el 80% de tus mensajes IA del mes. Cuando se agote, el agente deja de responder hasta el proximo periodo o un upgrade.');
      }
    }
    // Cruce del SALDO EXTRA a 0 (se consumio extra y quedo en <=0).
    if (extraDespues <= 0 && extraAntes > 0 && extraDespues < extraAntes) {
      await enviarPushAsesor(user_id, 'Se agoto tu saldo de mensajes IA', '', 'Se termino tu saldo extra de mensajes. El agente dejo de responder hasta el proximo periodo, un upgrade o un nuevo paquete.');
    }
  } catch (eAviso) { console.error('[BILLING] _avisosUsoIA fallo:', eAviso && eAviso.message); } // B6: no tragar en silencio (avisos de cupo/saldo)
}

// FALLBACK no-atomico (read-modify-write de a 1, IDENTICO al comportamiento historico) usado SOLO si la RPC atomica
// no esta disponible en la DB. Cobra UNA unidad: plan primero, si esta lleno cae al saldo extra. Avisa en el cruce exacto.
async function _registrarUsoIAUna(user_id) {
  try {
    if (!SUBSCRIPTIONS_ENABLED || !user_id) return;
    const sub = await getSubscription(user_id);
    if (!sub) return;
    const usadoAntes = (typeof sub.ai_messages_this_period === 'number') ? sub.ai_messages_this_period : 0;
    const extraAntes = (typeof sub.mensajes_extra === 'number') ? sub.mensajes_extra : 0;
    // M15: tope centralizado (mismo criterio CORRECTO que dentroDelTopeIA, incluye el cap del trial_con_tarjeta).
    const planN = (sub.cortesia === true) ? null : await planActual(user_id);
    const tope = topeEfectivoIA(sub, planN);
    if (usadoAntes < tope) {
      const nuevo = usadoAntes + 1;
      await supabase.from('subscriptions').update({ ai_messages_this_period: nuevo }).eq('user_id', user_id);
      if (sub.cortesia !== true) await _avisosUsoIA(user_id, tope, usadoAntes, nuevo, extraAntes, extraAntes);
    } else if (extraAntes > 0) {
      const extraNuevo = extraAntes - 1;
      await supabase.from('subscriptions').update({ mensajes_extra: extraNuevo }).eq('user_id', user_id);
      await _avisosUsoIA(user_id, tope, usadoAntes, usadoAntes, extraAntes, extraNuevo);
    }
    // (usadoAntes >= tope y extraAntes <= 0: no hay nada que consumir; dentroDelTopeIA ya habria bloqueado el mensaje)
  } catch (e) { console.error('[BILLING] _registrarUsoIAUna fallo (consumo NO contabilizado):', e && e.message); } // B6: un fallo aca = mensaje consumido pero no cobrado -> hay que poder verlo en logs
}

// Suma N (>=1) al consumo de mensajes IA (best-effort, no rompe si falla). Modelo: PLAN primero, despues SALDO EXTRA.
// El plan (ai_messages_this_period) se resetea cada ciclo; el extra (mensajes_extra: regalo/paquetes) NO se resetea.
// M10: el incremento es ATOMICO en la DB (RPC registrar_uso_ia: hace el split plan/extra y RETURNING en UNA operacion,
// sin perder incrementos bajo concurrencia). Los avisos 80%/100% se derivan del valor RETORNADO. Si la RPC no existe
// (migracion pendiente), cae al fallback read-modify-write de a 1 (comportamiento IDENTICO al historico).
//
//   SQL para crear la RPC (ejecutar una vez en Supabase; mientras tanto rige el fallback):
//   create or replace function registrar_uso_ia(p_user_id uuid, p_n int, p_tope numeric)
//   returns table(usado_antes int, usado_despues int, extra_antes int, extra_despues int)
//   language plpgsql as $$
//   declare ua int; ea int; cabe int; del_extra int;
//   begin
//     select coalesce(ai_messages_this_period,0), coalesce(mensajes_extra,0) into ua, ea
//       from subscriptions where user_id = p_user_id for update;
//     if not found then return; end if;
//     if p_tope is null then cabe := p_n;  -- NULL = ilimitado (cortesia)
//     else cabe := greatest(0, least(p_n, floor(p_tope)::int - ua)); end if;
//     del_extra := least(greatest(0, p_n - cabe), ea);
//     update subscriptions
//        set ai_messages_this_period = ua + cabe,
//            mensajes_extra = ea - del_extra
//      where user_id = p_user_id;
//     usado_antes := ua; usado_despues := ua + cabe; extra_antes := ea; extra_despues := ea - del_extra;
//     return next;
//   end $$;
async function registrarUsoIA(user_id, cantidad) {
  var _n = (typeof cantidad === 'number' && cantidad >= 1) ? Math.floor(cantidad) : 1;
  if (_n < 1) _n = 1;
  try {
    if (!SUBSCRIPTIONS_ENABLED || !user_id) return;
    const sub = await getSubscription(user_id);
    if (!sub) return;
    // M15: tope centralizado (mismo criterio CORRECTO que dentroDelTopeIA). Infinity (cortesia/ilimitado) -> NULL para la RPC.
    const planN = (sub.cortesia === true) ? null : await planActual(user_id);
    const tope = topeEfectivoIA(sub, planN);
    const pTope = (tope === Infinity) ? null : tope;
    // 1) VIA ATOMICA: una sola operacion en DB (no pierde incrementos en concurrencia).
    try {
      const { data, error } = await supabase.rpc('registrar_uso_ia', { p_user_id: user_id, p_n: _n, p_tope: pTope });
      if (!error && Array.isArray(data) && data.length > 0) {
        const r = data[0] || {};
        const ua = Number(r.usado_antes) || 0, ud = Number(r.usado_despues) || 0;
        const ea = Number(r.extra_antes) || 0, ed = Number(r.extra_despues) || 0;
        if (sub.cortesia !== true) await _avisosUsoIA(user_id, tope, ua, ud, ea, ed);
        return;
      }
      // error (p.ej. funcion inexistente / schema cache) -> cae al fallback de abajo.
    } catch (eRpc) { console.error('[BILLING] registrar_uso_ia RPC fallo, usando fallback:', eRpc && eRpc.message); } // B6: visibilizar que la via atomica fallo (cae al fallback)
    // 2) FALLBACK no-atomico: de a 1, N veces (cada pasada relee el estado y avisa en el cruce exacto). Identico al historico.
    for (var _i = 0; _i < _n; _i++) { await _registrarUsoIAUna(user_id); }
  } catch (e) { console.error('[BILLING] registrarUsoIA fallo (consumo NO contabilizado):', e && e.message); } // B6: un fallo aca = consumo IA sin cobrar -> no tragarlo en silencio
}

// M17: IDs de modelo centralizados (un solo string por modelo, sin copy-paste). Regla de modelos del proyecto:
//   - MODELO_CLIENTE  = customer-facing (atencion al lead, traduccion, reportes/soporte al dueno) -> Sonnet -> PRECIO_IA
//   - MODELO_INTERNO  = tareas de fondo (clasificadores, extraccion, memoria viva, vision, scraper, chat interno) -> Haiku -> PRECIO_HAIKU
// NO cambia QUE modelo usa cada llamada: solo reemplaza el literal hardcodeado. Cada call site se emparejo con la
// tabla de precio de SU modelo (Sonnet->PRECIO_IA, Haiku->PRECIO_HAIKU) para que el panel no infle/desinfle el gasto.
const MODELO_CLIENTE = 'claude-sonnet-4-6';
const MODELO_INTERNO = 'claude-haiku-4-5';
// Precio de Sonnet 4.6 (MODELO_CLIENTE) en USD por 1M de tokens (input / output / cache read / cache write).
const PRECIO_IA = { in: 3, out: 15, cache_read: 0.30, cache_write: 3.75 };
// Precio de Haiku 4.5 (MODELO_INTERNO, mucho mas barato) — para tareas de fondo (memoria viva, clasificadores). Asi el panel
// contabiliza el costo REAL del modelo usado y no infla el gasto (~3x) registrando Haiku a precio de Sonnet.
const PRECIO_HAIKU = { in: 1, out: 5, cache_read: 0.10, cache_write: 1.25 };
// Registra el uso real de tokens de una respuesta de la IA y su costo en USD (best-effort, no rompe).
// `precio` permite contabilizar al precio del MODELO usado (Haiku vs Sonnet); por defecto Sonnet.
async function registrarUsoTokens(user_id, usage, etiqueta, precio) {
  try {
    if (!user_id || !usage) return;
    const P = precio || PRECIO_IA;
    const i = usage.input_tokens || 0;
    const o = usage.output_tokens || 0;
    const cr = usage.cache_read_input_tokens || 0;
    const cw = usage.cache_creation_input_tokens || 0;
    const costo = (i * P.in + o * P.out + cr * P.cache_read + cw * P.cache_write) / 1000000;
    await supabase.from('ia_uso').insert({ user_id: user_id, input_tokens: i, output_tokens: o, cache_read: cr, cache_creation: cw, cost_usd: costo, etiqueta: etiqueta || null });
  } catch (e) { console.error('[BILLING] registrarUsoTokens fallo (gasto IA NO registrado en ia_uso):', e && e.message); } // B6: un fallo aca = costo de tokens que NO aparece en el panel -> hay que poder detectarlo
}

// Crea una notificacion en el Panel Maestro (best-effort y SILENCIOSO). CRITICO: todo va dentro de un try/catch
// que TRAGA cualquier error (tabla inexistente, fallo de red, etc.) para NO romper NUNCA al que lo llama.
// tipo: nuevo_cliente|suscripcion_nueva|suscripcion_cambio|suscripcion_cancelada|soporte|consumo_anomalo|ia_sin_saldo|sistema
// opts: { ref_user_id, ref_id, severidad } (severidad: info|warning|critico; default 'info').
async function crearNotifMaestro(tipo, titulo, cuerpo, opts) {
  try {
    var o = opts || {};
    var fila = {
      tipo: String(tipo || 'sistema'),
      titulo: String(titulo || ''),
      cuerpo: cuerpo != null ? String(cuerpo) : null,
      ref_user_id: o.ref_user_id || null,
      ref_id: o.ref_id != null ? String(o.ref_id) : null,
      severidad: o.severidad || 'info'
    };
    await supabase.from('maestro_notificaciones').insert(fila);
    // Push FCM al celular del Maestro (best-effort, fire-and-forget): asi las notifs llegan al telefono.
    enviarPushMaestro(fila.titulo, (fila.cuerpo || '').slice(0, 180)).catch(function(){});
  } catch (e) {}
}

// Push FCM a TODOS los dispositivos del Maestro (la app del dueno, tabla maestro_device_tokens). Best-effort.
async function enviarPushMaestro(titulo, cuerpo) {
  try {
    if (!_fcmReady) return;
    var q = await supabase.from('maestro_device_tokens').select('token');
    var toks = (q && q.data) || [];
    var tokens = toks.map(function(t){ return t.token; }).filter(Boolean);
    if (!tokens.length) return;
    var resp = await _fcmAdmin.messaging().sendEachForMulticast({
      tokens: tokens,
      notification: { title: String(titulo || 'Raices Maestro'), body: String(cuerpo || '') },
      android: { priority: 'high' }
    });
    if (resp && resp.responses) {
      for (var i = 0; i < resp.responses.length; i++) {
        var r = resp.responses[i];
        var code = (r && r.error && r.error.code) || '';
        if (!r.success && /not-registered|invalid-registration-token|invalid-argument/.test(code)) {
          try { await supabase.from('maestro_device_tokens').delete().eq('token', tokens[i]); } catch (eDel) {}
        }
      }
    }
  } catch (e) { console.error('enviarPushMaestro:', e && e.message); }
}

// Detecta si un error de anthropic.messages.create es por SALDO agotado/insuficiente y, si lo es, crea una
// notif 'ia_sin_saldo' (critico) con DEDUPE de 6h (no mas de 1 cada 6 horas). Best-effort: jamas relanza.
async function avisarSiIaSinSaldo(err) {
  try {
    var msg = String((err && err.message) || err || '').toLowerCase();
    var status = err && (err.status || err.statusCode);
    var esSaldo = msg.indexOf('credit balance') >= 0 || msg.indexOf('too low') >= 0 ||
                  (msg.indexOf('balance') >= 0 && (msg.indexOf('insufficient') >= 0 || status === 400));
    if (!esSaldo) return;
    // DEDUPE: no crear si ya hay una ia_sin_saldo en las ultimas 6h
    try {
      var desde6h = new Date(Date.now() - 6 * 3600 * 1000).toISOString();
      var ya = await supabase.from('maestro_notificaciones').select('id').eq('tipo', 'ia_sin_saldo').gte('created_at', desde6h).limit(1);
      if (ya && ya.data && ya.data.length) return;
    } catch (eDup) { /* si la consulta falla, igual avisamos (mejor avisar de mas que callar un corte de IA) */ }
    crearNotifMaestro('ia_sin_saldo', 'La IA dejo de responder', 'Saldo de Anthropic agotado o insuficiente. Recarga creditos.', { severidad: 'critico' }).catch(function(){});
  } catch (e) {}
}

// ============ FASE 0 FAILOVER: degradacion elegante ante caida del PROVEEDOR de IA (Anthropic) ============
// Texto fijo al lead cuando la IA no pudo responder tras los reintentos del SDK (0 tokens de IA).
const MSG_DEMORA_IA = 'Perdon, estamos con mucha demanda en este momento. Ya le aviso a un companero del equipo para que te responda a la brevedad 🙌';

// Detecta si un error de anthropic.messages.create es un corte TRANSITORIO del proveedor (529 Overloaded, 5xx,
// timeout, ECONNRESET) tras agotarse los reintentos del SDK. El saldo agotado NO cuenta (lo maneja avisarSiIaSinSaldo).
function esErrorTransitorioIA(err) {
  try {
    var status = err && (err.status || err.statusCode);
    var msg = String((err && err.message) || err || '').toLowerCase();
    if (msg.indexOf('credit balance') >= 0 || msg.indexOf('insufficient') >= 0) return false;
    if (status === 529 || (typeof status === 'number' && status >= 500)) return true;
    if (status === 429) return true;
    return /overloaded|timeout|timed out|econnreset|enotfound|econnrefused|socket hang up|network|fetch failed/.test(msg);
  } catch (e) { return false; }
}

// Avisa al Maestro UNA vez cada 15 min (dedupe) que la IA esta caida por el proveedor. Best-effort: jamas relanza.
async function avisarSiIaCaida(err) {
  try {
    if (!esErrorTransitorioIA(err)) return;
    try {
      var desde = new Date(Date.now() - 15 * 60 * 1000).toISOString();
      var ya = await supabase.from('maestro_notificaciones').select('id').eq('tipo', 'ia_caida').gte('created_at', desde).limit(1);
      if (ya && ya.data && ya.data.length) return;
    } catch (eDup) {}
    crearNotifMaestro('ia_caida', 'La IA no responde (proveedor)', 'Anthropic devolvio errores transitorios (529/5xx/timeout) tras los reintentos. Algunos leads recibieron un mensaje de demora y quedaron marcados para atencion humana.', { severidad: 'critico' }).catch(function(){});
  } catch (e) {}
}

// ============================================================================
// FEATURE #23 — FAILOVER IA via AWS BEDROCK (gateado y APAGADO por default)
// ----------------------------------------------------------------------------
// Objetivo: si la API directa de Anthropic se cae (529/5xx/timeout/red), reintentar
// EL MISMO request contra Claude servido por AWS Bedrock. Asi, ante un outage del
// proveedor directo, los leads cliente-facing siguen siendo atendidos.
//
// REGLA DURA (apagado por default):
//   - Solo se activa si BEDROCK_ENABLED=true Y estan las credenciales de AWS
//     (AWS_ACCESS_KEY_ID + AWS_SECRET_ACCESS_KEY, o un perfil/role en el entorno) Y
//     el paquete @anthropic-ai/bedrock-sdk esta instalado (require defensivo).
//   - Si falta CUALQUIERA de esas tres cosas, _bedrockReady=false y llamarIAConFailover
//     se comporta EXACTAMENTE como anthropic.messages.create (cero cambio de comportamiento,
//     cero dependencia nueva obligatoria).
//
// Modelos: Bedrock usa IDs DISTINTOS a la API directa (ej. claude-sonnet-4-6 ->
// 'us.anthropic.claude-sonnet-4-...-v1:0'). Se mapean por env (BEDROCK_MODEL_CLIENTE /
// BEDROCK_MODEL_INTERNO) para no hardcodear un ID que Diego quizas no tenga habilitado.
// Si no hay mapeo para el modelo pedido, NO se intenta Bedrock (se relanza el error
// original de Anthropic) — nunca se manda un modelId invalido.
//
// COMO EXTENDERLO al resto de las llamadas: cualquier `await anthropic.messages.create(P)`
// se reemplaza por `await llamarIAConFailover(P, etiqueta)`. La firma del request es
// identica; el wrapper no toca params. Hoy se aplica al call principal cliente-facing
// (generarRespuestaAgente / MODELO_CLIENTE). El resto sigue usando anthropic directo.
let _bedrockReady = false;
let _bedrockClient = null;
const BEDROCK_ENABLED = String(process.env.BEDROCK_ENABLED || '').toLowerCase() === 'true';
const BEDROCK_REGION = process.env.AWS_REGION || process.env.BEDROCK_REGION || 'us-east-1';
// Mapa modelo-directo -> modelId de Bedrock (por env, sin hardcodear un inference profile que no exista).
const _BEDROCK_MODEL_MAP = {};
try {
  if (process.env.BEDROCK_MODEL_CLIENTE) _BEDROCK_MODEL_MAP[MODELO_CLIENTE] = String(process.env.BEDROCK_MODEL_CLIENTE).trim();
  if (process.env.BEDROCK_MODEL_INTERNO) _BEDROCK_MODEL_MAP[MODELO_INTERNO] = String(process.env.BEDROCK_MODEL_INTERNO).trim();
} catch (e) {}
try {
  const _tieneCreds = !!(process.env.AWS_ACCESS_KEY_ID && process.env.AWS_SECRET_ACCESS_KEY) ||
                      !!process.env.AWS_PROFILE || !!process.env.AWS_CONTAINER_CREDENTIALS_RELATIVE_URI || !!process.env.AWS_WEB_IDENTITY_TOKEN_FILE;
  if (BEDROCK_ENABLED && _tieneCreds) {
    // require DEFENSIVO: si el paquete no esta instalado, NO rompe (queda _bedrockReady=false).
    const { AnthropicBedrock } = require('@anthropic-ai/bedrock-sdk');
    _bedrockClient = new AnthropicBedrock({
      awsRegion: BEDROCK_REGION,
      // El SDK de Bedrock toma las credenciales del entorno (AWS_ACCESS_KEY_ID/SECRET o el role).
      // Se pasan explicitas solo si estan en env (para entornos sin perfil/role).
      awsAccessKey: process.env.AWS_ACCESS_KEY_ID || undefined,
      awsSecretKey: process.env.AWS_SECRET_ACCESS_KEY || undefined,
      awsSessionToken: process.env.AWS_SESSION_TOKEN || undefined,
      maxRetries: 2
    });
    _bedrockReady = true;
    console.log('[FAILOVER] Bedrock listo (region ' + BEDROCK_REGION + ', modelos mapeados: ' + Object.keys(_BEDROCK_MODEL_MAP).join(',') + ')');
  } else if (BEDROCK_ENABLED && !_tieneCreds) {
    console.log('[FAILOVER] BEDROCK_ENABLED=true pero faltan credenciales AWS -> failover Bedrock DESACTIVADO');
  } else {
    console.log('[FAILOVER] Bedrock no configurado (BEDROCK_ENABLED!=true) -> comportamiento actual exacto (solo Anthropic directo)');
  }
} catch (e) {
  // Paquete ausente o error de init: failover OFF, sistema sigue 100% con Anthropic directo.
  _bedrockReady = false;
  console.log('[FAILOVER] @anthropic-ai/bedrock-sdk no disponible (' + (e && e.message) + ') -> failover Bedrock DESACTIVADO (comportamiento actual exacto)');
}

// Avisa al Maestro UNA vez cada 15 min (dedupe) que se cayo al failover de Bedrock. Best-effort.
async function _avisarFailoverBedrock(etiqueta) {
  try {
    var desde = new Date(Date.now() - 15 * 60 * 1000).toISOString();
    var ya = await supabase.from('maestro_notificaciones').select('id').eq('tipo', 'ia_failover_bedrock').gte('created_at', desde).limit(1);
    if (ya && ya.data && ya.data.length) return;
    crearNotifMaestro('ia_failover_bedrock', 'IA respondiendo via Bedrock (failover)', 'Anthropic directo fallo (transitorio) y el sistema esta respondiendo via AWS Bedrock. Revisa el estado del proveedor directo.' + (etiqueta ? ' Origen: ' + etiqueta : ''), { severidad: 'warning' }).catch(function(){});
  } catch (e) {}
}

// WRAPPER de failover. Intenta Anthropic directo; si falla con un error TRANSITORIO del
// proveedor (no por saldo, no por request invalido) y Bedrock esta listo + hay modelId
// mapeado, reintenta el MISMO request via Bedrock. Si Bedrock tampoco anda, relanza el
// error ORIGINAL de Anthropic (asi el caller activa su degradacion elegante de siempre).
// `params` se pasa TAL CUAL a messages.create (no se muta). `etiqueta` es solo para logs/avisos.
async function llamarIAConFailover(params, etiqueta) {
  try {
    return await anthropic.messages.create(params);
  } catch (err) {
    // Solo failover ante cortes TRANSITORIOS del proveedor. Saldo agotado / request invalido NO se reintenta en Bedrock.
    if (!_bedrockReady || !esErrorTransitorioIA(err)) throw err;
    const bedrockModel = _BEDROCK_MODEL_MAP[params && params.model];
    if (!bedrockModel) throw err; // sin modelId de Bedrock para ese modelo -> no se intenta (evita modelId invalido)
    try {
      // MISMO request, solo cambia el model al inference profile de Bedrock.
      const paramsBedrock = Object.assign({}, params, { model: bedrockModel });
      const r = await _bedrockClient.messages.create(paramsBedrock);
      console.log('[FAILOVER] respondido via Bedrock' + (etiqueta ? ' (' + etiqueta + ')' : '') + ' tras fallo de Anthropic directo: ' + (err && err.message));
      _avisarFailoverBedrock(etiqueta).catch(function(){});
      return r;
    } catch (errBedrock) {
      // Bedrock tampoco respondio: relanzar el error ORIGINAL de Anthropic (degradacion del caller intacta).
      console.error('[FAILOVER] Bedrock tambien fallo' + (etiqueta ? ' (' + etiqueta + ')' : '') + ': ' + (errBedrock && errBedrock.message) + ' | error original Anthropic: ' + (err && err.message));
      throw err;
    }
  }
}

// ---- MercadoPago via REST (sin SDK, sin dependencias nuevas; fetch es global en Node 18+) ----
async function mpFetch(path, metodo, cuerpo) {
  if (!MP_TOKEN) throw new Error('MercadoPago no configurado (falta MERCADOPAGO_ACCESS_TOKEN)');
  const r = await fetch(MP_BASE + path, {
    method: metodo || 'GET',
    headers: { 'Authorization': 'Bearer ' + MP_TOKEN, 'Content-Type': 'application/json' },
    body: cuerpo ? JSON.stringify(cuerpo) : undefined
  });
  const txt = await r.text();
  let json = null; try { json = txt ? JSON.parse(txt) : null; } catch (e) {}
  if (!r.ok) throw new Error('MP ' + r.status + ': ' + String((json && json.message) ? json.message : txt).slice(0, 200));
  return json;
}

// Crea un plan de suscripcion en MP (uno por nivel). Devuelve el preapproval_plan (con .id).
async function mpCrearPlan(nombre, montoARS, backUrl) {
  const body = {
    reason: nombre,
    auto_recurring: { frequency: 1, frequency_type: 'months', transaction_amount: montoARS, currency_id: 'ARS', free_trial: { frequency: 4, frequency_type: 'days' } },
    back_url: backUrl,
    payment_methods_allowed: { payment_types: [{ id: 'credit_card' }, { id: 'debit_card' }] }
  };
  return await mpFetch('/preapproval_plan', 'POST', body);
}

// Crea una suscripcion (preapproval). Devuelve el objeto con init_point (checkout de MP).
// IMPORTANTE: el flujo "con preapproval_plan_id + payer_email" via API exige card_token_id (MP400).
// Para obtener el init_point (checkout donde el cliente carga la tarjeta en MP) SIN exigir tarjeta,
// creamos la preapproval SIN plan, con status:'pending'. El MONTO sale HARDCODE de PRECIOS_MP[nivel]
// (NO del GET del plan en MP: ese GET a veces falla -> transaction_amount undefined -> MP 500). Tampoco
// mandamos free_trial: el preapproval DIRECTO (sin plan) no lo soporta y tira 500. Conserva external_reference.
async function mpCrearSuscripcion(planId, payerEmail, externalRef, backUrl, nivel, startDateISO, montoOverride) {
  // montoOverride: monto en ARS ya calculado (lo usa el Plan Personal, cuyo monto NO sale de BASE_PESOS sino de la
  // cantidad de mensajes elegida). Si no viene, se usa el precio fijo del nivel (precioPlanARS).
  var monto = (typeof montoOverride === 'number' && montoOverride > 0) ? Math.round(montoOverride) : precioPlanARS(nivel);
  // Sin precio configurado para este nivel => transaction_amount undefined => MP 500. Cortamos con un error claro ANTES.
  if (typeof monto === 'undefined' || monto === null) {
    throw new Error('Plan sin precio configurado: ' + nivel);
  }
  // NOMBRE que ve el cliente en MercadoPago: sale del CODIGO (ya NO usamos plantillas preapproval_plan de MP). El cobro
  // es un preapproval DIRECTO con transaction_amount = precio del codigo (atado al dolar). planId se ignora.
  var _nivelNombre = { basico: 'Basico', pro: 'Pro', premium: 'Premium', enterprise: 'Enterprise', personal: 'Personal' };
  var reasonPlan = 'Raices CRM - Plan ' + (_nivelNombre[nivel] || 'Suscripcion');
  var autoRecurring = {
    frequency: 1,
    frequency_type: 'months',
    transaction_amount: monto,
    currency_id: 'ARS'
  };
  // Sin trial: cobra al autorizar. (startDateISO se conserva por compat; hoy el checkout siempre lo manda null.)
  if (startDateISO) autoRecurring.start_date = startDateISO;
  var body = {
    reason: reasonPlan,
    external_reference: externalRef,
    payer_email: payerEmail,
    back_url: backUrl,
    status: 'pending',
    auto_recurring: autoRecurring
  };
  return await mpFetch('/preapproval', 'POST', body);
}

// Cancela un preapproval en MercadoPago (corta el cobro de la tarjeta). mpFetch tira en no-2xx:
// el que llama debe envolver en try/catch (best-effort) y seguir cancelando localmente igual.
async function mpCancelarSuscripcion(preapprovalId) {
  return await mpFetch('/preapproval/' + preapprovalId, 'PUT', { status: 'cancelled' });
}

// Consulta el estado de una suscripcion por id.
async function mpConsultarSuscripcion(preapprovalId) {
  return await mpFetch('/preapproval/' + preapprovalId, 'GET', null);
}

// Consulta un PAGO unico por id (Checkout Pro). Lo usa el webhook para acreditar la recarga.
async function mpConsultarPago(paymentId) {
  return await mpFetch('/v1/payments/' + paymentId, 'GET', null);
}

// LIMPIEZA one-time (idempotente): cancela las PLANTILLAS de suscripcion viejas de MP (preapproval_plan con reason que
// arranca con "Raices CRM") que ya NO se usan (el cobro es un preapproval DIRECTO con el monto del codigo). Deja las
// plantillas AJENAS (ej. "Plan Redes Basico") intactas. Cancelar = sacar de "activos"; idempotente (tras el 1er boot
// no quedan activas -> no hace nada). NUNCA cancela nada con suscriptores (esas plantillas nunca tuvieron, usamos directo).
async function _limpiarPlanesMpViejosUnaVez() {
  try {
    if (!MP_TOKEN) return;
    var r = await mpFetch('/preapproval_plan/search?status=active&limit=100', 'GET', null);
    var results = (r && (r.results || r.elements)) || [];
    var cancelados = 0;
    for (var i = 0; i < results.length; i++) {
      var p = results[i];
      if (!p || !p.id) continue;
      var reason = String(p.reason || '').toLowerCase();
      if (reason.indexOf('raices crm') !== 0) continue; // SOLO nuestras plantillas (no "Plan Redes", ni ajenas)
      var subs = (p.summarized && Number(p.summarized.subscribed)) || 0;
      if (subs > 0) continue; // jamas tocar una con suscriptores (por las dudas)
      try { await mpFetch('/preapproval_plan/' + p.id, 'PUT', { status: 'cancelled' }); cancelados++; }
      catch (eC) {
        // Algunos entornos de MP esperan 'inactive' en vez de 'cancelled' para desactivar una plantilla.
        try { await mpFetch('/preapproval_plan/' + p.id, 'PUT', { status: 'inactive' }); cancelados++; }
        catch (eC2) { console.error('limpiar plan MP ' + p.id + ':', (eC && eC.message), '|', (eC2 && eC2.message)); }
      }
    }
    if (cancelados) console.log('[mp] plantillas viejas canceladas: ' + cancelados);
  } catch (e) { console.error('_limpiarPlanesMpViejosUnaVez:', e && e.message); }
}
setTimeout(function () { try { _limpiarPlanesMpViejosUnaVez().catch(function () {}); } catch (e) {} }, 30 * 1000);

// URL publica del webhook (este mismo backend). MP manda aca las notificaciones del pago unico de la recarga.
const MP_WEBHOOK_URL = process.env.MP_WEBHOOK_URL || 'https://agente-inmobiliaria-production-7e1c.up.railway.app/api/webhook/mercadopago';

// Crea una PREFERENCIA de pago UNICO (Checkout Pro) para la recarga de mensajes (no recurrente).
// external_reference lleva 'recarga|user_id|cantidad' (siempre se propaga al pago -> el webhook lo lee de ahi).
async function mpCrearPreferencia(titulo, montoARS, externalRef, backUrl, metadata) {
  var body = {
    items: [{ title: String(titulo).slice(0, 250), quantity: 1, unit_price: Math.round(montoARS), currency_id: 'ARS' }],
    external_reference: externalRef,
    metadata: metadata || {},
    back_urls: { success: backUrl, pending: backUrl, failure: backUrl },
    notification_url: MP_WEBHOOK_URL
  };
  return await mpFetch('/checkout/preferences', 'POST', body);
}

// ============ FUNCION REUTILIZABLE: genera la respuesta del agente ============
// waMessageId = key.id del mensaje saliente de WhatsApp (Baileys). B5: deduplicamos por ESE id (idempotente y
// exacto) en vez de por content+2min (que tragaba mensajes salientes legitimos repetidos -ej. el asesor manda
// dos veces el mismo texto- y no cubria reenvios del webhook con el MISMO id pasados los 2 min).
async function guardarMensajeSaliente(remoteJid, texto, waMessageId) {
  try {
    if (!texto) return;
    const telefono = remoteJid.split('@')[0];
    const { data: contacto } = await supabase.from('contacts').select('id, user_id').eq('phone', telefono).maybeSingle();
    if (!contacto) return;
    const { data: conv } = await supabase.from('conversations').select('id, user_id').eq('contact_id', contacto.id).maybeSingle();
    if (!conv) return;
    // B5: DEDUPE por wa_message_id (key.id de WhatsApp). Si ya guardamos un mensaje con ese id, no re-insertamos
    // (cubre reentregas del webhook con el mismo id, sin ventana de tiempo). Si no hay id (caso raro), caemos al
    // dedupe historico por content+2min para no perder la proteccion minima.
    if (waMessageId) {
      const { data: yaGuardado } = await supabase.from('messages').select('id').eq('conversation_id', conv.id).eq('wa_message_id', waMessageId).limit(1).maybeSingle();
      if (yaGuardado) return;
    } else {
      const hace2min = new Date(Date.now() - 2 * 60 * 1000).toISOString();
      const { data: reciente } = await supabase.from('messages').select('id').eq('conversation_id', conv.id).eq('content', texto).gte('created_at', hace2min).limit(1).maybeSingle();
      if (reciente) return;
    }
    // TAREA F (derivacion-v3-refinements, NO gated / aditiva): el eco del celular lo escribio el DUEÑO desde su telefono.
    // Atribuimos autor_nombre='Dueño' (o el nombre del negocio si lo tenemos facil) y autor_asesor_id=null (no aplica).
    // _resolverAutorMensaje(ownerId, ownerId) devuelve exactamente eso. Defensivo: si las columnas no existen, el insert
    // reintenta sin ellas (no rompe el guardado del eco). 0 tokens.
    const _autorEco = await _resolverAutorMensaje(conv.user_id, conv.user_id);
    await _insertMensajeConAutor(
      { conversation_id: conv.id, user_id: conv.user_id, role: 'human', content: texto, origen: 'celular', enviado_por: 'WhatsApp (celular)', wa_message_id: waMessageId || null },
      _autorEco,
      null
    );
    await supabase.from('conversations').update({ last_message: texto, last_role: 'human', updated_at: new Date().toISOString() }).eq('id', conv.id);
    // FIX #2: el humano respondio DESDE EL CELULAR (la respuesta entra por el webhook como saliente). Igual que el
    // envio por la app, esto resuelve la espera -> reseteamos la escalada SLA (jsonb sla_avisos + Set _slaAvisoMem)
    // para que un nuevo ciclo de espera vuelva a escalar desde p1. Best-effort/0 IA.
    try { await supabase.from('conversations').update({ sla_avisos: {} }).eq('id', conv.id); } catch (eSlaClr) {}
    try { _slaAvisoMem.delete(conv.id + ':p1'); _slaAvisoMem.delete(conv.id + ':p2'); _slaAvisoMem.delete(conv.id + ':p3'); } catch (eMemClr) {}
    console.log('Mensaje saliente (celular) guardado en conversacion ' + conv.id);
  } catch (e) { console.error('Error en guardarMensajeSaliente:', e && e.message); }
}

// Backup automatico: junta todos los datos de cada user y guarda una foto en la tabla backups.
// Mantiene las ultimas 48 copias por user (24 hs a razon de 1 cada 30 min) y borra las viejas.
async function hacerBackup() {
  try {
    // Obtener todos los user_id que tienen configuracion (clientes activos)
    const { data: settings } = await supabase.from('business_settings').select('user_id');
    if (!settings || settings.length === 0) return;
    const userIds = [...new Set(settings.map(function(s){ return s.user_id; }))];
    for (const uid of userIds) {
      try {
        const tablas = ['conversations','messages','contacts','recontactos','business_settings','properties','knowledge_base','whatsapp_instancias'];
        const contenido = {};
        for (const t of tablas) {
          const { data } = await supabase.from(t).select('*').eq('user_id', uid);
          contenido[t] = data || [];
        }
        const resumen = 'conv:' + (contenido.conversations.length) + ' msg:' + (contenido.messages.length) + ' cont:' + (contenido.contacts.length);
        await supabase.from('backups').insert({ user_id: uid, contenido: contenido, resumen: resumen });
        // Limpieza: dejar solo las ultimas 48 copias de este user
        const { data: viejos } = await supabase.from('backups').select('id').eq('user_id', uid).order('created_at', { ascending: false }).range(48, 1000);
        if (viejos && viejos.length > 0) {
          const ids = viejos.map(function(v){ return v.id; });
          await supabase.from('backups').delete().in('id', ids);
        }
        console.log('Backup hecho para user ' + uid + ' (' + resumen + ')');
      } catch (e2) { console.error('Error backup user ' + uid + ':', e2 && e2.message); }
    }
  } catch (e) { console.error('Error en hacerBackup:', e && e.message); }
}

// PARTE A (punto 10 - migracion rol-administrador, DEFENSIVA): "administrador" deja de ser un valor de
// `rol` y pasa a ser una CAPACIDAD derivada de la visibilidad. Un usuario es administrador (ve-todo) si su
// visibilidad incluye 'generales'. COMPAT: las filas viejas que todavia tengan rol='administrador' se siguen
// respetando. `rol` queda como columna legacy de solo-lectura. Centralizado en este helper para un solo criterio.
function esAdministrador(ase) {
  if (!ase) return false;
  if (ase.rol === 'administrador') return true; // compat datos viejos
  return Array.isArray(ase.visibilidad) && ase.visibilidad.indexOf('generales') >= 0;
}

// M19: REPARTO EQUITATIVO compartido. Dado un array de ids de asesores candidatos, devuelve el id con MENOR
// carga = menor cantidad de conversations asignadas con status='listo_humano' (D1=B). Mismo criterio exacto que
// antes estaba duplicado en elegirAsesorActivo y elegirAsesorParaDepartamento. idsCandidatos vacio/nulo -> null.
//
// RACE #4 (MITIGACION, no eliminacion total): el conteo de carga es un read-count-then-pick NO atomico. Dos
// derivaciones de leads DISTINTOS casi simultaneas leen el mismo snapshot de cargas, ambas ven al mismo asesor
// como "el menos cargado" y las dos caen sobre el (concentracion injusta). La asignacion final la hace el caller
// con un UPDATE sobre conversations (no hay lock entre el conteo y ese UPDATE), por eso aca NO podemos hacerlo
// 100% atomico sin reescribir todos los callers. Mitigamos dentro de esta funcion (cambio acotado):
//   DESEMPATE ALEATORIO entre TODOS los que estan en el minimo (no "gana el primero" siempre). Antes, con empate,
//   el bucle '<' devolvia SIEMPRE el primer id del array -> dos derivaciones simultaneas con el mismo snapshot
//   elegian deterministicamente al mismo asesor. Ahora, si N asesores empatan en el minimo, se elige uno al azar
//   -> la probabilidad de colision baja a ~1/N y, a lo largo de muchas derivaciones, el reparto no se concentra
//   en uno solo. Es la mejor mitigacion posible sin un lock/secuencia en la base.
// NOTA: para una garantia DURA habria que mover conteo+asignacion a un RPC con SELECT ... FOR UPDATE o a una
// secuencia round-robin por tenant; queda fuera de este cambio acotado (no reescribir todo). 0 IA, aislamiento
// por-tenant intacto (los idsCandidatos ya vienen filtrados por admin_id desde cada caller).
async function asesorMenorCarga(idsCandidatos) {
  let empatados = []; let menos = Infinity;
  for (const id of (idsCandidatos || [])) {
    const { count } = await supabase.from('conversations').select('id', { count: 'exact', head: true }).eq('asesor_id', id).eq('status', 'listo_humano');
    const n = count || 0;
    if (n < menos) { menos = n; empatados = [id]; }      // nuevo minimo: reinicia el grupo de empatados
    else if (n === menos) { empatados.push(id); }         // mismo minimo: se suma al desempate aleatorio
  }
  if (!empatados.length) return null;
  if (empatados.length === 1) return empatados[0];
  // Desempate aleatorio entre los de menor carga (mitiga la concentracion descrita arriba).
  return empatados[Math.floor(Math.random() * empatados.length)];
}

// Elige el asesor ACTIVO con menos leads asignados (reparto equitativo). Devuelve su id o null.
// Los usuarios con rol 'administrador' quedan EXCLUIDOS de la auto-asignacion/rotacion
// (un admin no recibe leads automaticamente). El filtro deja pasar rol='asesor' y rol NULL (legacy).
// PARTE A (punto 10): con reparto_v2 ON, "administrador/empleado" se mapean ahora por disponibilidad='no_recibe',
// asi que ADITIVAMENTE tambien se excluye a quien tenga disponibilidad='no_recibe'. Con flag OFF, el filtro
// queda EXACTAMENTE como antes (solo excluye rol='administrador') para no cambiar el comportamiento actual.
async function elegirAsesorActivo(admin_id) {
  try {
    let q = supabase.from('asesores').select('id, disponibilidad').eq('admin_id', admin_id).eq('activo', true).or('rol.is.null,rol.neq.administrador');
    let v2 = false;
    try { v2 = await repartoV2Activo(admin_id, null); } catch (eV2) { v2 = false; }
    let { data: activos } = await q;
    if (v2 && Array.isArray(activos)) {
      // ADITIVO solo con flag ON: descartar a los que no reciben (disponibilidad='no_recibe') y a los pausados ('pausa').
      activos = activos.filter(function(a){ return a.disponibilidad !== 'no_recibe' && a.disponibilidad !== 'pausa'; });
    }
    if (!activos || activos.length === 0) return null;
    // contar leads asignados a cada asesor activo. D1=B: la "carga" cuenta SOLO las conversaciones que el asesor
    // atiende de verdad (asignadas a el y en atencion humana = status 'listo_humano'). Se excluyen las cerradas y
    // las que todavia maneja la IA (en_conversacion / interesado / recontacto). M19: reparto compartido.
    return await asesorMenorCarga(activos.map(function(a){ return a.id; }));
  } catch (e) { console.error('Error elegirAsesorActivo:', e && e.message); return null; }
}

// M18: BUSCAR-O-CREAR contacto + conversacion de un canal (gate de "no duplicar"). Antes estaba duplicado entre
// el webhook de WhatsApp y el de Meta (Messenger/Instagram). Unifica el lookup/insert del contacto por
// (user_id, phone=contactKey) y de la conversation por (user_id, contact_id), preservando EXACTAMENTE el
// comportamiento de ambos:
//   - contactKey = telefono (WA) o PSID/IGSID (Meta); se guarda en la columna 'phone' (mismo criterio que ya usaban).
//   - nombreNuevo = nombre a poner SOLO al CREAR el contacto (WA: data.pushName||telefono ; Meta: String(senderId)).
//   - canal = 'whatsapp' | 'messenger' | 'instagram' (channel del contacto y de la conversation al crear).
//   - convSelectCols = columnas a leer de una conversation EXISTENTE (WA lee mas columnas que Meta; se pasa el set
//     exacto de cada caller para no cambiar lo que cada webhook ve en convExistente).
// Asignacion de asesor al crear: ETAPA 6 — con reparto_v2 ON NO se asigna (asesor=null); con flag OFF -> EAGER
// (elegirAsesorActivo). Se usa la variante DEFENSIVA (try/catch alrededor de repartoV2Activo y elegirAsesorActivo,
// como ya hacia Meta): ambas funciones ya atrapan sus propios errores y NUNCA lanzan, asi que esto es
// observacionalmente identico a la version de WhatsApp (sin try/catch) — no cambia el comportamiento de ninguno.
// El INSERT de la conversation nueva devuelve SIEMPRE el mismo set minimo ('id, ai_enabled, asesor_id') que antes.
// NO hace el enriquecimiento del contacto (eso es especifico de WhatsApp y queda inline en su webhook).
// Devuelve { contacto, conv, convExistente }. contacto/conv pueden ser null/undefined si el insert no devolvio fila
// (mismo caso que antes: el caller cortaba con `if (!contacto) return;` / `if (!conv) return;`).
async function obtenerOcrearConvDeCanal(user_id, contactKey, canal, nombreNuevo, convSelectCols) {
  // RACE #8 (TOCTOU): dos webhooks del MISMO lead casi simultaneos (un lead que manda 2-3 mensajes juntos), o el
  // cron reintentarFallidos corriendo a la par, hacian SELECT->INSERT cada uno: ambos veian null y creaban DOS (o mas)
  // contacts / conversations -> mensajes repartidos entre varias conversaciones (el asesor ve "mensajes perdidos" y
  // el lead aparece duplicado N veces). Caso real: telefono 5492255622878 con 4 contacts creados en rafagas de ~57ms.
  // Fix: UPSERT idempotente con onConflict sobre el UNIQUE (user_id, phone, channel) / (user_id, contact_id).
  // DEFENSIVO: si el indice unico aun NO existe en prod, el upsert puede fallar (o no deduplicar) -> caemos al
  // check-then-insert ACTUAL (no rompemos el webhook). Para dedupe REAL en la base hacen falta los indices unicos
  // contacts(user_id,phone,channel) y conversations(user_id,contact_id) -> ver migracion-contactos-unique.sql.
  // ORDEN DE APLICACION: correr PRIMERO migracion-contactos-dedup.sql (limpia duplicados existentes), DESPUES
  // migracion-contactos-unique.sql (crea el indice; falla si aun hay duplicados), y RECIEN AHI desplegar este codigo.
  // Contacto (proyeccion minima segura: solo 'id'). El SELECT de busqueda se mantiene por (user_id, phone) SIN filtrar
  // por channel: asi encuentra CUALQUIER contacto existente de ese telefono (aunque tenga channel null legacy u otro
  // canal) y NO crea un duplicado. El channel solo entra en el conflict target del UPSERT (camino de insert atomico).
  let contacto;
  const { data: existente } = await supabase.from('contacts').select('id').eq('user_id', user_id).eq('phone', contactKey).maybeSingle();
  if (existente) { contacto = existente; }
  else {
    // UPSERT: si OTRO webhook concurrente ya inserto el contacto, onConflict (user_id,phone,channel) devuelve esa
    // misma fila (no duplica). El conflict target DEBE coincidir con el indice unico de migracion-contactos-unique.sql.
    let _upOk = false;
    try {
      const { data: nuevo, error: eUp } = await supabase.from('contacts')
        .upsert({ user_id: user_id, name: nombreNuevo, phone: contactKey, channel: canal }, { onConflict: 'user_id,phone,channel' })
        .select('id').single();
      if (!eUp && nuevo) { contacto = nuevo; _upOk = true; }
    } catch (eUpC) {}
    if (!_upOk) {
      // Fallback ACTUAL EXACTO (indice unico ausente u otro error): re-leer por si el concurrente ya lo creo; si no, insert.
      const { data: _reC } = await supabase.from('contacts').select('id').eq('user_id', user_id).eq('phone', contactKey).maybeSingle();
      if (_reC) { contacto = _reC; }
      else {
        const { data: nuevo } = await supabase.from('contacts').insert({ user_id: user_id, name: nombreNuevo, phone: contactKey, channel: canal }).select('id').single();
        contacto = nuevo;
      }
    }
  }
  if (!contacto) return { contacto: null, conv: null, convExistente: null };

  // Conversacion (buscar-o-crear por user_id + contact_id).
  let conv;
  const { data: convExistente } = await supabase.from('conversations').select(convSelectCols).eq('user_id', user_id).eq('contact_id', contacto.id).maybeSingle();
  if (convExistente) { conv = convExistente; }
  else {
    let _repV2 = false;
    try { _repV2 = await repartoV2Activo(user_id); } catch (e) {}
    let asesorAsignado = null;
    if (!_repV2) { try { asesorAsignado = await elegirAsesorActivo(user_id); } catch (e) {} }
    const _convPayload = { user_id: user_id, contact_id: contacto.id, channel: canal, status: 'en_conversacion', ai_enabled: true, asesor_id: asesorAsignado, ultimo_asesor_id: asesorAsignado };
    // UPSERT: si OTRO webhook concurrente ya creo la conv de este contacto, onConflict devuelve esa misma fila
    // (no duplica) -> todos los mensajes de la rafaga caen SIEMPRE en la misma conversacion.
    let _upConvOk = false;
    try {
      const { data: convNueva, error: eUpV } = await supabase.from('conversations')
        .upsert(_convPayload, { onConflict: 'user_id,contact_id' })
        .select('id, ai_enabled, asesor_id').single();
      if (!eUpV && convNueva) { conv = convNueva; _upConvOk = true; }
    } catch (eUpV2) {}
    if (!_upConvOk) {
      // Fallback ACTUAL EXACTO (indice unico ausente u otro error): re-leer por si el concurrente la creo; si no, insert.
      const { data: _reV } = await supabase.from('conversations').select('id, ai_enabled, asesor_id').eq('user_id', user_id).eq('contact_id', contacto.id).maybeSingle();
      if (_reV) { conv = _reV; }
      else {
        const { data: convNueva } = await supabase.from('conversations').insert(_convPayload).select('id, ai_enabled, asesor_id').single();
        conv = convNueva;
      }
    }
  }
  return { contacto: contacto, conv: conv, convExistente: convExistente };
}

// ===== FASE 2 (ETAPAS 6-7-8): FLAG POR-CUENTA reparto_v2 =====
// Red de seguridad: TODO el comportamiento nuevo del reparto por departamento/cola va GATED detras de este
// flag por-tenant (business_settings.reparto_v2). FALSE / ausente / null / columna inexistente -> comportamiento
// ACTUAL EXACTO. TRUE -> comportamiento nuevo. DEFENSIVO: si la columna todavia no existe, el .select devuelve
// error en el objeto (no throw) -> lo tratamos como FALSE. Lee eficiente: si ya hay un business_settings cargado
// del tenant y trae la propiedad reparto_v2, se reusa (sin query); si no, una query chica .select('reparto_v2').
async function repartoV2Activo(user_id, bs) {
  try {
    // DECISION DUENO 2026-07: reparto por DEPARTAMENTO siempre ON. Cada rubro trae sus departamentos por default;
    // el ruteo por departamento es el unico camino (se elimino el modo "pool general" de la config). El pool
    // (elegirAsesorActivo) queda solo como fallback interno cuando un lead no resuelve depto. Rollback = borrar esta linea.
    return true;
    // Reusar un business_settings ya cargado si trae la propiedad (evita una query extra por mensaje).
    if (bs && Object.prototype.hasOwnProperty.call(bs, 'reparto_v2')) return bs.reparto_v2 === true;
    if (!user_id) return false;
    const { data, error } = await supabase.from('business_settings').select('reparto_v2').eq('user_id', user_id).maybeSingle();
    if (error) return false; // columna ausente u otro error -> comportamiento actual (flag OFF)
    return !!(data && data.reparto_v2 === true);
  } catch (e) { return false; } // ante cualquier fallo, NUNCA romper: tratar como flag OFF
}

// ===== DERIVACION v3: FLAG POR-CUENTA derivacion_v3 (mismo patron defensivo que repartoV2Activo) =====
// GATE del comportamiento NUEVO de derivacion "Sonnet decide + rotacion + el que escribe atiende". Con el flag
// OFF (default: false / ausente / null / columna inexistente / cualquier error) -> comportamiento ACTUAL EXACTO:
// la tool derivar_a_humano NO se ofrece al agente, el webhook NO evalua pidioDerivar, el cron de rotacion hace
// early-return, y el camino clasificador(Haiku) -> derivarAHumano queda BYTE-IDENTICO al de hoy. TRUE -> se ofrece
// la tool + se activa la rotacion. FAIL-SAFE: si la columna todavia no existe en prod, el .select devuelve error
// -> tratamos como OFF. Reusa un bs ya cargado si trae la propiedad (evita una query extra por mensaje).
async function derivacionV3Activo(user_id, bs) {
  try {
    if (bs && Object.prototype.hasOwnProperty.call(bs, 'derivacion_v3')) return bs.derivacion_v3 === true;
    if (!user_id) return false;
    const { data, error } = await supabase.from('business_settings').select('derivacion_v3').eq('user_id', user_id).maybeSingle();
    if (error) return false; // columna ausente u otro error -> comportamiento actual (flag OFF)
    return !!(data && data.derivacion_v3 === true);
  } catch (e) { return false; } // ante cualquier fallo, NUNCA romper: tratar como flag OFF
}

// ===== DERIVACION v4: FLAG POR-CUENTA derivacion_v4 (mismo patron defensivo que derivacionV3Activo) =====
// GATE del REDISENO de derivacion pedido por Diego: "CUALQUIER disparador de derivacion entra en ROTACION (la IA
// sigue atendiendo), y el UNICO pase a listo_humano + IA off es que un ASESOR ESCRIBA". Con el flag OFF (default:
// false / ausente / null / columna inexistente / cualquier error) el comportamiento es EXACTO al de hoy (post-hotfix
// misruteo A+C+D): los triggers del webhook (handoff _pideHumano, confirmaciones, ia_fuera_alcance, clasificacion a
// listo_humano, cambio de tema) siguen yendo a listo_humano como siempre, la inactividad NO barre rotando, y el cron
// de cola escala a los 30 min como hoy. Con el flag ON: TODOS esos triggers RUTEAN A ROTACION (status='interesado',
// ai_enabled=true, derivacion_rotando=true) reusando la maquinaria de derivacion_v3 (iniciarRotacionDerivacionV3 +
// el cron revisarRotacionDerivacionV3 + "el que escribe = la señal"). REQUISITO OPERATIVO: v4 se apoya en la rotacion
// de v3, asi que en una cuenta con v4 ON tambien debe estar derivacion_v3 ON (la tool + el cron de rotacion). El
// codigo NO fuerza eso (cada gate es independiente y defensivo); es una condicion de configuracion. FAIL-SAFE: si la
// columna todavia no existe en prod, el .select devuelve error -> tratamos como OFF. Reusa un bs ya cargado si trae
// la propiedad (evita una query extra por mensaje). MISMO patron EXACTO que derivacionV3Activo.
async function derivacionV4Activo(user_id, bs) {
  try {
    if (bs && Object.prototype.hasOwnProperty.call(bs, 'derivacion_v4')) return bs.derivacion_v4 === true;
    if (!user_id) return false;
    const { data, error } = await supabase.from('business_settings').select('derivacion_v4').eq('user_id', user_id).maybeSingle();
    if (error) return false; // columna ausente u otro error -> comportamiento actual (flag OFF)
    return !!(data && data.derivacion_v4 === true);
  } catch (e) { return false; } // ante cualquier fallo, NUNCA romper: tratar como flag OFF
}

