              await derivarAHumano(_convId, user_id, 'handoff_pedido_humano', {
                setStatus: true, lastMessage: _msgHandoff, lastRole: 'ai',
                push: true, pushTitulo: 'Un lead pide un asesor', pushTexto: (data.pushName || telefono),
                resumen: true
              });
