// ===== ASESORES (gestionados por el admin) =====
// Crear un asesor: crea el usuario en Auth (con la service key) y la fila en asesores.
// Helpers Fase 1: validan y aplican los campos nuevos del usuario (aditivo, todo opcional).
function _camposUsuarioNuevos(b) {
  const out = {};
  if (['conectado', 'pausa', 'no_recibe'].indexOf(b.disponibilidad) >= 0) out.disponibilidad = b.disponibilidad;
  if (Array.isArray(b.visibilidad)) {
    out.visibilidad = b.visibilidad.filter(function(v){ return ['propias', 'departamento', 'generales'].indexOf(v) >= 0; });
    // Sincronizar el `rol` LEGACY con la visibilidad: admin = ve-todo ('generales'). Asi, sacar "Todos" desde el
    // formulario efectivamente le quita la condicion de admin (varios checks del FRONT todavia miran rol==='administrador').
    out.rol = (out.visibilidad.indexOf('generales') >= 0) ? 'administrador' : 'asesor';
  }
  // PARTE A (correccion 8): aceptar tambien el modo '24-7' (siempre disponible) ademas de oficina/personalizado.
  if (['oficina', 'personalizado', '24-7'].indexOf(b.horario_modo) >= 0) out.horario_modo = b.horario_modo;
  if (b.horario_json && typeof b.horario_json === 'object') out.horario_json = b.horario_json;
  if (typeof b.es_ia === 'boolean') out.es_ia = b.es_ia;
  // PERMISO por-usuario: "Cargar contacto manual" desde Conversaciones. Default false (la feature queda inerte).
  // DEFENSIVO: solo lo seteamos si llega un boolean; si la columna aun no existe en la base, el .update lo ignora/falla
  // en su propio bloque (no rompe el resto de la config) hasta que corra migracion-cargar-contacto.sql.
  if (typeof b.puede_cargar_contacto === 'boolean') out.puede_cargar_contacto = b.puede_cargar_contacto;
  // FASE 2: numero personal para notificaciones por WhatsApp (asesores.whatsapp_notif). Acepta string:
  // se guarda solo digitos (sanitiza espacios/+/guiones); '' => null (el usuario no recibe DM, solo push).
  // DEFENSIVO: solo se setea si llega un string; si la columna aun no existe, el .update lo maneja en su
  // propio bloque (no rompe el resto de la config) hasta que corra migracion-dm-individual.sql.
  if (typeof b.whatsapp_notif === 'string') { const _num = b.whatsapp_notif.replace(/[^0-9]/g, ''); out.whatsapp_notif = _num ? _num : null; }
  // PARTE A (punto 9): config del agente IA (jsonb). Acepta objeto (config) o null (limpiar al pasar a Humano).
  if (b.agente_config && typeof b.agente_config === 'object') out.agente_config = b.agente_config;
  else if (b.agente_config === null) out.agente_config = null;
  // ACCESO POR PANEL (permisos_paneles jsonb): { <navKey>: true }. Controla qué secciones del menú ve/entra el
  // usuario. Ausencia/null => default "solo Conversaciones" (lo resuelve el front: guard + shell). DEFENSIVO: solo
  // se setea si llega un objeto (o null para limpiar). Si la columna no existe todavía, el .update lo maneja en su
  // propio bloque (no rompe el resto de la config) hasta correr la migración permisos_paneles.
  if (b.permisos_paneles && typeof b.permisos_paneles === 'object' && !Array.isArray(b.permisos_paneles)) out.permisos_paneles = b.permisos_paneles;
  else if (b.permisos_paneles === null) out.permisos_paneles = null;
  return out;
}
// Reemplaza la membresia de departamentos de un usuario (valida que los deptos sean de la cuenta).
// PARTE A (punto 9): `departamentos` acepta DOS formatos:
//   (a) legacy: array de IDs (string[])  -> modo='recibe' por defecto.
//   (b) nuevo:  array de objetos { departamento_id|id, modo:'recibe'|'visualiza' }.
// Normaliza cada entrada a {id, modo}, valida el id contra los deptos de la cuenta e inserta con `modo`.
// DEFENSIVO: si la columna `modo` no existe, reintenta el insert sin ella (compat con base vieja).
async function _setDepartamentosUsuario(asesorId, adminId, departamentos) {
  if (!Array.isArray(departamentos)) return;
  // Normalizar entradas a { id, modo }.
  // PARTE A (correccion 3 y 7): un departamento TILDADO = el usuario RECIBE de ese depto. La "solo
  // visualizacion" ya NO se maneja por departamento (se maneja con "Visibilidad de leads"), por lo que la
  // membresia SIEMPRE se guarda con modo='recibe', ignorando cualquier 'visualiza' que pudiera llegar.
  const pedidos = [];
  departamentos.forEach(function(d){
    let id = null;
    let modo = 'recibe';
    if (d && typeof d === 'object') {
      id = d.departamento_id || d.id || null;
      // FORM v4 (punto 1): el botón "no recibe" por depto define modo='visualiza' (ve los mensajes del depto pero
      // NO recibe asignaciones AUTOMÁTICAS de la IA; manual sí). El reparto automático ya EXCLUYE 'visualiza'.
      if (d.modo === 'visualiza') modo = 'visualiza';
    } else {
      id = d; // legacy: string id => recibe
    }
    if (id) pedidos.push({ id: id, modo: modo });
  });
  let filas = [];
  if (pedidos.length) {
    const idsPedidos = pedidos.map(function(p){ return p.id; });
    const { data: validos } = await supabase.from('departamentos').select('id').eq('user_id', adminId).in('id', idsPedidos);
    const idsValidos = (validos || []).map(function(d){ return d.id; });
    filas = pedidos
      .filter(function(p){ return idsValidos.indexOf(p.id) >= 0; })
      .map(function(p){ return { asesor_id: asesorId, departamento_id: p.id, modo: p.modo }; });
  }
  await supabase.from('usuario_departamento').delete().eq('asesor_id', asesorId);
  if (filas.length) {
    const { error } = await supabase.from('usuario_departamento').insert(filas);
    if (error) {
      // DEFENSIVO: columna `modo` ausente u otro error -> reintentar sin `modo`.
      const filasSinModo = filas.map(function(f){ return { asesor_id: f.asesor_id, departamento_id: f.departamento_id }; });
      await supabase.from('usuario_departamento').insert(filasSinModo);
    }
  }
}

app.post('/api/asesores/crear', async (req, res) => {
  try {
    let { admin_id, nombre, usuario, clave, cargo, rol } = req.body || {};
    const _nuevos = _camposUsuarioNuevos(req.body);
    const esIa = req.body && req.body.es_ia === true;
    // SEGURIDAD: validar identidad por token
    const _uidToken = await verificarUsuario(req);
    if (!_uidToken) return res.status(401).json({ error: 'No autorizado: falta token valido' });
    if (_uidToken !== admin_id) return res.status(403).json({ error: 'Identidad no coincide' });
    admin_id = _uidToken; // B2: tenant autoritativo = el del JWT (el guard ya garantizo igualdad; esto evita que cualquier uso futuro de admin_id se desvie del token)
    // PARTE A (puntos 4/9 + correccion 7): un usuario IA NO inicia sesion, por lo que NO necesita usuario(alias)
    // ni clave. Para humanos AMBOS siguen siendo obligatorios. Si es IA y no llega usuario/clave, generamos
    // valores internos (el esquema requiere `usuario` NOT NULL; la clave queda sin Auth user => sin login).
    if (!admin_id || !nombre) return res.status(400).json({ error: 'Faltan datos' });
    if (esIa) {
      if (!usuario || !String(usuario).trim()) usuario = 'ia_' + Math.random().toString(36).slice(2, 10);
      // clave de IA: se ignora para login (no se crea Auth user); no se exige.
    } else {
      if (!usuario || !clave) return res.status(400).json({ error: 'Faltan datos' });
    }
    // PARTE A (punto 10 - migracion rol-administrador, defensivo): el front YA NO envia `rol`. Si llega
    // (retrocompat) se respeta y valida; si NO llega, `rol` cae a 'asesor' (default legacy: la columna
    // asesores.rol sigue siendo NOT NULL). La "capacidad administrador" se deriva de la visibilidad ('generales').
    if (rol && rol !== 'asesor' && rol !== 'administrador' && rol !== 'empleado') return res.status(400).json({ error: 'Rol invalido (debe ser asesor, administrador o empleado)' });
    const rolFinal = (rol === 'administrador') ? 'administrador' : ((rol === 'empleado') ? 'empleado' : 'asesor');
    // Limite de usuarios por admin: sale del plan vigente (PLAN_LIMITS[plan].asesores), salvo override por cliente
    // (limits_override.asesores, seteable desde el Maestro) que MANDA si es un numero > 0. Soporta Infinity (no bloquea).
    const { data: existentes } = await supabase.from('asesores').select('id').eq('admin_id', admin_id);
    const _planAse = await planActual(admin_id);
    let topeAsesores = (PLAN_LIMITS[_planAse] || PLAN_LIMITS[PLAN_DEFECTO]).asesores;
    try { const { data: subA } = await supabase.from('subscriptions').select('limits_override').eq('user_id', admin_id).maybeSingle(); if (subA && subA.limits_override && typeof subA.limits_override.asesores === 'number' && subA.limits_override.asesores > 0) topeAsesores = subA.limits_override.asesores; } catch (eLim) {}
    if (topeAsesores !== Infinity && existentes && existentes.length >= topeAsesores) return res.status(400).json({ error: 'Maximo ' + topeAsesores + ' usuarios' });
    // El email interno se arma con el usuario (no se usa para login real, pero Auth lo requiere)
    // Obtener el email del admin para derivar el del asesor (emailAdmin + alias)
    const { data: adminData, error: errAdmin } = await supabase.auth.admin.getUserById(admin_id);
    if (errAdmin || !adminData || !adminData.user || !adminData.user.email) return res.status(400).json({ error: 'No se pudo obtener el email del administrador' });
    const adminEmail = adminData.user.email;
    const aliasLimpio = usuario.toLowerCase().replace(/[^a-z0-9]/g, '');
    const partes = adminEmail.split('@');
    const email = partes[0] + '+' + aliasLimpio + '@' + partes[1];
    // PARTE A (punto 9): un usuario IA sin clave NO necesita usuario de Auth (no inicia sesion). Solo se
    // crea el Auth user si hay clave (humanos siempre; IA solo si el dueno le dio una clave opcional).
    let authId = null;
    if (clave) {
      const { data: created, error: errAuth } = await supabase.auth.admin.createUser({ email: email, password: clave, email_confirm: true, user_metadata: { rol: rolFinal, admin_id: admin_id, nombre: nombre } });
      if (errAuth) return res.status(400).json({ error: errAuth.message });
      authId = created && created.user ? created.user.id : null;
    }
    const { data: nuevoAse, error: errIns } = await supabase.from('asesores').insert(Object.assign({ admin_id: admin_id, auth_user_id: authId, nombre: nombre, usuario: usuario, cargo: (cargo && cargo.trim()) ? cargo.trim() : (esIa ? 'Agente IA' : 'Asesor'), rol: rolFinal, estado: 'activo', activo: true }, _nuevos)).select('id').single();
    if (errIns) { if (authId) { try { await supabase.auth.admin.deleteUser(authId); } catch (e) {} } return res.status(400).json({ error: errIns.message }); }
    try { if (nuevoAse && nuevoAse.id) await _setDepartamentosUsuario(nuevoAse.id, admin_id, req.body.departamentos); } catch (eDep) { console.error('membresia depto al crear:', eDep && eDep.message); }
    // Switch por-usuario "recibir aviso por WhatsApp" (asesores.notif_wa_activa). Update SEPARADO y DEFENSIVO (no rompe el alta si la columna aun no existe).
    if (nuevoAse && nuevoAse.id && typeof req.body.notif_wa_activa === 'boolean') { try { await supabase.from('asesores').update({ notif_wa_activa: req.body.notif_wa_activa }).eq('id', nuevoAse.id); } catch (eNW) {} }
    return res.json({ ok: true, email: email, id: nuevoAse && nuevoAse.id });
  } catch (e) { return res.status(500).json({ error: e && e.message }); }
});

// Eliminar un asesor: borra el usuario de Auth y la fila. Los mensajes conservan enviado_por.
// Actualiza los campos NUEVOS de un usuario (disponibilidad/visibilidad/horario/es_ia) + su membresia de departamentos. ADITIVO.
app.post('/api/asesores/config', async (req, res) => {
  try {
    const b = req.body || {};
    const _uidToken = await verificarUsuario(req);
    if (!_uidToken) return res.status(401).json({ error: 'No autorizado: falta token valido' });
    if (_uidToken !== b.admin_id) return res.status(403).json({ error: 'Identidad no coincide' });
    b.admin_id = _uidToken; // B2: tenant autoritativo = JWT (doble guard conservado arriba; downstream usa el del token)
    if (!b.admin_id || !b.asesor_id) return res.status(400).json({ error: 'Faltan datos' });
    const { data: ase } = await supabase.from('asesores').select('id').eq('id', b.asesor_id).eq('admin_id', b.admin_id).maybeSingle();
    if (!ase) return res.status(404).json({ error: 'Usuario no encontrado' });
    const nuevos = _camposUsuarioNuevos(b);
    if (Object.keys(nuevos).length) { const { error } = await supabase.from('asesores').update(nuevos).eq('id', b.asesor_id).eq('admin_id', b.admin_id); if (error) return res.status(500).json({ error: error.message }); }
    // Switch por-usuario "recibir aviso por WhatsApp" (asesores.notif_wa_activa). Update SEPARADO y DEFENSIVO: si la
    // columna aun no existe (migracion no corrida), falla en silencio y NO rompe el resto del guardado.
    if (typeof b.notif_wa_activa === 'boolean') { try { await supabase.from('asesores').update({ notif_wa_activa: b.notif_wa_activa }).eq('id', b.asesor_id).eq('admin_id', b.admin_id); } catch (eNW) {} }
    if (Array.isArray(b.departamentos)) await _setDepartamentosUsuario(b.asesor_id, b.admin_id, b.departamentos);
    return res.json({ ok: true });
  } catch (e) { return res.status(500).json({ error: e && e.message }); }
});

// ===== SWITCH ACTIVO/APAGADO (acceso del usuario) =====
// El dueño APAGA (activo=false) -> el usuario NO recibe leads + SE LE CIERRA LA SESION y se le BLOQUEA el ingreso
// externo (queda en _asesoresSinAcceso -> verificarUsuario corta con 401 en su proximo request; + ban en Auth). Sus
// leads asignados QUEDAN con el (no se reasignan). El dueño SIEMPRE entra a sus chats (visibilidad de tenant, no cambia).
// ACTIVAR (activo=true) -> lo repone (el drenaje de la cola de leads lo hace /api/asesores/activar). Contrato:
// POST { admin_id, asesor_id, activo }  (auth por token; admin_id debe coincidir con el JWT).
app.post('/api/asesores/acceso', async (req, res) => {
  try {
    const { admin_id, asesor_id, activo } = req.body || {};
    const _uidToken = await verificarUsuario(req);
    if (!_uidToken) return res.status(401).json({ error: 'No autorizado: falta token valido' });
    if (_uidToken !== admin_id) return res.status(403).json({ error: 'Identidad no coincide' });
    if (!admin_id || !asesor_id || typeof activo !== 'boolean') return res.status(400).json({ error: 'Faltan datos' });
    const { data: ase } = await supabase.from('asesores').select('id, auth_user_id').eq('id', asesor_id).eq('admin_id', admin_id).maybeSingle();
    if (!ase) return res.status(404).json({ error: 'Usuario no encontrado' });
    const { error } = await supabase.from('asesores').update({ activo: activo, estado: activo ? 'activo' : 'pausa' }).eq('id', asesor_id).eq('admin_id', admin_id);
    if (error) return res.status(500).json({ error: error.message });
    if (ase.auth_user_id) {
      if (activo === false) { _asesoresSinAcceso.add(ase.auth_user_id); await _setBanUsuario(ase.auth_user_id, true); }
      else { _asesoresSinAcceso.delete(ase.auth_user_id); await _setBanUsuario(ase.auth_user_id, false); }
    }
    return res.json({ ok: true });
  } catch (e) { return res.status(500).json({ error: e && e.message }); }
});

// ===== SENTINELA DE ACCESO =====
// El frontend lo pinga cada ~30s. Si el dueño APAGO al usuario, verificarUsuario devuelve null -> 401 -> el front
// cierra la sesion sola. Ultra-liviano: 0 queries extra (solo la validacion del token + el chequeo del Set en memoria).
app.get('/api/asesores/estado-acceso', async (req, res) => {
  try {
    const uid = await verificarUsuario(req);
    if (!uid) return res.status(401).json({ ok: false });
    return res.json({ ok: true });
  } catch (e) { return res.status(401).json({ ok: false }); }
});

// ===== VALIDAR EL WHATSAPP DE NOTIFICACION DE UN USUARIO (asesores.whatsapp_notif) =====
// PROBLEMA que resuelve: hoy whatsapp_notif se guarda SOLO sacando no-digitos, sin verificar que sea un
// WhatsApp real. Caso Bruno: quedo 542215776798 (sin el "9" de movil argentino) cuando su numero real es
// 5492215776798 -> Evolution NO le entrega las notificaciones. Este endpoint chequea el numero contra
// Evolution (misma instancia del DUENO) ANTES de guardar y, para AR, sugiere el numero con el "9" si ese
// existe y el original no. CERO IA / 0 tokens (solo /chat/whatsappNumbers).
//
// Contrato: POST { numero, admin_id? } (auth por token). Devuelve:
//   { ok:true, existe:true,  jid:'<normalizado>' }                     -> el numero SI figura en WhatsApp
//   { ok:true, existe:false, sugerido:'<con 9>'|null }                 -> NO figura (avisar; ofrecer sugerido)
//   { ok:true, existe:null }                                           -> Evolution no respondio/instancia off
//                                                                          (best-effort: el front NO bloquea el guardado)
// DEFENSIVO: cualquier fallo de Evolution => existe:null (no rompe ni bloquea el alta del usuario).
app.post('/api/asesores/validar-whatsapp', async function(req, res) {
  try {
    // 1) AUTH por token (mismo verificarUsuario que el resto).
    const uid = await verificarUsuario(req);
    if (!uid) return res.status(401).json({ error: 'No autorizado' });

    // 2) Resolver el DUENO del tenant. Por default el que llama ES el dueño (su uid = user_id del tenant);
    //    si es un asesor sub-cuenta, el dueño es su admin_id. (PATRON: todo gate/instancia resuelve el dueño;
    //    ver /api/contactos/renombrar). La instancia de Evolution es la del dueño.
    let ownerId = uid;
    try {
      const { data: ase } = await supabase.from('asesores').select('admin_id').eq('auth_user_id', uid).maybeSingle();
      if (ase && ase.admin_id) ownerId = ase.admin_id;
    } catch (e1) {}
    // Si mandaron admin_id explicito y coincide con el dueño resuelto, lo respetamos (no cambia el tenant).
    const b = req.body || {};
    if (b.admin_id && typeof b.admin_id === 'string' && b.admin_id === ownerId) ownerId = b.admin_id;

    // 3) Normalizar el numero IGUAL que se guarda (solo digitos).
    const soloDigitos = String(b.numero == null ? '' : b.numero).replace(/[^0-9]/g, '');
    if (!soloDigitos) return res.status(400).json({ error: 'Falta numero' });

    // 4) Instancia del dueño. Si Evolution no esta configurado, no bloqueamos (best-effort).
    if (!EVOLUTION_URL || !EVOLUTION_KEY) return res.json({ ok: true, existe: null, jid: soloDigitos });
    const instancia = nombreInstancia(ownerId);

    // 5) Consulta a Evolution para el numero tal cual vino.
    const r1 = await verificarNumeroWA(instancia, soloDigitos);
    // Errores de Evolution / instancia no conectada / respuesta rara => existe:null (best-effort, no bloquea).
    if (r1 && r1.error) return res.json({ ok: true, existe: null, jid: soloDigitos });

    if (r1 && r1.existe === true) {
      // El numero SI figura. Devolvemos el jid normalizado por Evolution si lo trae (sin el @dominio).
      const jidNorm = (r1.jid ? String(r1.jid).replace(/@.*$/, '').replace(/[^0-9]/g, '') : '') || soloDigitos;
      return res.json({ ok: true, existe: true, jid: jidNorm });
    }

    // 6) NO figura. Para ARGENTINA: los moviles llevan un "9" entre el 54 (pais) y el area. Si vino SIN ese 9
    //    (patron '54' + area, sin '549'), probamos la variante con "9" y, si ESA existe, la sugerimos.
    let sugerido = null;
    try {
      if (soloDigitos.indexOf('54') === 0 && soloDigitos.indexOf('549') !== 0 && soloDigitos.length >= 12) {
        const conNueve = '549' + soloDigitos.slice(2);
        const r2 = await verificarNumeroWA(instancia, conNueve);
        if (r2 && r2.existe === true) {
          sugerido = (r2.jid ? String(r2.jid).replace(/@.*$/, '').replace(/[^0-9]/g, '') : '') || conNueve;
        }
      }
    } catch (eSug) { /* si la 2da consulta falla, seguimos sin sugerido */ }

    return res.json({ ok: true, existe: false, sugerido: sugerido });
  } catch (e) {
    // Nunca bloqueamos el flujo del usuario por un error nuestro: best-effort.
    return res.json({ ok: true, existe: null });
  }
});

// ===== CARGAR CONTACTO MANUAL (desde Conversaciones) =====
// Un asesor con el permiso `puede_cargar_contacto` da de alta un contacto/conversacion a mano. La conversacion
// entra directo en status='listo_humano', IA OFF (ai_enabled=false), asignada a ESE asesor. CERO IA (0 tokens).
// MULTI-TENANT: el contacto y la conversacion pertenecen al DUENO de la cuenta (owner user_id = asesor.admin_id);
// asesor_id = el id del asesor que lo carga. Reusa el MISMO patron de upsert idempotente que obtenerOcrearConvDeCanal
// (onConflict 'user_id,phone,channel' para contacts, 'user_id,contact_id' para conversations), con los mismos
// fallbacks defensivos por si los indices unicos aun no existen en la base.
// ── Renombrar contacto (nombre de display) ──────────────────────────────────────────────────────
// El front NO puede escribir contacts.nombre_manual directo: la RLS de `contacts` solo deja al DUENO
// (policy own_contacts: auth.uid()=user_id) hacer UPDATE; los asesores tienen SOLO SELECT (asesor_ve_sus_
// contacts) -> el UPDATE se bloqueaba SIN error (0 filas) y el nombre revertia al recargar. Por eso el
// renombrado va por aca con el cliente service-key (saltea RLS) + chequeo de tenant. Cualquier miembro del
// tenant (dueno o asesor) puede renombrar (es solo el nombre visible); NO requiere puede_cargar_contacto.
app.post('/api/contactos/renombrar', async function(req, res) {
  try {
    // 1) AUTH: identidad por token (mismo verificarUsuario que el resto).
    const uid = await verificarUsuario(req);
    if (!uid) return res.status(401).json({ error: 'No autorizado' });

    // 2) Resolver el DUENO del tenant. Por DEFAULT el que llama ES el dueño (su uid = user_id del tenant);
    //    si es un asesor sub-cuenta, el dueño es su admin_id. (BUG anterior: exigiamos admin_id -> el DUENO
    //    real / el admin quedaba 403 porque no tiene un admin "arriba". La seguridad de tenant del paso 4
    //    igual limita a renombrar SOLO contactos del tenant resuelto.)
    let ownerId = uid;
    try {
      const { data: ase } = await supabase.from('asesores').select('admin_id').eq('auth_user_id', uid).maybeSingle();
      if (ase && ase.admin_id) ownerId = ase.admin_id;
    } catch (e1) {}

    // 3) BODY. contact_id obligatorio; nombre vacio => null (vuelve al nombre de WhatsApp).
    const b = req.body || {};
    const contactId = (b.contact_id != null) ? String(b.contact_id) : '';
    if (!contactId) return res.status(400).json({ error: 'Falta contact_id' });
    const valor = (b.nombre != null) ? String(b.nombre).trim() : '';
    const nombreFinal = (valor === '') ? null : valor;

    // 4) SEGURIDAD DE TENANT: el contacto debe pertenecer al DUENO del que llama (no renombrar cross-tenant).
    let cont = null;
    try {
      const { data } = await supabase.from('contacts').select('id, user_id').eq('id', contactId).maybeSingle();
      cont = data || null;
    } catch (eC) {}
    if (!cont) return res.status(404).json({ error: 'Contacto no encontrado' });
    if (cont.user_id !== ownerId) return res.status(403).json({ error: 'No autorizado' });

    // 5) UPDATE con service key (saltea RLS). Scoped por id + user_id del tenant.
    const { error: eUp } = await supabase.from('contacts').update({ nombre_manual: nombreFinal }).eq('id', contactId).eq('user_id', ownerId);
    if (eUp) return res.status(500).json({ error: 'No se pudo guardar el nombre' });

    return res.json({ ok: true, nombre_manual: nombreFinal });
  } catch (e) {
    return res.status(500).json({ error: 'Error interno' });
  }
});

app.post('/api/contactos/cargar-manual', async function(req, res) {
  try {
    // 1) AUTH: identidad por token (validacion local por firma; mismo verificarUsuario que el resto).
    const uid = await verificarUsuario(req);
    if (!uid) return res.status(401).json({ error: 'No autorizado' });

    // 2) Resolver el ASESOR (fila en `asesores` por auth_user_id) y el DUENO del tenant (admin_id).
    //    Proyeccion defensiva: intentamos leer `puede_cargar_contacto`; si la columna NO existe todavia
    //    (feature aun sin migrar), el select con esa columna falla -> reintentamos SIN ella y tratamos el
    //    permiso como false (=> 403). Asi la feature queda INERTE hasta correr migracion-cargar-contacto.sql.
    //    Traemos tambien `rol` y `visibilidad` para poder derivar la capacidad de administrador con el helper
    //    canonico esAdministrador() (rol legacy 'administrador' O visibilidad incluye 'generales').
    let ase = null;
    try {
      const r = await supabase.from('asesores').select('id, admin_id, nombre, rol, visibilidad, puede_cargar_contacto').eq('auth_user_id', uid).maybeSingle();
      if (!r.error && r.data) ase = r.data;
    } catch (e1) {}
    if (!ase) {
      // Fallback: sin la columna nueva (o cualquier otro error del select de arriba). puede_cargar_contacto queda undefined.
      try {
        const r2 = await supabase.from('asesores').select('id, admin_id, nombre, rol, visibilidad').eq('auth_user_id', uid).maybeSingle();
        if (!r2.error && r2.data) ase = r2.data;
      } catch (e2) {}
    }
    if (!ase) {
      // Fallback FINAL minimo: sin `visibilidad` (por si esa columna faltara en algun tenant). Solo rol legacy para el gate admin.
      try {
        const r3 = await supabase.from('asesores').select('id, admin_id, nombre, rol').eq('auth_user_id', uid).maybeSingle();
        if (!r3.error && r3.data) ase = r3.data;
      } catch (e3) {}
    }
    // Solo un ASESOR (fila en `asesores`) puede cargar contactos. El dueno "puro" (sin fila de asesor) no pasa por aca;
    // en esta app el dueno se loguea como un asesor con capacidad de administrador (rol='administrador' o visibilidad
    // 'generales'), asi que SI entra por el camino admin de abajo (decision de Diego).
    if (!ase || !ase.admin_id) return res.status(403).json({ error: 'No tenes permiso para cargar contactos' });

    // 3) PERMISO (refinamiento v2): el ADMINISTRADOR SIEMPRE puede; el asesor comun necesita puede_cargar_contacto===true.
    //    esAdministrador() es el criterio unico y centralizado (rol legacy 'administrador' O visibilidad='generales').
    //    Fail-safe para el asesor comun: columna ausente / null / false -> 403.
    const _esAdmin = esAdministrador(ase);
    if (!_esAdmin && ase.puede_cargar_contacto !== true) return res.status(403).json({ error: 'No tenes permiso para cargar contactos' });

    const ownerId = ase.admin_id;        // el contacto/conversacion son del DUENO (multi-tenant)
    const asesorId = ase.id;             // asignado a ESTE asesor
    const asesorNombre = (ase.nombre ? String(ase.nombre) : 'un asesor');

    // 4) BODY + validacion. nombre y telefono obligatorios.
    const b = req.body || {};
    const nombre = (b.nombre != null) ? String(b.nombre).trim() : '';
    // Normalizar el telefono IGUAL que el resto del codigo: solo digitos (la columna `phone` guarda digitos).
    const telefono = (b.telefono != null) ? String(b.telefono).replace(/[^0-9]/g, '') : '';
    if (!nombre) return res.status(400).json({ error: 'Falta el nombre' });
    if (!telefono || telefono.length < 6) return res.status(400).json({ error: 'Telefono invalido' });

    const canal = 'whatsapp';

    // 5) UPSERT del CONTACTO por (owner user_id, phone, channel). Mismo patron atomico que obtenerOcrearConvDeCanal.
    //    Seteamos name=nombre y nombre_manual=nombre (el front usa nombre_manual como nombre visible del lead).
    //    DEFENSIVO con nombre_manual: si esa columna faltara, el upsert falla -> reintentamos SIN ella.
    let contacto = null;
    let contactoYaExistia = false;
    // Primero: buscar un contacto existente de ese telefono (sin filtrar por channel, para no duplicar legacy).
    try {
      const { data: existente } = await supabase.from('contacts').select('id').eq('user_id', ownerId).eq('phone', telefono).maybeSingle();
      if (existente) { contacto = existente; contactoYaExistia = true; }
    } catch (eEx) {}
    if (!contacto) {
      const _payloadFull = { user_id: ownerId, name: nombre, nombre_manual: nombre, phone: telefono, channel: canal };
      let _ok = false;
      try {
        const { data: nuevo, error: eUp } = await supabase.from('contacts').upsert(_payloadFull, { onConflict: 'user_id,phone,channel' }).select('id').single();
        if (!eUp && nuevo) { contacto = nuevo; _ok = true; }
      } catch (eUpC) {}
      if (!_ok) {
        // Reintento SIN nombre_manual (por si esa columna no existe) usando el mismo upsert idempotente.
        try {
          const { data: nuevo2, error: eUp2 } = await supabase.from('contacts').upsert({ user_id: ownerId, name: nombre, phone: telefono, channel: canal }, { onConflict: 'user_id,phone,channel' }).select('id').single();
          if (!eUp2 && nuevo2) { contacto = nuevo2; _ok = true; }
        } catch (eUp2C) {}
      }
      if (!_ok) {
        // Fallback FINAL (indice unico ausente u otro error): re-leer por si un concurrente lo creo; si no, insert plano.
        const { data: _reC } = await supabase.from('contacts').select('id').eq('user_id', ownerId).eq('phone', telefono).maybeSingle();
        if (_reC) { contacto = _reC; contactoYaExistia = true; }
        else {
          const { data: _ins } = await supabase.from('contacts').insert({ user_id: ownerId, name: nombre, phone: telefono, channel: canal }).select('id').single();
          contacto = _ins;
        }
      } else if (contactoYaExistia === false) {
        // Si el upsert devolvio una fila preexistente (mismo conflict), no lo sabemos con certeza; lo dejamos como "nuevo".
      }
    }
    // NOTA (refinamiento v2): si el contacto YA existia (contactoYaExistia===true) NO lo tocamos. Podria ser un lead
    // real previo; sobreescribir su name/nombre_manual seria "pisarlo". El refresco de nombre solo se hace, mas abajo,
    // cuando efectivamente creamos una conversacion NUEVA para un contacto sin thread previo.
    if (!contacto) return res.status(500).json({ error: 'No se pudo crear el contacto' });

    // 6) CONVERSACION: buscar-o-crear por (owner user_id, contact_id).
    //    REFINAMIENTO v2 (NO PISAR): si el contacto YA existia O ya tiene una conversacion, es un lead real previo ->
    //    NO tocamos status / ai_enabled / asesor_id. Solo devolvemos la conversacion existente (para que el front la abra).
    //    SOLO cuando creamos una conversacion GENUINAMENTE NUEVA seteamos listo_humano + IA off + asignada al creador.
    //    Caso borde (decision Diego): contacto preexistente PERO sin conversacion -> la conversacion es nueva, asi que
    //    la creamos y la asignamos normalmente (no habia lead/thread previo que pisar).
    const _valores = { status: 'listo_humano', ai_enabled: false, asesor_id: asesorId, ultimo_asesor_id: asesorId, updated_at: new Date().toISOString() };
    let conv = null;
    let convYaExistia = false;
    try {
      const { data: convEx } = await supabase.from('conversations').select('id').eq('user_id', ownerId).eq('contact_id', contacto.id).maybeSingle();
      if (convEx) { conv = convEx; convYaExistia = true; }
    } catch (eCv) {}
    // Un lead "real previo" es: el contacto ya existia, O ya habia una conversacion para el.
    const _yaExistia = (contactoYaExistia === true) || (convYaExistia === true);
    if (conv) {
      // La conversacion YA existe -> NO la pisamos (ni status, ni ai_enabled, ni asesor_id). La dejamos intacta.
      // (Solo la devolvemos para que el front la abra.)
    } else {
      // Conversacion NUEVA -> la creamos con listo_humano + IA off + asignada a este creador.
      const _convPayload = Object.assign({ user_id: ownerId, contact_id: contacto.id, channel: canal }, _valores);
      let _okC = false;
      try {
        const { data: convNueva, error: eUpV } = await supabase.from('conversations').upsert(_convPayload, { onConflict: 'user_id,contact_id' }).select('id').single();
        if (!eUpV && convNueva) { conv = convNueva; _okC = true; }
      } catch (eUpV2) {}
      if (!_okC) {
        // Fallback (indice unico ausente): re-leer por si un concurrente la creo. Si aparece, es preexistente -> NO pisar.
        const { data: _reV } = await supabase.from('conversations').select('id').eq('user_id', ownerId).eq('contact_id', contacto.id).maybeSingle();
        if (_reV) { conv = _reV; convYaExistia = true; }
        else {
          const { data: _insV } = await supabase.from('conversations').insert(_convPayload).select('id').single();
          conv = _insV;
        }
      }
      // Solo si la conversacion es realmente NUEVA (y el contacto no venia de antes) refrescamos el nombre del contacto
      // preexistente que aun no tenia thread. Si el contacto ya existia lo dejamos como estaba (no pisar).
      if (conv && contactoYaExistia === true && convYaExistia !== true) {
        try { await supabase.from('contacts').update({ name: nombre, nombre_manual: nombre }).eq('id', contacto.id); }
        catch (eUpdN) { try { await supabase.from('contacts').update({ name: nombre }).eq('id', contacto.id); } catch (e) {} }
      }
    }
    if (!conv) return res.status(500).json({ error: 'No se pudo crear la conversacion' });

    // Recalcular "ya existia" incluyendo el caso de carrera detectado en el fallback (convYaExistia pudo cambiar arriba).
    const _yaExistiaFinal = _yaExistia || (convYaExistia === true);

    // 7) Mensaje de SISTEMA (0 IA): SOLO cuando creamos algo nuevo. Si el lead ya existia, NO dejamos traza (no tocar).
    if (!_yaExistiaFinal) {
      try {
        const _txtSis = 'Contacto cargado manualmente por ' + asesorNombre + ' — asignado y listo para humano';
        await supabase.from('messages').insert({ conversation_id: conv.id, user_id: ownerId, role: 'sistema', content: _txtSis, enviado_por: 'Sistema' });
      } catch (eSis) { console.error('cargar-manual mensaje sistema (best-effort):', eSis && eSis.message); }
    }

    return res.json({ ok: true, conversation_id: conv.id, contact_id: contacto.id, ya_existia: _yaExistiaFinal === true });
  } catch (e) {
    console.error('cargar-manual:', e && e.message);
    return res.status(500).json({ error: (e && e.message) || 'Error al cargar el contacto' });
  }
});

// Membresias de departamentos de todos los usuarios de la cuenta: { asesor_id: [departamento_id, ...] }. La tabla tiene RLS service-key, por eso pasa por aca.
app.get('/api/asesores/membresias', async (req, res) => {
  try {
    const userId = await verificarUsuario(req);
    if (!userId) return res.status(401).json({ error: 'No autorizado' });
    let ownerId = userId;
    const { data: ase } = await supabase.from('asesores').select('admin_id').eq('auth_user_id', userId).maybeSingle();
    if (ase && ase.admin_id) ownerId = ase.admin_id;
    const { data: ases } = await supabase.from('asesores').select('id').eq('admin_id', ownerId);
    const idsAse = (ases || []).map(function(a){ return a.id; });
    // PARTE A (punto 9): devolver tambien el `modo` por depto para precargar el sub-segmented Recibe/Visualiza.
    // Formato nuevo: { asesor_id: [{departamento_id, modo}] }. El front acepta tambien el legacy (string[]).
    // DEFENSIVO: si la columna `modo` no existe todavia, reintentar sin ella (modo=null -> el front asume 'recibe').
    const mapa = {};
    if (idsAse.length) {
      let rows = null;
      try {
        const rr = await supabase.from('usuario_departamento').select('asesor_id, departamento_id, modo').in('asesor_id', idsAse);
        if (rr.error) throw rr.error;
        rows = rr.data;
      } catch (eModo) {
        const rr2 = await supabase.from('usuario_departamento').select('asesor_id, departamento_id').in('asesor_id', idsAse);
        rows = (rr2.data || []).map(function(r){ return { asesor_id: r.asesor_id, departamento_id: r.departamento_id, modo: null }; });
      }
      (rows || []).forEach(function(r){ if (!mapa[r.asesor_id]) mapa[r.asesor_id] = []; mapa[r.asesor_id].push({ departamento_id: r.departamento_id, modo: r.modo || 'recibe' }); });
    }
    return res.json({ ok: true, membresias: mapa });
  } catch (e) { return res.status(500).json({ error: e && e.message }); }
});

app.post('/api/asesores/activar', async (req, res) => {
  try {
    const { admin_id, asesor_id } = req.body || {};
    // SEGURIDAD: validar identidad por token
    const _uidToken = await verificarUsuario(req);
    if (!_uidToken) return res.status(401).json({ error: 'No autorizado: falta token valido' });
    if (_uidToken !== admin_id) return res.status(403).json({ error: 'Identidad no coincide' });
    if (!admin_id || !asesor_id) return res.status(400).json({ error: 'Faltan datos' });
    // 1. Poner el asesor activo. Ademas reactivar su DISPONIBILIDAD para que ENTRE al reparto: sin esto quedaba
    // activo=true pero disponibilidad='pausa', y elegirAsesorParaDepartamento lo excluia ("lo activo y queda en pausa").
    // No pisamos 'no_recibe' (puede ser intencional, ej. admin de solo-vision).
    let _dispAct = 'conectado';
    try { const { data: _aPrev } = await supabase.from('asesores').select('disponibilidad').eq('id', asesor_id).maybeSingle(); if (_aPrev && _aPrev.disponibilidad === 'no_recibe') _dispAct = 'no_recibe'; } catch (eDisp) {}
    await supabase.from('asesores').update({ activo: true, estado: 'activo', disponibilidad: _dispAct }).eq('id', asesor_id);
    // Reponer el ACCESO del usuario (si estaba apagado): sacarlo del Set en memoria + desbanear el login en Auth.
    try { const { data: _aAcc } = await supabase.from('asesores').select('auth_user_id').eq('id', asesor_id).maybeSingle(); if (_aAcc && _aAcc.auth_user_id) { _asesoresSinAcceso.delete(_aAcc.auth_user_id); await _setBanUsuario(_aAcc.auth_user_id, false); } } catch (eAcc) {}
    // 2. Buscar asesores activos de la inmobiliaria (excluyendo administradores: no reciben leads)
    // PARTE A (punto 10): con reparto_v2 ON, ademas se excluye a los que tienen disponibilidad='no_recibe'
    // (que es como se mapean ahora Administrador/Empleado). Con flag OFF, queda igual que antes.
    let activos = null;
    // HOTFIX MISRUTEO (FIX C): hoisteamos v2act al scope del handler (antes era local al bloque de abajo) para REUSARLO
    // en el gate por-departamento del drenaje (mas abajo) sin repetir la query repartoV2Activo. Con el flag OFF queda
    // false -> el gate por-lead NO restringe -> drenaje byte-identico al actual.
    let v2act = false;
    {
      // PARTE B (fix hueco auditoria): traemos tambien es_ia para EXCLUIR usuarios IA del drenaje de la COLA humana.
      // La cola 'listo_humano' son leads que esperan un HUMANO; si se los asignaramos a un usuario IA quedarian con
      // ai_enabled=false (cola humana) y un asesor IA -> NADIE responde. DEFENSIVO: si es_ia no existe, reintentamos
      // sin esa columna (set legacy) y no se filtra (comportamiento ACTUAL EXACTO).
      let act0 = null;
      try {
        const r = await supabase.from('asesores').select('id, disponibilidad, es_ia').eq('admin_id', admin_id).eq('activo', true).or('rol.is.null,rol.neq.administrador');
        if (r.error) throw r.error; act0 = r.data;
      } catch (eIaCol) {
        const r2 = await supabase.from('asesores').select('id, disponibilidad').eq('admin_id', admin_id).eq('activo', true).or('rol.is.null,rol.neq.administrador');
        act0 = r2.data;
      }
      activos = act0;
      try { v2act = await repartoV2Activo(admin_id, null); } catch (eV2a) { v2act = false; }
      if (v2act && Array.isArray(activos)) {
        activos = activos.filter(function(a){ return a.disponibilidad !== 'no_recibe'; });
        activos = activos.filter(function(a){ return a.es_ia !== true; }); // la cola humana NO se reparte a usuarios IA
      }
    }
    if (!activos || activos.length === 0) return res.json({ ok: true, asignados: 0 });
    // 3. Buscar leads EN COLA: listos para humano, sin asignar y no tomados por el admin.
    //    Filtramos por status='listo_humano' para NO repartir conversaciones que aun maneja la IA.
    // HOTFIX MISRUTEO (FIX C): traemos tambien departamento_id para que el asesor que se conecta SOLO drene leads
    // de SU(S) departamento(s). Antes el drenaje repartia la cola account-wide por menor carga SIN mirar depto, asi
    // que un asesor de Alquiler podia llevarse un lead de Venta (misruteo). DEFENSIVO: si departamento_id no existe,
    // el reintento sin esa columna deja departamento_id=undefined en cada lead -> "sin depto" -> comportamiento ACTUAL
    // (lo puede tomar cualquiera). Ver el gate por-lead mas abajo.
    let enEspera = null;
    try {
      const _rEsp = await supabase.from('conversations').select('id, departamento_id').eq('user_id', admin_id).eq('status', 'listo_humano').is('asesor_id', null).eq('admin_tomo', false);
      if (_rEsp.error) throw _rEsp.error;
      enEspera = _rEsp.data;
    } catch (eDeptoCol) {
      // Columna departamento_id ausente u otro error: reintentar SIN ella -> cada lead queda sin depto (comportamiento ACTUAL).
      const { data: _reEsp } = await supabase.from('conversations').select('id').eq('user_id', admin_id).eq('status', 'listo_humano').is('asesor_id', null).eq('admin_tomo', false);
      enEspera = _reEsp;
    }
    if (!enEspera || enEspera.length === 0) return res.json({ ok: true, asignados: 0 });
    // HOTFIX MISRUTEO (FIX C): departamentos (modo='recibe') del asesor que SE CONECTA. Solo drenara leads cuyo
    // departamento_id este en este set. DEFENSIVO: si la tabla/columna 'modo' no existe -> reintento sin ella (legacy
    // = todos reciben). Si la lectura falla del todo -> Set vacio con bandera _sinMembresias=true, que hace que el gate
    // por-lead caiga al comportamiento ACTUAL (no bloquea el drenaje). SOLO se filtra cuando reparto_v2 esta ON: con el
    // flag OFF la variable v2act (calculada arriba) es false y el gate por-lead no restringe -> byte-identico a hoy.
    const _misDeptos = new Set();
    let _sinMembresias = false;
    try {
      let _memRows = null;
      try {
        const _rm = await supabase.from('usuario_departamento').select('departamento_id, modo').eq('asesor_id', asesor_id);
        if (_rm.error) throw _rm.error;
        _memRows = _rm.data;
      } catch (eModoC) {
        const _rm2 = await supabase.from('usuario_departamento').select('departamento_id').eq('asesor_id', asesor_id);
        _memRows = (_rm2.data || []).map(function(m){ return { departamento_id: m.departamento_id, modo: null }; });
      }
      (_memRows || [])
        .filter(function(m){ return m.modo == null || m.modo === 'recibe'; }) // excluir 'visualiza' (igual que elegirAsesorParaDepartamento)
        .forEach(function(m){ if (m.departamento_id) _misDeptos.add(m.departamento_id); });
    } catch (eMemAll) { _sinMembresias = true; /* no se pudo leer membresias: NO restringir (comportamiento actual) */ }
    // 4. Contar carga actual de cada activo para repartir equitativo
    const carga = {};
    for (const a of activos) {
      // D1=B: la carga cuenta SOLO conversaciones asignadas y en atencion humana ('listo_humano').
      // Se excluyen cerradas y las que aun maneja la IA (en_conversacion / interesado / recontacto).
      const { count } = await supabase.from('conversations').select('id', { count: 'exact', head: true }).eq('asesor_id', a.id).eq('status', 'listo_humano');
      carga[a.id] = count || 0;
    }
    // 5. Repartir cada lead en espera al activo con menos carga
    let asignados = 0;
    // HOTFIX MISRUTEO (FIX C): true SOLO cuando el gate por-departamento esta ACTIVO (reparto_v2 ON + membresias leidas).
    // Con el flag OFF, o si no se pudieron leer las membresias, queda false -> el drenaje se comporta byte-identico al
    // actual (reparto account-wide por menor carga, sin mirar depto).
    const _gateDeptoActivo = (v2act === true && !_sinMembresias);
    for (const lead of enEspera) {
      // HOTFIX MISRUTEO (FIX C): el asesor que se conecta SOLO toma leads de SU(S) departamento(s). Si el lead tiene
      // departamento_id y NO es miembro (modo='recibe') de ese depto -> saltearlo (queda en cola para su gente).
      // DEFENSIVO: lead SIN departamento_id -> comportamiento actual (lo puede tomar). Si no se pudieron leer las
      // membresias (_sinMembresias) o reparto_v2 OFF -> gate inactivo -> drenaje byte-identico al actual.
      const _leadConDepto = _gateDeptoActivo && !!lead.departamento_id;
      if (_leadConDepto && !_misDeptos.has(lead.departamento_id)) {
        continue; // lead de otro depto: no lo drena este asesor (queda en cola para su gente)
      }
      // Target: si el lead ES de un depto de ESTE asesor (gate activo + tiene depto + es miembro), se lo asignamos al
      // asesor que se CONECTA (spec: "asignarlo a este asesor"). Asi no cae en un tercero por menor-carga que podria NO
      // ser del depto (lo que reintroduciria el misruteo). GUARD: solo si el asesor que se conecta es ELEGIBLE (esta en
      // `activos`/`carga`, o sea NO fue filtrado por no_recibe/es_ia); si no lo es, NO drenamos este lead (queda en cola
      // para sus companeros del depto). Para leads SIN depto (o gate inactivo) se conserva EXACTO el reparto account-wide
      // por menor carga de siempre (con flag OFF esto es el unico camino -> byte-identico a hoy).
      let mejor, menos;
      if (_leadConDepto) {
        if (!Object.prototype.hasOwnProperty.call(carga, asesor_id)) {
          continue; // el asesor que se conecta no es receptor elegible (no_recibe / es_ia): dejar el lead para su gente
        }
        mejor = asesor_id; menos = carga[mejor];
      } else {
        mejor = activos[0].id; menos = carga[mejor];
        for (const a of activos) { if (carga[a.id] < menos) { menos = carga[a.id]; mejor = a.id; } }
      }
      // La asignacion va PRIMERO y sola, para no depender de columnas nuevas (si cola_avisada no existe,
      // Supabase devuelve error en vez de tirar excepcion y NO se escribiria la asignacion). Mantiene el drenaje intacto.
      // RACE #2 (PATRON CANONICO server.js:1866): UPDATE CONDICIONAL .is('asesor_id', null) + .select(). Si dos
      // asesores tocan "activar" a la vez (o este loop corre concurrente con derivarAHumano/escalado), el segundo
      // recibe 0 filas: ese lead YA fue tomado -> NO lo contamos como asignado ni tocamos carga[] (que quedaria stale).
      const { data: _asgDren } = await supabase.from('conversations')
        .update({ asesor_id: mejor, ultimo_asesor_id: mejor })
        .eq('id', lead.id).is('asesor_id', null).eq('admin_tomo', false).select('id');
      if (!_asgDren || !_asgDren.length) { continue; } // otro ya lo tomo: no incrementar carga ni asignados
      // ETAPA 5 (best-effort): limpiar la marca de aviso para que, si en el futuro vuelve a quedar sin asesor,
      // se pueda volver a avisar al dueno. Si la columna cola_avisada no existe, esto no afecta la asignacion.
      try { await supabase.from('conversations').update({ cola_avisada: false }).eq('id', lead.id); } catch (eFlag) {}
      try { _colaAvisada.delete(lead.id); } catch (eDel) {}
      carga[mejor] = (carga[mejor] || 0) + 1;
      asignados++;
    }
    return res.json({ ok: true, asignados });
  } catch (e) {
    console.error('Error en activar asesor:', e.message);
    return res.status(500).json({ error: e.message });
  }
});

app.post('/api/asesores/cambiar-clave', async (req, res) => {
  try {
    const { admin_id, asesor_id, clave_nueva } = req.body || {};
    // SEGURIDAD: validar identidad por token
    const _uidToken = await verificarUsuario(req);
    if (!_uidToken) return res.status(401).json({ error: 'No autorizado: falta token valido' });
    if (_uidToken !== admin_id) return res.status(403).json({ error: 'Identidad no coincide' });
    if (!admin_id || !asesor_id || !clave_nueva) return res.status(400).json({ error: 'Faltan datos' });
    if (String(clave_nueva).length < 6) return res.status(400).json({ error: 'La clave debe tener al menos 6 caracteres' });
    // verificar que el asesor pertenezca a este admin
    const { data: ases } = await supabase.from('asesores').select('*').eq('id', asesor_id).eq('admin_id', admin_id).maybeSingle();
    if (!ases) return res.status(404).json({ error: 'Asesor no encontrado' });
    if (!ases.auth_user_id) return res.status(400).json({ error: 'El asesor no tiene usuario de acceso' });
    // cambiar la clave en Supabase Auth
    const { error: errUpd } = await supabase.auth.admin.updateUserById(ases.auth_user_id, { password: String(clave_nueva) });
    if (errUpd) return res.status(500).json({ error: 'No se pudo cambiar la clave: ' + errUpd.message });
    // Mantener clave_visible en sync (si no, el listado muestra la clave vieja tras cambiarla). Best-effort.
    try { await supabase.from('asesores').update({ clave_visible: String(clave_nueva) }).eq('id', asesor_id).eq('admin_id', admin_id); } catch (eCv) {}
    return res.json({ ok: true });
  } catch (e) { return res.status(500).json({ error: e && e.message }); }
});

// Cambiar el ALIAS (usuario de login) de un asesor. El alias es la parte que arma el email interno de Auth
// (emailAdmin + '+' + aliasLimpio + '@' + dominio); por eso cambiarlo OBLIGA a re-sincronizar el email en Auth,
// si no el login queda desincronizado (bug historico: se cambiaba el nombre visible pero el login seguia pidiendo
// el alias original). La CLAVE NO se toca (se conserva). El dueno lo cambia desde la pantalla Usuarios. 0 tokens.
app.post('/api/asesores/cambiar-alias', async (req, res) => {
  try {
    const { admin_id, asesor_id, alias_nuevo } = req.body || {};
    // SEGURIDAD: validar identidad por token
    const _uidToken = await verificarUsuario(req);
    if (!_uidToken) return res.status(401).json({ error: 'No autorizado: falta token valido' });
    if (_uidToken !== admin_id) return res.status(403).json({ error: 'Identidad no coincide' });
    if (!admin_id || !asesor_id || !alias_nuevo) return res.status(400).json({ error: 'Faltan datos' });
    const aliasLimpio = String(alias_nuevo).toLowerCase().replace(/[^a-z0-9]/g, '');
    if (!aliasLimpio) return res.status(400).json({ error: 'El alias debe tener al menos una letra o numero' });
    // El asesor debe pertenecer a este admin y tener usuario de Auth (login).
    const { data: ase } = await supabase.from('asesores').select('*').eq('id', asesor_id).eq('admin_id', admin_id).maybeSingle();
    if (!ase) return res.status(404).json({ error: 'Usuario no encontrado' });
    if (!ase.auth_user_id) return res.status(400).json({ error: 'El usuario no tiene acceso (login) para cambiarle el alias' });
    // Si el alias LIMPIO no cambia (mismo login), no re-sincronizamos Auth; solo actualizamos el texto visible si difiere.
    const aliasActualLimpio = String(ase.usuario || '').toLowerCase().replace(/[^a-z0-9]/g, '');
    if (aliasLimpio === aliasActualLimpio) {
      if (String(ase.usuario || '') !== String(alias_nuevo).trim()) { try { await supabase.from('asesores').update({ usuario: String(alias_nuevo).trim() }).eq('id', asesor_id).eq('admin_id', admin_id); } catch (e) {} }
      return res.json({ ok: true, alias: String(alias_nuevo).trim(), sin_cambios: true });
    }
    // Unicidad dentro del tenant: ningun OTRO usuario del admin puede tener el mismo alias limpio (evita colision de email).
    const { data: hermanos } = await supabase.from('asesores').select('id, usuario').eq('admin_id', admin_id);
    if (Array.isArray(hermanos)) {
      for (const h of hermanos) {
        if (String(h.id) === String(asesor_id)) continue;
        if (String(h.usuario || '').toLowerCase().replace(/[^a-z0-9]/g, '') === aliasLimpio) {
          return res.status(400).json({ error: 'Ese alias ya lo usa otro usuario de tu cuenta, elegi otro' });
        }
      }
    }
    // Armar el email nuevo a partir del email del admin (mismo criterio que /crear).
    const { data: adminData, error: errAdmin } = await supabase.auth.admin.getUserById(admin_id);
    if (errAdmin || !adminData || !adminData.user || !adminData.user.email) return res.status(400).json({ error: 'No se pudo obtener el email del administrador' });
    const partes = String(adminData.user.email).split('@');
    const emailNuevo = partes[0] + '+' + aliasLimpio + '@' + partes[1];
    // Re-sincronizar el email en Auth. Usamos la función SQL cambiar_email_asesor (SECURITY DEFINER, solo service_role)
    // que cambia el email en auth.users + auth.identities DIRECTAMENTE, porque updateUserById({email}) NO lo cambia al
    // instante en esta config de Supabase ("secure email change" lo deja pendiente de una confirmación que nunca llega)
    // -> el login quedaba desincronizado (el nombre cambiaba pero se seguía entrando con el alias viejo). La CLAVE no se toca.
    const { error: errUpd } = await supabase.rpc('cambiar_email_asesor', { p_uid: ase.auth_user_id, p_email: emailNuevo });
    if (errUpd) {
      const _m = String(errUpd.message || '').toLowerCase();
      if (_m.indexOf('duplicate') >= 0 || _m.indexOf('unique') >= 0 || _m.indexOf('already') >= 0 || _m.indexOf('exists') >= 0) return res.status(400).json({ error: 'Ese alias ya esta en uso, elegi otro' });
      return res.status(500).json({ error: 'No se pudo cambiar el alias: ' + (errUpd.message || '') });
    }
    // Persistir el alias visible en la tabla (el email de Auth ya quedo cambiado; esto es el texto que se muestra/escribe).
    const { error: errUsu } = await supabase.from('asesores').update({ usuario: String(alias_nuevo).trim() }).eq('id', asesor_id).eq('admin_id', admin_id);
    if (errUsu) return res.status(500).json({ error: 'El alias cambio en el acceso pero no se pudo guardar el texto: ' + errUsu.message });
    return res.json({ ok: true, alias: String(alias_nuevo).trim(), email: emailNuevo });
  } catch (e) { return res.status(500).json({ error: e && e.message }); }
});
app.post('/api/asesores/eliminar', async (req, res) => {
  try {
    const { admin_id, asesor_id } = req.body || {};
    // SEGURIDAD: validar identidad por token
    const _uidToken = await verificarUsuario(req);
    if (!_uidToken) return res.status(401).json({ error: 'No autorizado: falta token valido' });
    if (_uidToken !== admin_id) return res.status(403).json({ error: 'Identidad no coincide' });
    if (!admin_id || !asesor_id) return res.status(400).json({ error: 'Faltan datos' });
    const { data: ases } = await supabase.from('asesores').select('*').eq('id', asesor_id).eq('admin_id', admin_id).maybeSingle();
    if (!ases) return res.status(404).json({ error: 'Asesor no encontrado' });
    if (ases.auth_user_id) { try { await supabase.auth.admin.deleteUser(ases.auth_user_id); } catch (e) {} }
    await supabase.from('asesores').delete().eq('id', asesor_id).eq('admin_id', admin_id);
    return res.json({ ok: true });
  } catch (e) { return res.status(500).json({ error: e && e.message }); }
});

// ===== DEPARTAMENTOS (Fase 1 - equipo configurable). ADITIVO: tablas nuevas, NO toca el reparto actual. =====
// Scope por cuenta: el dueno (token === admin_id) gestiona los departamentos de su inmobiliaria.
// Las tablas tienen RLS service-key-only, por eso el frontend SIEMPRE pasa por estos endpoints.
// Normaliza un rubro (incluye valores legacy) a uno de los 3 valores CANONICOS:
// 'inmobiliaria' | 'hotel_cabanas' | 'desarrolladora'. Backwards-compatible: los rubros
// viejos guardados en clientes existentes (hotel, cabanas, cabañas, temporario, hoteleria)
// se mapean a 'hotel_cabanas' sin necesidad de migrar la DB. Default defensivo: inmobiliaria.
function normalizarRubro(r) {
  var v = String(r || '').trim().toLowerCase();
  if (v === 'desarrolladora') return 'desarrolladora';
  if (v === 'hotel' || v === 'cabanas' || v === 'cabañas' || v === 'temporario' || v === 'hoteleria' || v === 'hotel_cabanas') return 'hotel_cabanas';
  return 'inmobiliaria';
}

// TIPOS DE CITA/EVENTO por rubro (fuente unica). El front muestra SOLO los del rubro; el backend
// ACEPTA el superset de todos (para no romper datos viejos ni inmobiliaria). Aditivo.
var _TIPOS_CITA = {
  inmobiliaria: [
    { value: 'visita', label: 'Visita' }, { value: 'tasacion', label: 'Tasacion' },
    { value: 'reunion', label: 'Reunion' }, { value: 'llamada', label: 'Llamada' },
    { value: 'alquiler', label: 'Alquiler' }, { value: 'alquiler_temporal', label: 'Alquiler temporal' },
    { value: 'otro', label: 'Otro' }
  ],
  hotel_cabanas: [
    { value: 'check_in', label: 'Check-in' }, { value: 'check_out', label: 'Check-out' },
    { value: 'limpieza', label: 'Limpieza' }, { value: 'mantenimiento', label: 'Mantenimiento' },
    { value: 'consulta', label: 'Consulta' }, { value: 'llamada', label: 'Llamada' },
    { value: 'reunion', label: 'Reunion' }, { value: 'otro', label: 'Otro' }
  ],
  desarrolladora: [
    { value: 'reunion_inversor', label: 'Reunion con inversor' }, { value: 'visita_obra', label: 'Visita a la obra' },
    { value: 'visita_showroom', label: 'Visita al showroom' }, { value: 'hito_obra', label: 'Hito de obra' },
    { value: 'entrega_unidad', label: 'Entrega de unidad' }, { value: 'seguimiento_reserva', label: 'Seguimiento de reserva' },
    { value: 'llamada', label: 'Llamada' }, { value: 'reunion', label: 'Reunion' }, { value: 'otro', label: 'Otro' }
  ]
};
function tiposCitaPorRubro(rubro) { return _TIPOS_CITA[normalizarRubro(rubro)] || _TIPOS_CITA.inmobiliaria; }
// Superset de valores validos para el clamp del backend (incluye legacy 'venta' y 'alquiler').
var _TIPOS_CITA_VALIDOS = (function () { var s = { venta: 1 }; Object.keys(_TIPOS_CITA).forEach(function (k) { _TIPOS_CITA[k].forEach(function (t) { s[t.value] = 1; }); }); return Object.keys(s); })();
// Tipos que representan un RANGO (fecha_fin) por rubro -> el front les pide fecha/hora fin.
