  if (!texto) return null;
  var t = String(texto).trim().replace(/^```(?:json)?\s*/i, '').replace(/\s*```$/i, '').trim();
  try { var d = JSON.parse(t); if (d && typeof d === 'object') return d; } catch (e) {}
