// ===== TEMPERATURA DE LEADS =====
// DEPRECADA / SIN USO: la temperatura ahora es DETERMINISTICA y sigue al status del lead via
// temperaturaPorEstado(status) (CERO IA / CERO tokens). Esta funcion ya NO se invoca desde ningun lado
// (su unico call site, el retorno de recontacto, fue reemplazado por la regla por-estado). Se deja para
// no romper nada y por si se necesita referencia historica; NO volver a usarla: gasta Haiku por mensaje.
async function clasificarTemperatura(textoUsuario, user_id) {
  try {
    if (!textoUsuario || !textoUsuario.trim()) return null;
    const prompt = 'Clasifica el interes de este mensaje de un posible cliente inmobiliario en UNA palabra: ' +
      'caliente (muestra interes concreto en ver, visitar, precio, o avanzar con una propiedad), ' +
      'tibio (responde pero sin interes claro), frio (no hay interes). ' +
      'Responde SOLO con: caliente, tibio o frio. Mensaje: ' + JSON.stringify(textoUsuario);
    const r = await anthropic.messages.create({ model: MODELO_INTERNO, max_tokens: 10, messages: [{ role: 'user', content: prompt }] });
    try { if (user_id && r && r.usage) await registrarUsoTokens(user_id, r.usage, 'clasificar_temperatura', PRECIO_HAIKU); } catch(e){} // M17: MODELO_INTERNO (Haiku) -> precio Haiku (antes default Sonnet, ~3x inflado)
    const t = (r && r.content && r.content[0] && r.content[0].text ? r.content[0].text : '').toLowerCase().trim();
    if (t.indexOf('caliente') >= 0) return 'caliente';
    if (t.indexOf('tibio') >= 0) return 'tibio';
    if (t.indexOf('frio') >= 0 || t.indexOf('frío') >= 0) return 'frio';
    return null;
  } catch (e) { console.log('clasificarTemperatura error:', e && e.message); return null; }
}
// ===== FASE 3: AUTO-CATALOGO DE FOTOS POR VISION =====
// Clasifica fotos de propiedades en una categoria (dormitorio, baño, etc) usando vision de Claude.
// Endpoint nuevo y aislado: NO toca el flujo del agente, webhook, debounce ni memoria.
const CATEGORIAS_FOTO = ['dormitorio', 'baño', 'cocina', 'comedor', 'living', 'parque', 'frente', 'pileta', 'cochera', 'exterior', 'otra'];
// Normaliza acentos y mayusculas para comparar contra la lista de categorias.
function normalizarTexto(s) {
  return (s || '').toString().toLowerCase().normalize('NFD').replace(/[̀-ͯ]/g, '').trim();
}
// Devuelve una categoria valida (sin acentos) a partir del texto crudo de Claude; si no matchea -> 'otra'.
function matchearCategoriaFoto(textoCrudo) {
  const norm = normalizarTexto(textoCrudo);
  if (!norm) return 'otra';
  // Mapa normalizado -> categoria canonica (con acento donde corresponde)
  for (let i = 0; i < CATEGORIAS_FOTO.length; i++) {
    const cat = CATEGORIAS_FOTO[i];
    if (normalizarTexto(cat) === norm) return cat;
  }
  // Match por inclusion (la respuesta puede traer palabras de mas, ej "es un dormitorio")
  for (let i = 0; i < CATEGORIAS_FOTO.length; i++) {
    const cat = CATEGORIAS_FOTO[i];
    if (norm.indexOf(normalizarTexto(cat)) >= 0) return cat;
  }
  return 'otra';
}
const PROMPT_CLASIFICAR_FOTO = 'Clasifica esta foto de una propiedad inmobiliaria en UNA sola palabra de esta lista exacta: dormitorio, baño, cocina, comedor, living, parque, frente, pileta, cochera, exterior, otra. Responde SOLO la palabra.';
// Fallback: descarga la imagen y la manda como base64 (cuando source.type:'url' falla o hay duda).
async function clasificarFotoBase64(url, user_id) {
  const resp = await fetch(url, { headers: { 'User-Agent': 'Mozilla/5.0 RaicesCRM' } });
  if (!resp.ok) throw new Error('HTTP ' + resp.status);
  let mediaType = (resp.headers.get('content-type') || '').split(';')[0].trim().toLowerCase();
  // La API de vision solo acepta estos tipos; default a jpeg si viene algo raro.
  if (['image/jpeg', 'image/png', 'image/gif', 'image/webp'].indexOf(mediaType) < 0) mediaType = 'image/jpeg';
  const buf = Buffer.from(await resp.arrayBuffer());
  const r = await anthropic.messages.create({
    model: MODELO_INTERNO,
    max_tokens: 10,
    messages: [{ role: 'user', content: [
      { type: 'image', source: { type: 'base64', media_type: mediaType, data: buf.toString('base64') } },
      { type: 'text', text: PROMPT_CLASIFICAR_FOTO }
    ] }]
  });
  try { if (user_id && r && r.usage) await registrarUsoTokens(user_id, r.usage, 'vision_foto', PRECIO_HAIKU); } catch(e){}
  return (r && r.content && r.content[0] && r.content[0].text) ? r.content[0].text : '';
}
// Clasifica una sola foto: primero intenta source.type:'url' (soportado por el SDK 0.91), y si falla cae a base64.
async function clasificarFotoUna(url, user_id) {
  try {
    const r = await anthropic.messages.create({
      model: MODELO_INTERNO,
      max_tokens: 10,
      messages: [{ role: 'user', content: [
        { type: 'image', source: { type: 'url', url: url } },
        { type: 'text', text: PROMPT_CLASIFICAR_FOTO }
      ] }]
    });
    try { if (user_id && r && r.usage) await registrarUsoTokens(user_id, r.usage, 'vision_foto', PRECIO_HAIKU); } catch(e){}
    const t = (r && r.content && r.content[0] && r.content[0].text) ? r.content[0].text : '';
    return matchearCategoriaFoto(t);
  } catch (eUrl) {
    console.log('clasificar-fotos url fallo, probando base64:', eUrl && eUrl.message);
    try {
      const t2 = await clasificarFotoBase64(url, user_id);
      return matchearCategoriaFoto(t2);
    } catch (eB64) {
      console.log('clasificar-fotos base64 tambien fallo:', eB64 && eB64.message);
      return 'otra';
    }
  }
}
app.post('/api/clasificar-fotos', async (req, res) => {
  try {
    const _uid = await verificarUsuario(req);
    if (!_uid) return res.status(401).json({ error: 'No autorizado: falta token valido' });
    const body = req.body || {};
    const urls = Array.isArray(body.urls) ? body.urls.filter(function(u){ return typeof u === 'string' && u.trim(); }) : [];
    const property_id = body.property_id;
    if (!urls.length) return res.status(400).json({ error: 'Falta urls (array de strings)' });
    // CACHE DE VISION: si la propiedad YA tiene categoria guardada para una URL, no la re-clasificamos (no se
    // re-paga la vision). Solo se clasifican las URLs nuevas/sin categoria -> re-importar cuesta casi $0 en fotos ya hechas.
    const yaClasif = {};
    if (property_id) {
      try {
        const { data: propPrev } = await supabase.from('properties').select('images').eq('id', property_id).eq('user_id', _uid).maybeSingle();
        if (propPrev && Array.isArray(propPrev.images)) {
          propPrev.images.forEach(function(it){ if (it && typeof it === 'object' && it.url && it.categoria) yaClasif[it.url] = it.categoria; });
        }
      } catch (eCache) {}
    }
    const urlsNuevas = urls.filter(function(u){ return !yaClasif[u]; });
    // Concurrencia limitada: procesar de a 4 en paralelo para no saturar la API.
    const LOTE = 4;
    const resultados = [];
    // Las ya cacheadas se devuelven sin costo (no llaman a la vision).
    for (let k = 0; k < urls.length; k++) { if (yaClasif[urls[k]]) resultados.push({ url: urls[k], categoria: yaClasif[urls[k]], cacheada: true }); }
    // Solo se clasifican (pagan vision) las URLs nuevas.
    for (let i = 0; i < urlsNuevas.length; i += LOTE) {
      const lote = urlsNuevas.slice(i, i + LOTE);
      const parciales = await Promise.all(lote.map(async function(u) {
        try {
          const categoria = await clasificarFotoUna(u, _uid);
          return { url: u, categoria: categoria };
        } catch (e) {
          console.log('clasificar-fotos error foto:', e && e.message);
          return { url: u, categoria: 'otra' };
        }
      }));
      for (let j = 0; j < parciales.length; j++) resultados.push(parciales[j]);
    }
    // COBRO v2: 1 mensaje POR PROPIEDAD (no por foto), solo si se clasifico al menos 1 foto NUEVA (las cacheadas no pagan).
    try { if (SUBSCRIPTIONS_ENABLED && _uid && urlsNuevas.length > 0 && await cobrarTodoV2Activo(_uid)) await registrarUsoIA(_uid, 1); } catch (eCobFoto) {}
    // Opcional: si viene property_id, persistir el catalogo en properties.images (no rompe si falla).
    if (property_id) {
      try {
        const mapa = {};
        for (let k = 0; k < resultados.length; k++) mapa[resultados[k].url] = resultados[k].categoria;
        const { data: prop } = await supabase.from('properties').select('images, user_id').eq('id', property_id).maybeSingle();
        if (prop && prop.user_id === _uid) {
          let imgs = prop.images;
          if (Array.isArray(imgs)) {
            imgs = imgs.map(function(it) {
              if (typeof it === 'string') {
                return mapa[it] ? { url: it, categoria: mapa[it] } : { url: it };
              }
              if (it && typeof it === 'object' && it.url && mapa[it.url]) {
                return Object.assign({}, it, { categoria: mapa[it.url] });
              }
              return it;
            });
            await supabase.from('properties').update({ images: imgs }).eq('id', property_id);
          }
        }
      } catch (ePersist) { console.log('clasificar-fotos persistir images fallo (no critico):', ePersist && ePersist.message); }
    }
    return res.json({ ok: true, resultados: resultados });
  } catch (e) {
    console.error('clasificar-fotos error:', e && e.message);
    if (!res.headersSent) return res.status(500).json({ error: e && e.message });
  }
});
// ===== FASE 2: IMPORTAR LEADS AL CONECTAR =====
// Paso 1: listar los chats existentes en el WhatsApp (sin guardar)
app.get('/api/whatsapp/listar-chats', async function(req, res) {
  try {
    const user_id = req.query.user_id;
    // SEGURIDAD: validar identidad por token
    const _uidToken = await verificarUsuario(req);
    if (!_uidToken) return res.status(401).json({ error: 'No autorizado: falta token valido' });
    if (_uidToken !== user_id) return res.status(403).json({ error: 'Identidad no coincide' });
    if (!user_id) return res.status(400).json({ error: 'Falta user_id' });
    const instancia = await instanciaActiva(user_id);
    if (!instancia) return res.status(400).json({ error: 'No hay instancia para este usuario' });
    const conectada = await instanciaConectada(instancia);
    if (!conectada) return res.json({ ok: false, conectado: false, nota: 'El WhatsApp no esta conectado.' });
    // 1) traer los chats (la parte de Mensajes = leads reales que escribieron)
    const r = await fetch(EVOLUTION_URL + '/chat/findChats/' + instancia, { method: 'POST', headers: { 'Content-Type': 'application/json', 'apikey': EVOLUTION_KEY }, body: JSON.stringify({}) });
    if (!r.ok) { const t = await r.text(); return res.status(502).json({ error: 'Evolution respondio ' + r.status, detalle: t.substring(0,200) }); }
    const chatsRaw = await r.json();
    const lista = Array.isArray(chatsRaw) ? chatsRaw : (chatsRaw && chatsRaw.chats ? chatsRaw.chats : []);
    // 2) traer contactos (agenda) para conseguir los nombres por telefono
    const mapaNombre = {};
    try {
      const rc = await fetch(EVOLUTION_URL + '/chat/findContacts/' + instancia, { method: 'POST', headers: { 'Content-Type': 'application/json', 'apikey': EVOLUTION_KEY }, body: JSON.stringify({}) });
      if (rc.ok) {
        const contRaw = await rc.json();
        const contactos = Array.isArray(contRaw) ? contRaw : (contRaw && contRaw.contacts ? contRaw.contacts : []);
        for (const ct of contactos) {
          const cjid = String(ct.remoteJid || '');
          if (cjid.indexOf('@s.whatsapp.net') < 0) continue;
          const ctel = cjid.replace(/@.*/, '').replace(/[^0-9]/g, '');
          if (ctel && ct.pushName) mapaNombre[ctel] = ct.pushName;
        }
      }
    } catch (e) { /* si falla, seguimos sin nombres de la agenda */ }
    // 3) armar leads: solo chats con telefono real, con nombre cruzado
    const leads = [];
    for (const ch of lista) {
      const jid = ch.remoteJid || '';
      if (jid.indexOf('@s.whatsapp.net') < 0) continue;
      const telefono = jid.replace(/@.*/, '').replace(/[^0-9]/g, '');
      if (!telefono || telefono.length < 8 || telefono.length > 15) continue;
      const nombre = ch.pushName || mapaNombre[telefono] || '';
      leads.push({ telefono: telefono, nombre: nombre });
    }
    const vistos = {}; const unicos = [];
    for (const l of leads) { if (!vistos[l.telefono]) { vistos[l.telefono] = 1; unicos.push(l); } }
    return res.json({ ok: true, conectado: true, total: unicos.length, leads: unicos });
  } catch (e) { return res.status(500).json({ error: e && e.message }); }
});

// Paso 2: importar los leads listados a la base (contactos + conversaciones), con duplicados por telefono
// #9 - Recupera el historial de mensajes de un lead, cruzando todas las vias posibles
async function recuperarHistorialLead(instancia, telefono, chatsCache) {
  try {
    // 1) ubicar el chat del lead: por telefono real (@s.whatsapp.net) en los chats
    const chats = chatsCache || [];
    let jidChat = null;
    const directo = chats.find(function(ch){ return String(ch.remoteJid||'').indexOf(telefono + '@s.whatsapp.net') >= 0; });
    if (directo) jidChat = directo.remoteJid;
    if (!jidChat) return [];
    // 2) pedir los mensajes de ese chat
    const r = await fetch(EVOLUTION_URL + '/chat/findMessages/' + instancia, { method: 'POST', headers: { 'Content-Type': 'application/json', 'apikey': EVOLUTION_KEY }, body: JSON.stringify({ where: { key: { remoteJid: jidChat } } }) });
    if (!r.ok) return [];
    const jm = await r.json();
    const msgs = Array.isArray(jm) ? jm : (jm && jm.messages && jm.messages.records ? jm.messages.records : (jm && jm.messages ? jm.messages : []));
    if (!Array.isArray(msgs) || msgs.length === 0) return [];
    // 3) ordenar por timestamp y tomar los ultimos 10
    const ordenados = msgs.slice().sort(function(a,b){ return (a.messageTimestamp||0) - (b.messageTimestamp||0); });
    const ultimos = ordenados.slice(-10);
    // 4) mapear a {role, content, created_at}
    const out = [];
    for (const m of ultimos) {
      const k = m.key || {};
      const esMio = k.fromMe === true;
      // extraer texto del mensaje (conversation o extendedTextMessage)
      let texto = '';
      const mm = m.message || {};
      if (typeof mm.conversation === 'string') texto = mm.conversation;
      else if (mm.extendedTextMessage && mm.extendedTextMessage.text) texto = mm.extendedTextMessage.text;
      else if (mm.imageMessage && mm.imageMessage.caption) texto = '[imagen] ' + mm.imageMessage.caption;
      else if (mm.imageMessage) texto = '[imagen]';
      else if (mm.audioMessage) texto = '[audio]';
      else if (mm.videoMessage && mm.videoMessage.caption) texto = '[video] ' + mm.videoMessage.caption;
      else if (mm.videoMessage) texto = '[video]';
      else if (mm.documentMessage) texto = '[documento]';
      else if (mm.templateMessage) {
        var tm = mm.templateMessage.hydratedTemplate || mm.templateMessage.hydratedFourRowTemplate || (mm.templateMessage.fourRowTemplate) || {};
        texto = (tm.hydratedContentText || tm.hydratedTitleText || (tm.content && tm.content.text) || (tm.title && tm.title.text) || '');
        if (!texto) texto = '[mensaje con plantilla]';
      }
      else if (mm.buttonsMessage) texto = (mm.buttonsMessage.contentText || mm.buttonsMessage.text || '[mensaje con botones]');
      else if (mm.listMessage) texto = (mm.listMessage.description || mm.listMessage.title || '[mensaje con lista]');
      else if (mm.buttonsResponseMessage) texto = (mm.buttonsResponseMessage.selectedDisplayText || '[respuesta de boton]');
      else if (mm.listResponseMessage) texto = ((mm.listResponseMessage.title) || '[respuesta de lista]');
      else if (mm.ephemeralMessage && mm.ephemeralMessage.message && mm.ephemeralMessage.message.conversation) texto = mm.ephemeralMessage.message.conversation;
      if (!texto) continue;
      const ts = m.messageTimestamp ? new Date(Number(m.messageTimestamp) * 1000).toISOString() : new Date().toISOString();
      out.push({ role: esMio ? 'human' : 'contact', content: texto, created_at: ts });
    }
    return out;
  } catch (e) { console.error('Error recuperando historial de lead:', e && e.message); return []; }
}
app.post('/api/whatsapp/importar-leads', async function(req, res) {
  try {
    const user_id = req.body && req.body.user_id;
    // SEGURIDAD: validar identidad por token
    const _uidToken = await verificarUsuario(req);
    if (!_uidToken) return res.status(401).json({ error: 'No autorizado: falta token valido' });
    if (_uidToken !== user_id) return res.status(403).json({ error: 'Identidad no coincide' });
    if (!user_id) return res.status(400).json({ error: 'Falta user_id' });
    const leadsRaw = (req.body && req.body.leads) || [];
    if (!Array.isArray(leadsRaw) || leadsRaw.length === 0) return res.status(400).json({ error: 'No hay leads para importar' });

    // Categoria de recontacto: 'frio' (nunca escrito) o 'viejo' ("ya le escribieron"). "viejo" ademas marca la
    // conversacion como TIBIO (ya contactado), no frio. Se acepta por body (aplica a todos) o por-lead.
    const _normCat = function (c) { return (c === 'viejo') ? 'viejo' : 'frio'; };
    const catBody = (req.body && req.body.categoria != null) ? _normCat(req.body.categoria) : 'frio';

    // 1) Normalizar + DEDUP por telefono dentro del request.
    const porTel = {}; let invalidos = 0;
    for (const lead of leadsRaw) {
      const tel = String((lead && lead.telefono) || '').replace(/[^0-9]/g, '');
      if (!tel || tel.length < 8) { invalidos++; continue; }
      if (!porTel[tel]) porTel[tel] = { nombre: (lead && lead.nombre) || tel, categoria: (lead && lead.categoria != null) ? _normCat(lead.categoria) : catBody };
    }
    const telefonos = Object.keys(porTel);
    if (!telefonos.length) return res.json({ ok: true, total: leadsRaw.length, unicos: 0, creados: 0, yaExistian: 0, enRecontacto: 0, invalidos: invalidos });

    // Helper: procesar en lotes de N (una query por lote, no una por lead -> no se cuelga con miles).
    const LOTE = 500;
    async function porLotes(arr, fn) { for (let i = 0; i < arr.length; i += LOTE) { await fn(arr.slice(i, i + LOTE)); } }

    // 2) Contactos EXISTENTES (por telefono) en pocas queries.
    const idPorTel = {}; // telefono -> contact_id
    await porLotes(telefonos, async function (lote) {
      try { const { data } = await supabase.from('contacts').select('id, phone').eq('user_id', user_id).in('phone', lote);
        (data || []).forEach(function (c) { if (c && c.phone) idPorTel[String(c.phone)] = c.id; }); } catch (e) {}
    });

    // 3) Contactos NUEVOS: bulk insert por lotes.
    const nuevosTel = telefonos.filter(function (t) { return !idPorTel[t]; });
    let creados = 0;
    await porLotes(nuevosTel, async function (lote) {
      const filas = lote.map(function (t) { return { user_id: user_id, name: porTel[t].nombre, phone: t, channel: 'whatsapp' }; });
      try { const { data, error } = await supabase.from('contacts').insert(filas).select('id, phone');
        if (!error && Array.isArray(data)) { data.forEach(function (c) { if (c && c.phone) { idPorTel[String(c.phone)] = c.id; creados++; } }); } } catch (e) {}
    });

    // 4) Conversaciones: solo para contactos SIN conversacion. Primero detectar cuales ya tienen.
    const contactIds = telefonos.map(function (t) { return idPorTel[t]; }).filter(Boolean);
    const conConv = {};
    await porLotes(contactIds, async function (lote) {
      try { const { data } = await supabase.from('conversations').select('contact_id').eq('user_id', user_id).in('contact_id', lote);
        (data || []).forEach(function (cv) { if (cv && cv.contact_id) conConv[cv.contact_id] = 1; }); } catch (e) {}
    });
    const sinConv = telefonos.filter(function (t) { return idPorTel[t] && !conConv[idPorTel[t]]; });

    // 5) Bulk insert de conversaciones en 'recontacto'. Categoria 'viejo' -> temperatura 'tibio' (ya contactado);
    //    'frio' -> 'frio'. FAIL-SAFE: si alguna columna faltara, reintenta el lote con el conjunto minimo.
    let enRecontacto = 0;
    await porLotes(sinConv, async function (lote) {
      const filas = lote.map(function (t) {
        const cat = porTel[t].categoria;
        // Los importados entran SIEMPRE 'frio' (son fríos hasta pasar por el proceso). El "ya escribió antes" NO se
        // fake-marca como tibio (se confundía con los tibios reales de Interesado): esa info queda en recontacto_categoria='viejo'.
        return { user_id: user_id, contact_id: idPorTel[t], channel: 'whatsapp', status: 'recontacto', ai_enabled: true, temperatura: 'frio', recontacto_categoria: cat };
      });
      try {
        const { data, error } = await supabase.from('conversations').insert(filas).select('id');
        if (error) {
          const filasMin = lote.map(function (t) { return { user_id: user_id, contact_id: idPorTel[t], channel: 'whatsapp', status: 'recontacto', ai_enabled: true, temperatura: 'frio' }; });
          const r2 = await supabase.from('conversations').insert(filasMin).select('id');
          if (!r2.error && Array.isArray(r2.data)) enRecontacto += r2.data.length;
        } else if (Array.isArray(data)) { enRecontacto += data.length; }
      } catch (e) {}
    });

    // NOTA: se saco la recuperacion de historial via Evolution (era 1 llamada HTTP por lead, en serie, sin timeout ->
    // colgaba el import con archivos grandes). El historial, si hace falta, se puede recuperar despues por-lead.
    return res.json({ ok: true, total: leadsRaw.length, unicos: telefonos.length, creados: creados, yaExistian: telefonos.length - creados, enRecontacto: enRecontacto, invalidos: invalidos });
  } catch (e) { return res.status(500).json({ error: e && e.message }); }
});

// ===== SCRAPER UNIVERSAL DE INVENTARIO (multiples vias, cualquier inmobiliaria) =====
// M20: helper UNICO de limpieza de HTML para scraping (antes duplicado en limpiarHTML/limpiarHTML2).
// Usa el set de entidades MAS COMPLETO (incluye &#8220;/&#8221; -> comillas dobles "). limpiarHTML2 es ahora
// un alias de esta funcion (ver mas abajo) para que no exista copy-paste divergente.
function limpiarHTML(html) {
  if (!html) return '';
  return String(html).replace(/<script[\s\S]*?<\/script>/gi, ' ').replace(/<style[\s\S]*?<\/style>/gi, ' ').replace(/<!--[\s\S]*?-->/g, ' ').replace(/<[^>]+>/g, ' ').replace(/&nbsp;/g, ' ').replace(/&amp;/g, '&').replace(/&#8211;/g, '-').replace(/&#8217;/g, "'").replace(/&#8220;|&#8221;/g, '"').replace(/&quot;/g, '"').replace(/&#\d+;/g, ' ').replace(/\s+/g, ' ').trim();
}
function extraerPrecioDe(html) {
  if (!html) return null;
  // metodo 1: clase item-price (Houzez), capturando contenido anidado
  var m = html.match(/<(span|div|p|h\d)[^>]*class="[^"]*item-price[^"]*"[^>]*>([\s\S]*?)<\/\1>/i);
  if (m) { var l = limpiarHTML(m[2]); if (l && /\d{3,}/.test(l)) return l; }
  // metodo 2: cualquier clase con 'price' que tenga numeros
  m = html.match(/class="[^"]*price[^"]*"[^>]*>([\s\S]{0,80}?\d[\d.,]{2,}[\s\S]{0,10}?)<\//i);
  if (m) { var l2 = limpiarHTML(m[1]); if (/\d{3,}/.test(l2)) return l2; }
  // metodo 3: JSON-LD con price
  var lds = html.match(/<script[^>]*application\/ld\+json[^>]*>([\s\S]*?)<\/script>/gi) || [];
  for (var i = 0; i < lds.length; i++) {
    try { var obj = JSON.parse(lds[i].replace(/<script[^>]*>/i,'').replace(/<\/script>/i,''));
      var stack = [obj];
      while (stack.length) { var o = stack.pop(); if (o && typeof o === 'object') { if (o.price) return String(o.price); if (o.offers) stack.push(o.offers); for (var k in o) { if (o[k] && typeof o[k] === 'object') stack.push(o[k]); } } }
    } catch (e) {}
  }
  // metodo 4: patron de precio en texto plano
  m = html.match(/(USD|U\$S)\s?[\d.,]{3,}/i) || html.match(/\$\s?[\d.,]{4,}/);
  if (m) return m[0].trim();
  return null;
}

// Trae propiedades probando varias vias. Devuelve array de objetos normalizados.
async function obtenerPropiedadesUniversal(sitio, limite) {
  var baseUrl = sitio.replace(/\/+$/, '');
  var props = [];
  // --- VIA 1: WordPress REST API con _embed (la mas completa) ---
  try {
    var pagina = 1; var seguir = true;
    while (seguir && props.length < (limite || 9999)) {
      var url = baseUrl + '/wp-json/wp/v2/properties?per_page=50&page=' + pagina + '&_embed=1';
      var r = await fetchScrape(url, { headers: { 'User-Agent': 'Mozilla/5.0 RaicesCRM' } });
      if (!r.ok) break;
      var data = await r.json();
      if (!Array.isArray(data) || data.length === 0) break;
      for (var i = 0; i < data.length; i++) {
        var p = data[i];
        var emb = p._embedded || {};
        var terms = emb['wp:term'] || [];
        function taxOf(tax) { for (var a = 0; a < terms.length; a++) { var g = terms[a] || []; for (var b = 0; b < g.length; b++) { if (g[b].taxonomy === tax) return g[b].name; } } return null; }
        var feats = []; for (var a = 0; a < terms.length; a++) { var g = terms[a] || []; for (var b = 0; b < g.length; b++) { if (g[b].taxonomy === 'property_feature') feats.push(g[b].name); } }
        var media = emb['wp:featuredmedia'] || [];
        var foto = (media[0] && media[0].source_url) ? media[0].source_url : null;
        props.push({
          titulo: limpiarHTML(p.title && p.title.rendered),
          descripcion: limpiarHTML(p.content && p.content.rendered),
          link: p.link || (baseUrl + '/?p=' + p.id),
          tipo: taxOf('property_type'),
          operacion: taxOf('property_status'),
          ciudad: taxOf('property_city'),
          zona: taxOf('property_area'),
          provincia: taxOf('property_state'),
          caracteristicas: feats.join(', '),
          foto: foto,
          precio: null,
          fuente: 'wp-rest'
        });
      }
      if (data.length < 50) seguir = false;
      pagina++;
    }
  } catch (e) {}
  return props;
}

// Endpoint del scraper universal. Params: url (sitio), modo ('update'|'reset'), limite (opcional)
app.post('/api/scrape/universal', async function(req, res) {
  try {
    var token = (req.headers.authorization || '').replace('Bearer ', '');
    var user_id = await verificarUsuario(req);
    if (!user_id) return res.status(401).json({ error: 'No autorizado' });
    var sitio = (req.body.url || '').trim();
    var modo = (req.body.modo === 'reset') ? 'reset' : 'update';
    var limite = req.body.limite ? parseInt(req.body.limite, 10) : null;
    if (!sitio) return res.status(400).json({ error: 'Falta la url del sitio' });
    if (!sitio.startsWith('http')) sitio = 'https://' + sitio;

    // restringir al dominio propio del tenant (anti-scrape de competencia / explosion de costo IA)
    const _perm = await scrapeUrlPermitida(user_id, sitio);
    if (!_perm.ok) return res.status(400).json({ error: _perm.error });

    var props = await obtenerPropiedadesUniversal(sitio, limite);
    if (!props.length) return res.json({ ok: false, mensaje: 'No se encontraron propiedades por ninguna via', total: 0 });

    // sacar el precio de cada propiedad entrando a su pagina (en tandas para no saturar)
    for (var i = 0; i < props.length; i++) {
      if (!props[i].link) continue;
      try {
        var h = await fetchScrape(props[i].link, { headers: { 'User-Agent': 'Mozilla/5.0 RaicesCRM' } });
        if (h.ok) { var html = await h.text(); props[i].precio = extraerPrecioDe(html); }
      } catch (e) {}
    }

    // RUTEO POR RUBRO: un HOTEL guarda las unidades scrapeadas en hotel_unidades (no en properties). Desarrolladora
    // tiene su scraper propio (no cae aca). Inmobiliaria = comportamiento actual EXACTO (mas abajo).
    var _rubScrape = 'inmobiliaria';
    try { var _bsScr = await supabase.from('business_settings').select('rubro').eq('user_id', user_id).maybeSingle(); _rubScrape = normalizarRubro((_bsScr.data && _bsScr.data.rubro) || 'inmobiliaria'); } catch (eR) {}
    if (_rubScrape === 'hotel_cabanas') {
      // UNIFICADO: el hotel usa el camino COMPLETO (complejo + habitaciones + fotos + tarifas), no el path plano viejo.
      var _baseH; try { var _uH = new URL(sitio); _baseH = _uH.protocol + '//' + _uH.host; } catch (eBH) { _baseH = sitio; }
      var _ownerH = user_id;
      try { var _aseH = await supabase.from('asesores').select('admin_id').eq('auth_user_id', user_id).maybeSingle(); if (_aseH && _aseH.data && _aseH.data.admin_id) _ownerH = _aseH.data.admin_id; } catch (eOH) {}
      var _resH = await _scrapeAlojamientoCompleto(_baseH, sitio, _ownerH, true);
      if (modo === 'reset') { try { await supabase.from('hotel_unidades').delete().eq('user_id', _ownerH); } catch (eDel) {} }
      var _gH = await _guardarComplejoYUnidades(_ownerH, _resH, sitio, modo);
      var _totH = (_resH.complejos || []).reduce(function (a, c) { return a + ((Array.isArray(c.unidades) ? c.unidades.length : 0)); }, 0);
      return res.json({ ok: true, rubro: 'hotel_cabanas', modo: modo, total: _totH, creados: _gH.creados, actualizados: _gH.actualizados, errores: _gH.errores, estrategia: _resH.estrategia, deteccion: _resH.deteccion });
    }

    // modo reset: borrar el inventario actual del usuario antes de cargar
    if (modo === 'reset') {
      await supabase.from('properties').delete().eq('user_id', user_id);
    }

    // guardar cada propiedad (upsert por link para no duplicar en modo update)
    var creados = 0, actualizados = 0, errores = 0;
    for (var j = 0; j < props.length; j++) {
      var p = props[j];
      var fila = {
        user_id: user_id,
        title: p.titulo || 'Sin titulo',
        type: p.tipo || null,
        operation: p.operacion || null,
        zone: [p.ciudad, p.zona].filter(Boolean).join(' - ') || null,
        direccion: p.direccion || null,
        entre_calles: p.entre_calles || null,
        ciudad: p.ciudad || null,
        price: p.precio || null,
        description: p.descripcion || null,
        caracteristicas: p.caracteristicas || null,
        link: p.link || null,
        activa: true
      };
      try {
        if (modo === 'reset') {
          var insR = await supabase.from('properties').insert(fila);
          if (insR.error) errores++; else creados++;
        } else {
          // update: buscar por link; si existe actualiza, si no inserta
          var ex = await supabase.from('properties').select('id').eq('user_id', user_id).eq('link', p.link).maybeSingle();
          if (ex.data && ex.data.id) {
            var upR = await supabase.from('properties').update(fila).eq('id', ex.data.id);
            if (upR.error) errores++; else actualizados++;
          } else {
            var inR = await supabase.from('properties').insert(fila);
            if (inR.error) errores++; else creados++;
          }
        }
      } catch (e) { errores++; }
    }
    return res.json({ ok: true, modo: modo, total: props.length, creados: creados, actualizados: actualizados, errores: errores });
  } catch (e) { return res.status(500).json({ error: e && e.message }); }
});


// ============================================================================
// SCRAPER DE ALOJAMIENTO  —  POST /api/scrape/alojamiento   (rubro hotel_cabanas)
// ----------------------------------------------------------------------------
// MISMA arquitectura que el scraper inmobiliaria (cascada de estrategias, la IA
// SOLO como ULTIMO recurso) pero ADAPTADA a alojamiento temporal (hoteles,
// cabañas, aparts, complejos). Guarda en hotel_unidades (las MISMAS tablas que
// lee la IA de hotel). NO toca properties ni el scraper inmobiliaria.
// Cascada (corta en la primera que trae unidades):
//   (1) WordPress wp-json: post types de plugins de hotel (mphb_room_type, etc.)  -> gratis
//   (2) JSON-LD schema.org: Hotel / LodgingBusiness / HotelRoom / Accommodation   -> gratis
//   (3) IA (Haiku = MODELO_INTERNO) sobre el texto de la pagina -> JSON de unidades  [🔴 gasto]
// Campos por unidad: nombre, tipo, capacidad, precio/noche, servicios, descripcion.
// ============================================================================

// (1) wp-json de un post type de alojamiento. Devuelve [] si el type no existe.
async function _wpAlojamiento(base, tipo) {
  var out = [];
  try {
    var r = await fetchScrape(base + '/wp-json/wp/v2/' + tipo + '?per_page=50&_embed=1', { headers: { 'User-Agent': 'Mozilla/5.0 RaicesCRM' } });
    if (!r || !r.ok) return out;
    var data; try { data = JSON.parse(await r.text()); } catch (e) { return out; }
    if (!Array.isArray(data)) return out;
    for (var i = 0; i < data.length; i++) {
      var p = data[i] || {};
      var emb = p._embedded || {};
      var media = emb['wp:featuredmedia'] || [];
      out.push({
        nombre: (limpiarHTML(p.title && p.title.rendered) || 'Unidad'),
        tipo: '', capacidad: '', precio: null, moneda: 'ARS', dormitorios: '', banos: '', servicios: '',
        descripcion: (limpiarHTML(p.content && p.content.rendered) || limpiarHTML(p.excerpt && p.excerpt.rendered) || ''),
        link: p.link || (base + '/?p=' + p.id),
        foto: (media[0] && media[0].source_url) || null
      });
    }
  } catch (e) {}
  return out;
}

// (2) JSON-LD (schema.org). Busca nodos de alojamiento (Hotel/LodgingBusiness/Resort/HotelRoom/
// Accommodation/Apartment/House/Cabin) con nombre, y sus habitaciones anidadas. Gratis. [] si nada.
function _alojamientosJsonLd(htmls, base) {
  var out = [], vistos = {};
  // esUnidad = tipos que son una UNIDAD alquilable (habitacion/cabaña/depto). OJO: el nodo "Hotel"/"LodgingBusiness"/
  // "Resort" es el ESTABLECIMIENTO, NO una unidad -> NO se agrega (si no, se crearia 1 sola unidad = el hotel entero,
  // y la cascada cortaria sin llegar a la IA). De un Hotel solo tomamos sus habitaciones anidadas (containsPlace/etc).
  function esUnidad(t) { return /hotelroom|suite|accommodation|apartment|\bhouse\b|cabin|lodgingunit|\broom\b/i.test(String(t || '')); }
  function precioDe(node) {
    try {
      var of = node.offers || node.makesOffer; if (Array.isArray(of)) of = of[0];
      if (of) return of.price || (of.priceSpecification && (of.priceSpecification.price || of.priceSpecification.minPrice)) || null;
    } catch (e) {}
    return null;
  }
  function push(node) {
    if (!node || typeof node !== 'object') return;
    var tipo = node['@type']; if (Array.isArray(tipo)) tipo = tipo.join(' ');
    var nombre = (typeof node.name === 'string') ? node.name.trim() : '';
    if (esUnidad(tipo) && nombre && !vistos[nombre.toLowerCase()]) {
      vistos[nombre.toLowerCase()] = 1;
      var cap = ''; try { cap = (node.occupancy && (node.occupancy.maxValue || node.occupancy.value)) || node.numberOfBeds || ''; } catch (e) {}
      out.push({ nombre: nombre, tipo: '', capacidad: cap || '', precio: precioDe(node) || '', moneda: 'ARS', dormitorios: '', banos: '', servicios: '', descripcion: (typeof node.description === 'string' ? node.description.slice(0, 500) : ''), link: node.url || base });
    }
    var kids = node.containsPlace || node.hasPart || node.makesOffer;
    if (Array.isArray(kids)) for (var i = 0; i < kids.length; i++) push(kids[i] && (kids[i].itemOffered || kids[i]));
  }
  for (var h = 0; h < htmls.length; h++) {
    var blocks = (htmls[h] || '').match(/<script[^>]+application\/ld\+json[^>]*>([\s\S]*?)<\/script>/gi) || [];
    for (var b = 0; b < blocks.length; b++) {
      var m = blocks[b].match(/>([\s\S]*?)<\/script>/i); if (!m) continue;
      var data; try { data = JSON.parse(m[1].trim()); } catch (e) { continue; }
      var nodes = Array.isArray(data) ? data : (data['@graph'] && Array.isArray(data['@graph']) ? data['@graph'] : [data]);
      for (var n = 0; n < nodes.length; n++) push(nodes[n]);
    }
  }
  return out;
}

// (3) IA (Haiku) — ULTIMO recurso. Manda el texto limpio de la pagina y pide TODAS las unidades
// de alojamiento como JSON. Cap de HTML + registro de tokens (control de costo). [] si no hay key.
async function _alojamientosIA(html, base, ownerId) {
  try {
    if (!process.env.ANTHROPIC_KEY) { console.log('[scraper alojamiento] sin ANTHROPIC_KEY, se omite IA'); return []; }
    var limpio = _htmlParaIA(html, 100000);
    if (limpio.length < 150) return [];
    // Extraer URLs de imagenes del HTML crudo (antes de limpiar) para que la IA pueda asociar fotos a cada unidad.
    var imgs = [], _seenImg = {};
    try {
      var _im, _reImg = /<img[^>]+src\s*=\s*["']([^"']+)["']/gi;
      while ((_im = _reImg.exec(html)) !== null && imgs.length < 40) {
        var _iu; try { _iu = new URL(_im[1], base + '/').toString(); } catch (e) { continue; }
        if (!/^https?:/i.test(_iu) || /\.(svg|gif)(\?|$)/i.test(_iu) || /logo|icon|sprite|favicon|placeholder|blank|pixel/i.test(_iu)) continue;
        if (_seenImg[_iu]) continue; _seenImg[_iu] = 1; imgs.push(_iu);
      }
    } catch (eImg) {}
    var sys = 'Sos un extractor de ALOJAMIENTOS turisticos (hoteles, cabañas, aparts, complejos, posadas). Te paso el TEXTO de una pagina web de un alojamiento y una LISTA DE IMAGENES. ' +
      'Devolve EXCLUSIVAMENTE un JSON array (sin markdown, sin texto alrededor) con TODAS las unidades que ofrece para alquilar por noche (habitaciones, cabañas, domos, departamentos, suites, bungalows). ' +
      'Cada item: {"nombre","tipo","capacidad","precio","moneda","dormitorios","banos","servicios","descripcion","imagenes"}. ' +
      'tipo: uno de Habitación|Suite|Cabaña|Domo|Departamento|Monoambiente|Loft|Bungalow|Casa|Glamping (elegi el mas parecido). capacidad: cantidad de personas (numero). precio: tarifa por NOCHE (solo numero, sin simbolos ni miles). moneda: ARS o USD. ' +
      'servicios: lista corta separada por comas (wifi, pileta, parrilla, cochera, aire, desayuno, etc.). ' +
      'imagenes: array con URLs de fotos de ESA unidad, copiadas TEXTUAL de la LISTA DE IMAGENES; si no podes asociar, deja []. ' +
      'Si un dato no aparece, deja "". NO inventes unidades ni URLs. Si la pagina no ofrece alojamiento, devolve [].';
    var _userMsg = 'TEXTO DE LA PAGINA:\n' + limpio;
    if (imgs.length) _userMsg += '\n\nLISTA DE IMAGENES (URLs; elegí de aca para el campo "imagenes"):\n' + imgs.map(function (u, i) { return (i + 1) + '. ' + u; }).join('\n');
    var r = await anthropic.messages.create({
      model: MODELO_CLIENTE, // Sonnet: mejor extraccion de alojamiento ("todo, no parte"). El costo corre por cuenta del cliente.
      max_tokens: 4000,
      system: sys,
      messages: [{ role: 'user', content: _userMsg }]
    });
    try { if (ownerId && r && r.usage) await registrarUsoTokens(ownerId, r.usage, 'scraper_alojamiento', PRECIO_IA); } catch (eU) {}
    var txt = (r && r.content && r.content[0] && r.content[0].text) ? r.content[0].text : '';
    var arr = _parseJsonArrayDefensivo(txt);
    if (!Array.isArray(arr)) return [];
    var out = [];
    for (var i = 0; i < arr.length; i++) {
      var p = arr[i] || {};
      var nombre = String(p.nombre || '').trim();
      if (!nombre) continue;
      var _imgsU = Array.isArray(p.imagenes) ? p.imagenes.filter(function (u) { return typeof u === 'string' && /^https?:/i.test(u); }).slice(0, 12) : [];
      out.push({ nombre: nombre, tipo: p.tipo || '', capacidad: p.capacidad || '', precio: (p.precio === 0 ? 0 : (p.precio || '')), moneda: (p.moneda === 'USD' ? 'USD' : 'ARS'), dormitorios: p.dormitorios || '', banos: p.banos || '', servicios: p.servicios || '', descripcion: p.descripcion || '', imagenes: _imgsU, link: base });
    }
    return out;
  } catch (e) { console.error('[scraper alojamiento] _alojamientosIA:', e && e.message); return []; }
}

// Orquesta la cascada de alojamiento. Devuelve un array de unidades + arr._estrategia con la via usada.
// permitirIA (default true): si es false NO se usa la IA (solo estrategias gratis). El cron de
// auto-update lo llama con false -> costo de IA = 0 en el camino automatico.
async function obtenerAlojamientosUniversal(base, sitio, ownerId, permitirIA) {
  if (permitirIA === undefined) permitirIA = true;
  // (1) wp-json de plugins de hotel conocidos
  var WP_TYPES = ['mphb_room_type', 'accommodation', 'hotel_room', 'room', 'rooms', 'lodging', 'cabin', 'cabana'];
  for (var t = 0; t < WP_TYPES.length; t++) {
    var wp = await _wpAlojamiento(base, WP_TYPES[t]);
    if (wp.length) { wp._estrategia = 'wp-json:' + WP_TYPES[t]; return wp; }
  }
  // Descargar HTML de la home + rutas tipicas de alojamiento (para JSON-LD e IA)
  var rutas = ['/', '/habitaciones', '/habitaciones/', '/cabanas', '/cabanas/', '/alojamiento', '/alojamientos', '/unidades', '/rooms', '/accommodation', '/tarifas', '/reservas', '/precios'];
  var homeHtml = '', htmls = [];
  for (var ri = 0; ri < rutas.length; ri++) {
    try {
      var rr = await fetchScrape(base + rutas[ri], { headers: { 'User-Agent': 'Mozilla/5.0 RaicesCRM' } });
      if (rr && rr.ok) { var h = await rr.text(); if (ri === 0) homeHtml = h; if (h && h.length > 500) htmls.push(h); }
    } catch (e) {}
  }
  if (!htmls.length && homeHtml) htmls.push(homeHtml);
  // DESCUBRIR links internos de la home que parezcan paginas de unidades (habitaciones/domos/cabañas/tarifas).
  // Cubre sitios estaticos u otras rutas que las fijas no aciertan (ej: /habitaciones.html, /domos.html). Cap 8.
  try {
    if (homeHtml) {
      var hrefs = (homeHtml.match(/href\s*=\s*["']([^"']+)["']/gi) || []).map(function (m) { return m.replace(/^href\s*=\s*["']|["']$/gi, ''); });
      var vistosL = {}, extra = [];
      for (var li = 0; li < hrefs.length && extra.length < 8; li++) {
        var hf = hrefs[li];
        if (!hf || /^(#|mailto:|tel:|javascript:)/i.test(hf)) continue;
        if (!/habitaci|domo|caba[nñ]|suite|bungalow|apart|aloj|tarifa|\broom|accommodation|unidad|precio/i.test(hf)) continue;
        var abs; try { abs = new URL(hf, base + '/').toString(); } catch (e) { continue; }
        if (abs.indexOf(base) !== 0) continue; // solo el dominio propio
        if (vistosL[abs]) continue; vistosL[abs] = 1;
        extra.push(abs);
      }
      for (var ei = 0; ei < extra.length; ei++) {
        try { var re = await fetchScrape(extra[ei], { headers: { 'User-Agent': 'Mozilla/5.0 RaicesCRM' } }); if (re && re.ok) { var he = await re.text(); if (he && he.length > 500) htmls.push(he); } } catch (e) {}
      }
    }
  } catch (e) {}
  // (2) JSON-LD (gratis)
  try { var ld = _alojamientosJsonLd(htmls, base); if (ld.length) { ld._estrategia = 'json-ld'; return ld; } } catch (e) {}
  // (3) IA (Haiku) — ULTIMO recurso y SOLO si permitirIA (el cron de auto-update lo pasa en false -> costo 0).
  if (permitirIA) {
    try {
      // Le pasamos TODAS las paginas relevantes concatenadas (paginas de unidades primero, home al final).
      // _alojamientosIA limpia y recorta; asi Sonnet ve /habitaciones + /domos + home, no una sola pagina.
      var htmlIA = htmls.slice().reverse().join('\n\n\n');
      var ia = await _alojamientosIA(htmlIA, base, ownerId);
      if (ia.length) {
        // Cobro al cliente: descuenta de SUS mensajes (igual que el scraper de inventario). Gateado por suscripcion.
        try { if (SUBSCRIPTIONS_ENABLED && ownerId && await cobrarTodoV2Activo(ownerId)) await registrarUsoIA(ownerId, 3); } catch (eCob) {}
        ia._estrategia = 'ia'; return ia;
      }
    } catch (e) {}
  }
  return [];
}

// Upsert de unidades de alojamiento en hotel_unidades (por title -> no duplica). Compartido por el
// endpoint manual y el cron de auto-update. Devuelve {creados, actualizados, errores}.
async function _guardarUnidadesAlojamiento(ownerId, unidades, modo, sitio) {
  if (modo === 'reset') { try { await supabase.from('hotel_unidades').delete().eq('user_id', ownerId); } catch (eDel) {} }
  var creados = 0, actualizados = 0, errores = 0;
  for (var i = 0; i < unidades.length; i++) {
    var un = unidades[i] || {};
    var _imgsUn = Array.isArray(un.imagenes) ? un.imagenes.filter(function (u) { return typeof u === 'string' && /^https?:/i.test(u); }).map(function (u) { return { url: u, categoria: '' }; }) : [];
    var fila = {
      user_id: ownerId,
      title: String(un.nombre || 'Unidad').slice(0, 200),
      type: un.tipo || null,
      capacidad: (parseInt(un.capacidad, 10) || null),
      descripcion: un.descripcion || null,
      precio_base: _sInvN(un.precio),
      moneda: (un.moneda === 'USD' ? 'USD' : 'ARS'),
      images: _imgsUn,
      activa: true,
      atributos: { origen_url: un.link || sitio, capacidad: un.capacidad || null, servicios: un.servicios || null, dormitorios: un.dormitorios || null, banos: un.banos || null, importado_por: 'scraper_alojamiento' }
    };
    try {
      var ex = await supabase.from('hotel_unidades').select('id, precio_base, images').eq('user_id', ownerId).eq('title', fila.title).maybeSingle();
      if (ex.data && ex.data.id) {
        // Re-scrape NO pisa lo editado a mano: preserva precio y fotos si ya estaban cargados.
        var upd = Object.assign({}, fila);
        if (ex.data.precio_base !== null && ex.data.precio_base !== undefined) delete upd.precio_base;
        if (Array.isArray(ex.data.images) && ex.data.images.length) delete upd.images;
        var up = await supabase.from('hotel_unidades').update(upd).eq('id', ex.data.id); if (up.error) errores++; else actualizados++;
      } else {
        var ins = await supabase.from('hotel_unidades').insert(fila); if (ins.error) errores++; else creados++;
      }
    } catch (eU) { errores++; }
  }
  return { creados: creados, actualizados: actualizados, errores: errores };
}

// Corre el scraper de alojamiento para una cuenta (cfg de scraping_config). Lo usan el cron de
// auto-update (permitirIA=false -> 0 gasto) y correr-ahora (permitirIA=true, lo dispara el dueño).
async function correrScrapingAlojamiento(cfg, permitirIA) {
  try {
    var sitio = (cfg && cfg.fuente_url ? String(cfg.fuente_url) : '').trim();
    if (!sitio) return { ok: false, motivo: 'sin url' };
    if (!sitio.startsWith('http')) sitio = 'https://' + sitio;
    var base; try { var u = new URL(sitio); base = u.protocol + '//' + u.host; } catch (e) { return { ok: false, motivo: 'url invalida' }; }
    // UNIFICADO: mismo camino que el boton Importar (complejo + habitaciones + fotos + tarifas), NO el path plano viejo.
    var res1 = await _scrapeAlojamientoCompleto(base, sitio, cfg.user_id, !!permitirIA);
    var totalUn = (res1.complejos || []).reduce(function (a, c) { return a + ((Array.isArray(c.unidades) ? c.unidades.length : 0)); }, 0);
    if (!totalUn && !(res1.complejos && res1.complejos[0] && res1.complejos[0].nombre)) return { ok: false, motivo: 'sin unidades', estrategia: res1.estrategia };
    var g = await _guardarComplejoYUnidades(cfg.user_id, res1, sitio, 'update');
    return { ok: true, estrategia: res1.estrategia, creados: g.creados, actualizados: g.actualizados, errores: g.errores };
  } catch (e) { return { ok: false, motivo: e && e.message }; }
}

// ============================================================================
// SCRAPER DE ALOJAMIENTO — VERSION COMPLETA (complejo + habitaciones + fotos).
// AISLADO: SOLO se usa desde /api/scrape/alojamiento* (rubro hotel_cabanas).
// NO toca inmobiliaria ni desarrolladora ni el boot del backend.
// Paso 1 = estatico (esta seccion). Paso 3 = profundo/headless (gateado, mas abajo).
// ============================================================================

// Baja home + rutas tipicas + links internos de unidades. Devuelve {homeHtml, htmls}.
async function _fetchPaginasAlojamiento(base) {
  var rutas = ['/', '/habitaciones', '/habitaciones/', '/cabanas', '/cabanas/', '/alojamiento', '/alojamientos', '/unidades', '/rooms', '/accommodation', '/tarifas', '/reservas', '/precios', '/domos'];
  var homeHtml = '', htmls = [];
  for (var ri = 0; ri < rutas.length; ri++) {
    try {
      var rr = await fetchScrape(base + rutas[ri], { headers: { 'User-Agent': 'Mozilla/5.0 RaicesCRM' } });
      if (rr && rr.ok) { var h = await rr.text(); if (ri === 0) homeHtml = h; if (h && h.length > 500) htmls.push(h); }
    } catch (e) {}
  }
  if (!htmls.length && homeHtml) htmls.push(homeHtml);
  // descubrir links internos de unidades (cubre .html u otras rutas)
  try {
    if (homeHtml) {
      var hrefs = (homeHtml.match(/href\s*=\s*["']([^"']+)["']/gi) || []).map(function (m) { return m.replace(/^href\s*=\s*["']|["']$/gi, ''); });
      var vistosL = {}, extra = [];
      for (var li = 0; li < hrefs.length && extra.length < 8; li++) {
        var hf = hrefs[li];
        if (!hf || /^(#|mailto:|tel:|javascript:)/i.test(hf)) continue;
        if (!/habitaci|domo|caba[nñ]|suite|bungalow|apart|aloj|tarifa|\broom|accommodation|unidad|precio/i.test(hf)) continue;
        var abs; try { abs = new URL(hf, base + '/').toString(); } catch (e) { continue; }
        if (abs.indexOf(base) !== 0) continue;
        if (vistosL[abs]) continue; vistosL[abs] = 1; extra.push(abs);
      }
      for (var ei = 0; ei < extra.length; ei++) {
        try { var re = await fetchScrape(extra[ei], { headers: { 'User-Agent': 'Mozilla/5.0 RaicesCRM' } }); if (re && re.ok) { var he = await re.text(); if (he && he.length > 500) htmls.push(he); } } catch (e) {}
      }
    }
  } catch (e) {}
  return { homeHtml: homeHtml, htmls: htmls };
}

// Extrae fotos y las agrupa: por habitacion (patron pxsol .../P<id>/photos) y del complejo (company/library).
// Fallback generico: junta todas las <img> http(s) que no sean iconos. {porRoom:{P123:[urls]}, complejo:[urls], todas:[urls]}.
function _extraerFotosAlojamiento(htmls, base) {
  var porRoom = {}, complejo = [], todas = [], seen = {};
  for (var h = 0; h < htmls.length; h++) {
    var html = htmls[h] || '';
    var m, re = /<img[^>]+src\s*=\s*["']([^"']+)["']/gi;
    while ((m = re.exec(html)) !== null) {
      var abs; try { abs = new URL(m[1], base + '/').toString(); } catch (e) { continue; }
      if (!/^https?:/i.test(abs)) continue;
      if (/\.(svg|gif)(\?|$)/i.test(abs) || /logo|icon|sprite|favicon|placeholder|blank|pixel|bnd_/i.test(abs)) continue;
      if (/rs:fill:(?:16|24|32|48|64):/i.test(abs)) continue; // pxsol: miniatura/icono
      if (seen[abs]) continue; seen[abs] = 1; todas.push(abs);
      var dec = ''; try { dec = decodeURIComponent(abs); } catch (e) { dec = abs; }
      var pm = dec.match(/\/(P\d+)\/photos/i);
      if (pm) { (porRoom[pm[1]] = porRoom[pm[1]] || []).push(abs); }
      else if (/\/company\/library|\/company\//i.test(dec)) { complejo.push(abs); }
    }
  }
  return { porRoom: porRoom, complejo: complejo, todas: todas };
}

// Detecta plataforma + cuantas habitaciones/galerias hay -> alimenta el Paso 2 (aviso de scrape profundo).
function _detectarAlojamiento(htmls, fotos) {
  var joined = htmls.join(' ');
  var esPxsol = /pxsol\.com/i.test(joined);
  var bookRooms = Array.from(new Set((joined.match(/bookRoom_(\d+)/g) || [])));
  var roomsWidget = bookRooms.length;
  var galeriasPorRoom = Object.keys(fotos.porRoom || {}).length;
  var faltanGalerias = Math.max(0, roomsWidget - galeriasPorRoom);
  var preciosPorJS = esPxsol; // en pxsol los precios los calcula el widget con fechas (no estan en el HTML)
  var hayMas = (faltanGalerias > 0) || preciosPorJS;
  var costoDeepMsgs = esPxsol ? Math.max(3, roomsWidget * 2) : 3;
  return {
    plataforma: esPxsol ? 'pxsol' : 'generico',
    habitacionesWidget: roomsWidget,
    galeriasEncontradas: galeriasPorRoom,
    faltanGalerias: faltanGalerias,
    preciosPorJS: preciosPorJS,
    hayMas: hayMas,
    deepDisponible: true,
    costoDeepMsgs: costoDeepMsgs,
    resumen: esPxsol
      ? ('Este sitio usa PXSOL. Encontre ' + galeriasPorRoom + ' galeria(s) de ' + roomsWidget + ' habitacion(es); las tarifas y el resto de las fotos las carga por JavaScript. Un scrape profundo las trae (gasta ~' + costoDeepMsgs + ' mensajes IA).')
      : (faltanGalerias > 0 ? 'Puede haber mas fotos o tarifas cargadas por JavaScript.' : '')
  };
}

// ============================================================================
// F0 — CONTRATO DE DATOS UNICO de una UNIDAD de hotel. TODO guardado (scraper, form,
// editor, CSV) pasa por normalizarUnidadHotel() -> la estructura es SIEMPRE la misma y
// la IA lee lo mismo venga de donde venga. amenities se guarda SIEMPRE como OBJETO de
// flags {clave:{on:true}} (igual que _FormHotel); lo que no matchea a un flag va a
// servicios_texto. Claves = las de _FormHotel AMENITIES_UNIDAD.
// ============================================================================
var _AMEN_DICT = [
  ['calef_lena', /le[ñn]a|salamandra|hogar a le/i],
  ['calef_radiadores', /radiador/i],
  ['calef_fancoil', /fan.?coil/i],
  ['ac', /aire\s*acond|climatiz|\bsplit\b|\ba\/?c\b/i],
  ['cocina', /cocina|kitchenette|cocinita/i],
  ['horno', /\bhorno\b/i],
  ['hidromasaje_int', /hidromasaje\s*(?:interior|int)\b|jacuzzi\s*interior/i],
  ['hidromasaje_ext', /hidromasaje|jacuzzi/i],
  ['parrilla', /parrilla|quincho|asador/i],
  ['deck', /\bdeck\b|terraza|balc[oó]n/i],
  ['wifi', /wi-?fi|internet/i],
  ['pileta', /pileta|piscina|alberca/i],
  ['tv', /smart\s*tv|televis|\btv\b|cable\b/i],
  ['cochera', /cochera|gara[gj]e|estacionamiento|parking/i]
];
// Etiquetas legibles de cada amenity (para el prompt de la IA).
var _AMEN_LABEL = { calef_lena: 'calefaccion a leña', calef_radiadores: 'radiadores', calef_fancoil: 'fan coil', ac: 'aire acondicionado', cocina: 'cocina', horno: 'horno', hidromasaje_int: 'hidromasaje interior', hidromasaje_ext: 'hidromasaje exterior', parrilla: 'parrilla', deck: 'deck', wifi: 'wifi', pileta: 'pileta', tv: 'TV', cochera: 'cochera' };

// Texto de servicios -> {flags:{clave:{on:true}}, resto:'lo que no matcheo'}.
function _amenitiesDeTexto(texto) {
  var flags = {}, resto = [];
  var items = String(texto || '').split(/[,;|\n·]+/).map(function (s) { return s.trim(); }).filter(Boolean);
  for (var i = 0; i < items.length; i++) {
    var it = items[i], matched = false;
    for (var d = 0; d < _AMEN_DICT.length; d++) { if (_AMEN_DICT[d][1].test(it)) { flags[_AMEN_DICT[d][0]] = { on: true }; matched = true; break; } }
    if (!matched) resto.push(it);
  }
  return { flags: flags, resto: resto.join(', ') };
}

// Normaliza los ATRIBUTOS de una unidad (venga del scraper, form, editor o CSV) al shape canonico.
// prev = atributos existentes en la DB (para no perder amenities/tarifas/textos cargados a mano).
function normalizarUnidadHotel(un, prev) {
  un = un || {}; prev = (prev && typeof prev === 'object') ? prev : {};
  var amen = Object.assign({}, (prev.amenities && typeof prev.amenities === 'object' && !Array.isArray(prev.amenities)) ? prev.amenities : {});
  if (un.amenities && typeof un.amenities === 'object' && !Array.isArray(un.amenities)) amen = Object.assign(amen, un.amenities);
  var servTxt = (typeof un.servicios === 'string') ? un.servicios : (prev.servicios_texto || (typeof prev.servicios === 'string' ? prev.servicios : ''));
  if (servTxt) { var m = _amenitiesDeTexto(servTxt); amen = Object.assign({}, m.flags, amen); servTxt = m.resto; }
  var _int = function (v, p) { var n = parseInt(v, 10); return (!isNaN(n) && n > 0) ? n : (p || null); };
  var _numP = function (v, p) { var n = _sInvN(v); return (n != null) ? n : (p != null ? p : null); };
  return {
    camas: _int(un.camas, prev.camas), dormitorios: _int(un.dormitorios, prev.dormitorios),
    banos: _int(un.banos, prev.banos), m2: _numP(un.m2, prev.m2),
    vista: (un.vista || prev.vista || '') || null, categoria_comercial: (un.categoria_comercial || prev.categoria_comercial || '') || null,
    amenities: amen,
    regimenes: Array.isArray(un.regimenes) ? un.regimenes : (Array.isArray(prev.regimenes) ? prev.regimenes : []),
    extras: Array.isArray(un.extras) ? un.extras : (Array.isArray(prev.extras) ? prev.extras : []),
    servicios_texto: servTxt || prev.servicios_texto || '',
    franjas: un.franjas || prev.franjas || {}, politicas: un.politicas || prev.politicas || {},
    ical_import_urls: Array.isArray(prev.ical_import_urls) ? prev.ical_import_urls : [],
    origen_url: un.origen_url || prev.origen_url || '', importado_por: un.importado_por || prev.importado_por || 'scraper_alojamiento'
  };
}

// IA (Sonnet): devuelve {complejos:[{...unidades:[...]}]} — soporta CADENA (varios complejos en una pagina).
async function _alojamientoIAcompleto(html, base, ownerId) {
  try {
    if (!process.env.ANTHROPIC_KEY) return { complejo: {}, unidades: [] };
    var limpio = _htmlParaIA(html, 140000);
    if (limpio.length < 150) return { complejo: {}, unidades: [] };
    // Lista de imagenes del HTML: para que la IA asigne fotos por unidad en sitios que NO son PXSOL.
    var imgs = [], _seenImg = {};
    try {
      var _im, _reImg = /<img[^>]+src\s*=\s*["']([^"']+)["']/gi;
      while ((_im = _reImg.exec(html)) !== null && imgs.length < 60) {
        var _iu; try { _iu = new URL(_im[1], base + '/').toString(); } catch (e) { continue; }
        if (!/^https?:/i.test(_iu) || /\.(svg|gif)(\?|$)/i.test(_iu) || /logo|icon|sprite|favicon|placeholder|blank|pixel|bnd_/i.test(_iu) || /rs:fill:(?:16|24|32|48|64):/i.test(_iu)) continue;
        if (_seenImg[_iu]) continue; _seenImg[_iu] = 1; imgs.push(_iu);
      }
    } catch (eImg) {}
    var sys = 'Sos un extractor EXHAUSTIVO de ALOJAMIENTOS turisticos (hoteles, cabañas, complejos, incluso CADENAS con varios hoteles). Te paso el TEXTO de las paginas y una LISTA DE IMAGENES. ' +
      'Devolve EXCLUSIVAMENTE un JSON objeto (sin markdown, sin texto alrededor): {"complejos":[{"nombre","subtipo","descripcion","direccion","amenities","servicios","beneficios","politicas","unidades":[{"nombre","tipo","capacidad","dormitorios","banos","m2","precio","moneda","servicios","descripcion","imagenes","tarifas"}]}]}. ' +
      'complejos = TODOS los hoteles/complejos que aparezcan (si es una CADENA con varios, devolve varios; si es uno solo, un array de 1). Cada complejo: nombre, subtipo (hotel|apart|cabañas|complejo|hosteria|posada), descripcion general COMPLETA, direccion/ubicacion, amenities (servicios generales del complejo, coma-separados), servicios adicionales (coma-separado), beneficios/promos (coma-separado), politicas (check-in, check-out, cancelacion, seña, formas de pago; texto libre corto). ' +
      'unidades (DENTRO de cada complejo) = TODAS las habitaciones/cabañas/tipos. NO omitas ninguna. Copia la descripcion COMPLETA y TODOS los servicios de cada una. ' +
      'tipo: uno de Habitación|Suite|Cabaña|Domo|Departamento|Monoambiente|Loft|Bungalow|Casa|Glamping. capacidad/dormitorios/banos = numeros; m2 = numero o "". precio = tarifa por noche (solo numero) o "". moneda ARS o USD. servicios = coma-separados. imagenes = URLs de fotos de ESA unidad copiadas TEXTUAL de la LISTA; si no podes asociar, []. ' +
      'tarifas = si el sitio publica precios POR TEMPORADA, array [{"temporada","desde","hasta","precio","moneda","min_noches"}] (fechas ISO YYYY-MM-DD o ""); si no hay temporadas, []. ' +
      'Si un dato no aparece deja "". NO inventes datos ni URLs. Devolve el objeto aunque no haya unidades.';
    var _userMsg = 'TEXTO:\n' + limpio;
    if (imgs.length) _userMsg += '\n\nLISTA DE IMAGENES (URLs, elegi de aca para "imagenes"):\n' + imgs.map(function (u, i) { return (i + 1) + '. ' + u; }).join('\n');
    var r = await anthropic.messages.create({ model: MODELO_CLIENTE, max_tokens: 8000, system: sys, messages: [{ role: 'user', content: _userMsg }] });
    try { if (ownerId && r && r.usage) await registrarUsoTokens(ownerId, r.usage, 'scraper_alojamiento', PRECIO_IA); } catch (eU) {}
    var txt = (r && r.content && r.content[0] && r.content[0].text) ? r.content[0].text : '';
    var o = _parseJsonObjetoDefensivo(txt) || {};
    // Soporta el shape nuevo {complejos:[...]} y el viejo {complejo, unidades} (retro-compat).
    var complejos = Array.isArray(o.complejos) ? o.complejos : (o.complejo ? [Object.assign({}, o.complejo, { unidades: Array.isArray(o.unidades) ? o.unidades : [] })] : []);
    for (var _c = 0; _c < complejos.length; _c++) {
      var _cp = complejos[_c] || {}; var _uds = Array.isArray(_cp.unidades) ? _cp.unidades : [];
      for (var _k = 0; _k < _uds.length; _k++) {
        var _pu = _uds[_k] || {};
        _pu.imagenes = Array.isArray(_pu.imagenes) ? _pu.imagenes.filter(function (u) { return typeof u === 'string' && /^https?:/i.test(u); }).slice(0, 40) : [];
        _pu.tarifas = Array.isArray(_pu.tarifas) ? _pu.tarifas : [];
      }
      _cp.unidades = _uds;
    }
    return { complejos: complejos };
  } catch (e) { console.error('[scraper alojamiento completo] IA:', e && e.message); return { complejo: {}, unidades: [] }; }
}

// Orquesta el Paso 1 (estatico). Devuelve {complejos:[...], deteccion, estrategia}. Asigna fotos por unidad.
async function _scrapeAlojamientoCompleto(base, sitio, ownerId, permitirIA) {
  var pag = await _fetchPaginasAlojamiento(base);
  var fotos = _extraerFotosAlojamiento(pag.htmls, base);
  var deteccion = _detectarAlojamiento(pag.htmls, fotos);
  var complejos = [], estrategia = 'estatico';
  if (permitirIA) {
    var htmlIA = pag.htmls.slice().reverse().join('\n\n\n');
    var data = await _alojamientoIAcompleto(htmlIA, base, ownerId);
    complejos = Array.isArray(data.complejos) ? data.complejos : [];
    var _tot = complejos.reduce(function (a, c) { return a + ((Array.isArray(c.unidades) ? c.unidades.length : 0)); }, 0);
    if (complejos.length || _tot) {
      estrategia = 'ia';
      try { if (SUBSCRIPTIONS_ENABLED && ownerId && await cobrarTodoV2Activo(ownerId)) await registrarUsoIA(ownerId, 3); } catch (eCob) {}
    }
  }
  if (!complejos.length) complejos = [{ nombre: '', unidades: [] }];
  // Fotos: grupos pxsol P<id> repartidos a las unidades EN ORDEN GLOBAL (complejo -> unidad).
  var grupos = Object.keys(fotos.porRoom).map(function (k) { return fotos.porRoom[k]; });
  var _gi = 0;
  for (var c = 0; c < complejos.length; c++) {
    var cp = complejos[c]; var uds = Array.isArray(cp.unidades) ? cp.unidades : [];
    for (var i = 0; i < uds.length; i++) {
      var _g = grupos[_gi++];
      if (_g && _g.length) uds[i].imagenes = _g.slice(0, 40);
      else uds[i].imagenes = Array.isArray(uds[i].imagenes) ? uds[i].imagenes.slice(0, 40) : [];
    }
    // fotos generales del complejo (company/library; con 1 solo complejo, las primeras genericas).
    cp.images = (fotos.complejo.length ? fotos.complejo : (complejos.length === 1 ? fotos.todas.slice(0, 8) : [])).slice(0, 20);
  }
  return { complejos: complejos, deteccion: deteccion, estrategia: estrategia };
}

// Upsert de UNA unidad de hotel al shape canonico (normalizarUnidadHotel) + tarifas. Devuelve 'creado'|'actualizado'|'error'.
async function _upsertUnidadHotel(ownerId, complejoId, un, sitio) {
  try {
    var title = String(un.nombre || 'Unidad').slice(0, 200);
    var imgs = Array.isArray(un.imagenes) ? un.imagenes.filter(function (u) { return typeof u === 'string' && /^https?:/i.test(u); }).map(function (u) { return { url: u, categoria: '' }; }) : [];
    var ex = await supabase.from('hotel_unidades').select('id, precio_base, images, descripcion, type, capacidad, complejo_id, atributos').eq('user_id', ownerId).eq('title', title).maybeSingle();
    var prevAtr = (ex.data && ex.data.atributos && typeof ex.data.atributos === 'object') ? ex.data.atributos : {};
    var atrNorm = normalizarUnidadHotel({ camas: un.camas, dormitorios: un.dormitorios, banos: un.banos, m2: un.m2, vista: un.vista, servicios: un.servicios, origen_url: sitio, importado_por: 'scraper_alojamiento' }, prevAtr);
    var fila = {
      user_id: ownerId, complejo_id: complejoId, title: title,
      type: un.tipo || null, capacidad: (parseInt(un.capacidad, 10) || null),
      descripcion: un.descripcion || null, precio_base: _sInvN(un.precio),
      moneda: (un.moneda === 'USD' ? 'USD' : 'ARS'), images: imgs, activa: true, atributos: atrNorm
    };
    var unidadId = null, resultado;
    if (ex.data && ex.data.id) {
      unidadId = ex.data.id;
      var upd = Object.assign({}, fila);
      if (ex.data.precio_base !== null && ex.data.precio_base !== undefined) delete upd.precio_base;
      if (Array.isArray(ex.data.images) && ex.data.images.length) delete upd.images;
      if (String(ex.data.descripcion || '').length > String(fila.descripcion || '').length) delete upd.descripcion;
      if (ex.data.capacidad && !fila.capacidad) delete upd.capacidad;
      if (ex.data.type && !fila.type) delete upd.type;
      if (!complejoId && ex.data.complejo_id) delete upd.complejo_id; // no desvincular si ya pertenece a un complejo
      var up = await supabase.from('hotel_unidades').update(upd).eq('id', unidadId);
      resultado = up.error ? 'error' : 'actualizado';
    } else {
      var ins = await supabase.from('hotel_unidades').insert(fila).select('id').maybeSingle();
      unidadId = ins.data && ins.data.id; resultado = ins.error ? 'error' : 'creado';
    }
    // Tarifas por temporada -> hotel_tarifa. NO pisa las manuales: inserta solo temporadas/fechas que no existan.
    if (unidadId && Array.isArray(un.tarifas) && un.tarifas.length) {
      try {
        var exTar = await supabase.from('hotel_tarifa').select('temporada, fecha_desde').eq('user_id', ownerId).eq('unidad_id', unidadId);
        var vistas = {}; (exTar.data || []).forEach(function (t) { vistas[(t.temporada || '') + '|' + (t.fecha_desde || '')] = 1; });
        for (var t = 0; t < un.tarifas.length; t++) {
          var ta = un.tarifas[t] || {}; var pr = _sInvN(ta.precio); if (pr == null) continue;
          var key = (ta.temporada || '') + '|' + (ta.desde || ''); if (vistas[key]) continue;
          await supabase.from('hotel_tarifa').insert({ user_id: ownerId, unidad_id: unidadId, temporada: ta.temporada || 'Temporada', fecha_desde: ta.desde || null, fecha_hasta: ta.hasta || null, precio_noche: pr, moneda: (ta.moneda === 'USD' ? 'USD' : 'ARS'), min_noches: (parseInt(ta.min_noches, 10) || null) });
          vistas[key] = 1;
        }
      } catch (eTar) {}
    }
    return resultado;
  } catch (e) { return 'error'; }
}

// Guarda un ARRAY de complejos (cadena) + sus habitaciones. Preserva ediciones manuales, no degrada. Todo pasa por el contrato canonico.
async function _guardarComplejoYUnidades(ownerId, data, sitio, modo) {
  var creados = 0, actualizados = 0, errores = 0, complejosGuardados = [];
  var complejos = Array.isArray(data.complejos) ? data.complejos : (data.complejo ? [Object.assign({}, data.complejo, { unidades: data.unidades || [] })] : []);
  for (var c = 0; c < complejos.length; c++) {
    var comp = complejos[c] || {}; var complejoId = null;
    var nombreComp = String(comp.nombre || 'Mi alojamiento').slice(0, 200);
    try {
      var cEx = await supabase.from('hotel_complejos').select('id, atributos').eq('user_id', ownerId).eq('nombre', nombreComp).maybeSingle();
      var atrComp = { descripcion: comp.descripcion || '', direccion: comp.direccion || '', amenities: comp.amenities || '', servicios: comp.servicios || '', beneficios: comp.beneficios || '', images: Array.isArray(comp.images) ? comp.images.map(function (u) { return { url: u }; }) : [], origen_url: sitio, importado_por: 'scraper_alojamiento' };
      if (comp.subtipo) atrComp.subtipo = comp.subtipo;
      if (comp.politicas && typeof comp.politicas === 'object') atrComp.politicas = comp.politicas;
      if (cEx.data && cEx.data.id) {
        complejoId = cEx.data.id;
        var atrPrev = (cEx.data.atributos && typeof cEx.data.atributos === 'object') ? cEx.data.atributos : {};
        var merged = Object.assign({}, atrPrev, atrComp);
        if (Array.isArray(atrPrev.images) && atrPrev.images.length) merged.images = atrPrev.images;
        ['descripcion', 'direccion', 'amenities', 'servicios', 'beneficios'].forEach(function (kk) { if (String(atrPrev[kk] || '').length > String(atrComp[kk] || '').length) merged[kk] = atrPrev[kk]; });
        if (atrPrev.politicas && (!comp.politicas || typeof comp.politicas !== 'object')) merged.politicas = atrPrev.politicas;
        if (atrPrev.subtipo && !comp.subtipo) merged.subtipo = atrPrev.subtipo;
        await supabase.from('hotel_complejos').update({ atributos: merged }).eq('id', complejoId).eq('user_id', ownerId);
      } else {
        var cIns = await supabase.from('hotel_complejos').insert({ user_id: ownerId, nombre: nombreComp, tipo: 'hotel_cabanas', atributos: atrComp }).select('id').maybeSingle();
        if (!cIns.error && cIns.data) complejoId = cIns.data.id;
      }
    } catch (eC) {}
    complejosGuardados.push({ id: complejoId, nombre: nombreComp });
    var unidades = Array.isArray(comp.unidades) ? comp.unidades : [];
    for (var i = 0; i < unidades.length; i++) {
      var _r = await _upsertUnidadHotel(ownerId, complejoId, unidades[i] || {}, sitio);
      if (_r === 'creado') creados++; else if (_r === 'actualizado') actualizados++; else errores++;
    }
  }
  return { complejos: complejosGuardados, complejoId: (complejosGuardados[0] && complejosGuardados[0].id) || null, creados: creados, actualizados: actualizados, errores: errores };
}

app.post('/api/scrape/alojamiento', async function (req, res) {
  try {
    var user_id = await verificarUsuario(req);
    if (!user_id) return res.status(401).json({ error: 'No autorizado' });
    // Un asesor opera sobre la cuenta del dueño: resolvemos ownerId para leer/escribir el inventario del TENANT.
    var ownerId = user_id;
    try { var ase = await supabase.from('asesores').select('admin_id').eq('auth_user_id', user_id).maybeSingle(); if (ase && ase.data && ase.data.admin_id) ownerId = ase.data.admin_id; } catch (eO) {}

    var sitio = (req.body && req.body.url ? String(req.body.url) : '').trim();
    var modo = (req.body && req.body.modo === 'reset') ? 'reset' : 'update';
    if (!sitio) return res.status(400).json({ error: 'Falta la url del sitio' });
    if (!sitio.startsWith('http')) sitio = 'https://' + sitio;
    var base; try { var u = new URL(sitio); base = u.protocol + '//' + u.host; } catch (e) { return res.status(400).json({ error: 'URL invalida' }); }

    // Restringir al dominio propio del tenant (anti-scrape de competencia / explosion de costo IA).
    var _perm = await scrapeUrlPermitida(ownerId, sitio);
    if (!_perm.ok) return res.status(400).json({ error: _perm.error });

    // PASO 1 (estatico): complejo + habitaciones + fotos por habitacion + deteccion para el Paso 2.
    var res1 = await _scrapeAlojamientoCompleto(base, sitio, ownerId, true);
    var totalUn = (res1.complejos || []).reduce(function (a, c) { return a + ((Array.isArray(c.unidades) ? c.unidades.length : 0)); }, 0);
    var _nomComp = (res1.complejos && res1.complejos[0] && res1.complejos[0].nombre) || null;
    if (!totalUn && !_nomComp) {
      return res.json({ ok: false, total: 0, deteccion: res1.deteccion, mensaje: 'No se encontraron alojamientos en la pagina. La web puede requerir JavaScript (probá el scrape profundo) o cargá las unidades a mano.' });
    }
    var g = await _guardarComplejoYUnidades(ownerId, res1, sitio, modo);
    return res.json({ ok: true, rubro: 'hotel_cabanas', modo: modo, total: totalUn, complejos: (g.complejos || []).length, creados: g.creados, actualizados: g.actualizados, errores: g.errores, estrategia: res1.estrategia, complejo: _nomComp, deteccion: res1.deteccion });
  } catch (e) { return res.status(500).json({ error: e && e.message }); }
});

// ---- POST /api/scrape/alojamiento/job --------------------------------------
// Encola un scrape de hotel/cabañas en SEGUNDO PLANO (mismo patrón/tabla que desarrollo:
// scrape_jobs, sin migración). Body: { url } (importar/actualizar por URL) o
// { complejo_id } (relee la origen_url guardada del complejo). Devuelve { ok, job_id }
// al INSTANTE; el runner procesarScrapeJobs lo corre y reporta progreso real por etapas.
// El front pollea GET /api/scrape/job/:id para la barra de progreso.
app.post('/api/scrape/alojamiento/job', async function (req, res) {
  try {
    var uid = await verificarUsuario(req);
    if (!uid) return res.status(401).json({ error: 'No autorizado' });
    var owner = await _resolverOwner(uid);

    var url = ((req.body && req.body.url) || '').trim();
    var cid = _invStr((req.body && (req.body.complejo_id || req.body.id)));
    var tipo, input;
    if (cid) {
      var cRow = await supabase.from('hotel_complejos').select('user_id, atributos').eq('id', cid).maybeSingle();
      if (cRow.error) return res.status(500).json({ error: 'Error leyendo el complejo: ' + cRow.error.message });
      if (!cRow.data) return res.status(404).json({ error: 'El complejo no existe', complejo_id: cid });
      if (cRow.data.user_id !== owner) return res.status(403).json({ error: 'El complejo no pertenece a tu cuenta' });
      var oUrl = (cRow.data.atributos && cRow.data.atributos.origen_url) ? String(cRow.data.atributos.origen_url).trim() : '';
      if (!url && !oUrl) return res.status(400).json({ error: 'Este complejo no tiene URL de origen guardada. Importalo primero por URL.' });
      tipo = 'alojamiento_update';
      input = { complejo_id: cid, url: (url || oUrl), modo: 'update' };
    } else if (url) {
      tipo = 'alojamiento_nuevo';
      input = { url: url, modo: (req.body && req.body.modo === 'reset') ? 'reset' : 'update' };
    } else {
      return res.status(400).json({ error: 'Falta la url del sitio (o complejo_id para actualizar)' });
    }

    var ins = await supabase.from('scrape_jobs').insert({
      user_id: owner, tipo: tipo, input: input, estado: 'pendiente', progreso: 0, mensaje: 'En cola…'
    }).select('id').single();
    if (ins.error) {
      if (_invTablaFaltante(ins.error)) return res.status(503).json({ error: 'La tabla scrape_jobs no existe todavía. Corré migracion-scrape-jobs.sql.', tabla: 'scrape_jobs' });
      return res.status(500).json({ error: 'No se pudo encolar el trabajo: ' + ins.error.message });
    }
    return res.json({ ok: true, job_id: ins.data.id });
  } catch (e) { return res.status(500).json({ error: e && e.message ? e.message : 'Error interno' }); }
});

// ============================================================================
// MOTOR HEADLESS (@sparticuz/chromium + puppeteer-core) — render de sitios JS (PXSOL, etc.)
// LAZY: el require es dentro del helper; si el navegador no puede lanzarse (falta lib en el
// server, etc.) NO rompe nada -> devuelve htmls:[] y el flujo cae a "cargar a mano". SERIALIZADO
// por el runner de jobs (_scrapeJobsEnCurso) y single-process para minimizar el pico de memoria.
// ============================================================================
var _headlessMods = undefined; // undefined=sin intentar, null=fallo, obj=ok
async function _cargarHeadless() {
  if (_headlessMods !== undefined) return _headlessMods;
  try {
    // import() DINAMICO: @sparticuz/chromium es ESM ("type":"module"). require() de ESM tira
    // ERR_REQUIRE_ESM en el Node de Railway (<22); import() funciona en cualquier version desde
    // CommonJS. Cacheado en _headlessMods -> corre una sola vez.
    var chMod = await import('@sparticuz/chromium');
    var ppMod = await import('puppeteer-core');
    _headlessMods = { pptr: (ppMod && ppMod.default) || ppMod, chromium: (chMod && chMod.default) || chMod };
  } catch (e) { console.error('[headless] no disponible:', e && e.message); _headlessMods = null; }
  return _headlessMods;
}

// Candado global: NUNCA dos navegadores a la vez (protege la memoria del proceso que atiende los chats).
var _headlessEnCurso = false;
// Renderiza una lista de URLs y devuelve los HTML resultantes. Cierra el navegador SIEMPRE.
async function _renderHeadless(urls, opciones) {
  var mod = await _cargarHeadless();
  if (!mod) return { via: null, htmls: [], error: 'headless no instalado' };
  if (_headlessEnCurso) return { via: 'headless', htmls: [], error: 'ya hay un render en curso' };
  _headlessEnCurso = true;
  var opts = opciones || {};
  var browser = null, htmls = [];
  try {
    var execPath = await mod.chromium.executablePath();
    browser = await mod.pptr.launch({
      args: mod.chromium.args.concat(['--disable-gpu']),
      executablePath: execPath,
      headless: true
    });
    for (var i = 0; i < urls.length; i++) {
      var page = null;
      try {
        page = await browser.newPage();
        await page.setUserAgent('Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 Chrome/120 Safari/537.36');
        await page.goto(urls[i], { waitUntil: 'networkidle2', timeout: opts.timeout || 30000 });
        if (opts.waitMs) await new Promise(function (r) { setTimeout(r, opts.waitMs); });
        var html = await page.content();
        if (html && html.length > 800) htmls.push(html);
      } catch (ep) { console.error('[headless] pagina', urls[i], ep && ep.message); }
      finally { try { if (page) await page.close(); } catch (eC) {} }
    }
  } catch (e) { console.error('[headless] launch:', e && e.message); _headlessEnCurso = false; return { via: 'headless', htmls: htmls, error: e && e.message }; }
  finally { try { if (browser) await browser.close(); } catch (eCl) {} _headlessEnCurso = false; }
  return { via: 'headless', htmls: htmls, error: null };
}

// PXSOL: las habitaciones solo aparecen DESPUES de una busqueda con fechas. Hacemos el "insert"
// server-side (sin navegador, sin token) para obtener un SearchID, y devolvemos la URL de la
// pagina de RESULTADOS (lp.html) para renderizar. Ahi la propia pagina pide las habitaciones con
// su token y quedan en el DOM. null si el sitio no es PXSOL o no se pudo armar la busqueda.
function _padDos(n) { return (n < 10 ? '0' : '') + n; }
async function _pxsolResultUrl(homepageHtml, base) {
  try {
    if (!/pxsol/i.test(homepageHtml)) return null;
    var mPid = homepageHtml.match(/product_id['"\s:=]+['"]?(\d{2,8})/i)
      || homepageHtml.match(/ProductID[^>]*value=['"](\d{2,8})/i)
      || homepageHtml.match(/Pid=(\d{2,8})/i);
    var pid = mPid ? mPid[1] : '';
    if (!pid) return null;
    var mApi = homepageHtml.match(/https?:\/\/[a-z0-9.-]*pxsol\.io/i);
    var api = mApi ? mApi[0] : 'https://api-1-eb-web.pxsol.io';
    var d1 = new Date(Date.now() + 30 * 86400000), d2 = new Date(Date.now() + 32 * 86400000);
    var ddmmyyyy = function (dt) { return _padDos(dt.getDate()) + '/' + _padDos(dt.getMonth() + 1) + '/' + dt.getFullYear(); };
    var iso = function (dt) { return dt.getFullYear() + '-' + _padDos(dt.getMonth() + 1) + '-' + _padDos(dt.getDate()); };
    var body = 'ProductID=' + pid + '&Start=' + ddmmyyyy(d1) + '&End=' + ddmmyyyy(d2) + '&Channel=2&RateType=auto&Currency=ARS&MaxRooms=1&Rooms=1&Adults=2&Nights=2&Lng=es';
    var r = await fetchScrape(api + '/search/insert', { method: 'POST', headers: { 'Content-Type': 'application/x-www-form-urlencoded', 'Origin': base, 'Referer': base + '/', 'User-Agent': 'Mozilla/5.0 (compatible; RaicesCRM/1.0)' }, body: body });
    if (!r.ok) return null;
    var txt = await r.text();
    var mSid = txt.match(/SearchID=(\d+)/);
    if (!mSid) return null;
    return base + '/lp.html?search=OK&SearchID=' + mSid[1] + '&cur=ARS&lng=es&Pid=' + pid + '&checkin=' + iso(d1) + '&checkout=' + iso(d2);
  } catch (e) { console.error('[pxsol] insert:', e && e.message); return null; }
}

// ============================================================================
// PXSOL — disponibilidad + precios REALES por fechas (para la tool de la IA).
// Flujo: /search/insert (crea búsqueda por fechas) -> /query/list6 con Sku=1 (trae habitaciones
// con precio TOTAL de la estadía —IVA + desayuno incluidos— y disponibilidad). GRATIS, sin token,
// sin navegador. Verificado contra el JSON real de Tequendama.
// ============================================================================

// Extrae la config PXSOL del HTML del sitio: ProductID (hotelId) + pos (posición del hotel, la pide
// list6) + api base. null si no es PXSOL o falta ProductID.
function _pxsolConfig(homepageHtml) {
  try {
    if (!/pxsol/i.test(homepageHtml)) return null;
    var mPid = homepageHtml.match(/product_id['"\s:=]+['"]?(\d{2,8})/i)
      || homepageHtml.match(/ProductID[^>]*value=['"](\d{2,8})/i)
      || homepageHtml.match(/Pid=(\d{2,8})/i);
    if (!mPid) return null;
    var mPos = homepageHtml.match(/[?&]pos=([^&"'\s]{1,40})/i)
      || homepageHtml.match(/ApiKey\s*[:=]\s*['"]([^'"]{1,40})['"]/i);
    var mApi = homepageHtml.match(/https?:\/\/[a-z0-9.-]*pxsol\.io/i);
    return { productId: mPid[1], pos: mPos ? decodeURIComponent(mPos[1]) : '', api: mApi ? mApi[0] : 'https://api-1-eb-web.pxsol.io' };
  } catch (e) { return null; }
}

// Consulta disponibilidad+precios para fechas concretas (YYYY-MM-DD). Devuelve
// { ok, nights, moneda, opciones:[{nombre, total, porNoche, disponibles, desayuno} | {nombre, sinDisponibilidad, minLOS}] } | { ok:false, error }.
async function _pxsolDisponibilidad(cfg, checkinISO, checkoutISO, adultos, ninos) {
  try {
    if (!cfg || !cfg.productId) return { ok: false, error: 'sin config pxsol' };
    var d1 = new Date(String(checkinISO) + 'T12:00:00'), d2 = new Date(String(checkoutISO) + 'T12:00:00');
    if (isNaN(d1.getTime()) || isNaN(d2.getTime())) return { ok: false, error: 'fechas invalidas' };
    var nights = Math.round((d2.getTime() - d1.getTime()) / 86400000);
    if (nights < 1) return { ok: false, error: 'el check-out debe ser posterior al check-in' };
    var ddmm = function (dt) { return _padDos(dt.getDate()) + '/' + _padDos(dt.getMonth() + 1) + '/' + dt.getFullYear(); };
    var ad = Math.max(1, Math.min(12, parseInt(adultos, 10) || 2));
    // NIÑOS (ADITIVO, verificado 2026-07-15 contra la API): PXSOL los recibe en GroupsForm
    // "habitacion:adultos,niños,bebes" (es lo que manda el buscador de la web). Cambian precio y
    // que habitaciones aplican. Sin niños, el body queda EXACTAMENTE como antes.
    var ni = Math.max(0, Math.min(8, parseInt(ninos, 10) || 0));
    var api = cfg.api || 'https://api-1-eb-web.pxsol.io';
    var body = 'ProductID=' + cfg.productId + '&Start=' + ddmm(d1) + '&End=' + ddmm(d2) + '&Channel=2&RateType=auto&Currency=ARS&MaxRooms=1&Rooms=1&Adults=' + ad + '&Nights=' + nights + '&Lng=es' + (ni > 0 ? '&GroupsForm=1:' + ad + ',' + ni + ',0' : '');
    var rIns = await fetchScrape(api + '/search/insert', { method: 'POST', headers: { 'Content-Type': 'application/x-www-form-urlencoded', 'User-Agent': 'RaicesCRM/1.0 (+https://raicescrm.com)' }, body: body });
    if (!rIns.ok) return { ok: false, error: 'insert http ' + rIns.status };
    var mSid = (await rIns.text()).match(/SearchID=(\d+)/);
    if (!mSid) return { ok: false, error: 'sin SearchID' };
    var url = api + '/query/list6?search=OK&pos=' + encodeURIComponent(cfg.pos || '') + '&lng=es&SearchID=' + mSid[1] + '&ProductID=' + cfg.productId + '&Sku=1&Currency=ARS&Email=NN&Tag=NN';
    var rList = await fetchScrape(url, { headers: { 'User-Agent': 'RaicesCRM/1.0 (+https://raicescrm.com)' } });
    if (!rList.ok) return { ok: false, error: 'list6 http ' + rList.status };
    var data = await rList.json();
    var pl = (data && Array.isArray(data.ProductList)) ? data.ProductList[0] : null;
    var skus = (pl && Array.isArray(pl.SkuList)) ? pl.SkuList : [];
    if (!skus.length) return { ok: false, error: 'sin habitaciones' };
    var opciones = skus.map(function (s) {
      var nombre = String(s.Title || s.SkuName || 'Habitación').replace(/\s+/g, ' ').trim();
      // OJO (verificado 2026-07-15 contra la web de Tequendama): Rate/PromotionalRate de PXSOL son
      // POR NOCHE y con impuestos INCLUIDOS (ClientLoad=FINAL, Taxes=21), NO el total de la estadia.
      // La WEB, en cambio, cotiza POR NOCHE SIN IVA ("Impuestos: 21% no incluidos"). Devolvemos las 2:
      // la de la WEB (default, lo que ve el huesped si entra a la pagina) y la FINAL con IVA.
      // NO usar RatePerDay para el total: su PromotionalRate NO trae aplicado el descuento.
      var porNocheFinal = Number(s.PromotionalRate || s.Rate || 0), avail = Number(s.Availability || 0);
      var ivaPct = 21;
      try { var _rl0 = Array.isArray(s.RateList) ? s.RateList : []; for (var k = 0; k < _rl0.length; k++) { var _rpd = _rl0[k].RatePerDay; if (_rpd && _rpd[0] && _rpd[0].Taxes != null) { ivaPct = Number(_rpd[0].Taxes) || 21; break; } } } catch (eTx) {}
      if (!(porNocheFinal > 0 && avail > 0)) {
        (Array.isArray(s.RateList) ? s.RateList : []).forEach(function (rt) {
          var a = Number(rt.Availability || 0), t = Number(rt.PromotionalRate || rt.Rate || 0);
          if (a > 0 && t > 0 && (!(porNocheFinal > 0) || t < porNocheFinal)) { porNocheFinal = t; avail = a; }
        });
      }
      if (porNocheFinal > 0 && avail > 0) {
        var _totalFinal = porNocheFinal * nights;
        var _div = 1 + (ivaPct / 100);
        return {
          nombre: nombre,
          porNocheWeb: Math.round(porNocheFinal / _div), totalWeb: Math.round(_totalFinal / _div),
          porNocheFinal: Math.round(porNocheFinal), totalFinal: Math.round(_totalFinal),
          ivaPct: ivaPct, disponibles: avail, desayuno: (s.Breakfast == 1 || s.Breakfast === true)
        };
      }
      var minLos = 0;
      (Array.isArray(s.RateList) ? s.RateList : []).forEach(function (rt) { var m = Number(rt.MinLOS || 0); if (m > minLos) minLos = m; });
      return { nombre: nombre, sinDisponibilidad: true, minLOS: (minLos > nights) ? minLos : null };
    });
    return { ok: true, nights: nights, moneda: 'ARS', opciones: opciones, sid: mSid[1] };
  } catch (e) { console.error('[pxsol] disponibilidad:', e && e.message); return { ok: false, error: e && e.message }; }
}

// FECHAS ALTERNATIVAS (ADITIVO, 0 IA): cuando NO hay disponibilidad, la WEB del hotel no deja al
// huesped sin opciones — le muestra "Mejores opciones disponibles" (fechas cercanas que SI se venden).
// Eso lo renderiza el module.php del sitio (mismo SearchID, sin token). Se lo damos a la IA para que
// conteste IGUAL que la web en vez de un "no hay" seco. Si el sitio no expone module.php -> [] y todo
// sigue como hoy.
async function _pxsolAlternativas(cfg, sid) {
  try {
    if (!cfg || !cfg.base || !sid) return [];
    var base = String(cfg.base).replace(/\/+$/, '');
    var u = base + '/neo_modules/cart_hotel_v2/module.php?cart_version=7&pos=' + encodeURIComponent(cfg.pos || '') +
      '&Sku=1&SearchID=' + sid + '&tag=NN&Pid=' + cfg.productId + '&cur=ARS&lng=es&Email=NN&search=OK';
    var r = await fetchScrape(u, { headers: { 'User-Agent': 'RaicesCRM/1.0 (+https://raicescrm.com)' } });
    if (!r.ok) return [];
    var html = await r.text();
    var out = [];
    var bloques = html.split(/class="cart_opcion/i).slice(1, 9);
    for (var i = 0; i < bloques.length; i++) {
      var b = bloques[i];
      var mIn = b.match(/Llegada:\s*<\/strong>\s*([^<]{4,40})/i) || b.match(/Entrada:\s*<\/strong>\s*([^<]{4,40})/i);
      var mOut = b.match(/Salida:\s*<\/strong>\s*([^<]{4,40})/i);
      var mNoc = b.match(/Noches:\s*<\/strong>\s*(\d{1,3})/i);
      var mDesde = b.match(/Desde<\/small>\s*<b>\s*([A-Z]{2,4}\s*\$\s*[\d.,]+)/i) || b.match(/<b>\s*(ARS\s*\$\s*[\d.,]+)\s*<\/b>\s*<span>\s*\/\s*noche/i);
      if (mIn && mOut && mNoc) {
        out.push({ llegada: mIn[1].trim(), salida: mOut[1].trim(), noches: parseInt(mNoc[1], 10), desde: mDesde ? mDesde[1].replace(/\s+/g, ' ').trim() : null });
      }
      if (out.length >= 4) break;
    }
    return out;
  } catch (e) { return []; }
}

// Resuelve la config PXSOL del hotel de una cuenta (cachea en hotel_complejos.atributos.pxsol para
// no re-bajar el sitio en cada consulta). null si la cuenta no tiene un complejo con sitio PXSOL.
async function _pxsolConfigDeCuenta(user_id) {
  try {
    var hc = await supabase.from('hotel_complejos').select('id, atributos').eq('user_id', user_id).limit(5);
    var comps = (hc && hc.data) ? hc.data : [];
    for (var i = 0; i < comps.length; i++) {
      var a = (comps[i].atributos && typeof comps[i].atributos === 'object') ? comps[i].atributos : {};
      // base = el sitio del hotel (para module.php de fechas alternativas). Se adjunta al vuelo,
      // sin persistirlo, asi los pxsol ya cacheados tambien lo tienen.
      var _baseSitio = a.origen_url || a.origenUrl || '';
      if (_baseSitio && !String(_baseSitio).startsWith('http')) _baseSitio = 'https://' + _baseSitio;
      _baseSitio = _baseSitio ? String(_baseSitio).replace(/^(https?:\/\/[^\/]+).*/, '$1') : '';
      if (a.pxsol && a.pxsol.productId) return Object.assign({}, a.pxsol, _baseSitio ? { base: _baseSitio } : {});
      var url = a.origen_url || a.origenUrl || '';
      if (!url) continue;
      if (!String(url).startsWith('http')) url = 'https://' + url;
      var rh = await fetchScrape(url);
      if (!rh.ok) continue;
      var cfg = _pxsolConfig(await rh.text());
      if (cfg) { try { await supabase.from('hotel_complejos').update({ atributos: Object.assign({}, a, { pxsol: cfg }) }).eq('id', comps[i].id); } catch (eU) {} return Object.assign({}, cfg, _baseSitio ? { base: _baseSitio } : {}); }
    }
    return null;
  } catch (e) { return null; }
}

// Arma la lista de URLs a renderizar (PXSOL primero, luego rutas tipicas de habitaciones) y las
// renderiza. Usa RENDER_API_URL si esta seteada (servicio externo, cero infra local); si no,
// el motor headless local. Devuelve { via, htmls, pxsol }.
async function _renderProfundoAlojamiento(base, sitio) {
  var homepageHtml = '';
  try { var rh = await fetchScrape(sitio); if (rh && rh.ok) homepageHtml = await rh.text(); } catch (e) {}
  var urls = [];
  var pxUrl = await _pxsolResultUrl(homepageHtml, base);
  if (pxUrl) urls.push(pxUrl);
  ['/habitaciones.html', '/habitaciones', '/domos.html', '/domos', '/cabanas.html', '/cabanas', '/'].forEach(function (r) { urls.push(base + r); });
  urls = urls.filter(function (u, i) { return urls.indexOf(u) === i; }).slice(0, 6);
  var RENDER_API = process.env.RENDER_API_URL || '';
  if (RENDER_API) {
    var htmls = [];
    for (var i = 0; i < urls.length && htmls.length < 5; i++) {
      try { var rr = await fetch(RENDER_API, { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ url: urls[i], gotoOptions: { waitUntil: 'networkidle2', timeout: 30000 } }) }); if (rr && rr.ok) { var h = await rr.text(); if (h && h.length > 800) htmls.push(h); } } catch (eR) {}
    }
    return { via: 'render-api', htmls: htmls, pxsol: !!pxUrl };
  }
  var res = await _renderHeadless(urls, { timeout: 30000, waitMs: 3500 });
  return { via: res.via, htmls: res.htmls, pxsol: !!pxUrl, error: res.error };
}

// Render profundo + extraccion + guardado (compartido por el endpoint y el runner de jobs).
async function _scrapeAlojamientoProfundo(base, sitio, ownerId, modo, costoMsgs) {
  var rend = await _renderProfundoAlojamiento(base, sitio);
  if (!rend.htmls.length) return { ok: false, via: rend.via, mensaje: rend.error ? ('No se pudo renderizar (' + rend.error + ').') : 'No se pudo renderizar el sitio.' };
  var fotos = _extraerFotosAlojamiento(rend.htmls, base);
  var data = await _alojamientoIAcompleto(rend.htmls.slice().reverse().join('\n\n\n'), base, ownerId);
  try { if (SUBSCRIPTIONS_ENABLED && ownerId && await cobrarTodoV2Activo(ownerId)) await registrarUsoIA(ownerId, Math.min(20, costoMsgs || 5)); } catch (eCob) {}
  var complejos = Array.isArray(data.complejos) ? data.complejos : [];
  if (!complejos.length) complejos = [{ nombre: '', unidades: [] }];
  var grupos = Object.keys(fotos.porRoom).map(function (k) { return fotos.porRoom[k]; });
  var _gi = 0;
  for (var c = 0; c < complejos.length; c++) {
    var cp = complejos[c]; var uds = Array.isArray(cp.unidades) ? cp.unidades : [];
    for (var j = 0; j < uds.length; j++) { var _g = grupos[_gi++]; if (_g && _g.length) uds[j].imagenes = _g.slice(0, 40); else uds[j].imagenes = Array.isArray(uds[j].imagenes) ? uds[j].imagenes.slice(0, 40) : []; }
    cp.images = (fotos.complejo.length ? fotos.complejo : (complejos.length === 1 ? fotos.todas.slice(0, 10) : [])).slice(0, 30);
  }
  var _totUn = complejos.reduce(function (a, c) { return a + ((Array.isArray(c.unidades) ? c.unidades.length : 0)); }, 0);
  var g = await _guardarComplejoYUnidades(ownerId, { complejos: complejos }, sitio, modo);
  return { ok: true, profundo: true, via: rend.via, pxsol: rend.pxsol, total: _totUn, creados: g.creados, actualizados: g.actualizados, errores: g.errores, complejos: (g.complejos || []).length, complejo: (complejos[0] && complejos[0].nombre) || null, fotosTotales: fotos.todas.length };
}

// ============================================================================
// PASO 3 — SCRAPE PROFUNDO (headless). Renderiza el JS (PXSOL, etc.) para traer TODAS
// las galerias. LAZY: si el navegador no esta disponible responde SIN romper el boot ni
// afectar los otros rubros. Opt-in del cliente (avisa gasto). Solo rubro hotel.
// ============================================================================
app.post('/api/scrape/alojamiento/profundo', async function (req, res) {
  try {
    var ownerId = await _ownerDe(req);
    if (!ownerId) return res.status(401).json({ error: 'No autorizado' });
    var sitio = (req.body && req.body.url ? String(req.body.url) : '').trim();
    var modo = (req.body && req.body.modo === 'reset') ? 'reset' : 'update';
    if (!sitio) return res.status(400).json({ error: 'Falta la url' });
    if (!sitio.startsWith('http')) sitio = 'https://' + sitio;
    var base; try { var u = new URL(sitio); base = u.protocol + '//' + u.host; } catch (e) { return res.status(400).json({ error: 'URL invalida' }); }
    var _perm = await scrapeUrlPermitida(ownerId, sitio);
    if (!_perm.ok) return res.status(400).json({ error: _perm.error });
    var costoMsgs = (req.body && parseInt(req.body.costoMsgs, 10)) || 5;
    var r = await _scrapeAlojamientoProfundo(base, sitio, ownerId, modo, costoMsgs);
    if (!r.ok && r.via === null) return res.status(503).json({ error: 'El render profundo no esta disponible en el servidor en este momento. Cargá las unidades a mano o reintentá más tarde.', necesita: 'render' });
    return res.json(r);
  } catch (e) { return res.status(500).json({ error: e && e.message }); }
});

// Resuelve el owner (un asesor opera sobre la cuenta del dueño). Devuelve el auth id del tenant o null.
async function _ownerDe(req) {
  var user_id = await verificarUsuario(req);
  if (!user_id) return null;
  try { var ase = await supabase.from('asesores').select('admin_id').eq('auth_user_id', user_id).maybeSingle(); if (ase && ase.data && ase.data.admin_id) return ase.data.admin_id; } catch (e) {}
  return user_id;
}

// Editar UNA unidad de alojamiento (edicion manual desde /alojamiento). Owner-scoped. Solo toca los campos enviados.
app.post('/api/inventario/hotel/unidad/actualizar', async function (req, res) {
  try {
    var ownerId = await _ownerDe(req);
    if (!ownerId) return res.status(401).json({ error: 'No autorizado' });
    var b = req.body || {};
    var id = b.id ? String(b.id) : '';
    if (!id) return res.status(400).json({ error: 'Falta id' });
    var cur = await supabase.from('hotel_unidades').select('user_id, atributos').eq('id', id).maybeSingle();
    if (cur.error) return res.status(500).json({ error: cur.error.message });
    if (!cur.data) return res.status(404).json({ error: 'Unidad no encontrada' });
    if (cur.data.user_id !== ownerId) return res.status(403).json({ error: 'La unidad no pertenece a tu cuenta' });
    var fila = {};
    if (b.title !== undefined) fila.title = String(b.title || 'Sin nombre').slice(0, 200);
    if (b.type !== undefined) fila.type = b.type || null;
    if (b.capacidad !== undefined) fila.capacidad = (parseInt(b.capacidad, 10) || null);
    if (b.descripcion !== undefined) fila.descripcion = b.descripcion || null;
    if (b.precio_base !== undefined) fila.precio_base = (b.precio_base === '' || b.precio_base === null) ? null : _sInvN(b.precio_base);
    if (b.moneda !== undefined) fila.moneda = (b.moneda === 'USD' ? 'USD' : 'ARS');
    if (b.activa !== undefined) fila.activa = !!b.activa;
    if (Array.isArray(b.images)) fila.images = b.images.filter(function (im) { return im && im.url; }).map(function (im) { return { url: im.url, categoria: im.categoria || '' }; });
    if (b.complejo_id !== undefined) fila.complejo_id = b.complejo_id || null; // mover de complejo (o desvincular)
    // atributos: merge canonico. amenities como flags; servicios_texto = servicios libres; camas/dorm/banos/m2/vista/regimenes.
    var atr = Object.assign({}, (cur.data.atributos && typeof cur.data.atributos === 'object') ? cur.data.atributos : {});
    if (b.amenities !== undefined && b.amenities && typeof b.amenities === 'object') atr.amenities = b.amenities;
    if (b.servicios !== undefined) atr.servicios_texto = b.servicios || '';
    ['camas', 'dormitorios', 'banos'].forEach(function (k) { if (b[k] !== undefined) atr[k] = (parseInt(b[k], 10) || null); });
    if (b.m2 !== undefined) atr.m2 = _sInvN(b.m2);
    if (b.vista !== undefined) atr.vista = b.vista || null;
    if (b.regimenes !== undefined && Array.isArray(b.regimenes)) atr.regimenes = b.regimenes;
    fila.atributos = atr;
    var up = await supabase.from('hotel_unidades').update(fila).eq('id', id).eq('user_id', ownerId);
    if (up.error) return res.status(500).json({ error: up.error.message });
    return res.json({ ok: true });
  } catch (e) { return res.status(500).json({ error: e && e.message }); }
});

