// ============================================================================
// SCRAPER DESARROLLADORA  —  POST /api/scrape/desarrollo   (ADITIVO)
// ----------------------------------------------------------------------------
// Lee la pagina de UN proyecto de una desarrolladora (texto + fotos/planos/renders)
// y con IA arma una ESTRUCTURA lista para PRE-CARGAR el form _FormDesarrollo.tsx
// (NO guarda: el front revisa y guarda con /api/inventario/guardar).
// Reusa el patron del scraper inmobiliaria: fetchScrape (fetch TLS-tolerante),
// _htmlParaIA (limpia HTML->texto), Claude (MODELO_INTERNO = Haiku por costo),
// registrarUsoTokens (panel de costos) y _parseJsonObjetoDefensivo (parser tolerante).
// La IA se ADAPTA a cualquier estructura de pagina; NO hay formato fijo.
// ============================================================================

// MODELO del scraper de desarrollo. El dueño quiere "TODO, no parte": priorizamos CALIDAD de
// extraccion sobre costo -> MODELO_CLIENTE (Sonnet). Este scrapeo lo corre el dueño manualmente
// (o el auto-update opt-in, default OFF), NO por cada lead, asi que el costo por corrida es acotado.
// Para ABARATAR (volver a Haiku): descomentar las dos lineas Haiku y comentar las dos Sonnet.
const MODELO_SCRAPE_DESARROLLO = MODELO_CLIENTE;              // Sonnet (calidad, "todo"). Alt: MODELO_INTERNO (Haiku, barato)
const PRECIO_SCRAPE_DESARROLLO = PRECIO_IA;                  // emparejar: Sonnet->PRECIO_IA. (Haiku->PRECIO_HAIKU)
// --- Alternativa BARATA (Haiku): comentar las 2 lineas de arriba y usar estas 2 ---
// const MODELO_SCRAPE_DESARROLLO = MODELO_INTERNO;           // Haiku (barato, menos exacto)
// const PRECIO_SCRAPE_DESARROLLO = PRECIO_HAIKU;             // emparejar: Haiku->PRECIO_HAIKU
// Tope de chars del texto limpio que se manda a la IA. Subido de 14k -> 40k para capturar
// TODAS las secciones de una pagina de desarrolladora (server-rendered: el fetch plano ya trae
// descripcion, amenities, master plan, etapas, equipo, ubicacion). 40k acota el costo de input.
const _MAX_TEXTO_DESARROLLO = 40000;

// MODELO del paso de VISION (leer el/los PLANOS/MASTERPLAN y sacar los LOTES + su estado
// codificado por color). Default a MODELO_CLIENTE (Sonnet) porque leer un plano con colores
// y una leyenda exige mas precision visual que la extraccion de texto. Se puede BAJAR a
// MODELO_INTERNO (Haiku) para abaratar si el dueño acepta menos exactitud — recordar emparejar
// el PRECIO de abajo (Sonnet->PRECIO_IA, Haiku->PRECIO_HAIKU). El costo de vision SOLO se paga
// si la pagina trae al menos un plano para mirar (ver _MAX_PLANOS_VISION mas abajo).
const MODELO_SCRAPE_VISION = MODELO_CLIENTE;                 // Sonnet (precision). Alt: MODELO_INTERNO (Haiku, mas barato)
const PRECIO_SCRAPE_VISION = PRECIO_IA;                      // emparejar con el modelo de arriba (Sonnet->PRECIO_IA, Haiku->PRECIO_HAIKU)
const _MAX_PLANOS_VISION = 5;                               // tope de imagenes a mirar por scrapeo en modo NORMAL (base historica; acota costo)
const _MAX_TOKENS_VISION = 2000;                            // max_tokens de la llamada de vision en modo NORMAL (base historica)

// ---- 🔴 GATE DE COSTO: modo "plano PROFUNDO" (OFF por default) ---------------
// El dueño NO quiere que un scrapeo suba el gasto en silencio. Por eso TODO el comportamiento
// "profundo" (mas imagenes de plano + max_tokens de vision mas alto) vive detras de un gate.
//   - GATE OFF (default): identico al comportamiento historico -> _MAX_PLANOS_VISION (5) imagenes
//     y _MAX_TOKENS_VISION (2000) tokens de salida por imagen. CERO gasto extra.
//   - GATE ON: procesa hasta PLANO_MAX_IMAGENES planos y pide hasta PLANO_MAX_TOKENS por imagen.
// Se prende por ENV global (PLANO_DEEP='true') O por-scrapeo desde el body del endpoint
// (opts.plano_deep === true). El helper _planoDeepCfg(opts) resuelve el modo efectivo y
// devuelve { deep, maxImagenes, maxTokens } para que el resto del codigo no repita la logica.
//
// 💲 COSTO EN MODO PROFUNDO (por scrapeo, aprox, PEOR CASO):
//   Cada imagen de plano = 1 llamada de vision a Sonnet (MODELO_SCRAPE_VISION).
//   Input por imagen ≈ imagen (~1.6k tokens una imagen tipica ~1.15MP) + prompt (~0.3k) ≈ 1.9k in.
//   Output por imagen = hasta PLANO_MAX_TOKENS (default 6000) out.
//   Precio Sonnet: $3/1M in, $15/1M out.
//   Por imagen ≈ 1.9k*($3/1M) + 6k*($15/1M) = $0.0057 + $0.090 = ~$0.096.
//   Con PLANO_MAX_IMAGENES=12 (tope profundo default) => 12 * $0.096 ≈ $1.15 por scrapeo (TOPE).
//   El output real casi nunca llega al tope; suele salir bastante menos. Es el peor caso.
//   En modo NORMAL (gate OFF): 5 img * (1.9k in + hasta 2k out) ≈ 5 * ($0.0057 + $0.030) = ~$0.18 tope.
const PLANO_DEEP_ENV = (process.env.PLANO_DEEP === 'true');  // gate GLOBAL por env (OFF si no esta seteado)
const _PLANO_MAX_IMAGENES_DEEP = (function () { var n = parseInt(process.env.PLANO_MAX_IMAGENES, 10); return (n && n >= 1 && n <= 40) ? n : 12; })();  // tope de imagenes en modo profundo (default 12, cap duro 40)
const _PLANO_MAX_TOKENS_DEEP = (function () { var n = parseInt(process.env.PLANO_MAX_TOKENS, 10); return (n && n >= 2000 && n <= 16000) ? n : 6000; })();  // max_tokens de vision en modo profundo (default 6000, cap 16000)

// Resuelve el modo efectivo. `opts` puede traer { plano_deep:true } para prender el modo profundo
// SOLO en ese scrapeo (sin tocar el env). El env PLANO_DEEP='true' lo prende globalmente.
// Con ambos OFF -> modo NORMAL byte-equivalente al historico (5 imagenes / 2000 tokens).
function _planoDeepCfg(opts) {
  var deep = PLANO_DEEP_ENV || !!(opts && opts.plano_deep === true);
  return deep
    ? { deep: true, maxImagenes: _PLANO_MAX_IMAGENES_DEEP, maxTokens: _PLANO_MAX_TOKENS_DEEP }
    : { deep: false, maxImagenes: _MAX_PLANOS_VISION, maxTokens: _MAX_TOKENS_VISION };
}

// Extrae URLs de IMAGENES y PDFs de un HTML, resolviendo relativas a absolutas.
// General (NO WordPress-especifico como _extraerGaleriaHtml): mira src, data-src,
// data-original, data-lazy, srcset y <a href> a .pdf. Devuelve el filename como pista
// para que la IA clasifique (plano/render/foto). Dedup, cap para no inflar el prompt.
function _extraerImagenesDesarrollo(html, baseUrl, cap) {
  var out = [];
  var visto = {};
  var tope = cap || 60;
  function _abs(u) { try { return new URL(u, (baseUrl || '') + '/').toString(); } catch (e) { return null; } }
  function _push(raw) {
    if (!raw) return;
    var t = String(raw).trim();
    if (!t || /^data:/i.test(t) || /^javascript:/i.test(t)) return;      // saltear data-uri inline / js
    var abs = _abs(t);
    if (!abs || !/^https?:/i.test(abs)) return;
    var limpia = abs.split('#')[0];
    if (visto[limpia]) return;
    visto[limpia] = 1;
    var archivo = '';
    try { archivo = decodeURIComponent((limpia.split('?')[0].split('/').pop() || '')); } catch (e) { archivo = limpia.split('?')[0].split('/').pop() || ''; }
    out.push({ url: limpia, filename: archivo });
  }
  if (!html) return out;
  // 1) <img> con src / data-src / data-original / data-lazy / data-lazy-src
  var rxImg = /<img\b[^>]*>/gi, mImg;
  while ((mImg = rxImg.exec(html)) !== null && out.length < tope) {
    var tag = mImg[0];
    var mA = tag.match(/\b(?:data-src|data-original|data-lazy-src|data-lazy|src)\s*=\s*["']([^"']+)["']/i);
    if (mA && mA[1]) _push(mA[1]);
    // primera url del srcset (suele ser una variante util) — resolucion mayor primero si aparece
    var mS = tag.match(/\bsrcset\s*=\s*["']([^"']+)["']/i);
    if (mS && mS[1]) {
      var cand = mS[1].split(',')[0].trim().split(/\s+/)[0];
      if (cand) _push(cand);
    }
  }
  // 2) <source srcset> (picture/gallery)
  var rxSrc = /<source\b[^>]*\bsrcset\s*=\s*["']([^"']+)["'][^>]*>/gi, mSr;
  while ((mSr = rxSrc.exec(html)) !== null && out.length < tope) {
    var c2 = mSr[1].split(',')[0].trim().split(/\s+/)[0];
    if (c2) _push(c2);
  }
  // 3) <a href> a PDF (planos / brochure) o a imagenes directas (lightbox)
  var rxA = /<a\b[^>]*\bhref\s*=\s*["']([^"']+)["'][^>]*>/gi, mHref;
  while ((mHref = rxA.exec(html)) !== null && out.length < tope) {
    var h = mHref[1];
    if (/\.(?:pdf|jpe?g|png|webp)(?:$|[?#])/i.test(h.split('?')[0]) || /\.pdf(?:$|[?#])/i.test(h)) _push(h);
  }
  return out.slice(0, tope);
}

// ---- VISION DE PLANOS (lotes + estado por color) ----------------------------
// Elige de las imagenes clasificadas cuales conviene MIRAR con vision para sacar
// los lotes. Prioriza URLs cuyo nombre/URL sugiera masterplan/loteo/plano/planta.
// Fuente: primero imagenes.planos (lo que la IA clasifico como plano); si esta vacio,
// cae a fotos+renders (por si el masterplan quedo mal clasificado). Devuelve HASTA
// `topeMax` URLs (acota costo). Si `topeMax` no viene -> _MAX_PLANOS_VISION (byte-compat
// con el comportamiento historico). NO mira nada si no hay ninguna imagen.
function _elegirPlanosParaVision(imagenes, topeMax) {
  var tope = (typeof topeMax === 'number' && topeMax >= 1) ? topeMax : _MAX_PLANOS_VISION;
  var planos = (imagenes && Array.isArray(imagenes.planos)) ? imagenes.planos.slice() : [];
  var fotos = (imagenes && Array.isArray(imagenes.fotos)) ? imagenes.fotos.slice() : [];
  var renders = (imagenes && Array.isArray(imagenes.renders)) ? imagenes.renders.slice() : [];
  // pool de candidatos: planos primero (mas probable que sean el masterplan), luego el resto
  // (defensivo: si el masterplan quedo mal clasificado como foto/render, igual entra al pool
  //  y el scoring por keywords lo levanta si la URL lo delata).
  var pool = planos.concat(fotos, renders).filter(function (u) { return typeof u === 'string' && u.trim(); });
  if (!pool.length) return [];
  // dedup preservando orden
  var visto = {}, uniq = [];
  pool.forEach(function (u) { var k = u.split('#')[0]; if (!visto[k]) { visto[k] = 1; uniq.push(u); } });
  // score por pistas de masterplan/loteo en la URL (mas alto = mira antes)
  var RX_FUERTE = /(master\s*plan|masterplan|loteo|lotes?|parcel|manzana|amanzana|etapa|sector|fase)/i;
  var RX_MEDIO = /(plano|planta|layout|plan\b)/i;
  function _score(u) {
    var s = String(u).toLowerCase();
    var sc = 0;
    if (RX_FUERTE.test(s)) sc += 100;
    if (RX_MEDIO.test(s)) sc += 40;
    // un plano ya clasificado como "plano" vale mas que uno que vino de fotos/renders
    if (planos.indexOf(u) >= 0) sc += 20;
    return sc;
  }
  // orden estable por score desc; si empatan, respeta el orden original (planos primero)
  var conIdx = uniq.map(function (u, i) { return { u: u, i: i, sc: _score(u) }; });
  conIdx.sort(function (a, b) { return (b.sc - a.sc) || (a.i - b.i); });
  return conIdx.slice(0, tope).map(function (x) { return x.u; });
}

// ---- STRUCTURAL-FIRST: intenta parsear un plano SVG sin vision (gratis) -------
// Si el "plano" es en realidad un SVG (o trae SVG embebido), los numeros de lote suelen
// venir como <text>...</text> y el estado como color de relleno (fill / style="fill:..").
// Parsear eso es GRATIS (cero tokens) y suele ser MAS exacto que la vision. Es 100%
// defensivo: si no es SVG, o no se puede parsear, o no hay <text>, devuelve null y el
// caller cae a la vision normal. Heuristica simple por regex (no DOM): asocia cada <text>
// con etiqueta tipo lote a un color cercano si el <text> trae fill/style propio; si no,
// deja el estado 'desconocido' (mejor no inventar). NO reemplaza a la vision cuando el
// SVG no codifica el color en el <text> (caso comun: el color esta en el <path>/<rect>).
function _parsearLotesDeSvg(svgText) {
  try {
    if (!svgText || typeof svgText !== 'string') return null;
    if (!/<svg[\s>]/i.test(svgText)) return null;
    // color -> estado (heuristica: primero por nombre; si es HEX, por dominancia de canal RGB).
    // verde -> disponible/libre ; rojo -> vendido ; amarillo/naranja -> reservado ; resto -> desconocido.
    function _estadoDeColor(col) {
      if (!col) return 'desconocido';
      var c = String(col).toLowerCase().trim();
      // 1) nombres CSS explicitos
      if (/\b(green|verde|lime|forestgreen|seagreen)\b/.test(c)) return 'disponible';
      if (/\b(red|rojo|crimson|firebrick|darkred)\b/.test(c)) return 'vendido';
      if (/\b(yellow|amarillo|orange|naranja|amber|gold|goldenrod)\b/.test(c)) return 'reservado';
      if (/\b(gray|grey|gris|black|white|blanco|negro)\b/.test(c)) return 'desconocido';
      // 2) HEX (#rgb o #rrggbb) -> RGB -> dominancia de canal
      var mHex = c.match(/#([0-9a-f]{3}|[0-9a-f]{6})\b/);
      if (mHex) {
        var h = mHex[1];
        if (h.length === 3) h = h[0] + h[0] + h[1] + h[1] + h[2] + h[2];
        var R = parseInt(h.slice(0, 2), 16), G = parseInt(h.slice(2, 4), 16), B = parseInt(h.slice(4, 6), 16);
        // amarillo/naranja: R y G altos, B bajo (R+G dominan sobre B con margen)
        if (R >= 150 && G >= 120 && B <= Math.min(R, G) - 60) return 'reservado';
        // verde: G claramente el canal dominante
        if (G >= 100 && G >= R + 40 && G >= B + 40) return 'disponible';
        // rojo: R claramente el canal dominante
        if (R >= 100 && R >= G + 40 && R >= B + 40) return 'vendido';
        return 'desconocido';
      }
      // 3) rgb(...) -> misma logica de dominancia
      var mRgb = c.match(/rgb[a]?\(\s*(\d+)\s*,\s*(\d+)\s*,\s*(\d+)/);
      if (mRgb) {
        var r2 = +mRgb[1], g2 = +mRgb[2], b2 = +mRgb[3];
        if (r2 >= 150 && g2 >= 120 && b2 <= Math.min(r2, g2) - 60) return 'reservado';
        if (g2 >= 100 && g2 >= r2 + 40 && g2 >= b2 + 40) return 'disponible';
        if (r2 >= 100 && r2 >= g2 + 40 && r2 >= b2 + 40) return 'vendido';
        return 'desconocido';
      }
      return 'desconocido';
    }
    var lotes = [];
    var rxText = /<text\b([^>]*)>([\s\S]*?)<\/text>/gi, m;
    var vistos = {};
    while ((m = rxText.exec(svgText)) !== null && lotes.length < 2000) {
      var attrs = m[1] || '';
      // contenido: sacar tags anidados (<tspan>) y espacios
      var contenido = (m[2] || '').replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ').trim();
      if (!contenido) continue;
      // etiqueta de lote: numero suelto, "Lote 12", "L-12", "12A", etc. (defensivo: cualquier token corto)
      var mm = contenido.match(/(?:lote\s*)?([A-Za-z]?\s*\d{1,4}[A-Za-z]?)/i);
      if (!mm) continue;
      var etiqueta = mm[1].replace(/\s+/g, '').trim();
      if (!etiqueta) continue;
      var clave = etiqueta.toLowerCase();
      if (vistos[clave]) continue;
      vistos[clave] = 1;
      // color: fill="..." o style="fill:.." en el propio <text> (si esta; muchas veces NO esta)
      var col = '';
      var mf = attrs.match(/\bfill\s*=\s*["']([^"']+)["']/i);
      if (mf && mf[1]) col = mf[1];
      if (!col) { var ms = attrs.match(/style\s*=\s*["'][^"']*fill\s*:\s*([^;"']+)/i); if (ms && ms[1]) col = ms[1]; }
      lotes.push({ etiqueta: etiqueta, estado: _estadoDeColor(col), superficie_m2: null, notas: '', etapa: '' });
    }
    if (!lotes.length) return null;   // no habia <text> util -> caer a vision
    return { lotes: lotes, leyenda: '', confianza: 'media', _fuente: 'svg' };
  } catch (e) { return null; }
}

// Baja UNA imagen de plano y le pide a Claude (VISION) los lotes + estado por color.
// Reusa EXACTAMENTE el patron del clasificador de fotos (clasificarFotoBase64):
// baja la imagen, la manda como base64 en content type:'image', registra tokens con
// registrarUsoTokens. Usa base64 (no source.type:'url') para maxima compatibilidad con
// CDNs que bloquean el fetch del lado de Anthropic. Devuelve el OBJETO parseado
// { lotes:[], leyenda, confianza } o null si algo falla (el caller es defensivo).
// `maxTokens` = tope de salida de la llamada de vision (viene del modo NORMAL/PROFUNDO);
// si no viene -> _MAX_TOKENS_VISION (2000), byte-compat con el comportamiento historico.
// `deep` = modo profundo (bool). En OFF, el request a la API es IDENTICO al historico
// (mismo prompt sin "etapa", mismos 2000 tokens, SIN structural-first SVG). En ON, usa el
// prompt etapa-aware, mas tokens, y STRUCTURAL-FIRST (parsea SVG GRATIS antes de gastar vision).
async function _leerLotesDePlano(url, user_id, maxTokens, deep) {
  var topeTokens = (typeof maxTokens === 'number' && maxTokens >= 1) ? maxTokens : _MAX_TOKENS_VISION;
  var resp = await fetch(url, { headers: { 'User-Agent': 'Mozilla/5.0 RaicesCRM' } });
  if (!resp.ok) throw new Error('HTTP ' + resp.status);
  var mediaType = (resp.headers.get('content-type') || '').split(';')[0].trim().toLowerCase();
  var buf = Buffer.from(await resp.arrayBuffer());
  // ---- STRUCTURAL-FIRST (solo modo PROFUNDO): SVG? -> parsear <text>/fill sin gastar tokens ----
  // Gateado por `deep` para que el modo NORMAL quede byte-identico (un SVG en NORMAL sigue yendo
  // a vision con media_type coercionado a jpeg, como antes).
  if (deep) {
    var esSvg = /(^|;)\s*image\/svg\+xml/i.test(mediaType) || /\.svg(?:$|[?#])/i.test(String(url).split('?')[0]);
    if (esSvg || mediaType === 'text/xml' || mediaType === 'application/xml') {
      try {
        var svgTxt = buf.toString('utf8');
        var parsedSvg = _parsearLotesDeSvg(svgTxt);
        if (parsedSvg && Array.isArray(parsedSvg.lotes) && parsedSvg.lotes.length) return parsedSvg;  // GRATIS: 0 tokens
      } catch (eSvg) { /* svg raro -> caer a vision */ }
      // Si el SVG no dio lotes utiles, no podemos mandarlo como imagen (la API no acepta svg+xml).
      // Devolvemos null (el caller es defensivo: cuenta como "no leido" y sigue).
      if (esSvg) return null;
    }
  }
  // La API de vision solo acepta estos tipos; default a jpeg si viene algo raro (ej PDF/octet-stream).
  if (['image/jpeg', 'image/png', 'image/gif', 'image/webp'].indexOf(mediaType) < 0) mediaType = 'image/jpeg';
  // Prompt: en NORMAL, el prompt HISTORICO exacto (byte-compat). En PROFUNDO, el prompt
  // etapa-aware que pide TODOS los lotes + el grupo etapa/sector (para no pisar "Lote 1" entre etapas).
  var promptVision = deep
    ? ('Este es el plano/masterplan de un loteo o desarrollo inmobiliario. ' +
      'Identifica TODOS los LOTES visibles (no solo algunos) y su ESTADO. Los estados suelen estar codificados por COLOR ' +
      '(ej. verde=disponible/libre, rojo=vendido, amarillo=reservado); si hay una referencia/leyenda ' +
      'de colores en la imagen, usala. Si la imagen agrupa lotes por ETAPA/SECTOR/FASE/MANZANA (ej. "Etapa 1", "Sector B"), ' +
      'poné ese grupo en el campo "etapa" de cada lote (asi dos etapas distintas pueden repetir "Lote 1" sin pisarse). ' +
      'Devolve SOLO un JSON (sin markdown, sin texto alrededor): ' +
      '{ "lotes": [ { "etiqueta":"", "etapa":"", "estado":"disponible|reservado|vendido|libre|desconocido", ' +
      '"superficie_m2": null, "notas":"" } ], "leyenda":"", "confianza":"alta|media|baja" }. ' +
      'Si no podes leerlo con confianza, devolve los que puedas y el resto marcalos "desconocido". ' +
      'No inventes lotes que no ves. "etapa" vacio si no es visible. "superficie_m2" numerico o null.')
    : ('Este es el plano/masterplan de un loteo o desarrollo inmobiliario. ' +
      'Identifica los LOTES visibles y su ESTADO. Los estados suelen estar codificados por COLOR ' +
      '(ej. verde=disponible/libre, rojo=vendido, amarillo=reservado); si hay una referencia/leyenda ' +
      'de colores en la imagen, usala. Devolve SOLO un JSON (sin markdown, sin texto alrededor): ' +
      '{ "lotes": [ { "etiqueta":"", "estado":"disponible|reservado|vendido|libre|desconocido", ' +
      '"superficie_m2": null, "notas":"" } ], "leyenda":"", "confianza":"alta|media|baja" }. ' +
      'Si no podes leerlo con confianza, devolve los que puedas y el resto marcalos "desconocido". ' +
      'No inventes lotes que no ves. "superficie_m2" numerico o null.');
  var r = await anthropic.messages.create({
    model: MODELO_SCRAPE_VISION,
    max_tokens: topeTokens,                                 // NORMAL=2000 / PROFUNDO=hasta PLANO_MAX_TOKENS (mas lotes por imagen)
    messages: [{ role: 'user', content: [
      { type: 'image', source: { type: 'base64', media_type: mediaType, data: buf.toString('base64') } },
      { type: 'text', text: promptVision }
    ] }]
  });
  try { if (user_id && r && r.usage) await registrarUsoTokens(user_id, r.usage, 'scraper_vision', PRECIO_SCRAPE_VISION); } catch (e) {}
  var t = (r && r.content && r.content[0] && r.content[0].text) ? r.content[0].text : '';
  return _parseJsonObjetoDefensivo(t);
}

// ---- FUNCION COMPARTIDA: scrape PROFUNDO de un emprendimiento -----------------
// La usa el endpoint /api/scrape/desarrollo (precarga del form), el endpoint de
// ACTUALIZAR (/api/scrape/desarrollo/actualizar) y el cron de auto-update. Recibe la
// URL + el owner (para registrar tokens) y devuelve un objeto de resultado uniforme:
//   { ok:true, data:{...}, imagenes_encontradas, planos_analizados, aviso }
//   { ok:false, status, error }   (status = codigo HTTP sugerido para el endpoint)
// NO usa req/res: es reutilizable desde un cron. NO tira excepciones esperables
// (las convierte en { ok:false, ... }); solo bugs inesperados suben.
// `opts` (opcional): { plano_deep:true } prende el modo PROFUNDO SOLO en este scrapeo
// (mas imagenes de plano + max_tokens de vision mas alto). Sin opts -> modo NORMAL
// (byte-compat: 5 imagenes / 2000 tokens), salvo que el ENV PLANO_DEEP='true' lo prenda global.
async function _scrapeDesarrolloProfundo(url, user_id, opts) {
  var _deepCfg = _planoDeepCfg(opts);   // { deep, maxImagenes, maxTokens } — gate de costo resuelto
  // ---- Validar url ----
  url = (url || '').trim();
  if (!url) return { ok: false, status: 400, error: 'Falta la url del proyecto' };
  if (!/^https?:\/\//i.test(url)) url = 'https://' + url;
  try { new URL(url); } catch (eUrl) { return { ok: false, status: 400, error: 'La url no es valida' }; }

  // ---- Fetch de la pagina (fetch TLS-tolerante, mismo mecanismo que el scraper inmobiliaria) ----
  // Las paginas de desarrolladoras son SERVER-RENDERED: el fetch plano ya trae TODO el texto
  // (descripcion, amenities, master plan, etapas, equipo, ubicacion). NO hace falta headless.
  var html = '';
  try {
    var r = await fetchScrape(url);
    if (!r || !r.ok) return { ok: false, status: 502, error: 'No se pudo acceder a la pagina (status ' + (r ? r.status : 'sin respuesta') + ')' };
    html = await r.text();
  } catch (eFetch) {
    return { ok: false, status: 502, error: 'No se pudo bajar la pagina: ' + (eFetch && eFetch.message ? eFetch.message : 'error de red/timeout') };
  }
  if (!html || html.length < 50) return { ok: false, status: 502, error: 'La pagina vino vacia o inaccesible' };

  // ---- Texto visible para la IA (truncado a _MAX_TEXTO_DESARROLLO ~40k para capturar TODA la pagina) ----
  var texto = _htmlParaIA(html, _MAX_TEXTO_DESARROLLO);
  // ---- Imagenes + PDFs (con filename como pista para clasificar) ----
  var imgs = _extraerImagenesDesarrollo(html, url, 60);
  var listaImgs = imgs.map(function (x, i) { return (i + 1) + '. ' + x.filename + ' -> ' + x.url; }).join('\n');

  if ((!texto || texto.length < 60) && imgs.length === 0) {
    return { ok: false, status: 422, error: 'La pagina no tiene texto ni imagenes utiles para analizar (¿render por JS?)' };
  }

  // ---- Extraccion con IA (Sonnet por default; ver MODELO_SCRAPE_DESARROLLO) ----
  if (!process.env.ANTHROPIC_KEY) return { ok: false, status: 503, error: 'IA no disponible (sin ANTHROPIC_KEY)' };
  // Prompt AMPLIADO: capturar TODAS las secciones (el dueño quiere "todo, no parte").
  var sys = 'Sos un extractor EXHAUSTIVO de datos de un proyecto inmobiliario / desarrollo (desarrolladora). ' +
    'Te paso el TEXTO visible COMPLETO de la pagina de UN emprendimiento y una lista de URLs de imagenes con su nombre de archivo. ' +
    'Entende la pagina (se adapta a cualquier estructura) y captura TODO lo relevante. NO inventes datos que no esten: si no aparece, deja "" o null o [].\n' +
    'Devolve EXCLUSIVAMENTE un JSON objeto (sin markdown, sin texto alrededor) con esta forma EXACTA:\n' +
    '{\n' +
    '  "emprendimiento": { "nombre":"", "ubicacion":"", "descripcion":"", "estado_obra":"", "fecha_entrega":"", "amenities":[], "financiacion":"", "contacto":"", "link":"' + url + '" },\n' +
    '  "resumen": { "superficie_total":"", "lotes_total":null, "lotes_vendidos":null, "lotes_disponibles":null, "tamanos_lotes":"", "etapas":[ { "nombre":"", "anio":"", "lotes":null, "estado":"" } ] },\n' +
    '  "master_plan": [ { "etapa":"", "anio":"", "descripcion":"", "estado":"" } ],\n' +
    '  "equipo": [ { "nombre":"", "rol":"" } ],\n' +
    '  "ubicacion_detalle": { "direccion":"", "coordenadas":"", "distancias":[ { "referencia":"", "distancia":"" } ] },\n' +
    '  "tipologias": [ { "tipo":"", "ambientes":null, "superficie_m2":null, "precio":null, "moneda":"", "disponibilidad":"", "notas":"" } ],\n' +
    '  "imagenes": { "fotos":[], "planos":[], "renders":[] }\n' +
    '}\n' +
    'REGLAS:\n' +
    '- "descripcion": el texto descriptivo COMPLETO del emprendimiento (concepto, propuesta, entorno). NO lo resumas de mas; captura los parrafos relevantes.\n' +
    '- "estado_obra": normaliza a "pozo", "en_construccion" o "terminado" si el texto lo permite; si no, deja el texto tal cual o "".\n' +
    '- "amenities": lista de strings con TODOS los que aparezcan (Pileta, Gimnasio, SUM, Seguridad 24hs, Cochera, Club House, Cancha, Laguna, etc.).\n' +
    '- "resumen": superficie total del predio, cantidad total de lotes/unidades, cuantos vendidos y disponibles si el TEXTO lo dice (esto es el OVERVIEW, no el estado lote-por-lote), rango de tamaños, y las ETAPAS con su año y cantidad de lotes/estado. Numeros como numero o null.\n' +
    '- "master_plan": las etapas/fases del proyecto en el tiempo (etapa 1/2/3, por año), con su descripcion y estado. Si no hay, [].\n' +
    '- "equipo": desarrolladora/estudio/arquitectos/comercializadora mencionados, con su rol. Si no hay, [].\n' +
    '- "ubicacion_detalle": direccion exacta, coordenadas si estan, y distancias a puntos de referencia (centro, aeropuerto, ruta, ciudad). Si no hay, dejar vacio/[].\n' +
    '- "tipologias": una por cada tipo de unidad/depto/lote que ofrezca (Monoambiente, 2 ambientes, Lote, etc.). "ambientes"/"superficie_m2"/"precio" numericos (o null). "moneda" en USD/ARS/PYG si se sabe.\n' +
    '- "imagenes": clasifica CADA URL de la lista en fotos (obra/entorno/reales), planos (planta/plano/layout/masterplan/loteo) o renders (render/ilustracion/fachada 3D). Usa el nombre de archivo (plano, planta, masterplan, render, fachada, amenities, brochure) y el contexto. Los PDF suelen ser planos o brochure -> ponelos en "planos". Devolve las URLs COMPLETAS tal cual te las paso. Si dudas, "fotos".';

  var userMsg = 'TEXTO DE LA PAGINA:\n' + (texto || '(sin texto)') + '\n\n' +
    'IMAGENES / PDF ENCONTRADOS (nombre -> url):\n' + (listaImgs || '(ninguna)');

  var iaResp;
  try {
    iaResp = await anthropic.messages.create({
      model: MODELO_SCRAPE_DESARROLLO,
      max_tokens: 4000,                                     // subido de 2500 -> 4000 por las secciones nuevas (resumen/masterplan/equipo/ubicacion)
      system: sys,
      messages: [{ role: 'user', content: userMsg }]
    });
  } catch (eIA) {
    return { ok: false, status: 502, error: 'La IA no pudo procesar la pagina: ' + (eIA && eIA.message ? eIA.message : 'error') };
  }
  // Costo -> panel (best-effort, con el precio del MODELO usado)
  try { if (iaResp && iaResp.usage) await registrarUsoTokens(user_id, iaResp.usage, 'scraper_desarrollo', PRECIO_SCRAPE_DESARROLLO); } catch (eTok) {}

  var txt = (iaResp && iaResp.content && iaResp.content[0] && iaResp.content[0].text) ? iaResp.content[0].text : '';
  var parsed = _parseJsonObjetoDefensivo(txt);
  if (!parsed || typeof parsed !== 'object') {
    return { ok: false, status: 422, error: 'La IA no devolvio un JSON valido. Reintentá o cargá el emprendimiento a mano.' };
  }

  // ---- Normalizar la salida a la forma prometida (defensivo: nunca undefined) ----
  var emp = parsed.emprendimiento || {};
  var tipologias = Array.isArray(parsed.tipologias) ? parsed.tipologias : [];
  var imagenes = parsed.imagenes || {};
  function _arrStr(a) { return Array.isArray(a) ? a.filter(function (x) { return x != null && String(x).trim() !== ''; }).map(String) : []; }
  function _numONull2(v) { if (v === null || v === undefined || v === '') return null; var n = Number(v); return isNaN(n) ? null : n; }
  function _s(v) { return v != null ? String(v) : ''; }
  // Normalizar secciones nuevas (todas opcionales, siempre en un shape estable)
  var pr = parsed.resumen || {};
  var etapasPr = Array.isArray(pr.etapas) ? pr.etapas : [];
  var resumen = {
    superficie_total: _s(pr.superficie_total),
    lotes_total: _numONull2(pr.lotes_total),
    lotes_vendidos: _numONull2(pr.lotes_vendidos),
    lotes_disponibles: _numONull2(pr.lotes_disponibles),
    tamanos_lotes: _s(pr.tamanos_lotes),
    etapas: etapasPr.map(function (e) { e = e || {}; return { nombre: _s(e.nombre), anio: _s(e.anio), lotes: _numONull2(e.lotes), estado: _s(e.estado) }; })
  };
  var mpPr = Array.isArray(parsed.master_plan) ? parsed.master_plan : [];
  var master_plan = mpPr.map(function (m) { m = m || {}; return { etapa: _s(m.etapa), anio: _s(m.anio), descripcion: _s(m.descripcion), estado: _s(m.estado) }; });
  var eqPr = Array.isArray(parsed.equipo) ? parsed.equipo : [];
  var equipo = eqPr.map(function (m) { m = m || {}; return { nombre: _s(m.nombre), rol: _s(m.rol) }; });
  var ubPr = parsed.ubicacion_detalle || {};
  var distPr = Array.isArray(ubPr.distancias) ? ubPr.distancias : [];
  var ubicacion_detalle = {
    direccion: _s(ubPr.direccion),
    coordenadas: _s(ubPr.coordenadas),
    distancias: distPr.map(function (d) { d = d || {}; return { referencia: _s(d.referencia), distancia: _s(d.distancia) }; })
  };

  var data = {
    emprendimiento: {
      nombre: emp.nombre != null ? String(emp.nombre) : '',
      ubicacion: emp.ubicacion != null ? String(emp.ubicacion) : '',
      descripcion: emp.descripcion != null ? String(emp.descripcion) : '',
      estado_obra: emp.estado_obra != null ? String(emp.estado_obra) : '',
      fecha_entrega: emp.fecha_entrega != null ? String(emp.fecha_entrega) : '',
      amenities: _arrStr(emp.amenities),
      financiacion: emp.financiacion != null ? String(emp.financiacion) : '',
      contacto: emp.contacto != null ? String(emp.contacto) : '',
      link: emp.link != null && String(emp.link).trim() ? String(emp.link) : url
    },
    resumen: resumen,
    master_plan: master_plan,
    equipo: equipo,
    ubicacion_detalle: ubicacion_detalle,
    tipologias: tipologias.map(function (t) {
      t = t || {};
      return {
        tipo: t.tipo != null ? String(t.tipo) : '',
        ambientes: (t.ambientes === null || t.ambientes === undefined || t.ambientes === '') ? null : (isNaN(Number(t.ambientes)) ? t.ambientes : Number(t.ambientes)),
        superficie_m2: (t.superficie_m2 === null || t.superficie_m2 === undefined || t.superficie_m2 === '') ? null : (isNaN(Number(t.superficie_m2)) ? t.superficie_m2 : Number(t.superficie_m2)),
        precio: (t.precio === null || t.precio === undefined || t.precio === '') ? null : (isNaN(Number(t.precio)) ? t.precio : Number(t.precio)),
        moneda: t.moneda != null ? String(t.moneda) : '',
        disponibilidad: t.disponibilidad != null ? String(t.disponibilidad) : '',
        notas: t.notas != null ? String(t.notas) : ''
      };
    }),
    imagenes: {
      fotos: _arrStr(imagenes.fotos),
      planos: _arrStr(imagenes.planos),
      renders: _arrStr(imagenes.renders)
    }
  };

  // aviso si la IA no clasifico ninguna imagen pero SI habia imagenes en la pagina
  var clasificadas = data.imagenes.fotos.length + data.imagenes.planos.length + data.imagenes.renders.length;
  var aviso = '';
  if (imgs.length > 0 && clasificadas === 0) aviso = 'Se encontraron ' + imgs.length + ' imagenes pero la IA no las clasifico; revisalas manualmente.';
  else if (!data.emprendimiento.nombre) aviso = 'No se detecto el nombre del emprendimiento; completalo a mano.';

  // ---- PASO DE VISION: leer LOTES + estado del/los PLANO(S) --------------------
  // El texto de la pagina NO trae el estado de los lotes uno-por-uno (esta EN LA IMAGEN, por color).
  // Aca miramos HASTA _deepCfg.maxImagenes planos (NORMAL=5 / PROFUNDO=hasta PLANO_MAX_IMAGENES)
  // con hasta _deepCfg.maxTokens de salida por imagen, y fusionamos los lotes que la vision lea.
  // 100% DEFENSIVO: si no hay plano, o no se puede bajar, o la vision falla/parsea mal,
  // NO rompemos el scrape -> devolvemos data:{...,lotes:[]} con un aviso. El costo de
  // vision SOLO se paga si hay al menos un plano para mirar.
  data.lotes = [];
  var _normEstadoLote = function (e) {
    var n = (e == null ? '' : String(e)).toLowerCase().normalize('NFD').replace(/[̀-ͯ]/g, '').trim();
    if (['disponible', 'reservado', 'vendido', 'libre'].indexOf(n) >= 0) return n;
    return 'desconocido';
  };
  var _numONull = function (v) {
    if (v === null || v === undefined || v === '') return null;
    var num = Number(v);
    return isNaN(num) ? null : num;
  };
  var planosParaMirar = _elegirPlanosParaVision(data.imagenes, _deepCfg.maxImagenes);
  var resumen_lotes = { total: 0, disponibles: 0, reservados: 0, vendidos: 0, leyenda: '', confianza: '', modo: _deepCfg.deep ? 'profundo' : 'normal' };
  if (planosParaMirar.length === 0) {
    // no hay nada que mirar -> no se cobra vision; aviso claro (sin pisar un aviso previo mas importante)
    if (!aviso) aviso = 'No se encontro un plano/masterplan para leer los lotes; cargalos a mano.';
  } else {
    var lotesFusion = [];
    var vistoLote = {};                                   // dedup por (etapa/sector + etiqueta) normalizada
    var leyendas = [];
    var confianzas = [];
    var algunoOk = false;
    for (var pi = 0; pi < planosParaMirar.length; pi++) {
      var urlPlano = planosParaMirar[pi];
      try {
        var visionOut = await _leerLotesDePlano(urlPlano, user_id, _deepCfg.maxTokens, _deepCfg.deep);
        if (visionOut && typeof visionOut === 'object') {
          algunoOk = true;
          if (visionOut.leyenda != null && String(visionOut.leyenda).trim()) leyendas.push(String(visionOut.leyenda).trim());
          if (visionOut.confianza != null && String(visionOut.confianza).trim()) confianzas.push(String(visionOut.confianza).trim().toLowerCase());
          var lotesArr = Array.isArray(visionOut.lotes) ? visionOut.lotes : [];
          for (var li = 0; li < lotesArr.length; li++) {
            var lo = lotesArr[li] || {};
            var etiqueta = lo.etiqueta != null ? String(lo.etiqueta).trim() : '';
            // etapa/sector: si el modelo (o el SVG) la trae, la usamos para NO pisar "Lote 1" entre etapas.
            var etapaLote = (lo.etapa != null && String(lo.etapa).trim()) ? String(lo.etapa).trim()
              : (lo.sector != null && String(lo.sector).trim() ? String(lo.sector).trim() : '');
            var estado = _normEstadoLote(lo.estado);
            // dedup por (etapa + etiqueta): dos etapas distintas pueden repetir "Lote 1" sin pisarse.
            // Etiqueta vacia SIEMPRE entra (no hay clave). Cuando no hay etapa, el key cae a solo-etiqueta
            // (comportamiento historico dentro de un mismo plano/etapa).
            var claveDedup = etiqueta ? ('e:' + etapaLote.toLowerCase() + '|' + etiqueta.toLowerCase()) : null;
            if (claveDedup && vistoLote[claveDedup]) continue;
            if (claveDedup) vistoLote[claveDedup] = 1;
            lotesFusion.push({
              etiqueta: etiqueta,
              etapa: etapaLote,
              estado: estado,
              superficie_m2: _numONull(lo.superficie_m2),
              notas: lo.notas != null ? String(lo.notas) : ''
            });
          }
        }
      } catch (eVis) {
        // un plano fallo (fetch/base64/vision) -> seguimos con el proximo, no rompemos
        console.log('scrape/desarrollo vision plano fallo:', urlPlano, '-', (eVis && eVis.message) ? eVis.message : eVis);
      }
    }
    data.lotes = lotesFusion;
    // resumen agregado
    resumen_lotes.total = lotesFusion.length;
    lotesFusion.forEach(function (l) {
      if (l.estado === 'disponible' || l.estado === 'libre') resumen_lotes.disponibles++;
      else if (l.estado === 'reservado') resumen_lotes.reservados++;
      else if (l.estado === 'vendido') resumen_lotes.vendidos++;
    });
    resumen_lotes.leyenda = leyendas.join(' | ');
    // confianza global = la MAS BAJA de las lecturas (conservador); si no hubo, ''
    if (confianzas.indexOf('baja') >= 0) resumen_lotes.confianza = 'baja';
    else if (confianzas.indexOf('media') >= 0) resumen_lotes.confianza = 'media';
    else if (confianzas.indexOf('alta') >= 0) resumen_lotes.confianza = 'alta';
    // avisos especificos de vision (sin pisar un aviso previo mas importante)
    if (!algunoOk && !aviso) aviso = 'Se encontro un plano pero no se pudieron leer los lotes; revisalos manualmente.';
    else if (algunoOk && lotesFusion.length === 0 && !aviso) aviso = 'Se leyo el plano pero no se identificaron lotes; revisalo manualmente.';
  }
  data.resumen_lotes = resumen_lotes;

  return {
    ok: true,
    data: data,
    imagenes_encontradas: imgs.length,
    planos_analizados: planosParaMirar.length,
    aviso: aviso || undefined
  };
}

app.post('/api/scrape/desarrollo', async function (req, res) {
  try {
    // ---- AUTH + owner (asesor -> admin_id, como el resto de endpoints) ----
    var user_id = await verificarUsuario(req);
    if (!user_id) return res.status(401).json({ error: 'No autorizado' });
    try {
      var _yo = await supabase.from('asesores').select('admin_id').eq('auth_user_id', user_id).maybeSingle();
      if (_yo && _yo.data && _yo.data.admin_id) user_id = _yo.data.admin_id; // el owner del tenant (sin fila -> es el dueño)
    } catch (eOwner) { /* sin fila -> user_id queda como esta */ }

    var url = ((req.body && req.body.url) || '').trim();
    if (!url) return res.status(400).json({ error: 'Falta la url del proyecto' });

    // 🔴 Gate de costo por-scrapeo: el body puede pedir modo PROFUNDO (mas imagenes/tokens de vision).
    // Con plano_deep ausente/false -> modo NORMAL (salvo que el ENV PLANO_DEEP lo prenda global).
    var _opts = { plano_deep: !!(req.body && (req.body.plano_deep === true || req.body.plano_deep === 'true')) };
    var out = await _scrapeDesarrolloProfundo(url, user_id, _opts);
    if (!out.ok) return res.status(out.status || 500).json({ error: out.error || 'Error interno' });
    return res.json({
      ok: true,
      data: out.data,
      imagenes_encontradas: out.imagenes_encontradas,
      planos_analizados: out.planos_analizados,
      aviso: out.aviso
    });
  } catch (e) {
    return res.status(500).json({ error: e && e.message ? e.message : 'Error interno' });
  }
});


// ============================================================================
// ACTUALIZAR UN EMPRENDIMIENTO POR SCRAPING  (manual + automatico)  — ADITIVO
// ----------------------------------------------------------------------------
// Vuelve a scrapear la source_url de UN emprendimiento y REEMPLAZA su ficha
// (development + sectores + unidades), reusando _scrapeDesarrolloProfundo (scraper
// profundo A) + guardarDesarrolladora (mismo UPDATE/reemplazo que /api/inventario/guardar).
// Lo usan el endpoint manual (/api/scrape/desarrollo/actualizar) y el cron de auto-update.
// ============================================================================

// Mapea la SALIDA del scraper (data:{emprendimiento,resumen,master_plan,equipo,
// ubicacion_detalle,tipologias,imagenes,lotes,resumen_lotes}) al BODY que espera
// guardarDesarrolladora ({ development, dev_data, sectores, unidades }). Es un mapeo
// CONSERVADOR: lo que no tiene columna propia va a dev_data (jsonb) para no perder nada.
//   - emprendimiento.nombre/descripcion/estado_obra/fecha_entrega/link/ubicacion -> development
//   - amenities/resumen/master_plan/equipo/ubicacion_detalle/tipologias/lotes overview -> dev_data.*
//   - etapas del resumen -> sectores (nombre = etapa, para que queden como filas)
//   - lotes leidos por vision -> unidades (tipo_producto 'lote', numero=etiqueta, estado)
// development_id se inyecta aparte (en actualizarDevelopment) para forzar el UPDATE.
// `sourceUrl` (opcional): la URL que se scrapeo. Se persiste en development.source_url para
// que el emprendimiento creado por scrape quede RE-ACTUALIZABLE (guardarDesarrolladora la
// escribe si dev.source_url !== undefined). Si no viene, cae a emp.link (que el scraper ya
// rellena con la url scrapeada como fallback).
function _mapScrapeAGuardar(data, sourceUrl) {
  data = data || {};
  var emp = data.emprendimiento || {};
  var resumen = data.resumen || {};
  var etapas = Array.isArray(resumen.etapas) ? resumen.etapas : [];
  var lotes = Array.isArray(data.lotes) ? data.lotes : [];
  // URL de origen: la explicita (la que se paso a _scrapeDesarrolloProfundo) o, en su defecto,
  // el link que el scraper dejo en emprendimiento.link. '' si no hay ninguna (no rompe el guardado).
  var _srcUrl = (sourceUrl != null && String(sourceUrl).trim()) ? String(sourceUrl).trim()
    : (emp.link != null && String(emp.link).trim() ? String(emp.link).trim() : '');

  // DIRECCION (Fase 1): la calle exacta que scrapea la IA vive en ubicacion_detalle.direccion.
  // La sacamos a campos de primer nivel (antes quedaba SOLO enterrada en dev_data.material) para
  // que guardarDesarrolladora la persista en las columnas nuevas y la IA la lea.
  var _ubDet = data.ubicacion_detalle || {};
  var development = {
    nombre: emp.nombre || '',
    // "tipo" del emprendimiento no lo infiere el scraper de forma fiable -> lo dejamos vacio (no pisa nada malo).
    tipo: '',
    zona: emp.ubicacion || '',
    direccion: (_ubDet && _ubDet.direccion) ? String(_ubDet.direccion) : '',
    entre_calles: (_ubDet && (_ubDet.entre_calles || _ubDet.entrecalles)) ? String(_ubDet.entre_calles || _ubDet.entrecalles) : '',
    ciudad: (_ubDet && _ubDet.ciudad) ? String(_ubDet.ciudad) : (emp.ubicacion || ''),
    descripcion: emp.descripcion || '',
    link: emp.link || '',
    // source_url: URL scrapeada -> guardarDesarrolladora la persiste (v2). Sin esto, un emprendimiento
    // creado por scrape quedaba SIN URL de origen y NO se podia re-actualizar por scraping.
    source_url: _srcUrl,
    estado_obra: emp.estado_obra || '',
    // avance_pct no viene del scraper -> null.
    avance_pct: null,
    fecha_entrega: emp.fecha_entrega || ''
  };

  // FIX Etapa 1 (bug planes): el prompt de la IA (armarInventarioDesarrollos) lee
  // dev_data.planes como ARRAY de {nombre,anticipo,cuotas,ajuste,refuerzos,moneda}. Antes el
  // scraper guardaba `planes` como OBJETO {financiacion,contacto,tipologias} => la financiacion
  // scrapeada NUNCA llegaba a la IA ni se podia editar en el form. Ahora la financiacion se
  // guarda como un PLAN en el array (mismo shape que el form: nombre 'Financiación' + refuerzos),
  // y contacto/tipologias se mueven a `material` (que guardarDesarrolladora persiste igual) para
  // no perder nada. 0 IA.
  var _finTxt = emp.financiacion ? String(emp.financiacion).trim() : '';
  var dev_data = {
    amenities: Array.isArray(emp.amenities) ? emp.amenities : [],
    planes: _finTxt ? [{ nombre: 'Financiación', anticipo: '', cuotas: '', ajuste: 'fijo', refuerzos: _finTxt, moneda: '' }] : [],
    // "material" reutiliza el jsonb existente para el material descriptivo scrapeado + contacto/tipologias.
    material: {
      resumen: resumen,
      master_plan: Array.isArray(data.master_plan) ? data.master_plan : [],
      equipo: Array.isArray(data.equipo) ? data.equipo : [],
      ubicacion_detalle: data.ubicacion_detalle || {},
      resumen_lotes: data.resumen_lotes || {},
      contacto: emp.contacto || '',
      tipologias: Array.isArray(data.tipologias) ? data.tipologias : []
    },
    legal: {}
  };

  // Sectores = etapas del OVERVIEW (nombre no vacio). Cada etapa -> una fila de sector.
  var sectores = etapas
    .filter(function (e) { return e && String(e.nombre || '').trim(); })
    .map(function (e) { return { nombre: String(e.nombre), tipo: 'etapa', fecha_entrega: e.anio ? String(e.anio) : '' }; });

  // Unidades = lotes leidos por vision (overview lote-por-lote, si el plano lo permitio).
  var unidades = lotes.map(function (l) {
    l = l || {};
    return {
      tipo_producto: 'lote',
      numero: l.etiqueta || '',
      tipologia: '',
      superficie_terreno: (l.superficie_m2 === null || l.superficie_m2 === undefined) ? '' : l.superficie_m2,
      estado: l.estado || 'disponible',
      precio_estado: 'a_consultar',
      moneda: 'USD'
    };
  });

  return { development: development, dev_data: dev_data, sectores: sectores, unidades: unidades };
}

// Orquesta: scrapea `sourceUrl` (scraper profundo) -> mapea -> guardarDesarrolladora con
// development_id forzado (UPDATE + reemplazo de sectores/unidades) -> setea ultimo_scrape.
// NO usa req/res: reusable desde el endpoint manual y desde el cron. Devuelve
// { ok:true, ...resultadoGuardar, scrape:{...} } o { ok:false, status, error }.
// `opts` (opcional): { plano_deep:true } prende el modo PROFUNDO de vision en este scrapeo.
async function actualizarDevelopment(devId, ownerId, sourceUrl, opts) {
  if (!sourceUrl || !String(sourceUrl).trim()) {
    return { ok: false, status: 400, error: 'El emprendimiento no tiene URL de origen (source_url) para actualizar.' };
  }
  // 1) Scrape profundo de la source_url (reusa la funcion de A; registra tokens con ownerId).
  var scr = await _scrapeDesarrolloProfundo(sourceUrl, ownerId, opts);
  if (!scr.ok) return { ok: false, status: scr.status || 502, error: scr.error || 'No se pudo scrapear la pagina' };

  // 2) Map -> body de guardarDesarrolladora + inyectar development_id para FORZAR el UPDATE.
  //    Pasamos sourceUrl al mapper -> se persiste source_url (el dev sigue siendo re-actualizable).
  var body = _mapScrapeAGuardar(scr.data, sourceUrl);
  body.development_id = devId;

  // 3) MERGE de sectores/unidades (misma logica que /api/inventario/guardar) pero con
  //    origen 'scraper': NUNCA borra unidades, NUNCA pisa `estado` manual, y si el scrape
  //    devolvio unidades=[] NO toca las unidades (IDs estables — Etapa 1).
  var g = await guardarDesarrolladora(ownerId, body, { origen: 'scraper' });
  if (!g.ok) return { ok: false, status: g.status || 500, error: g.error, tabla: g.tabla, development_id: g.development_id };

  // 4) Marcar ultimo_scrape (best-effort; si la columna no existe todavia, no rompe).
  try { await supabase.from('developments').update({ ultimo_scrape: new Date().toISOString() }).eq('id', devId).eq('user_id', ownerId); } catch (eTs) {}

  return {
    ok: true,
    status: 200,
    development_id: g.development_id,
    sectores_guardados: g.sectores_guardados,
    unidades_guardadas: g.unidades_guardadas,
    unidades_con_error: g.unidades_con_error,
    actualizado: true,
    scrape: {
      imagenes_encontradas: scr.imagenes_encontradas,
      planos_analizados: scr.planos_analizados,
      aviso: scr.aviso
    }
  };
}

// ---- POST /api/scrape/desarrollo/actualizar --------------------------------
// Body: { development_id, plano_deep? }. Lee developments.source_url de ese dev (verifica
// tenant), re-scrapea esa URL y REEMPLAZA la ficha. 🔴 COSTO: corre Sonnet + hasta 5 imagenes
// (NORMAL) por corrida; con plano_deep=true (o ENV PLANO_DEEP) sube a modo PROFUNDO (mas caro).
app.post('/api/scrape/desarrollo/actualizar', async function (req, res) {
  try {
    // AUTH + owner (asesor -> admin_id, como el resto de endpoints)
    var user_id = await verificarUsuario(req);
    if (!user_id) return res.status(401).json({ error: 'No autorizado' });
    try {
      var _yo = await supabase.from('asesores').select('admin_id').eq('auth_user_id', user_id).maybeSingle();
      if (_yo && _yo.data && _yo.data.admin_id) user_id = _yo.data.admin_id;
    } catch (eOwner) { /* sin fila -> user_id queda como esta */ }

    var devId = _invStr((req.body && (req.body.development_id || req.body.id)));
    if (!devId) return res.status(400).json({ error: 'Falta development_id' });

    // Traer source_url + verificar tenant (el dev debe pertenecer al owner).
    var dRow = await supabase.from('developments').select('user_id, source_url').eq('id', devId).maybeSingle();
    if (dRow.error) {
      if (_invTablaFaltante(dRow.error)) return res.status(503).json({ error: 'La columna source_url no existe todavia (o la tabla developments). Corré la migracion migracion-scraper-desarrollo-v2.sql.', tabla: 'developments' });
      return res.status(500).json({ error: 'Error leyendo el emprendimiento: ' + dRow.error.message });
    }
    if (!dRow.data) return res.status(404).json({ error: 'El emprendimiento no existe', development_id: devId });
    if (dRow.data.user_id !== user_id) return res.status(403).json({ error: 'El emprendimiento no pertenece a tu cuenta' });
    var sourceUrl = (dRow.data.source_url || '').trim();
    if (!sourceUrl) return res.status(400).json({ error: 'Este emprendimiento no tiene URL de origen guardada. Guardá la source_url antes de actualizar por scraping.' });

    // 🔴 Gate de costo por-scrapeo (opt-in): body.plano_deep=true -> modo PROFUNDO en esta corrida.
    var _opts = { plano_deep: !!(req.body && (req.body.plano_deep === true || req.body.plano_deep === 'true')) };
    var r = await actualizarDevelopment(devId, user_id, sourceUrl, _opts);
    if (!r.ok) return res.status(r.status || 500).json(r);
    delete r.status;
    return res.json(r);
  } catch (e) {
    return res.status(500).json({ error: e && e.message ? e.message : 'Error interno' });
  }
});

// ---- CRON: auto-update de emprendimientos (OPT-IN, default OFF) -------------
// Cada hora busca developments con auto_scrape=true cuyo ultimo_scrape sea mas viejo
// que scrape_cada_horas y los re-scrapea (misma funcion actualizarDevelopment).
// 🔴 COSTO: corre Sonnet + vision por emprendimiento -> por eso es OPT-IN por dev y el
// default es conservador (auto_scrape OFF, cada 24hs). GATEADO defensivo: si las columnas
// de la migracion v2 no existen, el query falla -> NO corre nada (no rompe el server).
async function revisarScrapingsDesarrollo() {
  try {
    var q = await supabase.from('developments')
      .select('id, user_id, source_url, scrape_cada_horas, ultimo_scrape')
      .eq('auto_scrape', true);
    // Gate defensivo: columnas de la migracion v2 ausentes -> salir en silencio (no corre, no loguea error ruidoso).
    if (q.error) {
      if (!_invTablaFaltante(q.error)) console.log('[cron auto-scrape desarrollo] query fallo:', q.error.message);
      return;
    }
    var devs = q.data || [];
    if (!devs.length) return;
    var ahora = Date.now();
    for (var i = 0; i < devs.length; i++) {
      var d = devs[i];
      var url = (d.source_url || '').trim();
      if (!url) continue;                                   // sin url -> nada que scrapear
      var cada = Number(d.scrape_cada_horas);
      if (!cada || isNaN(cada) || cada < 1) cada = 24;      // default conservador
      // ¿le toca? nunca corrio, o paso mas tiempo que scrape_cada_horas desde el ultimo.
      var due = true;
      if (d.ultimo_scrape) {
        var last = new Date(d.ultimo_scrape).getTime();
        if (!isNaN(last) && (ahora - last) < cada * 3600 * 1000) due = false;
      }
      if (!due) continue;
      // P1 (CRON): freno de gasto IA por tope de plan (el gate HTTP no cubre los cron). Si la cuenta paso su
      // tope -> saltear SIN tocar ultimo_scrape, asi reintenta cuando tenga cupo. Cortesia/ilimitado => pasa.
      try { if (!(await dentroDelTopeIA(d.user_id))) { console.log('[cron auto-scrape desarrollo] dev', d.id, 'salteado: cuenta sin cupo IA'); continue; } } catch (eTope) {}
      try {
        console.log('[cron auto-scrape desarrollo] actualizando dev', d.id, 'de', url, '(cada', cada, 'hs)');
        var r = await actualizarDevelopment(d.id, d.user_id, url);
        console.log('[cron auto-scrape desarrollo] dev', d.id, r.ok ? ('OK sectores=' + r.sectores_guardados + ' unidades=' + r.unidades_guardadas) : ('FALLO: ' + r.error));
      } catch (eDev) {
        console.log('[cron auto-scrape desarrollo] dev', d.id, 'excepcion:', (eDev && eDev.message) ? eDev.message : eDev);
      }
    }
  } catch (e) {
    console.log('[cron auto-scrape desarrollo] error general:', (e && e.message) ? e.message : e);
  }
}
// Revisar cada hora, con un arranque a los 2 min del deploy (misma cadencia que el cron de inmobiliaria).
setInterval(revisarScrapingsDesarrollo, 60 * 60 * 1000);
setTimeout(revisarScrapingsDesarrollo, 120 * 1000);


// ============================================================================
// SCRAPE JOBS  —  TRABAJOS DE SCRAPING EN SEGUNDO PLANO (server-side)  — ADITIVO
// ----------------------------------------------------------------------------
// El scrape de DESARROLLO corre como TRABAJO EN SEGUNDO PLANO del server: el
// usuario lo dispara (POST .../job), sale de la pagina, vuelve, y sigue corriendo
// (no depende del navegador). Los jobs viven en la tabla scrape_jobs -> sobreviven
// a que el usuario cierre el navegador Y a reinicios del server (los 'pendiente'
// se retoman en el proximo tick del runner). El runner (cron procesarScrapeJobs)
// toma DE A UNO el job 'pendiente' mas viejo, lo marca 'corriendo', lo procesa
// segun `tipo` y va actualizando estado/progreso/mensaje/resultado.
//
// 🔴 COSTO: cada job de scrape corre Sonnet + vision (~10-40s). El runner procesa
//    DE A UNO (no en paralelo) para no disparar el gasto/carga.
//
// GATEADO DEFENSIVO: si la tabla scrape_jobs no existe todavia (migracion no
// corrida), los endpoints devuelven un error claro (_invTablaFaltante) y el runner
// sale en silencio -> no rompe el server.
// ============================================================================

// Resuelve el OWNER del tenant a partir del uid del token (asesor -> admin_id).
// Mismo patron que /api/scrape/desarrollo y el resto de endpoints.
async function _resolverOwner(uid) {
  try {
    var _yo = await supabase.from('asesores').select('admin_id').eq('auth_user_id', uid).maybeSingle();
    if (_yo && _yo.data && _yo.data.admin_id) return _yo.data.admin_id; // owner del tenant
  } catch (eOwner) { /* sin fila -> es el dueño; queda el uid */ }
  return uid;
}

// Setea progreso/mensaje (y campos opcionales) de un job. Best-effort: si falla
// el UPDATE (p.ej. tabla ausente en medio de un deploy), NO tira: el runner sigue.
async function _scrapeJobUpdate(jobId, patch) {
  try {
    patch = patch || {};
    patch.updated_at = new Date().toISOString();
    await supabase.from('scrape_jobs').update(patch).eq('id', jobId);
  } catch (e) { /* best-effort */ }
}

// ---- POST /api/scrape/desarrollo/job ---------------------------------------
// Body: { url } (nuevo) o { development_id } (update; lee su source_url).
// Crea una fila 'pendiente' en scrape_jobs y DEVUELVE AL INSTANTE { ok, job_id }.
// NO ejecuta el scrape aca -> lo hace el runner (procesarScrapeJobs) en segundo plano.
app.post('/api/scrape/desarrollo/job', async function (req, res) {
  try {
    // AUTH + owner (asesor -> admin_id).
    var uid = await verificarUsuario(req);
    if (!uid) return res.status(401).json({ error: 'No autorizado' });
    var user_id = await _resolverOwner(uid);

    var url = ((req.body && req.body.url) || '').trim();
    var devId = _invStr((req.body && (req.body.development_id || req.body.id)));

    var tipo, input, devIdCol = null;
    if (devId) {
      // UPDATE: leer la source_url del emprendimiento + verificar tenant.
      var dRow = await supabase.from('developments').select('user_id, source_url').eq('id', devId).maybeSingle();
      if (dRow.error) {
        if (_invTablaFaltante(dRow.error)) return res.status(503).json({ error: 'La tabla developments o su columna source_url no existe todavia. Corré migracion-scraper-desarrollo-v2.sql.', tabla: 'developments' });
        return res.status(500).json({ error: 'Error leyendo el emprendimiento: ' + dRow.error.message });
      }
      if (!dRow.data) return res.status(404).json({ error: 'El emprendimiento no existe', development_id: devId });
      if (dRow.data.user_id !== user_id) return res.status(403).json({ error: 'El emprendimiento no pertenece a tu cuenta' });
      var sourceUrl = (dRow.data.source_url || '').trim();
      if (!sourceUrl) return res.status(400).json({ error: 'Este emprendimiento no tiene URL de origen guardada. Guardá la source_url antes de actualizar por scraping.' });
      tipo = 'desarrollo_update';
      input = { development_id: devId, source_url: sourceUrl };
      devIdCol = devId;
    } else if (url) {
      tipo = 'desarrollo_nuevo';
      // 🔴 Gate de costo por-scrapeo (opt-in): body.plano_deep=true -> el job corre en modo
      // PROFUNDO (plano lote-por-lote, mas caro). Se guarda DENTRO del input para que el runner
      // lo lea. Ausente/false -> NORMAL (identico al comportamiento anterior).
      input = { url: url, plano_deep: !!(req.body && (req.body.plano_deep === true || req.body.plano_deep === 'true')) };
    } else {
      return res.status(400).json({ error: 'Falta la url del proyecto (o development_id para actualizar)' });
    }

    var ins = await supabase.from('scrape_jobs').insert({
      user_id: user_id,
      tipo: tipo,
      input: input,
      estado: 'pendiente',
      progreso: 0,
      mensaje: 'En cola…',
      development_id: devIdCol
    }).select('id').single();

    if (ins.error) {
      if (_invTablaFaltante(ins.error)) return res.status(503).json({ error: 'La tabla scrape_jobs no existe todavia. Corré migracion-scrape-jobs.sql.', tabla: 'scrape_jobs' });
      return res.status(500).json({ error: 'No se pudo encolar el trabajo: ' + ins.error.message });
    }

    return res.json({ ok: true, job_id: ins.data.id });
  } catch (e) {
    return res.status(500).json({ error: e && e.message ? e.message : 'Error interno' });
  }
});

// ---- GET /api/scrape/jobs --------------------------------------------------
// Lista los ultimos ~10 jobs del usuario (aislado por user_id). El front puede
// pollear esto para el estado de sus trabajos activos + los recien terminados.
app.get('/api/scrape/jobs', async function (req, res) {
  try {
    var uid = await verificarUsuario(req);
    if (!uid) return res.status(401).json({ error: 'No autorizado' });
    var user_id = await _resolverOwner(uid);

    var q = await supabase.from('scrape_jobs')
      .select('id, tipo, estado, progreso, mensaje, development_id, error, created_at, updated_at')
      .eq('user_id', user_id)
      .order('created_at', { ascending: false })
      .limit(10);

    if (q.error) {
      if (_invTablaFaltante(q.error)) return res.status(503).json({ error: 'La tabla scrape_jobs no existe todavia. Corré migracion-scrape-jobs.sql.', tabla: 'scrape_jobs' });
      return res.status(500).json({ error: 'Error listando trabajos: ' + q.error.message });
    }
    return res.json({ ok: true, jobs: q.data || [] });
  } catch (e) {
    return res.status(500).json({ error: e && e.message ? e.message : 'Error interno' });
  }
});

// ---- GET /api/scrape/job/:id  (o ?id=) -------------------------------------
// Devuelve UN job (estado/progreso/mensaje/resultado/error). Verifica que sea
// del user (aislamiento por user_id). El front usa esto para leer el resultado
// cuando estado='listo' (y cargarlo en el form) o mostrar el error.
async function _handlerScrapeJobUno(req, res) {
  try {
    var uid = await verificarUsuario(req);
    if (!uid) return res.status(401).json({ error: 'No autorizado' });
    var user_id = await _resolverOwner(uid);

    var jobId = _invStr((req.params && req.params.id)) || _invStr((req.query && req.query.id));
    if (!jobId) return res.status(400).json({ error: 'Falta el id del trabajo' });

    var q = await supabase.from('scrape_jobs')
      .select('id, user_id, tipo, input, estado, progreso, mensaje, resultado, development_id, error, created_at, updated_at')
      .eq('id', jobId)
      .maybeSingle();

    if (q.error) {
      if (_invTablaFaltante(q.error)) return res.status(503).json({ error: 'La tabla scrape_jobs no existe todavia. Corré migracion-scrape-jobs.sql.', tabla: 'scrape_jobs' });
      return res.status(500).json({ error: 'Error leyendo el trabajo: ' + q.error.message });
    }
    if (!q.data) return res.status(404).json({ error: 'El trabajo no existe', job_id: jobId });
    if (q.data.user_id !== user_id) return res.status(403).json({ error: 'El trabajo no pertenece a tu cuenta' });

    return res.json({ ok: true, job: q.data });
  } catch (e) {
    return res.status(500).json({ error: e && e.message ? e.message : 'Error interno' });
  }
}
// path-to-regexp v8 (Express 5) NO soporta ':id?' opcional (crasheaba el boot con
// "Unexpected ? at index 19"). Registramos las 2 formas que el handler ya contempla:
//   /api/scrape/job/:id  (id como segmento, lo que usa el front)
//   /api/scrape/job      (id como ?id=, fallback)
app.get('/api/scrape/job/:id', _handlerScrapeJobUno);
app.get('/api/scrape/job', _handlerScrapeJobUno);

// ---- RUNNER (cron): procesarScrapeJobs -------------------------------------
// Corre en el SERVER (no en el navegador) -> cumple "trabajo en segundo plano".
// Cada ~25s toma el job 'pendiente' mas viejo (DE A UNO, para no disparar el
// gasto/carga en paralelo), lo marca 'corriendo' y lo procesa segun `tipo`,
// actualizando progreso/mensaje en etapas. Guard anti-solape (_scrapeJobsEnCurso).
// Gateado defensivo: si la tabla no existe, sale en silencio. try/catch por job:
// NUNCA deja un job colgado en 'corriendo' -> ante cualquier fallo lo pasa a 'error'.
var _scrapeJobsEnCurso = false;
async function procesarScrapeJobs() {
  if (_scrapeJobsEnCurso) return;              // anti-solape entre ticks
  _scrapeJobsEnCurso = true;
  try {
    // Tomar el 'pendiente' mas viejo (DE A UNO). Si la tabla no existe -> salir en silencio.
    var q = await supabase.from('scrape_jobs')
      .select('id, user_id, tipo, input')
      .eq('estado', 'pendiente')
      .order('created_at', { ascending: true })
      .limit(1);
    if (q.error) {
      if (!_invTablaFaltante(q.error)) console.log('[scrape-jobs runner] query fallo:', q.error.message);
      return; // tabla ausente o error -> no corre nada
    }
    var jobs = q.data || [];
    if (!jobs.length) return;                  // nada pendiente
    var job = jobs[0];

    // P1 (CRON): freno de gasto IA por tope. El ENCOLADO por HTTP ya esta gateado, pero un job encolado CON
    // cupo puede ejecutarse DESPUES de que la cuenta supere el tope -> sin esto gastaba IA igual. Se marca
    // 'error' con mensaje claro (NO se deja 'pendiente': el runner toma el mas viejo DE A UNO y un job sin
    // cupo bloquearia la cola para siempre). Cortesia/ilimitado/flag-off => dentroDelTopeIA=true => corre.
    try {
      if (!(await dentroDelTopeIA(job.user_id))) {
        await _scrapeJobUpdate(job.id, { estado: 'error', mensaje: 'Sin cupo de mensajes', error: 'Alcanzaste el tope de mensajes IA de tu plan. Ampliá el plan o esperá al próximo período y volvé a intentarlo.' });
        return;
      }
    } catch (eTope) { /* fail-open: ante error de lectura no frenamos el job */ }

    // Marcar 'corriendo' (best-effort). Nota: no hay lock atomico; el guard
    // _scrapeJobsEnCurso + un unico proceso alcanzan para el volumen esperado.
    await _scrapeJobUpdate(job.id, { estado: 'corriendo', progreso: 5, mensaje: 'Arrancando…', error: null });

    var input = job.input || {};
    try {
      if (job.tipo === 'desarrollo_update') {
        // ---- ACTUALIZAR un emprendimiento existente ----
        var devId = _invStr(input.development_id);
        var sourceUrl = (input.source_url || '').trim();
        if (!devId || !sourceUrl) throw new Error('Job de update sin development_id o source_url');
        await _scrapeJobUpdate(job.id, { progreso: 20, mensaje: 'Bajando la página…' });
        // actualizarDevelopment orquesta scrape + map + guardar (reemplaza sectores/unidades).
        var r = await actualizarDevelopment(devId, job.user_id, sourceUrl);
        if (!r.ok) throw new Error(r.error || 'No se pudo actualizar el emprendimiento');
        await _scrapeJobUpdate(job.id, {
          estado: 'listo',
          progreso: 100,
          mensaje: 'Emprendimiento actualizado',
          development_id: r.development_id || devId,
          resultado: {
            development_id: r.development_id || devId,
            sectores_guardados: r.sectores_guardados,
            unidades_guardadas: r.unidades_guardadas,
            unidades_con_error: r.unidades_con_error,
            actualizado: true,
            scrape: r.scrape || null
          },
          error: null
        });
        console.log('[scrape-jobs runner] job', job.id, 'update OK dev', (r.development_id || devId));
      } else if (job.tipo === 'alojamiento_nuevo' || job.tipo === 'alojamiento_update') {
        // ---- HOTEL/CABAÑAS: scrapea + GUARDA directo (mismo camino que /api/scrape/alojamiento,
        // pero en segundo plano para no timeoutear el request). Progreso real por etapas. ----
        var sitioJ = (input.url || '').trim();
        if (!sitioJ && input.complejo_id) {
          var cRowJ = await supabase.from('hotel_complejos').select('atributos').eq('id', input.complejo_id).eq('user_id', job.user_id).maybeSingle();
          sitioJ = (cRowJ.data && cRowJ.data.atributos && cRowJ.data.atributos.origen_url) ? String(cRowJ.data.atributos.origen_url).trim() : '';
        }
        if (!sitioJ) throw new Error('Job de alojamiento sin url (ni el complejo tiene origen_url)');
        if (!sitioJ.startsWith('http')) sitioJ = 'https://' + sitioJ;
        var baseJ; try { var uJ = new URL(sitioJ); baseJ = uJ.protocol + '//' + uJ.host; } catch (e0) { throw new Error('URL inválida: ' + sitioJ); }
        var permJ = await scrapeUrlPermitida(job.user_id, sitioJ);
        if (!permJ.ok) throw new Error(permJ.error || 'URL no permitida para tu cuenta');
        await _scrapeJobUpdate(job.id, { progreso: 25, mensaje: 'Bajando las páginas del sitio…' });
        var resAl = await _scrapeAlojamientoCompleto(baseJ, sitioJ, job.user_id, true);
        var totAl = (resAl.complejos || []).reduce(function (a, c) { return a + ((Array.isArray(c.unidades) ? c.unidades.length : 0)); }, 0);
        var nomAl = (resAl.complejos && resAl.complejos[0] && resAl.complejos[0].nombre) || null;
        // PXSOL / sitios JS: las habitaciones se cargan por JavaScript. El scrape PLANO es INESTABLE e
        // incompleto en PXSOL (a veces 0, a veces algunas), asi que si detectamos PXSOL usamos SIEMPRE el
        // render PROFUNDO (headless): trae TODAS las unidades. Para sitios no-PXSOL, solo caemos al profundo
        // cuando el plano no trajo nada. Si el profundo falla pero el plano trajo algo -> se guarda el plano
        // (fallback, mas abajo). Solo se avisa "cargar a mano" si no hay NADA por ningun camino.
        var _esPxsol = false;
        try { var _rhp = await fetchScrape(sitioJ); if (_rhp && _rhp.ok) { var _hp = await _rhp.text(); _esPxsol = /pxsol/i.test(_hp); } } catch (ePx) {}
        var _hechoProfundo = false;
        if (_esPxsol || !totAl) {
          await _scrapeJobUpdate(job.id, { progreso: 45, mensaje: (_esPxsol ? 'Motor de reservas detectado: renderizando el sitio…' : 'La página carga por JavaScript: renderizando…') });
          var _prof = await _scrapeAlojamientoProfundo(baseJ, sitioJ, job.user_id, (input.modo === 'reset' ? 'reset' : 'update'), 5);
          if (_prof && _prof.ok && _prof.total > 0) {
            _hechoProfundo = true;
            await _scrapeJobUpdate(job.id, {
              estado: 'listo', progreso: 100,
              mensaje: 'Importado (render profundo): ' + (_prof.complejos || 1) + ' complejo(s), ' + (_prof.creados + _prof.actualizados) + ' unidad(es)',
              resultado: { total: _prof.total, complejos: _prof.complejos || 1, creados: _prof.creados, actualizados: _prof.actualizados, errores: _prof.errores, estrategia: 'profundo:' + (_prof.via || 'headless'), complejo: _prof.complejo, profundo: true },
              error: null
            });
            console.log('[scrape-jobs runner] job', job.id, 'alojamiento OK por render PROFUNDO (' + sitioJ + ')');
          } else if (!nomAl) {
            throw new Error('No se encontraron alojamientos, ni siquiera renderizando la página' + (_prof && _prof.via === null ? ' (el render profundo no está disponible ahora)' : '') + '. Cargá las unidades a mano.');
          }
        }
        if (!_hechoProfundo) {
          await _scrapeJobUpdate(job.id, { progreso: 70, mensaje: 'Guardando complejo y habitaciones…' });
          var gAl = await _guardarComplejoYUnidades(job.user_id, resAl, sitioJ, (input.modo === 'reset' ? 'reset' : 'update'));
          await _scrapeJobUpdate(job.id, {
            estado: 'listo', progreso: 100,
            mensaje: 'Importado: ' + (gAl.complejos || []).length + ' complejo(s), ' + (gAl.creados + gAl.actualizados) + ' unidad(es)',
            resultado: { total: totAl, complejos: (gAl.complejos || []).length, creados: gAl.creados, actualizados: gAl.actualizados, errores: gAl.errores, estrategia: resAl.estrategia, complejo: nomAl },
            error: null
          });
          console.log('[scrape-jobs runner] job', job.id, 'alojamiento OK (' + sitioJ + ')');
        }
      } else {
        // ---- NUEVO: scrape profundo -> guarda el PREVIEW en resultado ----
        // (default; cubre tipo 'desarrollo_nuevo'). El usuario despues revisa y
        // guarda desde el form usando este resultado.
        var url = (input.url || '').trim();
        if (!url) throw new Error('Job nuevo sin url');
        await _scrapeJobUpdate(job.id, { progreso: 20, mensaje: 'Bajando la página…' });
        await _scrapeJobUpdate(job.id, { progreso: 50, mensaje: 'Leyendo e interpretando…' });
        // 🔴 Gate de costo: un job iniciado por el usuario CON el flag corre PROFUNDO; ausente/false
        // -> NORMAL. El cron de auto-update (revisarScrapingsDesarrollo) NO setea el flag -> sigue
        // NORMAL siempre (proteccion de costo, no la toques).
        var out = await _scrapeDesarrolloProfundo(url, job.user_id, { plano_deep: input.plano_deep === true });
        if (!out.ok) throw new Error(out.error || 'No se pudo scrapear la página');
        await _scrapeJobUpdate(job.id, { progreso: 80, mensaje: 'Analizando planos…' });
        await _scrapeJobUpdate(job.id, {
          estado: 'listo',
          progreso: 100,
          mensaje: 'Listo para revisar',
          resultado: {
            data: out.data,
            imagenes_encontradas: out.imagenes_encontradas,
            planos_analizados: out.planos_analizados,
            aviso: out.aviso
          },
          error: null
        });
        console.log('[scrape-jobs runner] job', job.id, 'nuevo OK (' + url + ')');
      }
    } catch (eJob) {
      // NUNCA dejar el job colgado en 'corriendo': cualquier fallo -> 'error'.
      var msg = (eJob && eJob.message) ? eJob.message : String(eJob);
      await _scrapeJobUpdate(job.id, { estado: 'error', mensaje: 'Falló', error: msg });
      console.log('[scrape-jobs runner] job', job.id, 'FALLO:', msg);
    }
  } catch (e) {
    console.log('[scrape-jobs runner] error general:', (e && e.message) ? e.message : e);
  } finally {
    _scrapeJobsEnCurso = false;
  }
}
// Correr cada 25s, con un arranque a los 30s del deploy. Al reiniciar el server,
// los jobs que quedaron 'pendiente' se retoman solos en el proximo tick.
setInterval(procesarScrapeJobs, 25 * 1000);
setTimeout(procesarScrapeJobs, 30 * 1000);


// ============================================================================
// INVENTARIO MULTI-RUBRO  (HOTEL/CABAÑAS + DESARROLLADORA)  — ADITIVO
// ----------------------------------------------------------------------------
// Persiste los forms _FormHotel.tsx y _FormDesarrollo.tsx.
//   - NO toca el camino inmobiliaria (properties para inmobiliaria sigue igual).
//   - SIEMPRE setea user_id = el del JWT (verificarUsuario), nunca el del body
//     (asi aplica la RLS auth.uid() = user_id de la migracion).
//   - Fail-safe: si una tabla nueva no existe todavia (migracion no corrida)
//     devuelve un JSON de error claro en vez de crashear.
//   - Campos sin columna propia -> al jsonb correspondiente (no se pierde nada).
// Tablas HOTEL (propias, NO usan properties): hotel_complejos, hotel_unidades,
//         hotel_tarifa, hotel_disponibilidad.
// Tablas DESARROLLO: developments, development_sectors, development_units.
// `properties` queda 100% inmobiliaria e intacta (este endpoint no la toca).
// ============================================================================

// Helpers locales: parseo numerico tolerante (los inputs del form mandan strings,
// "" debe ir como NULL para no romper columnas numeric/int/date).
function _invNum(v) {
  if (v === null || v === undefined) return null;
  var s = String(v).trim();
  if (s === '') return null;
  var n = Number(s);
  return isNaN(n) ? null : n;
}
function _invInt(v) {
  var n = _invNum(v);
  return n === null ? null : Math.trunc(n);
}
function _invStr(v) {
  if (v === null || v === undefined) return null;
  var s = String(v).trim();
  return s === '' ? null : s;
}
function _invDate(v) {
  // El form de hotel manda <input type=date> => "YYYY-MM-DD" o "". Validacion blanda.
  var s = _invStr(v);
  if (!s) return null;
  return /^\d{4}-\d{2}-\d{2}/.test(s) ? s.slice(0, 10) : null;
}
// Detecta el error de "tabla/relacion inexistente" (migracion no corrida todavia)
// o columna ausente (cache de PostgREST sin refrescar). Devuelve true si conviene
// abortar con un mensaje claro en vez de seguir.
function _invTablaFaltante(err) {
  if (!err) return false;
  var m = String((err && (err.message || err.details || err.hint || err.code)) || '').toLowerCase();
  return /does not exist|could not find the table|relation .* does not exist|schema cache|pgrst205|pgrst204|42p01|undefined table/i.test(m);
}

// ============================================================================
// ETAPA 1 — Helpers de MERGE de unidades/sectores de desarrollo (IDs ESTABLES)
// ----------------------------------------------------------------------------
// El guardado de EDICION (form manual y scraper) hacia DELETE-ALL + REINSERT ->
// los IDs de cada unidad cambiaban en cada guardado (nada podia referenciarla) y
// el scraper con unidades=[] borraba todo. Ahora se hace MERGE por `id` (el form
// manual round-trip-ea el id) o por `numero` (el scraper): update de existentes,
// insert de nuevas y borrado de las que ya no vienen SOLO cuando el origen es el
// form MANUAL. El SCRAPER NUNCA borra y NUNCA pisa `estado` manual.
// ============================================================================
// Clave de match por numero: trim + lowercase (robusto ante mayusculas/espacios).
function _devNumKey(v) {
  if (v === null || v === undefined) return '';
  return String(v).trim().toLowerCase();
}
// Compara un valor de la fila existente contra el valor calculado del payload.
// null/undefined equivalentes; comparacion numerica cuando alguno es numero.
function _devEqVal(a, b) {
  if (a === undefined) a = null;
  if (b === undefined) b = null;
  if (a === null && b === null) return true;
  if (a === null || b === null) return false;
  if (typeof a === 'number' || typeof b === 'number') { return Number(a) === Number(b); }
  return String(a) === String(b);
}
// ¿los campos del payload difieren de la fila existente? (solo las claves del payload)
function _devUnidadCambio(row, fields) {
  var ks = Object.keys(fields);
  for (var i = 0; i < ks.length; i++) { if (!_devEqVal(row[ks[i]], fields[ks[i]])) return true; }
  return false;
}
// Fila COMPLETA para INSERT de una unidad nueva (defaults; unit_data/images vacios).
function _devFilaUnidadInsert(un, development_id, user_id) {
  un = un || {};
  return {
    development_id: development_id,
    sector_id: null,
    user_id: user_id,
    tipo_producto: _invStr(un.tipo_producto),
    numero: _invStr(un.numero),
    tipologia: _invStr(un.tipologia),
    m2_cubiertos: _invNum(un.m2_cubiertos),
    m2_totales: _invNum(un.m2_totales),
    superficie_terreno: _invNum(un.superficie_terreno),
    frente: _invNum(un.frente),
    fondo: _invNum(un.fondo),
    orientacion: _invStr(un.orientacion),
    piso: _invStr(un.piso),
    precio: _invNum(un.precio),
    precio_estado: _invStr(un.precio_estado) || 'a_consultar',
    moneda: _invStr(un.moneda) || 'USD',
    estado: _invStr(un.estado) || 'disponible',
    unit_data: {},
    images: []
  };
}
// Campos para UPDATE de una unidad existente. NO incluye unit_data/images (para no
// pisar fotos/datos guardados) ni id/development_id/user_id. `estado` SOLO se incluye
// cuando el origen es el form MANUAL (el scraper NUNCA pisa el estado manual).
function _devFilaUnidadUpdate(un, origen) {
  un = un || {};
  var f = {
    tipo_producto: _invStr(un.tipo_producto),
    numero: _invStr(un.numero),
    tipologia: _invStr(un.tipologia),
    m2_cubiertos: _invNum(un.m2_cubiertos),
    m2_totales: _invNum(un.m2_totales),
    superficie_terreno: _invNum(un.superficie_terreno),
    frente: _invNum(un.frente),
    fondo: _invNum(un.fondo),
    orientacion: _invStr(un.orientacion),
    piso: _invStr(un.piso),
    precio: _invNum(un.precio),
    precio_estado: _invStr(un.precio_estado) || 'a_consultar',
    moneda: _invStr(un.moneda) || 'USD'
  };
  if (origen !== 'scraper') f.estado = _invStr(un.estado) || 'disponible';
  return f;
}
// Trae TODAS las filas hijas de un desarrollo (paginado .range: PostgREST corta en 1000).
async function _devCargarHijos(tabla, cols, development_id, user_id) {
  var out = [];
  var page = 0, size = 1000;
  for (;;) {
    var r = await supabase.from(tabla).select(cols)
      .eq('development_id', development_id).eq('user_id', user_id)
      .range(page * size, page * size + size - 1);
    if (r.error) return { data: null, error: r.error };
    var rows = r.data || [];
    out = out.concat(rows);
    if (rows.length < size) break;
    page++;
    if (page > 100) break; // tope de seguridad (100k filas)
  }
  return { data: out, error: null };
}
// UPDATE defensivo de una unidad: si se pide estado_updated_at y la columna aun no
// existe (migracion E1 sin correr), reintenta sin ella (no rompe el guardado).
async function _devUpdateUnidad(id, user_id, fields, tocarEstadoTs) {
  var payload = Object.assign({}, fields);
  if (tocarEstadoTs) payload.estado_updated_at = new Date().toISOString();
  var r = await supabase.from('development_units').update(payload).eq('id', id).eq('user_id', user_id);
  if (r.error && tocarEstadoTs && _invTablaFaltante(r.error)) {
    delete payload.estado_updated_at;
    r = await supabase.from('development_units').update(payload).eq('id', id).eq('user_id', user_id);
  }
  return r;
}

// ---- FUNCION COMPARTIDA: guardar/actualizar un EMPRENDIMIENTO (desarrolladora) --
// Extraida del branch desarrolladora de /api/inventario/guardar para poder REUSARLA
// desde el endpoint de ACTUALIZAR por scraping y desde el cron de auto-update.
// NO usa req/res. Recibe (user_id, body) con el MISMO shape del endpoint
//   { development:{...}, dev_data:{...}, sectores:[...], unidades:[...], development_id? }
// y devuelve { ok:true, status:200, development_id, sectores_guardados, unidades_guardadas,
//   unidades_actualizadas, unidades_insertadas, unidades_eliminadas, unidades_sin_cambio,
//   unidades_con_error, actualizado, origen } o { ok:false, status, error, ... }.
// Si trae development_id (o development.id) => UPDATE del dev existente (verifica tenant)
// + MERGE de sectores/unidades por id/numero (Etapa 1: IDs ESTABLES). El 3er arg opcional
// `opts.origen` ('manual'|'scraper', default 'manual') define si se puede BORRAR lo que ya no
// viene y pisar `estado`: el SCRAPER nunca borra ni pisa estado, y con unidades=[] no toca nada.
// Sin development_id => INSERT nuevo (unidades por chunks). Los errores esperables (tabla
// faltante, dev ajeno) vuelven como { ok:false, status } en vez de tirar.
async function guardarDesarrolladora(user_id, b, opts) {
  // origen: 'manual' (form) => puede cambiar estado y BORRAR unidades que ya no vienen.
  //         'scraper'        => NUNCA borra unidades y NUNCA pisa `estado`; unidades=[] no toca nada.
  var origen = (opts && opts.origen === 'scraper') ? 'scraper' : 'manual';
  var dev = b.development || {};
  var devData = b.dev_data || {};
  var sectores = Array.isArray(b.sectores) ? b.sectores : [];
  var unidades = Array.isArray(b.unidades) ? b.unidades : [];

  if (!_invStr(dev.nombre)) return { ok: false, status: 400, error: 'Falta el nombre del emprendimiento' };

  // Campos comunes del emprendimiento (mismo mapeo para INSERT nuevo y UPDATE de edicion).
  var filaDev = {
    user_id: user_id,
    nombre: _invStr(dev.nombre),
    tipo: _invStr(dev.tipo),
    zona: _invStr(dev.zona),
    direccion: _invStr(dev.direccion),
    entre_calles: _invStr(dev.entre_calles),
    ciudad: _invStr(dev.ciudad),
    descripcion: _invStr(dev.descripcion),
    link: _invStr(dev.link),
    estado_obra: _invStr(dev.estado_obra),
    avance_pct: _invInt(dev.avance_pct),
    fecha_entrega: _invStr(dev.fecha_entrega),
    dev_data: {
      amenities: devData.amenities || [],
      planes: devData.planes || [],
      // E2: precios por etapa [{nombre, ajuste_pct, desde_fecha}] (editable en el form manual). El SCRAPER no manda
      // etapas -> en re-scrape se PRESERVAN las manuales (ver rama de edicion mas abajo). 0 IA.
      etapas: Array.isArray(devData.etapas) ? devData.etapas : [],
      legal: devData.legal || {},
      material: devData.material || {}
    }
  };

  // ¿Edicion? Si el body trae development_id => UPDATE del emprendimiento existente
  // y MERGE de sus sectores/unidades. Sin development_id => INSERT nuevo.
  var devEditId = _invStr(b.development_id) || _invStr(dev.id);
  var esEdicion = !!devEditId;
  var development_id;

  // Contadores (se completan segun la rama).
  var sectoresOk = 0, unidadesOk = 0, unidadesErr = 0;
  var unidadesActualizadas = 0, unidadesInsertadas = 0, unidadesEliminadas = 0, unidadesSinCambio = 0;

  // ---------------------------------------------------------------------------
  // 1) EMPRENDIMIENTO (developments): UPDATE si edicion, INSERT si alta nueva.
  // ---------------------------------------------------------------------------
  if (esEdicion) {
    var dOwn = await supabase.from('developments').select('user_id, dev_data').eq('id', devEditId).maybeSingle();
    if (dOwn.error) {
      if (_invTablaFaltante(dOwn.error)) return { ok: false, status: 503, error: 'La tabla developments no existe todavia. Corré la migracion migracion-inventario-multirubro.sql.', tabla: 'developments' };
      return { ok: false, status: 500, error: 'Error verificando el emprendimiento: ' + dOwn.error.message };
    }
    if (!dOwn.data) return { ok: false, status: 404, error: 'El emprendimiento a editar no existe', development_id: devEditId };
    if (dOwn.data.user_id !== user_id) return { ok: false, status: 403, error: 'El emprendimiento no pertenece a tu cuenta' };

    // E2: PRESERVAR las etapas de precio MANUALES cuando el origen es el SCRAPER (que no las manda).
    // El scraper reemplaza dev_data completo; sin esto perderiamos las etapas cargadas a mano en cada re-scrape.
    var _devDataUpd = filaDev.dev_data;
    if (origen === 'scraper' && !Array.isArray(devData.etapas)) {
      var _exEt = (dOwn.data && dOwn.data.dev_data && Array.isArray(dOwn.data.dev_data.etapas)) ? dOwn.data.dev_data.etapas : [];
      _devDataUpd = Object.assign({}, filaDev.dev_data, { etapas: _exEt });
    }
    var filaDevUpd = {
      nombre: filaDev.nombre, tipo: filaDev.tipo, zona: filaDev.zona,
      direccion: filaDev.direccion, entre_calles: filaDev.entre_calles, ciudad: filaDev.ciudad,
      descripcion: filaDev.descripcion, link: filaDev.link, estado_obra: filaDev.estado_obra,
      avance_pct: filaDev.avance_pct, fecha_entrega: filaDev.fecha_entrega, dev_data: _devDataUpd
    };
    var dUpd = await supabase.from('developments').update(filaDevUpd).eq('id', devEditId).eq('user_id', user_id).select('id').maybeSingle();
    if (dUpd.error) {
      if (_invTablaFaltante(dUpd.error)) return { ok: false, status: 503, error: 'La tabla developments no existe todavia. Corré la migracion migracion-inventario-multirubro.sql.', tabla: 'developments' };
      return { ok: false, status: 500, error: 'Error actualizando el emprendimiento: ' + dUpd.error.message };
    }
    development_id = (dUpd.data && dUpd.data.id) || devEditId;
  } else {
    var dIns = await supabase.from('developments').insert(filaDev).select('id').maybeSingle();
    if (dIns.error) {
      if (_invTablaFaltante(dIns.error)) return { ok: false, status: 503, error: 'La tabla developments no existe todavia. Corré la migracion migracion-inventario-multirubro.sql.', tabla: 'developments' };
      return { ok: false, status: 500, error: 'Error guardando el emprendimiento: ' + dIns.error.message };
    }
    development_id = dIns.data && dIns.data.id;
  }

  // 1d) Columnas de auto-update v2 (source_url / auto_scrape / scrape_cada_horas) — BEST-EFFORT.
  var v2 = {};
  if (dev.source_url !== undefined) v2.source_url = _invStr(dev.source_url);
  if (dev.auto_scrape !== undefined) v2.auto_scrape = !!dev.auto_scrape;
  if (dev.scrape_cada_horas !== undefined) { var _h = _invInt(dev.scrape_cada_horas); if (_h && _h >= 1) v2.scrape_cada_horas = _h; }
  if (Object.keys(v2).length) {
    try { await supabase.from('developments').update(v2).eq('id', development_id).eq('user_id', user_id); } catch (eV2) { /* columna ausente -> ignorar */ }
  }

  // ---------------------------------------------------------------------------
  // 2) SECTORES (development_sectors)
  //    Edicion => MERGE por id/nombre (scraper nunca borra). Alta => INSERT.
  // ---------------------------------------------------------------------------
  if (!esEdicion) {
    for (var s = 0; s < sectores.length; s++) {
      var sec = sectores[s] || {};
      if (!_invStr(sec.nombre)) continue;
      var sIns = await supabase.from('development_sectors').insert({
        development_id: development_id, user_id: user_id,
        nombre: _invStr(sec.nombre), tipo: _invStr(sec.tipo), fecha_entrega: _invStr(sec.fecha_entrega), sector_data: {}
      }).select('id').maybeSingle();
      if (sIns.error) {
        if (_invTablaFaltante(sIns.error)) return { ok: false, status: 503, error: 'La tabla development_sectors no existe todavia. Corré la migracion.', tabla: 'development_sectors', development_id: development_id };
      } else sectoresOk++;
    }
  } else if (origen === 'scraper' && sectores.length === 0) {
    console.log('[guardarDesarrolladora] scraper sin sectores para dev', development_id, '-> sectores INTACTOS');
  } else {
    var secEx = await _devCargarHijos('development_sectors', 'id, nombre', development_id, user_id);
    if (secEx.error) {
      if (_invTablaFaltante(secEx.error)) return { ok: false, status: 503, error: 'La tabla development_sectors no existe todavia. Corré la migracion.', tabla: 'development_sectors', development_id: development_id };
      return { ok: false, status: 500, error: 'Error leyendo sectores previos: ' + secEx.error.message, development_id: development_id };
    }
    var secRows = secEx.data || [];
    var secById = {}, secByNom = {};
    for (var si = 0; si < secRows.length; si++) { var sr = secRows[si]; secById[String(sr.id)] = sr; var snk = _devNumKey(sr.nombre); if (snk) { (secByNom[snk] = secByNom[snk] || []).push(sr); } }
    var secConsumed = {};
    for (var s2 = 0; s2 < sectores.length; s2++) {
      var sc = sectores[s2] || {};
      if (!_invStr(sc.nombre)) continue;
      var secFields = { nombre: _invStr(sc.nombre), tipo: _invStr(sc.tipo), fecha_entrega: _invStr(sc.fecha_entrega) };
      var secTarget = null;
      var secIncId = _invStr(sc.id);
      if (secIncId && secById[secIncId] && !secConsumed[secIncId]) secTarget = secById[secIncId];
      if (!secTarget) { var snk2 = _devNumKey(sc.nombre); if (snk2 && secByNom[snk2]) { for (var sj = 0; sj < secByNom[snk2].length; sj++) { var scd = secByNom[snk2][sj]; if (!secConsumed[String(scd.id)]) { secTarget = scd; break; } } } }
      if (secTarget) {
        secConsumed[String(secTarget.id)] = true;
        var su = await supabase.from('development_sectors').update(secFields).eq('id', secTarget.id).eq('user_id', user_id);
        if (!su.error) sectoresOk++;
      } else {
        var scIns = await supabase.from('development_sectors').insert({ development_id: development_id, user_id: user_id, nombre: secFields.nombre, tipo: secFields.tipo, fecha_entrega: secFields.fecha_entrega, sector_data: {} }).select('id').maybeSingle();
        if (scIns.error) { if (_invTablaFaltante(scIns.error)) return { ok: false, status: 503, error: 'La tabla development_sectors no existe todavia. Corré la migracion.', tabla: 'development_sectors', development_id: development_id }; }
        else sectoresOk++;
      }
    }
    // Borrar sectores no vistos SOLO en manual (el scraper NUNCA borra).
    if (origen !== 'scraper') {
      var secDel = [];
      for (var si2 = 0; si2 < secRows.length; si2++) { if (!secConsumed[String(secRows[si2].id)]) secDel.push(secRows[si2].id); }
      for (var sd = 0; sd < secDel.length; sd += 100) {
        await supabase.from('development_sectors').delete().in('id', secDel.slice(sd, sd + 100)).eq('user_id', user_id);
      }
    }
  }

  // ---------------------------------------------------------------------------
  // 3) UNIDADES (development_units)
  //    Edicion => MERGE por id/numero (IDs estables; scraper nunca borra ni pisa estado).
  //    Alta => INSERT por CHUNKS. `unidades=[]` del scraper => NO toca unidades.
  // ---------------------------------------------------------------------------
  if (!esEdicion) {
    var insertsNew = unidades.map(function (un) { return _devFilaUnidadInsert(un, development_id, user_id); });
    for (var ci0 = 0; ci0 < insertsNew.length; ci0 += 100) {
      var chunk0 = insertsNew.slice(ci0, ci0 + 100);
      var ins0 = await supabase.from('development_units').insert(chunk0);
      if (ins0.error) {
        if (_invTablaFaltante(ins0.error)) return { ok: false, status: 503, error: 'La tabla development_units no existe todavia. Corré la migracion.', tabla: 'development_units', development_id: development_id };
        unidadesErr += chunk0.length;
      } else { unidadesInsertadas += chunk0.length; unidadesOk += chunk0.length; }
    }
  } else if (origen === 'scraper' && unidades.length === 0) {
    console.log('[guardarDesarrolladora] scraper devolvio unidades=[] para dev', development_id, '-> unidades INTACTAS (no se borra nada)');
  } else {
    var uEx = await _devCargarHijos('development_units', 'id, numero, estado, tipo_producto, tipologia, m2_cubiertos, m2_totales, superficie_terreno, frente, fondo, orientacion, piso, precio, precio_estado, moneda', development_id, user_id);
    if (uEx.error) {
      if (_invTablaFaltante(uEx.error)) return { ok: false, status: 503, error: 'La tabla development_units no existe todavia. Corré la migracion.', tabla: 'development_units', development_id: development_id };
      return { ok: false, status: 500, error: 'Error leyendo unidades previas: ' + uEx.error.message, development_id: development_id };
    }
    var uRows = uEx.data || [];
    var uById = {}, uByNum = {};
    for (var ui = 0; ui < uRows.length; ui++) { var ur = uRows[ui]; uById[String(ur.id)] = ur; var unk = _devNumKey(ur.numero); if (unk) { (uByNum[unk] = uByNum[unk] || []).push(ur); } }
    var uConsumed = {};
    var insertsU = [];
    for (var u = 0; u < unidades.length; u++) {
      var un = unidades[u] || {};
      var target = null;
      var incId = _invStr(un.id);
      if (incId && uById[incId] && !uConsumed[incId]) target = uById[incId];
      if (!target) { var unk2 = _devNumKey(un.numero); if (unk2 && uByNum[unk2]) { for (var uj = 0; uj < uByNum[unk2].length; uj++) { var uc = uByNum[unk2][uj]; if (!uConsumed[String(uc.id)]) { target = uc; break; } } } }
      if (target) {
        uConsumed[String(target.id)] = true;
        var fields = _devFilaUnidadUpdate(un, origen);
        if (!_devUnidadCambio(target, fields)) { unidadesSinCambio++; unidadesOk++; continue; }
        var tocarTs = (origen !== 'scraper') && (String(target.estado || '') !== String(fields.estado || ''));
        var ru = await _devUpdateUnidad(target.id, user_id, fields, tocarTs);
        if (ru.error) {
          if (_invTablaFaltante(ru.error)) return { ok: false, status: 503, error: 'La tabla development_units no existe todavia. Corré la migracion.', tabla: 'development_units', development_id: development_id };
          unidadesErr++;
        } else { unidadesActualizadas++; unidadesOk++; }
      } else {
        insertsU.push(_devFilaUnidadInsert(un, development_id, user_id));
      }
    }
    // INSERT de nuevas por CHUNKS (~100/req).
    for (var ci = 0; ci < insertsU.length; ci += 100) {
      var chunk = insertsU.slice(ci, ci + 100);
      var ins = await supabase.from('development_units').insert(chunk);
      if (ins.error) {
        if (_invTablaFaltante(ins.error)) return { ok: false, status: 503, error: 'La tabla development_units no existe todavia. Corré la migracion.', tabla: 'development_units', development_id: development_id };
        unidadesErr += chunk.length;
      } else { unidadesInsertadas += chunk.length; unidadesOk += chunk.length; }
    }
    // BORRAR las que ya no vienen SOLO en manual (el scraper NUNCA borra).
    if (origen !== 'scraper') {
      var uDelIds = [];
      for (var ui2 = 0; ui2 < uRows.length; ui2++) { if (!uConsumed[String(uRows[ui2].id)]) uDelIds.push(uRows[ui2].id); }
      for (var di = 0; di < uDelIds.length; di += 100) {
        var slice = uDelIds.slice(di, di + 100);
        var ddel = await supabase.from('development_units').delete().in('id', slice).eq('user_id', user_id);
        if (!ddel.error) unidadesEliminadas += slice.length;
      }
    }
  }

  return {
    ok: true,
    status: 200,
    rubro: 'desarrolladora',
    development_id: development_id,
    sectores_guardados: sectoresOk,
    unidades_guardadas: unidadesOk,
    unidades_con_error: unidadesErr,
    unidades_actualizadas: unidadesActualizadas,
    unidades_insertadas: unidadesInsertadas,
    unidades_eliminadas: unidadesEliminadas,
    unidades_sin_cambio: unidadesSinCambio,
    actualizado: esEdicion,
    origen: origen
  };
}

// ---- POST /api/inventario/guardar -----------------------------------------
// Body HOTEL:        { tipo_inventario:'hotel_cabanas', group:{nombre,modo},
//                      unidad:{...}, atributos:{amenities,regimenes,franjas,politicas},
//                      tarifas:[...], extras:[...], images:[...] }
// Body DESARROLLO:   { tipo_inventario:'desarrolladora', development:{...},
//                      dev_data:{amenities,planes,legal,material},
//                      sectores:[...], unidades:[...] }
app.post('/api/inventario/guardar', async function (req, res) {
  try {
    var user_id = await verificarUsuario(req);
    if (!user_id) return res.status(401).json({ error: 'No autorizado' });

    var b = req.body || {};
    var rubro = normalizarRubro(b.tipo_inventario || b.rubro || '');

    // ======================= HOTEL / CABAÑAS ===============================
    if (rubro === 'hotel_cabanas') {
      var grupo = b.group || {};
      var unidad = b.unidad || {};
      var atributos = b.atributos || {};
      var tarifas = Array.isArray(b.tarifas) ? b.tarifas : [];
      var extras = Array.isArray(b.extras) ? b.extras : [];
      var images = Array.isArray(b.images) ? b.images : [];

      if (!_invStr(unidad.nombre)) return res.status(400).json({ error: 'Falta el nombre de la unidad' });

      // 1) Complejo -> hotel_complejos (un complejo por nombre+user; reusar si ya existe)
      var complejo_id = null;
      var nombreComplejo = _invStr(grupo.nombre);
      if (nombreComplejo) {
        var gExist = await supabase.from('hotel_complejos')
          .select('id').eq('user_id', user_id).eq('nombre', nombreComplejo).maybeSingle();
        if (gExist.error && _invTablaFaltante(gExist.error)) {
          return res.status(503).json({ error: 'La tabla hotel_complejos no existe todavia. Corré la migracion migracion-inventario-multirubro.sql.', tabla: 'hotel_complejos' });
        }
        if (gExist.data && gExist.data.id) {
          complejo_id = gExist.data.id;
        } else {
          var gIns = await supabase.from('hotel_complejos').insert({
            user_id: user_id,
            nombre: nombreComplejo,
            tipo: 'hotel_cabanas',
            atributos: { modo: _invStr(grupo.modo) || 'unidad_real' }
          }).select('id').maybeSingle();
          if (gIns.error) {
            if (_invTablaFaltante(gIns.error)) return res.status(503).json({ error: 'La tabla hotel_complejos no existe todavia. Corré la migracion.', tabla: 'hotel_complejos' });
            return res.status(500).json({ error: 'Error guardando el complejo: ' + gIns.error.message });
          }
          complejo_id = gIns.data && gIns.data.id;
        }
      }

      // 2) Unidad -> hotel_unidades (tabla propia de hotel; complejo_id, atributos jsonb)
      //    Lo descriptivo basico va a columnas reales de hotel_unidades; el resto al jsonb atributos.
      var precioBase = null, monedaBase = 'ARS';
      if (tarifas.length) {
        // precio_base / moneda = la primer tarifa con precio (referencia para listados)
        for (var ti = 0; ti < tarifas.length; ti++) {
          var pr = _invNum(tarifas[ti].precio);
          if (pr !== null) { precioBase = pr; monedaBase = _invStr(tarifas[ti].moneda) || 'ARS'; break; }
        }
      }
      var filaUnidadH = {
        user_id: user_id,
        complejo_id: complejo_id,
        numero: _invStr(unidad.numero),
        title: _invStr(unidad.nombre) || 'Sin nombre',
        type: _invStr(unidad.tipo_unidad),
        capacidad: _invInt(unidad.capacidad),
        descripcion: _invStr(unidad.descripcion),
        precio_base: precioBase,
        moneda: monedaBase,
        images: images,
        activa: true,
        // Todo lo descriptivo extra/amenities/regimenes/franjas/politicas/extras va al jsonb atributos (no se pierde):
        atributos: {
          tipo_unidad: _invStr(unidad.tipo_unidad),
          capacidad: _invInt(unidad.capacidad),
          camas: _invInt(unidad.camas),
          dormitorios: _invInt(unidad.dormitorios),
          banos: _invInt(unidad.banos),
          m2: _invNum(unidad.m2),
          vista: _invStr(unidad.vista),
          categoria_comercial: _invStr(unidad.categoria_comercial),
          amenities: atributos.amenities || {},
          regimenes: atributos.regimenes || [],
          franjas: atributos.franjas || {},
          politicas: atributos.politicas || {},
          extras: extras,
          // F6.2: URLs iCal de OTAs (Airbnb/Booking) para el import de bloqueos. Solo strings http(s).
          ical_import_urls: Array.isArray(atributos.ical_import_urls) ? atributos.ical_import_urls.filter(function(u){ return typeof u === 'string' && /^https?:\/\//i.test(u); }) : []
        }
      };
      var pIns = await supabase.from('hotel_unidades').insert(filaUnidadH).select('id').maybeSingle();
      if (pIns.error) {
        // Tabla/columna ausente => migracion no corrida o cache PostgREST sin refrescar.
        if (_invTablaFaltante(pIns.error)) return res.status(503).json({ error: 'La tabla hotel_unidades no existe todavia (o el cache de PostgREST no se refresco). Corré la migracion y NOTIFY pgrst.', tabla: 'hotel_unidades' });
        return res.status(500).json({ error: 'Error guardando la unidad: ' + pIns.error.message });
      }
      var unidad_id = pIns.data && pIns.data.id;

      // 3) Tarifas -> hotel_tarifa (una fila por temporada). Sin precio ni temporada -> se saltea.
      var tarifasOk = 0, tarifasErr = 0;
      for (var t = 0; t < tarifas.length; t++) {
        var tar = tarifas[t] || {};
        if (!_invStr(tar.temporada) && _invNum(tar.precio) === null) continue;
        var filaTar = {
          unidad_id: unidad_id,
          user_id: user_id,
          temporada: _invStr(tar.temporada),
          fecha_desde: _invDate(tar.desde),
          fecha_hasta: _invDate(tar.hasta),
          precio_noche: _invNum(tar.precio),
          moneda: _invStr(tar.moneda) || 'ARS',
          ocupacion_base: _invInt(tar.ocupacion_base),
          precio_persona_extra: _invNum(tar.persona_extra),
          min_noches: _invInt(tar.min_noches),
          prioridad: t
        };
        var trIns = await supabase.from('hotel_tarifa').insert(filaTar);
        if (trIns.error) {
          if (_invTablaFaltante(trIns.error)) return res.status(503).json({ error: 'La tabla hotel_tarifa no existe todavia. Corré la migracion.', tabla: 'hotel_tarifa', unidad_id: unidad_id });
          tarifasErr++;
        } else tarifasOk++;
      }

      // 4) Disponibilidad: el form NO manda filas de disponibilidad por fecha todavia
      //    (la seccion dice "se carga en proxima fase" y la disponibilidad sigue a las
      //    tarifas). No insertamos en hotel_disponibilidad para no inventar datos.
      //    El endpoint queda listo para recibirlas cuando el form las mande.

      return res.json({
        ok: true,
        rubro: 'hotel_cabanas',
        complejo_id: complejo_id,
        unidad_id: unidad_id,
        tarifas_guardadas: tarifasOk,
        tarifas_con_error: tarifasErr
      });
    }

    // ========================= DESARROLLADORA ==============================
    // Logica movida a guardarDesarrolladora() (compartida con /api/scrape/desarrollo/actualizar y el cron).
    if (rubro === 'desarrolladora') {
      var rDes = await guardarDesarrolladora(user_id, b);
      if (!rDes.ok) return res.status(rDes.status || 500).json(rDes);
      delete rDes.status;
      return res.json(rDes);
    }

    // Rubro no soportado por este endpoint (inmobiliaria usa su propio camino intacto).
    return res.status(400).json({ error: 'Rubro no soportado por /api/inventario/guardar: ' + (b.tipo_inventario || b.rubro || '(vacio)') + '. Este endpoint solo cubre hotel_cabanas y desarrolladora; inmobiliaria usa su flujo propio.' });
  } catch (e) {
    return res.status(500).json({ error: e && e.message });
  }
});

// ---- POST /api/inventario/desarrollo/eliminar -----------------------------
// Elimina un emprendimiento de desarrollo COMPLETO (sus unidades + sectores + la fila
// del emprendimiento). Feature aditiva: hoy no se puede borrar y quedan duplicados basura.
// Body: { development_id }. Auth con verificarUsuario (mismo que el resto).
// Tenant safety: el emprendimiento debe pertenecer al DUENO del tenant que llama.
app.post('/api/inventario/desarrollo/eliminar', async function (req, res) {
  try {
    // 1) AUTH: identidad por token (mismo verificarUsuario que el resto).
    var uid = await verificarUsuario(req);
    if (!uid) return res.status(401).json({ error: 'No autorizado' });

    // 2) Resolver el DUENO del tenant. Por DEFAULT el que llama ES el dueño (su uid = user_id
    //    del tenant); si es un asesor sub-cuenta, el dueño es su admin_id (patron estandar,
    //    igual que /api/contactos/renombrar). El paso 4 igual limita a SOLO el tenant resuelto.
    var ownerId = uid;
    try {
      var ase = await supabase.from('asesores').select('admin_id').eq('auth_user_id', uid).maybeSingle();
      if (ase && ase.data && ase.data.admin_id) ownerId = ase.data.admin_id;
    } catch (e1) {}

    // 3) BODY. development_id obligatorio.
    var b = req.body || {};
    var development_id = (b.development_id != null) ? String(b.development_id) : '';
    if (!development_id) return res.status(400).json({ error: 'Falta development_id' });

    // 4) SEGURIDAD DE TENANT: el emprendimiento debe pertenecer al DUENO del que llama.
    var dOwn;
    try {
      dOwn = await supabase.from('developments').select('user_id').eq('id', development_id).maybeSingle();
    } catch (eSel) {
      return res.status(500).json({ error: 'Error verificando el emprendimiento' });
    }
    if (dOwn && dOwn.error) {
      if (_invTablaFaltante(dOwn.error)) return res.status(503).json({ error: 'La tabla developments no existe todavia. Corré la migracion migracion-inventario-multirubro.sql.', tabla: 'developments' });
      return res.status(500).json({ error: 'Error verificando el emprendimiento: ' + dOwn.error.message });
    }
    if (!dOwn || !dOwn.data) return res.status(404).json({ error: 'El emprendimiento no existe', development_id: development_id });
    if (dOwn.data.user_id !== ownerId) return res.status(403).json({ error: 'El emprendimiento no pertenece a tu cuenta' });

    // 5) BORRADO en orden (hijos -> padre). Defensivo: si una tabla no existe todavia, seguimos;
    //    cualquier otro error corta con 500 para no dejar un borrado a medias silencioso.
    //    Todo scoped por development_id + user_id del tenant (nunca cross-tenant).
    try {
      var uDel = await supabase.from('development_units').delete().eq('development_id', development_id).eq('user_id', ownerId);
      if (uDel.error && !_invTablaFaltante(uDel.error)) {
        return res.status(500).json({ error: 'Error borrando unidades: ' + uDel.error.message, development_id: development_id });
      }
    } catch (eU) {}

    try {
      var sDel = await supabase.from('development_sectors').delete().eq('development_id', development_id).eq('user_id', ownerId);
      if (sDel.error && !_invTablaFaltante(sDel.error)) {
        return res.status(500).json({ error: 'Error borrando etapas: ' + sDel.error.message, development_id: development_id });
      }
    } catch (eS) {}

    var dDel;
    try {
      dDel = await supabase.from('developments').delete().eq('id', development_id).eq('user_id', ownerId);
    } catch (eD) {
      return res.status(500).json({ error: 'Error borrando el emprendimiento' });
    }
    if (dDel && dDel.error) {
      if (_invTablaFaltante(dDel.error)) return res.status(503).json({ error: 'La tabla developments no existe todavia. Corré la migracion migracion-inventario-multirubro.sql.', tabla: 'developments' });
      return res.status(500).json({ error: 'Error borrando el emprendimiento: ' + dDel.error.message, development_id: development_id });
    }

    return res.json({ ok: true });
  } catch (e) {
    return res.status(500).json({ error: e && e.message });
  }
});

// ---- POST /api/inventario/desarrollo/unidad-estado ------------------------
// Etapa 1: cambiar el ESTADO de UNA unidad de desarrollo SIN re-guardar todo el
// emprendimiento (evita la reescritura completa de unidades). Body:
//   { development_id, unit_id, estado }  con estado ∈ disponible|reservado|vendido|bloqueado.
// Auth con verificarUsuario + resolver DUENO por admin_id (patron estandar). Tenant safety:
// el emprendimiento debe pertenecer al dueño y la unidad debe pertenecer a ese emprendimiento.
// Setea development_units.estado + estado_updated_at (defensivo: si la columna aun no existe,
// reintenta sin ella). Ruta PLANA (sin :param opcional) — Express 5.
app.post('/api/inventario/desarrollo/unidad-estado', async function (req, res) {
  try {
    // 1) AUTH
    var uid = await verificarUsuario(req);
    if (!uid) return res.status(401).json({ error: 'No autorizado' });

    // 2) DUENO del tenant (asesor -> admin_id; dueño -> su propio uid).
    var ownerId = uid;
    try {
      var ase = await supabase.from('asesores').select('admin_id').eq('auth_user_id', uid).maybeSingle();
      if (ase && ase.data && ase.data.admin_id) ownerId = ase.data.admin_id;
    } catch (e1) {}

    // 3) BODY + validacion de enum.
    var b = req.body || {};
    var development_id = (b.development_id != null) ? String(b.development_id) : '';
    var unit_id = (b.unit_id != null) ? String(b.unit_id) : '';
    var estado = (b.estado != null) ? String(b.estado).trim().toLowerCase() : '';
    if (!development_id) return res.status(400).json({ error: 'Falta development_id' });
    if (!unit_id) return res.status(400).json({ error: 'Falta unit_id' });
    var ESTADOS_OK = ['disponible', 'reservado', 'vendido', 'bloqueado'];
    if (ESTADOS_OK.indexOf(estado) < 0) return res.status(400).json({ error: 'Estado invalido. Debe ser uno de: ' + ESTADOS_OK.join(', ') });

    // 4) TENANT: el emprendimiento debe pertenecer al dueño.
    var dOwn;
    try {
      dOwn = await supabase.from('developments').select('user_id').eq('id', development_id).maybeSingle();
    } catch (eSel) {
      return res.status(500).json({ error: 'Error verificando el emprendimiento' });
    }
    if (dOwn && dOwn.error) {
      if (_invTablaFaltante(dOwn.error)) return res.status(503).json({ error: 'La tabla developments no existe todavia. Corré la migracion migracion-inventario-multirubro.sql.', tabla: 'developments' });
      return res.status(500).json({ error: 'Error verificando el emprendimiento: ' + dOwn.error.message });
    }
    if (!dOwn || !dOwn.data) return res.status(404).json({ error: 'El emprendimiento no existe', development_id: development_id });
    if (dOwn.data.user_id !== ownerId) return res.status(403).json({ error: 'El emprendimiento no pertenece a tu cuenta' });

    // 5) UPDATE de la unidad (scoped por unit_id + development_id + user_id del dueño).
    //    estado_updated_at defensivo: si la columna aun no existe (migracion E1 sin correr),
    //    _devUpdateUnidad reintenta sin ella. Verificamos con .select para saber si matcheo.
    var payload = { estado: estado, estado_updated_at: new Date().toISOString() };
    var upd = await supabase.from('development_units')
      .update(payload).eq('id', unit_id).eq('development_id', development_id).eq('user_id', ownerId).select('id');
    if (upd.error && _invTablaFaltante(upd.error)) {
      // Puede ser la tabla ausente O la columna estado_updated_at ausente -> reintentar solo estado.
      var upd2 = await supabase.from('development_units')
        .update({ estado: estado }).eq('id', unit_id).eq('development_id', development_id).eq('user_id', ownerId).select('id');
      if (upd2.error) {
        if (_invTablaFaltante(upd2.error)) return res.status(503).json({ error: 'La tabla development_units no existe todavia. Corré la migracion.', tabla: 'development_units' });
        return res.status(500).json({ error: 'Error actualizando la unidad: ' + upd2.error.message });
      }
      if (!upd2.data || !upd2.data.length) return res.status(404).json({ error: 'La unidad no existe en este emprendimiento', unit_id: unit_id });
      _maybeMatchUnidadDisponible(ownerId, development_id, unit_id, estado); // E4: matching (gated matching_v1, best-effort)
      return res.json({ ok: true, unit_id: unit_id, estado: estado, estado_updated_at: false });
    }
    if (upd.error) return res.status(500).json({ error: 'Error actualizando la unidad: ' + upd.error.message });
    if (!upd.data || !upd.data.length) return res.status(404).json({ error: 'La unidad no existe en este emprendimiento', unit_id: unit_id });
    _maybeMatchUnidadDisponible(ownerId, development_id, unit_id, estado); // E4: matching (gated matching_v1, best-effort)
    return res.json({ ok: true, unit_id: unit_id, estado: estado, estado_updated_at: true });
  } catch (e) {
    return res.status(500).json({ error: e && e.message });
  }
});

// ============================================================================
// ===== ETAPA 2 — DESARROLLADORA: RESERVA/SEÑA DE UNIDAD (sin pagos linkeados) =
// ============================================================================
// TODO gateado por business_settings.dev_reservas_v1 en los endpoints que MUTAN
// (crear/estado/sena); el GET (listar) responde acotado al tenant (ownerId) sin
// exponer datos de otras cuentas. Auth verificarUsuario + ownerId por admin_id
// (un asesor opera sobre la cuenta del dueño). DEFENSIVO: si falta la tabla
// dev_reservas -> 503 con mensaje claro en los mutantes; el GET devuelve lista
// vacia (no rompe la UI). NO cambia el comportamiento de inmobiliaria/hotel ni de
// una desarrolladora con dev_reservas_v1 OFF. CERO IA / CERO tokens.
// RESTRICCION MAESTRA: la seña se registra SOLO por COMPROBANTE subido
// (comprobante_url via subirImagenSoporte, patron hotel_pagos). PROHIBIDO MercadoPago.
// Rutas PLANAS (Express 5): solo segmentos :param OBLIGATORIOS, sin ? ni *.

// Estados de una reserva de unidad. ACTIVA (bloquea la unidad) = senada|confirmada.
var _DR_ACTIVAS = ['senada', 'confirmada'];
// Orden del ciclo "hacia adelante". 'caida' es terminal y sale de cualquier no-terminal.
var _DR_ORDEN = { tentativa: 0, senada: 1, confirmada: 2 };
var _DR_ESTADOS = ['tentativa', 'senada', 'confirmada', 'caida'];
// Estados con los que una reserva puede NACER (carga manual puede nacer ya señada/confirmada).
var _DR_ESTADOS_INICIALES = ['tentativa', 'senada', 'confirmada'];

// Gate maestro dev_reservas_v1 (mirror de _reservasV1Activo). Ante error o columna
// ausente -> false (comportamiento actual). NUNCA rompe.
async function _devReservasV1Activo(user_id) {
  try {
    if (!user_id) return false;
    var r = await supabase.from('business_settings').select('dev_reservas_v1').eq('user_id', user_id).maybeSingle();
    if (r.error) return false; // columna ausente u otro error -> flag OFF
    return !!(r.data && r.data.dev_reservas_v1 === true);
  } catch (e) { return false; }
}

// Mapea el estado de la RESERVA al estado que debe tener la UNIDAD (sync E2->E1).
//   senada -> reservado ; confirmada -> vendido ; caida -> disponible.
//   tentativa -> null (no toca la unidad: es solo un interes/hold blando).
function _devEstadoUnidadPara(estadoReserva) {
  if (estadoReserva === 'senada') return 'reservado';
  if (estadoReserva === 'confirmada') return 'vendido';
  if (estadoReserva === 'caida') return 'disponible';
  return null;
}

// Sincroniza el estado de la unidad via el UPDATE defensivo de E1 (_devUpdateUnidad):
// si la columna estado_updated_at aun no existe, reintenta sin ella. Best-effort: si
// falla, la reserva NO se revierte (loguea y sigue). Devuelve true/false.
async function _devReservaSyncUnidad(ownerId, unit_id, estadoReserva) {
  try {
    var eu = _devEstadoUnidadPara(estadoReserva);
    if (!eu || !unit_id) return false;
    var r = await _devUpdateUnidad(unit_id, ownerId, { estado: eu }, true);
    if (r && r.error) { console.error('_devReservaSyncUnidad:', r.error.message); return false; }
    return true;
  } catch (e) { console.error('_devReservaSyncUnidad:', e && e.message); return false; }
}

// Busca reservas ACTIVAS (senada|confirmada) de una unidad, excluyendo una propia
// (excludeId). Devuelve el array (vacio = libre). Si la tabla falta -> tira
// { _tablaFaltante:true } para que el caller responda 503.
async function _devReservaActivaEnUnidad(ownerId, unit_id, excludeId) {
  var r = await supabase.from('dev_reservas')
    .select('id, estado, contact_id, created_at')
    .eq('user_id', ownerId).eq('unit_id', unit_id).in('estado', _DR_ACTIVAS);
  if (r.error) { if (_invTablaFaltante(r.error)) throw { _tablaFaltante: true, tabla: 'dev_reservas' }; throw r.error; }
  return (r.data || []).filter(function (x) { return String(x.id) !== String(excludeId || ''); });
}

// Verifica que la unidad pertenezca al desarrollo Y al dueño. Devuelve la fila de la
// unidad o null. Si la tabla falta -> tira { _tablaFaltante:true }.
async function _devUnidadDeDesarrollo(ownerId, development_id, unit_id) {
  var r = await supabase.from('development_units').select('id, estado, numero, tipologia')
    .eq('id', unit_id).eq('development_id', development_id).eq('user_id', ownerId).maybeSingle();
  if (r.error) { if (_invTablaFaltante(r.error)) throw { _tablaFaltante: true, tabla: 'development_units' }; throw r.error; }
  return r.data || null;
}

// ---- POST /api/dev/reservas/crear ------------------------------------------
// GATEADO dev_reservas_v1. Crea una reserva de unidad. body: { development_id, unit_id,
// contact_id? | conversation_id?, estado?, monto_sena?, moneda?, notas? }.
// ANTI-DOBLE: rechaza (409) si la unidad ya tiene una reserva ACTIVA (senada|confirmada).
// Si nace señada/confirmada -> sincroniza el estado de la unidad (reservado/vendido).
app.post('/api/dev/reservas/crear', async function (req, res) {
  try {
    var userId = await verificarUsuario(req);
    if (!userId) return res.status(401).json({ error: 'No autorizado' });
    var ownerId = await _resolverOwnerId(userId);
    if (!(await _devReservasV1Activo(ownerId))) return res.status(403).json({ error: 'La gestion de reservas de desarrollo no esta activada para esta cuenta.', gate: 'dev_reservas_v1' });
    var b = req.body || {};
    var development_id = (b.development_id != null) ? String(b.development_id) : '';
    var unit_id = (b.unit_id != null) ? String(b.unit_id) : '';
    if (!development_id) return res.status(400).json({ error: 'Falta development_id' });
    if (!unit_id) return res.status(400).json({ error: 'Falta unit_id' });
    var contactId = b.contact_id || null;
    var conversationId = b.conversation_id || null;
    // Derivar el contacto desde la conversacion si no vino contact_id (acotado al tenant).
    if (!contactId && conversationId) {
      try { var cv = await supabase.from('conversations').select('contact_id').eq('id', conversationId).eq('user_id', ownerId).maybeSingle(); if (cv && cv.data) contactId = cv.data.contact_id || null; } catch (eCv) {}
    }
    // La unidad debe pertenecer al desarrollo y al dueño.
    var unidad;
    try { unidad = await _devUnidadDeDesarrollo(ownerId, development_id, unit_id); }
    catch (eU) { if (eU && eU._tablaFaltante) return res.status(503).json({ error: 'La tabla ' + eU.tabla + ' no existe todavia. Corré la migracion.', tabla: eU.tabla }); return res.status(500).json({ error: 'Error verificando la unidad' }); }
    if (!unidad) return res.status(404).json({ error: 'La unidad no existe en este emprendimiento (o no es de tu cuenta)' });
    var estado = (_DR_ESTADOS_INICIALES.indexOf(b.estado) >= 0) ? b.estado : 'tentativa';
    // ANTI-DOBLE: si nace ACTIVA, o si simplemente hay otra reserva activa en la unidad -> 409.
    // (Una tentativa NO bloquea; pero NO se puede crear una nueva si ya hay una señada/confirmada.)
    try {
      var activas = await _devReservaActivaEnUnidad(ownerId, unit_id, null);
      if (activas.length) return res.status(409).json({ error: 'La unidad ya tiene una reserva activa (señada o confirmada).', reserva_activa: activas[0] });
    } catch (eA) { if (eA && eA._tablaFaltante) return res.status(503).json({ error: 'La tabla dev_reservas no existe todavia. Corré la migracion migracion-dev-reservas.sql.', tabla: 'dev_reservas' }); return res.status(500).json({ error: 'Error verificando reservas de la unidad' }); }
    var fila = {
      user_id: ownerId, development_id: development_id, unit_id: unit_id,
      contact_id: contactId, conversation_id: conversationId,
      estado: estado,
      monto_sena: (b.monto_sena != null && b.monto_sena !== '') ? (Number(b.monto_sena) || 0) : null,
      moneda: b.moneda ? String(b.moneda).slice(0, 8) : 'USD',
      notas: (b.notas || b.internal_notes) ? String(b.notas || b.internal_notes).slice(0, 2000) : null,
      created_by: userId
    };
    var ins = await supabase.from('dev_reservas').insert(fila).select('*').single();
    if (ins.error) {
      if (_invTablaFaltante(ins.error)) return res.status(503).json({ error: 'La tabla dev_reservas no existe todavia. Corré la migracion migracion-dev-reservas.sql.', tabla: 'dev_reservas' });
      return res.status(500).json({ error: ins.error.message });
    }
    var reserva = ins.data;
    // Sync de la unidad si nace ACTIVA (señada -> reservado; confirmada -> vendido). Best-effort.
    if (_DR_ACTIVAS.indexOf(estado) >= 0) { await _devReservaSyncUnidad(ownerId, unit_id, estado); }
    return res.json({ ok: true, reserva: reserva });
  } catch (e) { return res.status(500).json({ error: e && e.message }); }
});

// ---- POST /api/dev/reservas/:id/estado -------------------------------------
// GATEADO dev_reservas_v1. Transicion de estado validada por grafo:
//   tentativa -> senada -> confirmada (forward-only), y cualquiera-no-terminal -> caida
//   (con motivo_caida OBLIGATORIO). 'caida' es terminal. Al pasar a ACTIVA re-chequea
//   anti-doble (409). Sincroniza el estado de la unidad. Ruta PLANA (:id obligatorio).
app.post('/api/dev/reservas/:id/estado', async function (req, res) {
  try {
    var userId = await verificarUsuario(req);
    if (!userId) return res.status(401).json({ error: 'No autorizado' });
    var ownerId = await _resolverOwnerId(userId);
    if (!(await _devReservasV1Activo(ownerId))) return res.status(403).json({ error: 'La gestion de reservas de desarrollo no esta activada para esta cuenta.', gate: 'dev_reservas_v1' });
    var id = req.params.id;
    var b = req.body || {};
    var nuevo = String(b.estado || b.status || '');
    if (_DR_ESTADOS.indexOf(nuevo) < 0) return res.status(400).json({ error: 'Estado invalido. Debe ser uno de: ' + _DR_ESTADOS.join(', ') });
    var rr = await supabase.from('dev_reservas').select('*').eq('id', id).eq('user_id', ownerId).maybeSingle();
    if (rr.error) { if (_invTablaFaltante(rr.error)) return res.status(503).json({ error: 'La tabla dev_reservas no existe todavia. Corré la migracion migracion-dev-reservas.sql.', tabla: 'dev_reservas' }); return res.status(500).json({ error: rr.error.message }); }
    if (!rr.data) return res.status(404).json({ error: 'Reserva no encontrada' });
    var reserva = rr.data;
    var actual = reserva.estado;
    // Validacion de grafo.
    var esCaida = (nuevo === 'caida');
    var valido = false;
    if (actual === 'caida') valido = false; // terminal: no se mueve
    else if (esCaida) valido = true;        // cualquiera-no-terminal -> caida
    else if (Object.prototype.hasOwnProperty.call(_DR_ORDEN, actual) && Object.prototype.hasOwnProperty.call(_DR_ORDEN, nuevo) && _DR_ORDEN[nuevo] > _DR_ORDEN[actual]) valido = true;
    if (!valido) return res.status(400).json({ error: 'Transicion no permitida: ' + actual + ' -> ' + nuevo });
    if (esCaida && !String(b.motivo_caida || b.motivo || '').trim()) return res.status(400).json({ error: 'caida exige un motivo (motivo_caida)' });
    // Al pasar a ACTIVA, re-chequear anti-doble (otra reserva pudo ganar la unidad).
    if (_DR_ACTIVAS.indexOf(nuevo) >= 0) {
      try {
        var activas = await _devReservaActivaEnUnidad(ownerId, reserva.unit_id, reserva.id);
        if (activas.length) return res.status(409).json({ error: 'Otra reserva activa gano esta unidad.', reserva_activa: activas[0] });
      } catch (eA) { if (eA && eA._tablaFaltante) return res.status(503).json({ error: 'La tabla dev_reservas no existe todavia.', tabla: 'dev_reservas' }); }
    }
    var upd = { estado: nuevo, updated_at: new Date().toISOString() };
    if (esCaida) upd.motivo_caida = String(b.motivo_caida || b.motivo).slice(0, 500);
    var wr = await supabase.from('dev_reservas').update(upd).eq('id', reserva.id).eq('user_id', ownerId).select('*').single();
    if (wr.error) return res.status(500).json({ error: wr.error.message });
    // Sync de la unidad (senada->reservado; confirmada->vendido; caida->disponible). Best-effort.
    if (reserva.unit_id) { await _devReservaSyncUnidad(ownerId, reserva.unit_id, nuevo); }
    return res.json({ ok: true, reserva: wr.data });
  } catch (e) { return res.status(500).json({ error: e && e.message }); }
});

// ---- POST /api/dev/reservas/:id/sena ---------------------------------------
// GATEADO dev_reservas_v1. Registra la SEÑA de una reserva con COMPROBANTE subido
// (foto/PDF). body: { monto_sena, moneda?, comprobante_data_url? (data URL base64) |
// comprobante_url? (ya subido), notas? }. Sube el comprobante al bucket 'media' via
// subirImagenSoporte (mismo patron que hotel_pagos). PROHIBIDO MercadoPago/checkout.
// Si la reserva estaba 'tentativa' -> AUTO-AVANZA a 'senada' (seña recibida = unidad
// reservada), re-chequeando anti-doble. Ruta PLANA (:id obligatorio).
app.post('/api/dev/reservas/:id/sena', async function (req, res) {
  try {
    var userId = await verificarUsuario(req);
    if (!userId) return res.status(401).json({ error: 'No autorizado' });
    var ownerId = await _resolverOwnerId(userId);
    if (!(await _devReservasV1Activo(ownerId))) return res.status(403).json({ error: 'La gestion de reservas de desarrollo no esta activada para esta cuenta.', gate: 'dev_reservas_v1' });
    var id = req.params.id;
    var b = req.body || {};
    var rr = await supabase.from('dev_reservas').select('*').eq('id', id).eq('user_id', ownerId).maybeSingle();
    if (rr.error) { if (_invTablaFaltante(rr.error)) return res.status(503).json({ error: 'La tabla dev_reservas no existe todavia. Corré la migracion migracion-dev-reservas.sql.', tabla: 'dev_reservas' }); return res.status(500).json({ error: rr.error.message }); }
    if (!rr.data) return res.status(404).json({ error: 'Reserva no encontrada' });
    var reserva = rr.data;
    if (reserva.estado === 'caida') return res.status(400).json({ error: 'La reserva esta caida: no se puede registrar una seña.' });
    var monto = Number(b.monto_sena != null ? b.monto_sena : b.amount);
    if (!(monto > 0)) return res.status(400).json({ error: 'monto_sena invalido (debe ser > 0)' });
    // COMPROBANTE: data URL base64 -> subir al bucket 'media'; o comprobante_url ya subido.
    // NUNCA una pasarela de pago (restriccion maestra): solo el comprobante que sube el equipo.
    var comprobanteUrl = null;
    var _dataUrl = b.comprobante_data_url || b.proof_data_url;
    if (_dataUrl && String(_dataUrl).indexOf('data:') === 0) { try { comprobanteUrl = await subirImagenSoporte(_dataUrl, 'cliente'); } catch (ePu) {} }
    else if (b.comprobante_url && typeof b.comprobante_url === 'string') comprobanteUrl = String(b.comprobante_url).slice(0, 1000);
    // Si la reserva sigue tentativa, la seña la lleva a 'senada' -> re-chequear anti-doble.
    var nuevoEstado = reserva.estado;
    if (reserva.estado === 'tentativa') {
      try {
        var activas = await _devReservaActivaEnUnidad(ownerId, reserva.unit_id, reserva.id);
        if (activas.length) return res.status(409).json({ error: 'La unidad ya tiene otra reserva activa: no se puede señar esta.', reserva_activa: activas[0] });
      } catch (eA) { if (eA && eA._tablaFaltante) return res.status(503).json({ error: 'La tabla dev_reservas no existe todavia.', tabla: 'dev_reservas' }); }
      nuevoEstado = 'senada';
    }
    var upd = {
      monto_sena: monto,
      moneda: b.moneda ? String(b.moneda).slice(0, 8) : (reserva.moneda || 'USD'),
      estado: nuevoEstado, updated_at: new Date().toISOString()
    };
    if (comprobanteUrl) upd.comprobante_url = comprobanteUrl;
    if (b.notas != null) upd.notas = String(b.notas).slice(0, 2000);
    var wr = await supabase.from('dev_reservas').update(upd).eq('id', reserva.id).eq('user_id', ownerId).select('*').single();
    if (wr.error) return res.status(500).json({ error: wr.error.message });
    // Sync unidad si la seña la dejo ACTIVA (señada -> reservado). Best-effort.
    if (_DR_ACTIVAS.indexOf(nuevoEstado) >= 0 && reserva.unit_id) { await _devReservaSyncUnidad(ownerId, reserva.unit_id, nuevoEstado); }
    return res.json({ ok: true, reserva: wr.data, comprobante_url: comprobanteUrl });
  } catch (e) { return res.status(500).json({ error: e && e.message }); }
});

// ---- GET /api/dev/reservas -------------------------------------------------
// Lista de reservas del tenant con filtro por ?development_id= o ?conversation_id=.
// Join liviano a contacts (nombre/tel) y development_units (numero/tipologia). Acotado
// a ownerId (no expone otras cuentas). Sin gate (leer no muta). DEFENSIVO: si la tabla
// dev_reservas no existe todavia -> lista vacia (no rompe la UI).
app.get('/api/dev/reservas', async function (req, res) {
  try {
    var userId = await verificarUsuario(req);
    if (!userId) return res.status(401).json({ error: 'No autorizado' });
    var ownerId = await _resolverOwnerId(userId);
    var query = req.query || {};
    var q = supabase.from('dev_reservas').select('*').eq('user_id', ownerId);
    if (query.development_id) q = q.eq('development_id', String(query.development_id));
    if (query.conversation_id) q = q.eq('conversation_id', String(query.conversation_id));
    if (query.estado) q = q.eq('estado', String(query.estado));
    q = q.order('created_at', { ascending: false }).limit(2000);
    var r = await q;
    if (r.error) { if (_invTablaFaltante(r.error)) return res.json({ ok: true, reservas: [] }); return res.status(500).json({ error: r.error.message }); }
    var reservas = r.data || [];
    var cIds = [], uIds = [];
    reservas.forEach(function (x) { if (x.contact_id) cIds.push(x.contact_id); if (x.unit_id) uIds.push(x.unit_id); });
    var contactosMap = {}, unidadesMap = {};
    if (cIds.length) { try { var cr = await supabase.from('contacts').select('id, name, nombre_manual, phone').in('id', Array.from(new Set(cIds))); (cr.data || []).forEach(function (c) { contactosMap[c.id] = { nombre: c.nombre_manual || c.name || null, telefono: c.phone || null }; }); } catch (eC) {} }
    if (uIds.length) { try { var ur = await supabase.from('development_units').select('id, numero, tipologia, tipo_producto').in('id', Array.from(new Set(uIds))); (ur.data || []).forEach(function (u) { unidadesMap[u.id] = { numero: u.numero || null, tipologia: u.tipologia || u.tipo_producto || null }; }); } catch (eU) {} }
    var out = reservas.map(function (x) {
      return Object.assign({}, x, {
        contacto: x.contact_id ? (contactosMap[x.contact_id] || null) : null,
        unidad_ref: x.unit_id ? (unidadesMap[x.unit_id] || null) : null
      });
    });
    return res.json({ ok: true, reservas: out });
  } catch (e) { return res.status(500).json({ error: e && e.message }); }
});

// ---- GET /api/inventario/cargar -------------------------------------------
// Devuelve el inventario del rubro del usuario (filtrado por user_id, via RLS y
// filtro explicito) para que el form pueda precargar.
//   - hotel_cabanas: complejos (hotel_complejos) + unidades (hotel_unidades)
//                    + tarifas por unidad (hotel_tarifa).
//   - desarrolladora: emprendimientos + sectores + unidades.
//   - inmobiliaria: NO se toca aca (tiene su propio listado de properties); se
//     devuelve un hint para que el front use el endpoint inmobiliaria de siempre.
// El rubro sale de business_settings.rubro; si no hay, se infiere por ?rubro=.
app.get('/api/inventario/cargar', async function (req, res) {
  try {
    var user_id = await verificarUsuario(req);
    if (!user_id) return res.status(401).json({ error: 'No autorizado' });

    var rubro = normalizarRubro((req.query && req.query.rubro) || '');
    if (!req.query || !req.query.rubro) {
      try {
        var bs = await supabase.from('business_settings').select('rubro').eq('user_id', user_id).maybeSingle();
        rubro = normalizarRubro((bs && bs.data && bs.data.rubro) || '');
      } catch (eBs) {}
    }

    // ======================= HOTEL / CABAÑAS ===============================
    if (rubro === 'hotel_cabanas') {
      var grupos = await supabase.from('hotel_complejos')
        .select('*').eq('user_id', user_id).order('created_at', { ascending: true });
      if (grupos.error && _invTablaFaltante(grupos.error)) {
        return res.status(503).json({ error: 'La tabla hotel_complejos no existe todavia. Corré la migracion migracion-inventario-multirubro.sql.', tabla: 'hotel_complejos' });
      }
      var unidadesH = await supabase.from('hotel_unidades')
        .select('*').eq('user_id', user_id);
      if (unidadesH.error && _invTablaFaltante(unidadesH.error)) {
        return res.status(503).json({ error: 'La tabla hotel_unidades no existe todavia. Corré la migracion y NOTIFY pgrst.', tabla: 'hotel_unidades' });
      }
      var tarifasH = await supabase.from('hotel_tarifa').select('*').eq('user_id', user_id);
      if (tarifasH.error && _invTablaFaltante(tarifasH.error)) {
        return res.status(503).json({ error: 'La tabla hotel_tarifa no existe todavia. Corré la migracion.', tabla: 'hotel_tarifa' });
      }
      // Agrupar tarifas por unidad_id para que el front las precargue por unidad.
      var tarifasPorUnidad = {};
      (tarifasH.data || []).forEach(function (tr) {
        (tarifasPorUnidad[tr.unidad_id] = tarifasPorUnidad[tr.unidad_id] || []).push(tr);
      });
      var unidadesOut = (unidadesH.data || []).map(function (p) {
        return Object.assign({}, p, { tarifas: tarifasPorUnidad[p.id] || [] });
      });
      return res.json({
        ok: true,
        rubro: 'hotel_cabanas',
        grupos: grupos.data || [],
        unidades: unidadesOut
      });
    }

    // ========================= DESARROLLADORA ==============================
    if (rubro === 'desarrolladora') {
      var devs = await supabase.from('developments')
        .select('*').eq('user_id', user_id).order('created_at', { ascending: true });
      if (devs.error && _invTablaFaltante(devs.error)) {
        return res.status(503).json({ error: 'La tabla developments no existe todavia. Corré la migracion migracion-inventario-multirubro.sql.', tabla: 'developments' });
      }
      var secs = await supabase.from('development_sectors').select('*').eq('user_id', user_id);
      if (secs.error && _invTablaFaltante(secs.error)) {
        return res.status(503).json({ error: 'La tabla development_sectors no existe todavia. Corré la migracion.', tabla: 'development_sectors' });
      }
      var uns = await supabase.from('development_units').select('*').eq('user_id', user_id);
      if (uns.error && _invTablaFaltante(uns.error)) {
        return res.status(503).json({ error: 'La tabla development_units no existe todavia. Corré la migracion.', tabla: 'development_units' });
      }
      // Anidar sectores y unidades dentro de su emprendimiento.
      var secsPorDev = {}, unsPorDev = {};
      (secs.data || []).forEach(function (s) { (secsPorDev[s.development_id] = secsPorDev[s.development_id] || []).push(s); });
      (uns.data || []).forEach(function (u) { (unsPorDev[u.development_id] = unsPorDev[u.development_id] || []).push(u); });
      var devsOut = (devs.data || []).map(function (d) {
        return Object.assign({}, d, { sectores: secsPorDev[d.id] || [], unidades: unsPorDev[d.id] || [] });
      });
      return res.json({ ok: true, rubro: 'desarrolladora', emprendimientos: devsOut });
    }

    // Inmobiliaria u otro: este endpoint no maneja inmobiliaria (flujo intacto aparte).
    return res.json({ ok: true, rubro: rubro, inmobiliaria: true, mensaje: 'El rubro inmobiliaria usa su propio listado de properties; /api/inventario/cargar solo cubre hotel_cabanas y desarrolladora.' });
  } catch (e) {
    return res.status(500).json({ error: e && e.message });
  }
});


// ============================================================================
// ===== FASE 2 — MOTOR DE RESERVAS DE HOTEL (endpoints backend) ==============
// ============================================================================
// TODO gateado por business_settings.reservas_v1 en los endpoints que MUTAN
// (crear/estado/pago/editar); los GET (lista/rack) responden acotados al tenant
// (ownerId) sin exponer datos de otras cuentas. Auth verificarUsuario + ownerId
// por admin_id (un asesor opera sobre la cuenta del dueno). DEFENSIVO: si faltan
// las tablas hotel_reservas/hotel_pagos -> 503 con mensaje claro (_invTablaFaltante),
// nunca crashea. NO cambia el comportamiento de inmobiliaria/desarrolladora ni de
// hoteles con reservas_v1 OFF. CERO IA / CERO tokens (solo SQL + storage).
// Rutas PLANAS (Express 5): solo segmentos :param OBLIGATORIOS, sin ? ni *.

// Estados que BLOQUEAN el calendario (una unidad no puede tener dos de estos
// SOLAPADOS en las mismas fechas). El resto (tentative/quote_sent/cancelled/
// lost/checked_out) NO bloquea.
var _HR_BLOQUEANTES = ['deposit_pending', 'confirmed', 'checked_in'];
// Orden del ciclo de vida "hacia adelante". cancelled/lost salen aparte (terminal).
var _HR_ORDEN = { tentative: 0, quote_sent: 1, deposit_pending: 2, confirmed: 3, checked_in: 4, checked_out: 5 };
var _HR_TERMINALES = ['checked_out', 'cancelled', 'lost'];
// Estados con los que una reserva puede NACER (carga manual puede nacer confirmada).
var _HR_ESTADOS_INICIALES = ['tentative', 'quote_sent', 'deposit_pending', 'confirmed'];

// Gate maestro reservas_v1 (mirror EXACTO de oportunidadesV1Activo): ante cualquier
// error o columna ausente -> false (comportamiento actual). NUNCA rompe.
async function _reservasV1Activo(user_id, bs) {
  try {
    if (bs && Object.prototype.hasOwnProperty.call(bs, 'reservas_v1')) return bs.reservas_v1 === true;
    if (!user_id) return false;
    const { data, error } = await supabase.from('business_settings').select('reservas_v1').eq('user_id', user_id).maybeSingle();
    if (error) return false; // columna ausente u otro error -> flag OFF (comportamiento actual)
    return !!(data && data.reservas_v1 === true);
  } catch (e) { return false; }
}

// Normaliza 'YYYY-MM-DD' -> ISO al MEDIODIA UTC (evita corrimiento de dia por TZ al
// crear la cita espejo). null si la fecha es invalida.
function _hrFechaISOmediodia(d) {
  var s = String(d || '').slice(0, 10);
  if (!/^\d{4}-\d{2}-\d{2}$/.test(s)) return null;
  return s + 'T12:00:00.000Z';
}

// Busca reservas BLOQUEANTES de una unidad que SOLAPEN [check_in, check_out) (intervalos
// semiabiertos: ex.check_in < nueva.check_out AND ex.check_out > nueva.check_in), excluyendo
// una reserva propia (excludeId). Devuelve el array de conflictos (vacio = libre). Si la tabla
// falta, tira { _tablaFaltante:true } para que el caller responda 503.
async function _hrConflictosSolape(ownerId, unit_id, check_in, check_out, excludeId) {
  var r = await supabase.from('hotel_reservas')
    .select('id, check_in, check_out, status, contact_id')
    .eq('user_id', ownerId).eq('unit_id', unit_id)
    .in('status', _HR_BLOQUEANTES)
    .lt('check_in', check_out).gt('check_out', check_in); // solape semiabierto a nivel SQL
  if (r.error) { if (_invTablaFaltante(r.error)) throw { _tablaFaltante: true, tabla: 'hotel_reservas' }; throw r.error; }
  return (r.data || []).filter(function (x) { return String(x.id) !== String(excludeId || ''); });
}
function _hrConflictoOut(lista) {
  return (lista || []).map(function (c) { return { id: c.id, check_in: c.check_in, check_out: c.check_out, status: c.status }; });
}

// Crea la CITA ESPEJO de una reserva confirmada (tipo alquiler_temporal) y DISPARA el motor
// de housekeeping (generarTareasAlquiler, igual que POST /api/citas). Devuelve cita_id o null
// (best-effort: si algo falla, la reserva NO se revierte). Guarda unidad_id (con retry defensivo).
async function _hrCrearCitaEspejo(ownerId, reserva) {
  try {
    var ci = _hrFechaISOmediodia(reserva.check_in);
    var co = _hrFechaISOmediodia(reserva.check_out);
    if (!ci) return null;
    var unidadTitle = '';
    try { var u = await supabase.from('hotel_unidades').select('title, numero').eq('id', reserva.unit_id).maybeSingle(); if (u && u.data) unidadTitle = u.data.title || u.data.numero || ''; } catch (eU) {}
    var leadNombre = null, leadTel = null;
    if (reserva.contact_id) { try { var c = await supabase.from('contacts').select('name, nombre_manual, phone').eq('id', reserva.contact_id).maybeSingle(); if (c && c.data) { leadNombre = c.data.nombre_manual || c.data.name || null; leadTel = c.data.phone || null; } } catch (eC) {} }
    var titulo = ('Reserva ' + (unidadTitle || 'unidad') + (leadNombre ? (' - ' + leadNombre) : '')).slice(0, 160);
    var fila = {
      user_id: ownerId, fecha_hora: ci, fecha_fin: co, tipo: 'alquiler_temporal',
      titulo: titulo, estado: 'agendada', contact_id: reserva.contact_id || null,
      conversation_id: reserva.conversation_id || null,
      unidad: unidadTitle ? String(unidadTitle).slice(0, 120) : null, unidad_id: reserva.unit_id || null,
      todo_el_dia: true, lead_nombre: leadNombre ? String(leadNombre).slice(0, 120) : null,
      lead_telefono: leadTel ? String(leadTel).slice(0, 40) : null, origen: 'manual'
    };
    var r = await supabase.from('citas').insert(fila).select('id').single();
    if (r.error) {
      // Retry defensivo sin la columna mas nueva (unidad_id) por si el cache/migracion.
      var filaMin = Object.assign({}, fila); delete filaMin.unidad_id;
      r = await supabase.from('citas').insert(filaMin).select('id').single();
      if (r.error) { console.error('_hrCrearCitaEspejo insert cita:', r.error.message); return null; }
    }
    var citaId = r.data && r.data.id;
    // Motor de housekeeping (limpiezas pre/post): mismo disparo que POST /api/citas alquiler_temporal.
    if (citaId && co) { try { await generarTareasAlquiler(ownerId, citaId, ci, co, titulo); } catch (eG) { console.error('_hrCrearCitaEspejo generarTareas:', eG && eG.message); } }
    return citaId || null;
  } catch (e) { console.error('_hrCrearCitaEspejo:', e && e.message); return null; }
}

// Recalcula deposit_amount / balance_amount / payment_status de una reserva a partir de la
// suma de pagos APROBADOS. Best-effort: devuelve { deposit_amount, balance_amount, payment_status,
// aprobado } o null.
async function _hrRecalcularMontos(ownerId, reservaId, totalAmount) {
  try {
    var pr = await supabase.from('hotel_pagos').select('amount, status').eq('user_id', ownerId).eq('reservation_id', reservaId);
    if (pr.error) { if (_invTablaFaltante(pr.error)) return null; }
    var sumApr = 0;
    (pr.data || []).forEach(function (p) { if (p && p.status === 'approved') sumApr += Number(p.amount) || 0; });
    var total = Number(totalAmount) || 0;
    var balance = total > 0 ? (total - sumApr) : (0 - sumApr);
    var payStatus = 'unpaid';
    if (sumApr <= 0) payStatus = 'unpaid';
    else if (total > 0 && sumApr >= total) payStatus = 'paid';
    else payStatus = 'partial';
    var upd = { deposit_amount: sumApr, balance_amount: balance, payment_status: payStatus, updated_at: new Date().toISOString() };
    await supabase.from('hotel_reservas').update(upd).eq('id', reservaId).eq('user_id', ownerId);
    return { deposit_amount: sumApr, balance_amount: balance, payment_status: payStatus, aprobado: sumApr };
  } catch (e) { console.error('_hrRecalcularMontos:', e && e.message); return null; }
}

// ---- GET /api/hotel/reservas ------------------------------------------------
// Lista de reservas del tenant con filtros por querystring: ?estado= ?unidad=
// ?desde= ?hasta= ?conversation_id=. Join liviano a contacts (nombre/tel) y
// hotel_unidades (title). Acotado a ownerId (no expone otras cuentas). Sin gate
// (leer no muta; sin reservas cargadas devuelve lista vacia = inerte).
app.get('/api/hotel/reservas', async function (req, res) {
  try {
    var userId = await verificarUsuario(req);
    if (!userId) return res.status(401).json({ error: 'No autorizado' });
    var ownerId = await _resolverOwnerId(userId);
    var query = req.query || {};
    var q = supabase.from('hotel_reservas').select('*').eq('user_id', ownerId);
    if (query.estado) q = q.eq('status', String(query.estado));
    if (query.unidad) q = q.eq('unit_id', String(query.unidad));
    if (query.conversation_id) q = q.eq('conversation_id', String(query.conversation_id));
    // Rango [desde, hasta): reservas que SOLAPAN el rango (semiabierto).
    if (query.hasta) q = q.lt('check_in', String(query.hasta).slice(0, 10));
    if (query.desde) q = q.gt('check_out', String(query.desde).slice(0, 10));
    q = q.order('check_in', { ascending: true }).limit(2000);
    var r = await q;
    if (r.error) {
      if (_invTablaFaltante(r.error)) return res.status(503).json({ error: 'La tabla hotel_reservas no existe todavia. Corré la migracion de reservas.', tabla: 'hotel_reservas' });
      return res.status(500).json({ error: r.error.message });
    }
    var reservas = r.data || [];
    // Join liviano por batch de ids (sin depender de FKs de PostgREST).
    var cIds = [], uIds = [];
    reservas.forEach(function (x) { if (x.contact_id) cIds.push(x.contact_id); if (x.unit_id) uIds.push(x.unit_id); });
    var contactosMap = {}, unidadesMap = {};
    if (cIds.length) { try { var cr = await supabase.from('contacts').select('id, name, nombre_manual, phone').in('id', Array.from(new Set(cIds))); (cr.data || []).forEach(function (c) { contactosMap[c.id] = { nombre: c.nombre_manual || c.name || null, telefono: c.phone || null }; }); } catch (eC) {} }
    if (uIds.length) { try { var ur = await supabase.from('hotel_unidades').select('id, title, numero').in('id', Array.from(new Set(uIds))); (ur.data || []).forEach(function (u) { unidadesMap[u.id] = { title: u.title || u.numero || null }; }); } catch (eU) {} }
    var out = reservas.map(function (x) {
      return Object.assign({}, x, {
        contacto: x.contact_id ? (contactosMap[x.contact_id] || null) : null,
        unidad_ref: x.unit_id ? (unidadesMap[x.unit_id] || null) : null
      });
    });
    return res.json({ ok: true, reservas: out });
  } catch (e) { return res.status(500).json({ error: e && e.message }); }
});

// ---- POST /api/hotel/reservas/crear ----------------------------------------
// GATEADO reservas_v1. Crea una reserva. body: { contact_id | conversation_id,
// unit_id, check_in, check_out, adults, children, pets, total_amount, currency,
// status?, source?, notas }. ANTI-SOLAPE server-side si nace bloqueante -> 409.
app.post('/api/hotel/reservas/crear', async function (req, res) {
  try {
    var userId = await verificarUsuario(req);
    if (!userId) return res.status(401).json({ error: 'No autorizado' });
    var ownerId = await _resolverOwnerId(userId);
    if (!(await _reservasV1Activo(ownerId))) return res.status(403).json({ error: 'La gestion de reservas no esta activada para esta cuenta.', gate: 'reservas_v1' });
    var b = req.body || {};
    var contactId = b.contact_id || null;
    var conversationId = b.conversation_id || null;
    // Derivar contact desde la conversacion si no vino contact_id (acotado al tenant).
    if (!contactId && conversationId) {
      try { var cv = await supabase.from('conversations').select('contact_id').eq('id', conversationId).eq('user_id', ownerId).maybeSingle(); if (cv && cv.data) contactId = cv.data.contact_id || null; } catch (eCv) {}
    }
    // F4: alta rapida desde el rack (walk-in). Si no hay contacto ligado y vino un nombre/telefono,
    // crear un contacto minimo para nombrar la reserva. Defensivo: si falla, la reserva se crea sin contacto.
    if (!contactId && (b.huesped_nombre || b.huesped_telefono)) {
      try {
        var _hnom = b.huesped_nombre ? String(b.huesped_nombre).slice(0, 120) : null;
        var _htel = b.huesped_telefono ? String(b.huesped_telefono).slice(0, 40) : null;
        var _base = _hnom || _htel || 'Huésped';
        var ncc = await supabase.from('contacts').insert({ user_id: ownerId, name: _base, phone: _htel, nombre_manual: _hnom, channel: 'manual' }).select('id').single();
        if (ncc.error) { var ncc2 = await supabase.from('contacts').insert({ user_id: ownerId, name: _base, phone: _htel, channel: 'manual' }).select('id').single(); if (ncc2 && ncc2.data) contactId = ncc2.data.id; }
        else if (ncc.data) contactId = ncc.data.id;
      } catch (eHc) { /* sin contacto: la reserva igual se crea */ }
    }
    var unitId = b.unit_id || null;
    if (!unitId) return res.status(400).json({ error: 'Falta unit_id' });
    var checkIn = String(b.check_in || '').slice(0, 10);
    var checkOut = String(b.check_out || '').slice(0, 10);
    if (!/^\d{4}-\d{2}-\d{2}$/.test(checkIn) || !/^\d{4}-\d{2}-\d{2}$/.test(checkOut)) return res.status(400).json({ error: 'Fechas invalidas (check_in/check_out en YYYY-MM-DD)' });
    if (!(checkOut > checkIn)) return res.status(400).json({ error: 'check_out debe ser posterior a check_in' });
    // La unidad debe pertenecer a la cuenta (no cross-tenant).
    try {
      var uOwn = await supabase.from('hotel_unidades').select('id').eq('id', unitId).eq('user_id', ownerId).maybeSingle();
      if (uOwn && uOwn.error && _invTablaFaltante(uOwn.error)) return res.status(503).json({ error: 'La tabla hotel_unidades no existe todavia.', tabla: 'hotel_unidades' });
      if (!uOwn || !uOwn.data) return res.status(404).json({ error: 'Unidad no encontrada en esta cuenta' });
    } catch (eU) {}
    var status = (_HR_ESTADOS_INICIALES.indexOf(b.status) >= 0) ? b.status : 'tentative';
    // ANTI-SOLAPE: solo si nace BLOQUEANTE.
    if (_HR_BLOQUEANTES.indexOf(status) >= 0) {
      try {
        var conf = await _hrConflictosSolape(ownerId, unitId, checkIn, checkOut, null);
        if (conf.length) return res.status(409).json({ error: 'La unidad ya tiene una reserva que solapa esas fechas.', conflicto: _hrConflictoOut(conf) });
      } catch (eS) { if (eS && eS._tablaFaltante) return res.status(503).json({ error: 'La tabla hotel_reservas no existe todavia. Corré la migracion de reservas.', tabla: 'hotel_reservas' }); }
    }
    var fila = {
      user_id: ownerId, contact_id: contactId, unit_id: unitId, conversation_id: conversationId,
      check_in: checkIn, check_out: checkOut,
      adults: (b.adults != null ? (parseInt(b.adults, 10) || 0) : null),
      children: (b.children != null ? (parseInt(b.children, 10) || 0) : null),
      pets: (b.pets != null ? (parseInt(b.pets, 10) || 0) : null),
      total_amount: (b.total_amount != null ? (Number(b.total_amount) || 0) : null),
      currency: b.currency ? String(b.currency).slice(0, 8) : null,
      status: status, source: b.source ? String(b.source).slice(0, 40) : 'manual',
      internal_notes: (b.notas || b.internal_notes) ? String(b.notas || b.internal_notes).slice(0, 2000) : null,
      created_by: userId
    };
    var ins = await supabase.from('hotel_reservas').insert(fila).select('*').single();
    if (ins.error) {
      if (_invTablaFaltante(ins.error)) return res.status(503).json({ error: 'La tabla hotel_reservas no existe todavia. Corré la migracion de reservas.', tabla: 'hotel_reservas' });
      return res.status(500).json({ error: ins.error.message });
    }
    var reserva = ins.data;
    if (conversationId) { try { await supabase.from('conversations').update({ etapa_reserva: status }).eq('id', conversationId).eq('user_id', ownerId); } catch (eE) {} }
    // Si nace confirmada -> cita espejo + housekeeping. EXCEPTO un bloqueo manual de mantenimiento
    // (F4.2: sin contacto + internal_notes "BLOQUEO: ..."), que solo bloquea el calendario y NO debe
    // generar cita espejo ni tareas de limpieza.
    var _esBloqueoManual = (!contactId) && /^BLOQUEO:/.test(String(fila.internal_notes || ''));
    if (status === 'confirmed' && !_esBloqueoManual) {
      var citaId = await _hrCrearCitaEspejo(ownerId, reserva);
      if (citaId) { try { await supabase.from('hotel_reservas').update({ cita_id: citaId, updated_at: new Date().toISOString() }).eq('id', reserva.id); reserva.cita_id = citaId; } catch (eCi) {} }
      // F5.2: aviso de estadia "confirmacion" inmediato (best-effort, no bloquea la respuesta). Gateado
      // reservas_v1 + rubro hotel dentro del helper; idempotente por avisos.confirmacion.
      try { _estadiaConfirmacionInline(ownerId, reserva.id).catch(function () {}); } catch (eEc) {}
    }
    return res.json({ ok: true, reserva: reserva });
  } catch (e) { return res.status(500).json({ error: e && e.message }); }
});

// ---- POST /api/hotel/reservas/:id/estado -----------------------------------
// GATEADO reservas_v1. Transicion de estado validada por grafo (forward-only +
// cancelled/lost desde cualquier no-terminal). Al pasar a BLOQUEANTE re-chequea
// solape (409). Al confirmar crea la cita espejo (housekeeping). Al cancelar,
// cancela tareas pendientes de esa cita. cancelled exige cancellation_reason.
app.post('/api/hotel/reservas/:id/estado', async function (req, res) {
  try {
    var userId = await verificarUsuario(req);
    if (!userId) return res.status(401).json({ error: 'No autorizado' });
    var ownerId = await _resolverOwnerId(userId);
    if (!(await _reservasV1Activo(ownerId))) return res.status(403).json({ error: 'La gestion de reservas no esta activada para esta cuenta.', gate: 'reservas_v1' });
    var id = req.params.id;
    var b = req.body || {};
    var nuevo = String(b.status || b.estado || '');
    if (!nuevo) return res.status(400).json({ error: 'Falta status' });
    var rr = await supabase.from('hotel_reservas').select('*').eq('id', id).eq('user_id', ownerId).maybeSingle();
    if (rr.error) { if (_invTablaFaltante(rr.error)) return res.status(503).json({ error: 'La tabla hotel_reservas no existe todavia.', tabla: 'hotel_reservas' }); return res.status(500).json({ error: rr.error.message }); }
    if (!rr.data) return res.status(404).json({ error: 'Reserva no encontrada' });
    var reserva = rr.data;
    var actual = reserva.status;
    // Validacion de grafo.
    var esCancelLost = (nuevo === 'cancelled' || nuevo === 'lost');
    var valido = false;
    if (_HR_TERMINALES.indexOf(actual) >= 0) valido = false; // terminal: no se mueve
    else if (esCancelLost) valido = true;
    else if (Object.prototype.hasOwnProperty.call(_HR_ORDEN, actual) && Object.prototype.hasOwnProperty.call(_HR_ORDEN, nuevo) && _HR_ORDEN[nuevo] > _HR_ORDEN[actual]) valido = true;
    if (!valido) return res.status(400).json({ error: 'Transicion no permitida: ' + actual + ' -> ' + nuevo });
    if (nuevo === 'cancelled' && !String(b.cancellation_reason || '').trim()) return res.status(400).json({ error: 'cancelled exige cancellation_reason' });
    // Al pasar a BLOQUEANTE, re-chequear solape (otro pudo ganar).
    if (_HR_BLOQUEANTES.indexOf(nuevo) >= 0) {
      try {
        var conf = await _hrConflictosSolape(ownerId, reserva.unit_id, reserva.check_in, reserva.check_out, reserva.id);
        if (conf.length) return res.status(409).json({ error: 'Otra reserva bloqueante gano esas fechas para la unidad.', conflicto: _hrConflictoOut(conf) });
      } catch (eS) { if (eS && eS._tablaFaltante) return res.status(503).json({ error: 'La tabla hotel_reservas no existe todavia.', tabla: 'hotel_reservas' }); }
    }
    var upd = { status: nuevo, updated_at: new Date().toISOString() };
    if (nuevo === 'cancelled') upd.cancellation_reason = String(b.cancellation_reason).slice(0, 500);
    var citaIdNueva = null;
    if (nuevo === 'confirmed' && !reserva.cita_id) {
      citaIdNueva = await _hrCrearCitaEspejo(ownerId, reserva);
      if (citaIdNueva) upd.cita_id = citaIdNueva;
    }
    var wr = await supabase.from('hotel_reservas').update(upd).eq('id', reserva.id).eq('user_id', ownerId).select('*').single();
    if (wr.error) return res.status(500).json({ error: wr.error.message });
    if (reserva.conversation_id) { try { await supabase.from('conversations').update({ etapa_reserva: nuevo }).eq('id', reserva.conversation_id).eq('user_id', ownerId); } catch (eE) {} }
    // Al cancelar -> cancelar tareas pendientes de la cita espejo + marcar cita cancelada (best-effort).
    if (nuevo === 'cancelled' && reserva.cita_id) {
      try { await cancelarTareasDeEvento(ownerId, reserva.cita_id); } catch (eT) {}
      try { await supabase.from('citas').update({ estado: 'cancelada', actualizado_en: new Date().toISOString() }).eq('id', reserva.cita_id).eq('user_id', ownerId); } catch (eCc) {}
    }
    // F5.2: al confirmar, aviso de estadia "confirmacion" inmediato (best-effort, no bloquea la respuesta).
    if (nuevo === 'confirmed') { try { _estadiaConfirmacionInline(ownerId, reserva.id).catch(function () {}); } catch (eEc) {} }
    return res.json({ ok: true, reserva: wr.data });
  } catch (e) { return res.status(500).json({ error: e && e.message }); }
});

// ---- POST /api/hotel/reservas/:id/pago -------------------------------------
// GATEADO reservas_v1. Registra un pago en hotel_pagos y recalcula deposit/balance/
// payment_status de la reserva. Si estaba deposit_pending y entra un pago approved ->
// AUTO-CONFIRMA (sena recibida = confirmada + bloquear calendario via cita espejo).
// Comprobante: proof_data_url (data URL base64, se sube al bucket media) o proof_url.
app.post('/api/hotel/reservas/:id/pago', async function (req, res) {
  try {
    var userId = await verificarUsuario(req);
    if (!userId) return res.status(401).json({ error: 'No autorizado' });
    var ownerId = await _resolverOwnerId(userId);
    if (!(await _reservasV1Activo(ownerId))) return res.status(403).json({ error: 'La gestion de reservas no esta activada para esta cuenta.', gate: 'reservas_v1' });
    var id = req.params.id;
    var b = req.body || {};
    var rr = await supabase.from('hotel_reservas').select('*').eq('id', id).eq('user_id', ownerId).maybeSingle();
    if (rr.error) { if (_invTablaFaltante(rr.error)) return res.status(503).json({ error: 'La tabla hotel_reservas no existe todavia.', tabla: 'hotel_reservas' }); return res.status(500).json({ error: rr.error.message }); }
    if (!rr.data) return res.status(404).json({ error: 'Reserva no encontrada' });
    var reserva = rr.data;
    var amount = Number(b.amount);
    if (!(amount > 0)) return res.status(400).json({ error: 'amount invalido (debe ser > 0)' });
    var METODOS = ['efectivo', 'transferencia', 'mercadopago', 'tarjeta', 'otro'];
    var method = (METODOS.indexOf(b.method) >= 0) ? b.method : 'otro';
    var ESTADOS_PAGO = ['pending', 'approved', 'rejected', 'refunded'];
    var status = (ESTADOS_PAGO.indexOf(b.status) >= 0) ? b.status : 'approved';
    // Comprobante: data URL base64 -> subir al bucket 'media'; o proof_url ya subido.
    var proofUrl = null;
    if (b.proof_data_url && String(b.proof_data_url).indexOf('data:') === 0) { try { proofUrl = await subirImagenSoporte(b.proof_data_url, 'cliente'); } catch (ePu) {} }
    else if (b.proof_url && typeof b.proof_url === 'string') proofUrl = String(b.proof_url).slice(0, 1000);
    var filaPago = {
      reservation_id: reserva.id, user_id: ownerId, amount: amount,
      currency: b.currency ? String(b.currency).slice(0, 8) : (reserva.currency || null),
      method: method, status: status, proof_url: proofUrl,
      notes: b.notes ? String(b.notes).slice(0, 1000) : null,
      paid_at: (status === 'approved') ? new Date().toISOString() : null,
      created_by: userId
    };
    var ip = await supabase.from('hotel_pagos').insert(filaPago).select('*').single();
    if (ip.error) {
      if (_invTablaFaltante(ip.error)) return res.status(503).json({ error: 'La tabla hotel_pagos no existe todavia. Corré la migracion de reservas.', tabla: 'hotel_pagos' });
      return res.status(500).json({ error: ip.error.message });
    }
    var montos = await _hrRecalcularMontos(ownerId, reserva.id, reserva.total_amount);
    // AUTO-CONFIRMAR: deposit_pending + pago approved -> confirmed (misma logica de cita espejo).
    var confirmada = false, citaIdNueva = null, avisoSolape = null;
    var huboApproved = (status === 'approved') || (montos && montos.aprobado > 0);
    if (reserva.status === 'deposit_pending' && huboApproved) {
      var conflicto = [];
      try { conflicto = await _hrConflictosSolape(ownerId, reserva.unit_id, reserva.check_in, reserva.check_out, reserva.id); } catch (eS) { conflicto = []; }
      if (conflicto.length) {
        avisoSolape = 'La sena quedo registrada pero la reserva NO se confirmo automaticamente: otra reserva bloqueante solapa esas fechas.';
      } else {
        if (!reserva.cita_id) { citaIdNueva = await _hrCrearCitaEspejo(ownerId, reserva); }
        var updC = { status: 'confirmed', updated_at: new Date().toISOString() };
        if (citaIdNueva) updC.cita_id = citaIdNueva;
        try { await supabase.from('hotel_reservas').update(updC).eq('id', reserva.id).eq('user_id', ownerId); confirmada = true; } catch (eUc) {}
        if (confirmada && reserva.conversation_id) { try { await supabase.from('conversations').update({ etapa_reserva: 'confirmed' }).eq('id', reserva.conversation_id).eq('user_id', ownerId); } catch (eE) {} }
        // F5.2: sena recibida = confirmada -> aviso de estadia "confirmacion" inmediato (best-effort).
        if (confirmada) { try { _estadiaConfirmacionInline(ownerId, reserva.id).catch(function () {}); } catch (eEc) {} }
      }
    }
    return res.json({ ok: true, pago: ip.data, montos: montos, confirmada: confirmada, cita_id: citaIdNueva, aviso: avisoSolape });
  } catch (e) { return res.status(500).json({ error: e && e.message }); }
});

// ---- GET /api/hotel/rack ----------------------------------------------------
// Unidades de la cuenta + reservas BLOQUEANTES que solapan [desde, hasta), listo
// para pintar la grilla de F4. Acotado a ownerId. Sin gate (solo lectura).
app.get('/api/hotel/rack', async function (req, res) {
  try {
    var userId = await verificarUsuario(req);
    if (!userId) return res.status(401).json({ error: 'No autorizado' });
    var ownerId = await _resolverOwnerId(userId);
    var query = req.query || {};
    var desde = query.desde ? String(query.desde).slice(0, 10) : null;
    var hasta = query.hasta ? String(query.hasta).slice(0, 10) : null;
    var ur = await supabase.from('hotel_unidades').select('id, title, numero, type, capacidad, activa').eq('user_id', ownerId).order('title', { ascending: true });
    if (ur.error && _invTablaFaltante(ur.error)) return res.status(503).json({ error: 'La tabla hotel_unidades no existe todavia.', tabla: 'hotel_unidades' });
    var unidades = ur.data || [];
    var q = supabase.from('hotel_reservas').select('id, unit_id, contact_id, check_in, check_out, status, internal_notes').eq('user_id', ownerId).in('status', _HR_BLOQUEANTES);
    if (hasta) q = q.lt('check_in', hasta);
    if (desde) q = q.gt('check_out', desde);
    q = q.order('check_in', { ascending: true }).limit(5000);
    var rr = await q;
    if (rr.error) { if (_invTablaFaltante(rr.error)) return res.status(503).json({ error: 'La tabla hotel_reservas no existe todavia.', tabla: 'hotel_reservas' }); return res.status(500).json({ error: rr.error.message }); }
    var reservas = rr.data || [];
    var cIds = []; reservas.forEach(function (x) { if (x.contact_id) cIds.push(x.contact_id); });
    var contactosMap = {};
    if (cIds.length) { try { var cr = await supabase.from('contacts').select('id, name, nombre_manual').in('id', Array.from(new Set(cIds))); (cr.data || []).forEach(function (c) { contactosMap[c.id] = c.nombre_manual || c.name || null; }); } catch (eC) {} }
    var reservasOut = reservas.map(function (x) { return Object.assign({}, x, { huesped: x.contact_id ? (contactosMap[x.contact_id] || null) : null }); });
    return res.json({ ok: true, desde: desde, hasta: hasta, unidades: unidades, reservas: reservasOut });
  } catch (e) { return res.status(500).json({ error: e && e.message }); }
});

// ---- POST /api/hotel/reservas/:id/editar -----------------------------------
// GATEADO reservas_v1. Edita fechas/unidad/montos/huespedes. Re-chequea solape si
// la reserva es bloqueante y cambio el calendario. Si tiene cita espejo y cambio
// fecha/unidad, sincroniza la cita y recalcula las tareas de housekeeping.
app.post('/api/hotel/reservas/:id/editar', async function (req, res) {
  try {
    var userId = await verificarUsuario(req);
    if (!userId) return res.status(401).json({ error: 'No autorizado' });
    var ownerId = await _resolverOwnerId(userId);
    if (!(await _reservasV1Activo(ownerId))) return res.status(403).json({ error: 'La gestion de reservas no esta activada para esta cuenta.', gate: 'reservas_v1' });
    var id = req.params.id;
    var b = req.body || {};
    var rr = await supabase.from('hotel_reservas').select('*').eq('id', id).eq('user_id', ownerId).maybeSingle();
    if (rr.error) { if (_invTablaFaltante(rr.error)) return res.status(503).json({ error: 'La tabla hotel_reservas no existe todavia.', tabla: 'hotel_reservas' }); return res.status(500).json({ error: rr.error.message }); }
    if (!rr.data) return res.status(404).json({ error: 'Reserva no encontrada' });
    var reserva = rr.data;
    var nuevoUnit = (typeof b.unit_id !== 'undefined' && b.unit_id) ? String(b.unit_id) : reserva.unit_id;
    var nuevoIn = (typeof b.check_in !== 'undefined') ? String(b.check_in).slice(0, 10) : String(reserva.check_in).slice(0, 10);
    var nuevoOut = (typeof b.check_out !== 'undefined') ? String(b.check_out).slice(0, 10) : String(reserva.check_out).slice(0, 10);
    if (!/^\d{4}-\d{2}-\d{2}$/.test(nuevoIn) || !/^\d{4}-\d{2}-\d{2}$/.test(nuevoOut)) return res.status(400).json({ error: 'Fechas invalidas' });
    if (!(nuevoOut > nuevoIn)) return res.status(400).json({ error: 'check_out debe ser posterior a check_in' });
    if (nuevoUnit !== reserva.unit_id) {
      try { var uOwn = await supabase.from('hotel_unidades').select('id').eq('id', nuevoUnit).eq('user_id', ownerId).maybeSingle(); if (!uOwn || !uOwn.data) return res.status(404).json({ error: 'Unidad no encontrada en esta cuenta' }); } catch (eU) {}
    }
    var cambioCalendario = (nuevoUnit !== reserva.unit_id) || (nuevoIn !== String(reserva.check_in).slice(0, 10)) || (nuevoOut !== String(reserva.check_out).slice(0, 10));
    if (cambioCalendario && _HR_BLOQUEANTES.indexOf(reserva.status) >= 0) {
      try {
        var conf = await _hrConflictosSolape(ownerId, nuevoUnit, nuevoIn, nuevoOut, reserva.id);
        if (conf.length) return res.status(409).json({ error: 'La unidad ya tiene una reserva que solapa esas fechas.', conflicto: _hrConflictoOut(conf) });
      } catch (eS) { if (eS && eS._tablaFaltante) return res.status(503).json({ error: 'La tabla hotel_reservas no existe todavia.', tabla: 'hotel_reservas' }); }
    }
    var upd = { unit_id: nuevoUnit, check_in: nuevoIn, check_out: nuevoOut, updated_at: new Date().toISOString() };
    if (typeof b.adults !== 'undefined') upd.adults = (b.adults != null ? (parseInt(b.adults, 10) || 0) : null);
    if (typeof b.children !== 'undefined') upd.children = (b.children != null ? (parseInt(b.children, 10) || 0) : null);
    if (typeof b.pets !== 'undefined') upd.pets = (b.pets != null ? (parseInt(b.pets, 10) || 0) : null);
    var totalCambio = false;
    if (typeof b.total_amount !== 'undefined') { upd.total_amount = (b.total_amount != null ? (Number(b.total_amount) || 0) : null); totalCambio = true; }
    if (typeof b.currency !== 'undefined') upd.currency = b.currency ? String(b.currency).slice(0, 8) : null;
    if (typeof b.notas !== 'undefined' || typeof b.internal_notes !== 'undefined') upd.internal_notes = String(b.notas || b.internal_notes || '').slice(0, 2000) || null;
    var wr = await supabase.from('hotel_reservas').update(upd).eq('id', reserva.id).eq('user_id', ownerId).select('*').single();
    if (wr.error) return res.status(500).json({ error: wr.error.message });
    var reservaFinal = wr.data;
    if (totalCambio) { try { await _hrRecalcularMontos(ownerId, reserva.id, reservaFinal.total_amount); } catch (eRb) {} }
    // Sincronizar cita espejo (si existe) + recalcular tareas de housekeeping.
    if (reserva.cita_id && cambioCalendario) {
      var ci = _hrFechaISOmediodia(nuevoIn), co = _hrFechaISOmediodia(nuevoOut);
      try {
        var wc = await supabase.from('citas').update({ fecha_hora: ci, fecha_fin: co, unidad_id: nuevoUnit, actualizado_en: new Date().toISOString() }).eq('id', reserva.cita_id).eq('user_id', ownerId);
        if (wc.error) { await supabase.from('citas').update({ fecha_hora: ci, fecha_fin: co }).eq('id', reserva.cita_id).eq('user_id', ownerId); }
      } catch (eWc) {}
      try { await recalcularTareasAlquiler(ownerId, reserva.cita_id, ci, co, null); } catch (eRt) {}
    }
    return res.json({ ok: true, reserva: reservaFinal });
  } catch (e) { return res.status(500).json({ error: e && e.message }); }
});

// ---- GET /api/hotel/reservas/:id/pagos --------------------------------------
// Lista los pagos de una reserva (para el detalle de la UI F3). Acotado a ownerId
// (no expone otras cuentas). Sin gate (solo lectura). DEFENSIVO: si la tabla
// hotel_pagos no existe todavia -> lista vacia (no rompe). Ruta PLANA (:id obligatorio).
app.get('/api/hotel/reservas/:id/pagos', async function (req, res) {
  try {
    var userId = await verificarUsuario(req);
    if (!userId) return res.status(401).json({ error: 'No autorizado' });
    var ownerId = await _resolverOwnerId(userId);
    var id = req.params.id;
    var r = await supabase.from('hotel_pagos').select('*').eq('user_id', ownerId).eq('reservation_id', id).order('created_at', { ascending: true }).limit(500);
    if (r.error) { if (_invTablaFaltante(r.error)) return res.json({ ok: true, pagos: [] }); return res.status(500).json({ error: r.error.message }); }
    return res.json({ ok: true, pagos: r.data || [] });
  } catch (e) { return res.status(500).json({ error: e && e.message }); }
});

// ============================================================================
// F6 — SEGUNDA OLA (vertical HOTEL). Todo ADITIVO + DEFENSIVO. CERO IA / CERO
// tokens (solo SQL + storage + fetch de iCal). Rutas PLANAS (Express 5): solo
// segmentos :param OBLIGATORIOS, sin ? ni *. NO cambia el comportamiento de
// inmobiliaria/desarrolladora ni de hoteles con el gate OFF.
// ============================================================================

// Helper: la cuenta (ownerId) es rubro hotel_cabanas? Defensivo: ante error/columna
// ausente -> false (no habilita nada). Se usa para gatear import/fotos de unidades
// (que NO dependen de reservas_v1, igual que el alta manual de unidades).
async function _esCuentaHotel(ownerId) {
  try {
    if (!ownerId) return false;
    var r = await supabase.from('business_settings').select('rubro').eq('user_id', ownerId).maybeSingle();
    if (r && r.error) return false;
    return !!(r && r.data && normalizarRubro(r.data.rubro) === 'hotel_cabanas');
  } catch (e) { return false; }
}

// ---- POST /api/hotel/imagen -------------------------------------------------
// Sube UNA imagen (data URL base64) al bucket 'media' y devuelve su URL publica.
// Reusa subirImagenSoporte (mismo patron que los comprobantes de pago F2 y las
// imagenes de soporte). Owner-only (JWT). Sirve para la galeria de fotos por unidad
// del FormHotel. NO gateado por reservas_v1 (es carga de inventario, como el alta de
// unidades). Ruta PLANA. CERO IA.
app.post('/api/hotel/imagen', async function (req, res) {
  try {
    var userId = await verificarUsuario(req);
    if (!userId) return res.status(401).json({ error: 'No autorizado' });
    var b = req.body || {};
    var dataUrl = b.imagen || b.data_url || b.dataUrl;
    if (!dataUrl || String(dataUrl).indexOf('data:') !== 0) return res.status(400).json({ error: 'Falta la imagen (data URL base64)' });
    var url = await subirImagenSoporte(dataUrl, 'cliente');
    if (!url) return res.status(400).json({ error: 'No se pudo subir la imagen (¿formato o tamaño? tope 8MB).' });
    return res.json({ ok: true, url: url });
  } catch (e) { return res.status(500).json({ error: e && e.message }); }
});

// ---- POST /api/hotel/unidades/import ----------------------------------------
// Import masivo de unidades de hotel. body: { items: [ {numero,title,type,capacidad,
// descripcion,precio_base,moneda,activa,atributos}, ... ] }. Reusa el motor de UPSERT
// _syncInvHotel (el mismo del sync publico por API key), por 'numero' (o title). Owner-only,
// SOLO rubro hotel (no reservas_v1: es carga de inventario). Ruta PLANA. CERO IA.
app.post('/api/hotel/unidades/import', async function (req, res) {
  try {
    var userId = await verificarUsuario(req);
    if (!userId) return res.status(401).json({ error: 'No autorizado' });
    var ownerId = await _resolverOwnerId(userId);
    if (!(await _esCuentaHotel(ownerId))) return res.status(403).json({ error: 'Esta cuenta no es de rubro hotel/cabañas.' });
    var items = Array.isArray(req.body && req.body.items) ? req.body.items : (Array.isArray(req.body) ? req.body : null);
    if (!items) return res.status(400).json({ error: 'Falta el array "items" en el body' });
    if (items.length > 2000) return res.status(400).json({ error: 'Maximo 2000 unidades por import' });
    if (items.length === 0) return res.json({ ok: true, creadas: 0, actualizadas: 0, errores: 0, total: 0 });
    var out = await _syncInvHotel(ownerId, items);
    return res.json(Object.assign({ ok: true }, out));
  } catch (e) { return res.status(500).json({ error: e && e.message }); }
});

// ---- GET /api/hotel/metricas ------------------------------------------------
// Metricas de ocupacion/ingresos/estados para Reportes (rubro hotel). Rango por
// ?desde=&hasta= (YYYY-MM-DD) o ?mes=YYYY-MM; default = mes actual. Acotado a ownerId
// (no expone otras cuentas). Solo lectura (sin gate: sin reservas devuelve ceros = inerte).
// DEFENSIVO: tablas ausentes -> ceros. CERO IA.
app.get('/api/hotel/metricas', async function (req, res) {
  try {
    var userId = await verificarUsuario(req);
    if (!userId) return res.status(401).json({ error: 'No autorizado' });
    var ownerId = await _resolverOwnerId(userId);
    var query = req.query || {};
    // Resolver rango. mes=YYYY-MM tiene prioridad; sino desde/hasta; sino mes actual.
    var desde, hasta;
    function _finDeMes(y, m0) { return new Date(Date.UTC(y, m0 + 1, 1)); } // primer dia del mes siguiente (exclusivo)
    if (/^\d{4}-\d{2}$/.test(String(query.mes || ''))) {
      var _p = String(query.mes).split('-'); var _y = parseInt(_p[0], 10), _m = parseInt(_p[1], 10) - 1;
      desde = _p[0] + '-' + _p[1] + '-01';
      var _f = _finDeMes(_y, _m); hasta = _f.toISOString().slice(0, 10);
    } else if (/^\d{4}-\d{2}-\d{2}$/.test(String(query.desde || '')) && /^\d{4}-\d{2}-\d{2}$/.test(String(query.hasta || ''))) {
      desde = String(query.desde).slice(0, 10); hasta = String(query.hasta).slice(0, 10);
    } else {
      var _now = new Date(); var _yy = _now.getUTCFullYear(), _mm = _now.getUTCMonth();
      desde = _yy + '-' + String(_mm + 1).padStart(2, '0') + '-01';
      hasta = _finDeMes(_yy, _mm).toISOString().slice(0, 10);
    }
    // Dias del rango (semiabierto [desde, hasta)).
    var _msDia = 24 * 60 * 60 * 1000;
    var _dDesde = new Date(desde + 'T00:00:00.000Z').getTime();
    var _dHasta = new Date(hasta + 'T00:00:00.000Z').getTime();
    var diasRango = Math.max(0, Math.round((_dHasta - _dDesde) / _msDia));
    // Unidades activas de la cuenta (denominador de ocupacion).
    var unidadesCount = 0;
    try {
      var ur = await supabase.from('hotel_unidades').select('id', { count: 'exact', head: true }).eq('user_id', ownerId).eq('activa', true);
      if (!(ur && ur.error)) unidadesCount = ur.count || 0;
    } catch (eU) {}
    // Reservas que SOLAPAN el rango (semiabierto): check_in < hasta AND check_out > desde.
    var reservas = [];
    var tablaFalta = false;
    try {
      var rr = await supabase.from('hotel_reservas')
        .select('id, unit_id, status, check_in, check_out, total_amount, deposit_amount, currency')
        .eq('user_id', ownerId)
        .lt('check_in', hasta).gt('check_out', desde)
        .limit(5000);
      if (rr && rr.error) { if (_invTablaFaltante(rr.error)) tablaFalta = true; } else { reservas = rr.data || []; }
    } catch (eR) {}
    var BLOQ = ['deposit_pending', 'confirmed', 'checked_in', 'checked_out'];
    // Noches ocupadas dentro del rango (clamp de cada reserva bloqueante al rango).
    var nochesOcupadas = 0;
    var ingresoEstimado = 0, ingresoCobrado = 0;
    var porEstado = {};
    var monedaTop = null; var _monedaCount = {};
    reservas.forEach(function (r) {
      porEstado[r.status] = (porEstado[r.status] || 0) + 1;
      var esBloq = BLOQ.indexOf(r.status) >= 0;
      if (esBloq) {
        var ci = new Date(String(r.check_in).slice(0, 10) + 'T00:00:00.000Z').getTime();
        var co = new Date(String(r.check_out).slice(0, 10) + 'T00:00:00.000Z').getTime();
        var a = Math.max(ci, _dDesde), b2 = Math.min(co, _dHasta);
        if (b2 > a) nochesOcupadas += Math.round((b2 - a) / _msDia);
        if (r.total_amount != null) ingresoEstimado += Number(r.total_amount) || 0;
        if (r.deposit_amount != null) ingresoCobrado += Number(r.deposit_amount) || 0;
        var _cur = r.currency || 'ARS'; _monedaCount[_cur] = (_monedaCount[_cur] || 0) + 1;
      }
    });
    Object.keys(_monedaCount).forEach(function (k) { if (monedaTop == null || _monedaCount[k] > _monedaCount[monedaTop]) monedaTop = k; });
    var capacidadNoches = unidadesCount * diasRango;
    var ocupacionPct = capacidadNoches > 0 ? Math.round((nochesOcupadas / capacidadNoches) * 1000) / 10 : 0;
    return res.json({
      ok: true, tabla_faltante: tablaFalta,
      rango: { desde: desde, hasta: hasta, dias: diasRango },
      unidades_activas: unidadesCount,
      noches_ocupadas: nochesOcupadas, capacidad_noches: capacidadNoches, ocupacion_pct: ocupacionPct,
      ingreso_estimado: Math.round(ingresoEstimado), ingreso_cobrado: Math.round(ingresoCobrado),
      moneda: monedaTop || 'ARS',
      reservas_por_estado: porEstado, total_reservas: reservas.length
    });
  } catch (e) { return res.status(500).json({ error: e && e.message }); }
});

// ---- iCal EXPORT (F6.2) -----------------------------------------------------
// Token PUBLICO por cuenta (business_settings.ical_token, DEDICADO — NO se reusa la
// inventario_api_key que da acceso de escritura). El dueño obtiene sus links por unidad
// desde /api/hotel/ical-links; los pega en Airbnb/Booking para que esas OTAs vean las
// fechas ocupadas. El .ics no expone datos del huesped (solo fechas + "Reservado"/"No
// disponible"). Rutas PLANAS. CERO IA.
function _icalDate(d) { var s = String(d || '').slice(0, 10); return /^\d{4}-\d{2}-\d{2}$/.test(s) ? s.replace(/-/g, '') : null; }
function _icalEsc(t) { return String(t == null ? '' : t).replace(/\\/g, '\\\\').replace(/;/g, '\\;').replace(/,/g, '\\,').replace(/\r?\n/g, '\\n'); }
function _icalBuild(unitTitle, reservas) {
  var now = new Date().toISOString().replace(/[-:]/g, '').replace(/\.\d{3}Z$/, 'Z');
  var out = ['BEGIN:VCALENDAR', 'VERSION:2.0', 'PRODID:-//Raices CRM//Hotel//ES', 'CALSCALE:GREGORIAN', 'METHOD:PUBLISH', 'X-WR-CALNAME:' + _icalEsc(unitTitle || 'Unidad')];
  (reservas || []).forEach(function (r) {
    var di = _icalDate(r.check_in), df = _icalDate(r.check_out);
    if (!di || !df) return;
    var esBloqueoManual = (!r.contact_id) && /^BLOQUEO/i.test(String(r.internal_notes || ''));
    var resumen = esBloqueoManual ? 'No disponible' : 'Reservado';
    out.push('BEGIN:VEVENT');
    out.push('UID:' + String(r.id) + '@raicescrm');
    out.push('DTSTAMP:' + now);
    out.push('DTSTART;VALUE=DATE:' + di);
    out.push('DTEND;VALUE=DATE:' + df); // exclusivo: check_out = dia de salida (libre)
    out.push('SUMMARY:' + _icalEsc(resumen));
    out.push('TRANSP:OPAQUE');
    out.push('END:VEVENT');
  });
  out.push('END:VCALENDAR');
  return out.join('\r\n') + '\r\n';
}

// GET /api/hotel/ical-links — owner-only. Genera (lazy) el ical_token y devuelve un link
// .ics por unidad activa. GATEADO reservas_v1 (es parte del motor de reservas). DEFENSIVO:
// si falta la columna ical_token -> 503 con mensaje claro (correr la migracion).
app.get('/api/hotel/ical-links', async function (req, res) {
  try {
    var userId = await verificarUsuario(req);
    if (!userId) return res.status(401).json({ error: 'No autorizado' });
    var ownerId = await _resolverOwnerId(userId);
    if (!(await _reservasV1Activo(ownerId))) return res.status(403).json({ error: 'La gestion de reservas no esta activada para esta cuenta.', gate: 'reservas_v1' });
    var bs = await supabase.from('business_settings').select('ical_token').eq('user_id', ownerId).maybeSingle();
    if (bs && bs.error) return res.status(503).json({ error: 'Falta la columna ical_token (corré migracion-hotel-ical-token.sql).' });
    var token = bs && bs.data && bs.data.ical_token;
    if (!token) {
      token = 'ical_' + _cryptoInv.randomBytes(24).toString('hex');
      var up = await supabase.from('business_settings').update({ ical_token: token }).eq('user_id', ownerId);
      if (up && up.error) return res.status(503).json({ error: 'Falta la columna ical_token (corré migracion-hotel-ical-token.sql).' });
    }
    var base = 'https://' + (req.get('host') || 'agente-inmobiliaria-production-7e1c.up.railway.app');
    var ur = await supabase.from('hotel_unidades').select('id, title, numero, activa').eq('user_id', ownerId).order('title', { ascending: true });
    if (ur && ur.error && _invTablaFaltante(ur.error)) return res.status(503).json({ error: 'La tabla hotel_unidades no existe todavia.', tabla: 'hotel_unidades' });
    var unidades = (ur && ur.data || []).map(function (u) {
      return { unit_id: u.id, title: u.title || u.numero || 'Unidad', activa: u.activa !== false, url: base + '/api/public/ical/' + token + '/' + u.id + '.ics' };
    });
    return res.json({ ok: true, token: token, unidades: unidades });
  } catch (e) { return res.status(500).json({ error: e && e.message }); }
});

// GET /api/public/ical/:token/:unitid — PUBLICO (sin sesion). Auth por token en la ruta.
// :unitid puede venir con sufijo ".ics" (se strippea). Devuelve el .ics de las reservas
// BLOQUEANTES de esa unidad. Rutas PLANAS (dos :param OBLIGATORIOS). Si el gate reservas_v1
// esta OFF o faltan tablas -> devuelve un VCALENDAR VACIO valido (las OTAs no rompen).
app.get('/api/public/ical/:token/:unitid', async function (req, res) {
  try {
    var token = String(req.params.token || '').trim();
    var unitId = String(req.params.unitid || '').replace(/\.ics$/i, '').trim();
    if (!token || token.length < 8 || !unitId) return res.status(404).type('text/plain').send('Not found');
    var bs = await supabase.from('business_settings').select('user_id, rubro, reservas_v1').eq('ical_token', token).maybeSingle();
    if (bs && bs.error) return res.status(404).type('text/plain').send('Not found'); // columna ausente -> 404 (aun no habilitado)
    if (!bs || !bs.data || !bs.data.user_id) return res.status(404).type('text/plain').send('Not found');
    var ownerId = bs.data.user_id;
    // La unidad debe pertenecer a la cuenta del token (no cross-tenant).
    var uTitle = 'Unidad';
    try {
      var uq = await supabase.from('hotel_unidades').select('id, title, numero').eq('id', unitId).eq('user_id', ownerId).maybeSingle();
      if (!uq || uq.error || !uq.data) return res.status(404).type('text/plain').send('Not found');
      uTitle = uq.data.title || uq.data.numero || 'Unidad';
    } catch (eU) { return res.status(404).type('text/plain').send('Not found'); }
    var reservas = [];
    // Gate OFF -> calendario vacio (inerte). Con el gate ON, listar bloqueantes futuras/actuales.
    if (bs.data.reservas_v1 === true) {
      try {
        var hoy = _fechaLocalArg();
        var rr = await supabase.from('hotel_reservas')
          .select('id, check_in, check_out, status, contact_id, internal_notes')
          .eq('user_id', ownerId).eq('unit_id', unitId)
          .in('status', _HR_BLOQUEANTES)
          .gte('check_out', hoy)
          .order('check_in', { ascending: true }).limit(2000);
        if (!(rr && rr.error)) reservas = rr.data || [];
      } catch (eR) { reservas = []; }
    }
    var ics = _icalBuild(uTitle, reservas);
    res.set('Content-Type', 'text/calendar; charset=utf-8');
    res.set('Content-Disposition', 'inline; filename="' + unitId + '.ics"');
    res.set('Cache-Control', 'public, max-age=600');
    return res.status(200).send(ics);
  } catch (e) { return res.status(500).type('text/plain').send('Error'); }
});

// ---- iCal IMPORT (F6.2) — cron que lee iCal de OTAs -> bloqueos source='ical' ----
// Lee las URLs iCal configuradas por unidad en hotel_unidades.atributos.ical_import_urls
// (array de strings) y crea/actualiza bloqueos (status confirmed, contact null, source
// 'ical', internal_notes "BLOQUEO OTA") en hotel_reservas. Idempotente: por unidad, si al
// menos una feed responde, REEMPLAZA los bloqueos ical FUTUROS de esa unidad (nunca toca
// reservas reales: el filtro exige source='ical'). GATEADO reservas_v1 (solo hoteles con el
// motor activo). INERTE por defecto: el cron SOLO se registra si ICAL_IMPORT_ENABLED==='true'.
// CERO IA / CERO tokens (fetch + SQL). Defensivo end-to-end.
function _parseICalBloques(texto) {
  // Devuelve [{ check_in:'YYYY-MM-DD', check_out:'YYYY-MM-DD' }] de cada VEVENT. Soporta
  // DTSTART;VALUE=DATE:YYYYMMDD y DTSTART:YYYYMMDDT... (toma solo la fecha). Line-unfolding RFC5545.
  var out = [];
  try {
    if (!texto || typeof texto !== 'string') return out;
    var raw = texto.replace(/\r\n/g, '\n').replace(/\r/g, '\n').split('\n');
    var lineas = [];
    raw.forEach(function (l) { if (l.length && (l[0] === ' ' || l[0] === '\t')) { if (lineas.length) lineas[lineas.length - 1] += l.slice(1); } else lineas.push(l); });
    var cur = null;
    function _fecha(v) { var m = /(\d{4})(\d{2})(\d{2})/.exec(String(v || '')); return m ? (m[1] + '-' + m[2] + '-' + m[3]) : null; }
    lineas.forEach(function (l) {
      var up = l.toUpperCase();
      if (up.indexOf('BEGIN:VEVENT') === 0) { cur = { check_in: null, check_out: null }; return; }
      if (up.indexOf('END:VEVENT') === 0) { if (cur && cur.check_in && cur.check_out && cur.check_out > cur.check_in) out.push(cur); cur = null; return; }
      if (!cur) return;
      if (up.indexOf('DTSTART') === 0) { var i = l.indexOf(':'); if (i >= 0) cur.check_in = _fecha(l.slice(i + 1)); }
      else if (up.indexOf('DTEND') === 0) { var j = l.indexOf(':'); if (j >= 0) cur.check_out = _fecha(l.slice(j + 1)); }
    });
  } catch (e) { console.error('_parseICalBloques:', e && e.message); }
  return out;
}
async function _fetchTextoConTimeout(url, ms) {
  try {
    var ctrl = new AbortController();
    var t = setTimeout(function () { ctrl.abort(); }, ms || 15000);
    var r = await fetch(url, { signal: ctrl.signal, redirect: 'follow', headers: { 'User-Agent': 'RaicesCRM-iCal/1.0' } });
    clearTimeout(t);
    if (!r || !r.ok) return null;
    var txt = await r.text();
    return (txt && txt.indexOf('BEGIN:VCALENDAR') >= 0) ? txt : null;
  } catch (e) { return null; }
}
async function importarICalOTAs() {
  try {
    // Cuentas hotel con el gate ON (query separada y defensiva: si la columna reservas_v1 no existe -> nada).
    var rc = await supabase.from('business_settings').select('user_id, rubro').eq('reservas_v1', true);
    if (!rc || rc.error) return;
    var cuentas = (rc.data || []).filter(function (b) { return normalizarRubro(b.rubro) === 'hotel_cabanas'; });
    if (!cuentas.length) return;
    var hoy = _fechaLocalArg();
    for (var ci = 0; ci < cuentas.length; ci++) {
      var ownerId = cuentas[ci].user_id;
      var uq;
      try { uq = await supabase.from('hotel_unidades').select('id, atributos').eq('user_id', ownerId).eq('activa', true).limit(1000); } catch (eUq) { continue; }
      if (!uq || uq.error || !uq.data) continue;
      for (var ui = 0; ui < uq.data.length; ui++) {
        var unidad = uq.data[ui];
        var at = (unidad && unidad.atributos && typeof unidad.atributos === 'object') ? unidad.atributos : {};
        var urls = Array.isArray(at.ical_import_urls) ? at.ical_import_urls.filter(function (u) { return typeof u === 'string' && /^https?:\/\//i.test(u); }) : [];
        if (!urls.length) continue; // unidad sin feeds -> inerte
        var eventos = [], algunaOk = false;
        for (var k = 0; k < urls.length && k < 10; k++) {
          var txt = await _fetchTextoConTimeout(urls[k], 15000);
          if (txt == null) continue;
          algunaOk = true;
          var bloques = _parseICalBloques(txt);
          bloques.forEach(function (b) { if (b.check_out >= hoy) eventos.push(b); });
        }
        if (!algunaOk) continue; // ninguna feed respondio -> NO tocar (evita borrar en un outage)
        // Reemplazo idempotente: borra SOLO los bloqueos ical futuros de esta unidad, luego inserta los frescos.
        try { await supabase.from('hotel_reservas').delete().eq('user_id', ownerId).eq('unit_id', unidad.id).eq('source', 'ical').gte('check_out', hoy); } catch (eDel) {}
        for (var ei = 0; ei < eventos.length && ei < 500; ei++) {
          var ev = eventos[ei];
          try {
            await supabase.from('hotel_reservas').insert({
              user_id: ownerId, unit_id: unidad.id, contact_id: null,
              check_in: ev.check_in, check_out: ev.check_out,
              status: 'confirmed', source: 'ical', internal_notes: 'BLOQUEO OTA', created_by: null
            });
          } catch (eIns) {}
        }
      }
    }
  } catch (e) { console.error('importarICalOTAs:', e && e.message); }
}

// ============================================================================
// F5.2 — MENSAJES AUTOMATICOS DE ESTADIA (vertical HOTEL). 0 IA / 0 tokens:
// plantillas fijas + cron. GATEADO por reservas_v1 y SOLO rubro hotel_cabanas.
// Idempotente por hotel_reservas.avisos (jsonb): cada tipo se marca al enviarse
// para no repetir. Guard de conexion Evolution por cuenta (no envia si el
// WhatsApp del cliente esta caido -> reintenta cuando reconecta). DEFENSIVO: si
// faltan las columnas avisos/estadia_config o la tabla, NO rompe y NO spamea
// (claim-before-send: si no puede MARCAR el aviso, tampoco lo ENVIA).
// NO cambia el comportamiento de inmobiliaria/desarrolladora ni de hoteles con
// reservas_v1 OFF (el cron los saltea; la config solo se muestra en esas cuentas).
// ----------------------------------------------------------------------------

// Tipos de aviso de estadia (orden del ciclo) y sus DEFAULTS (editables por cuenta
// en Configuracion -> Estadia). Placeholders: {huesped} {alojamiento} {checkin}
// {checkout} {noches} {empresa} {resena_link}.
var _ESTADIA_TIPOS = ['confirmacion', 'pre_checkin', 'bienvenida', 'checkout_recordatorio', 'post_checkout'];
var _ESTADIA_DEFAULTS = {
  confirmacion:          { on: true,          texto: 'Hola {huesped}! Confirmamos tu reserva en {alojamiento} del {checkin} al {checkout} ({noches}). Te esperamos! Cualquier cosa que necesites, escribinos por aca. - {empresa}' },
  pre_checkin:           { on: true, dias: 1, texto: 'Hola {huesped}! Te escribimos de {empresa}. Se acerca tu llegada a {alojamiento} el {checkin}. El check-in es a partir de las 14 hs. Si necesitas indicaciones para llegar o coordinar el horario, avisanos. Buen viaje!' },
  bienvenida:            { on: true,          texto: 'Bienvenido/a {huesped}! Hoy comienza tu estadia en {alojamiento}. Que la disfrutes muchisimo. Estamos a disposicion para lo que necesites. - {empresa}' },
  checkout_recordatorio: { on: true,          texto: 'Hola {huesped}! Te recordamos que manana es tu check-out de {alojamiento}, hasta las 10 hs. Fue un gusto tenerte. Si necesitas coordinar el horario de salida, avisanos. - {empresa}' },
  post_checkout:         { on: true,          texto: 'Gracias por elegirnos, {huesped}! Esperamos que hayas disfrutado tu estadia en {alojamiento}. Si nos dejas tu opinion nos ayudas un monton: {resena_link} Te esperamos de nuevo! - {empresa}' }
};

// Merge de la config guardada (jsonb) con los defaults. NUNCA rompe: si es null/invalida usa defaults.
// Cada tipo: on (default true salvo false explicito) + texto (default si vacio). pre_checkin.dias 0..30.
function _estadiaConfigMerge(raw) {
  var cfg = (raw && typeof raw === 'object') ? raw : {};
  var out = {};
  _ESTADIA_TIPOS.forEach(function (k) {
    var d = _ESTADIA_DEFAULTS[k], c = (cfg[k] && typeof cfg[k] === 'object') ? cfg[k] : {};
    out[k] = {
      on: (c.on === false) ? false : true,
      texto: (typeof c.texto === 'string' && c.texto.trim()) ? c.texto : d.texto
    };
    if (k === 'pre_checkin') {
      var nd = Number(c.dias);
      out[k].dias = (Number.isFinite(nd) && nd >= 0 && nd <= 30) ? Math.floor(nd) : d.dias;
    }
  });
  out.resena_link = (typeof cfg.resena_link === 'string') ? cfg.resena_link.slice(0, 500) : '';
  return out;
}

// Hoy 'YYYY-MM-DD' en huso Argentina (mismo criterio que los demas crons).
function _estadiaHoyStr() {
  var a = new Date(); var u = a.getTime() + a.getTimezoneOffset() * 60000; var arg = new Date(u - 3 * 60 * 60000); return arg.toISOString().slice(0, 10);
}
// Suma dias a una fecha 'YYYY-MM-DD' (UTC puro, sin corrimiento de TZ). null si invalida.
function _estadiaAddDias(fechaStr, dias) {
  var s = String(fechaStr || '').slice(0, 10);
  if (!/^\d{4}-\d{2}-\d{2}$/.test(s)) return null;
  var d = new Date(s + 'T00:00:00.000Z'); d.setUTCDate(d.getUTCDate() + (Number(dias) || 0));
  return d.toISOString().slice(0, 10);
}
function _estadiaFmtDDMM(fechaStr) {
  var s = String(fechaStr || '').slice(0, 10);
  if (!/^\d{4}-\d{2}-\d{2}$/.test(s)) return s;
  return s.slice(8, 10) + '/' + s.slice(5, 7);
}
// Reemplaza los placeholders de una plantilla con los datos de la reserva.
function _estadiaTexto(plantilla, ctx) {
  var noches = '';
  try {
    var ci = new Date(String(ctx.check_in).slice(0, 10) + 'T00:00:00.000Z').getTime();
    var co = new Date(String(ctx.check_out).slice(0, 10) + 'T00:00:00.000Z').getTime();
    if (isFinite(ci) && isFinite(co) && co > ci) { var n = Math.round((co - ci) / 86400000); noches = n + (n === 1 ? ' noche' : ' noches'); }
  } catch (eN) {}
  return String(plantilla || '')
    .replace(/\{huesped\}/g, ctx.huesped || 'Hola')
    .replace(/\{alojamiento\}/g, ctx.alojamiento || 'tu alojamiento')
    .replace(/\{checkin\}/g, _estadiaFmtDDMM(ctx.check_in))
    .replace(/\{checkout\}/g, _estadiaFmtDDMM(ctx.check_out))
    .replace(/\{noches\}/g, noches)
    .replace(/\{empresa\}/g, ctx.empresa || '')
    .replace(/\{resena_link\}/g, ctx.resena_link || '')
    .replace(/[ \t]{2,}/g, ' ')
    .trim();
}

// Procesa UNA reserva: calcula que avisos corresponden HOY y los envia. Idempotente por reserva.avisos.
// claim-before-send: MARCA en avisos ANTES de enviar; si no puede marcar (columna ausente/error) NO envia
// (evita spam cuando la migracion no corrio). tiposPermitidos: subconjunto de _ESTADIA_TIPOS (null = todos).
// Requiere que la instancia YA este verificada conectada por el caller. Devuelve la cantidad enviada.
async function _estadiaProcesarReserva(ownerId, reserva, config, empresa, instancia, tiposPermitidos) {
  try {
    if (!reserva || !reserva.id) return 0;
    var hoy = _estadiaHoyStr();
    var st = reserva.status;
    var avisos = (reserva.avisos && typeof reserva.avisos === 'object') ? reserva.avisos : {};
    var permit = Array.isArray(tiposPermitidos) ? tiposPermitidos : _ESTADIA_TIPOS;
    var ci = String(reserva.check_in || '').slice(0, 10);
    var co = String(reserva.check_out || '').slice(0, 10);
    function pend(tipo) { return permit.indexOf(tipo) >= 0 && config[tipo] && config[tipo].on !== false && !avisos[tipo]; }
    var due = [];
    // confirmacion: confirmada y AUN NO llego el huesped (check_in hoy o futuro). El guard ci>=hoy evita mandar
    // "confirmamos tu reserva" a estadias ya en curso o pasadas (anti-spam si se activa reservas_v1 sobre una
    // cuenta con reservas viejas ya cargadas).
    if (pend('confirmacion') && st === 'confirmed' && ci && ci >= hoy) due.push('confirmacion');
    // pre_checkin: ventana [check_in - N dias, check_in). N configurable (default 1).
    if (pend('pre_checkin') && (st === 'confirmed' || st === 'checked_in')) {
      var nd = (config.pre_checkin && Number.isFinite(Number(config.pre_checkin.dias))) ? Math.floor(Number(config.pre_checkin.dias)) : 1;
      var desde = _estadiaAddDias(ci, -Math.max(0, nd));
      if (desde && hoy >= desde && hoy < ci) due.push('pre_checkin');
    }
    // bienvenida: el dia del check_in.
    if (pend('bienvenida') && (st === 'confirmed' || st === 'checked_in') && ci && hoy === ci) due.push('bienvenida');
    // checkout_recordatorio: el dia anterior al check_out.
    if (pend('checkout_recordatorio') && (st === 'confirmed' || st === 'checked_in') && co && hoy === _estadiaAddDias(co, -1)) due.push('checkout_recordatorio');
    // post_checkout: el dia del check_out o despues.
    if (pend('post_checkout') && (st === 'confirmed' || st === 'checked_in' || st === 'checked_out') && co && hoy >= co) due.push('post_checkout');
    if (!due.length) return 0;
    // Huesped (nombre/telefono). Sin telefono no hay a quien enviar (ej. bloqueo manual sin contacto).
    var huesped = null, telefono = null;
    if (reserva.contact_id) { try { var cRow = await supabase.from('contacts').select('name, nombre_manual, phone').eq('id', reserva.contact_id).maybeSingle(); if (cRow && cRow.data) { huesped = cRow.data.nombre_manual || cRow.data.name || null; telefono = cRow.data.phone || null; } } catch (eC) {} }
    if (!telefono) return 0;
    var alojamiento = null;
    if (reserva.unit_id) { try { var uRow = await supabase.from('hotel_unidades').select('title, numero').eq('id', reserva.unit_id).maybeSingle(); if (uRow && uRow.data) alojamiento = uRow.data.title || uRow.data.numero || null; } catch (eU) {} }
    // CLAIM: marcar TODOS los due ANTES de enviar. Si el update falla (columna avisos ausente) -> NO enviar
    // (best-effort anti-spam). Si funciona, aunque un envio puntual falle, no se reintentara (best-effort).
    var ahora = new Date().toISOString();
    var nuevos = Object.assign({}, avisos);
    due.forEach(function (tp) { nuevos[tp] = ahora; });
    try {
      var wr = await supabase.from('hotel_reservas').update({ avisos: nuevos, updated_at: ahora }).eq('id', reserva.id).eq('user_id', ownerId);
      if (wr.error) { console.log('[estadia] no se pudo marcar avisos (falta la columna? corre migracion-hotel-avisos.sql) -> no envio. ' + (wr.error.message || '')); return 0; }
    } catch (eMk) { return 0; }
    reserva.avisos = nuevos; // en memoria: evita re-procesar en la misma corrida
    var ctx = { huesped: huesped, alojamiento: alojamiento, check_in: ci, check_out: co, empresa: empresa || '', resena_link: config.resena_link || '' };
    var enviados = 0;
    for (var i = 0; i < due.length; i++) {
      var tipo = due[i];
      var texto = _estadiaTexto(config[tipo] && config[tipo].texto, ctx);
      if (!texto || !texto.trim()) continue;
      var msgId = null;
      // Trazabilidad: registrar el mensaje en la conversacion (si esta ligada). role 'ai' NO dispara la IA
      // (esta solo reacciona a mensajes ENTRANTES por el webhook). Best-effort.
      if (reserva.conversation_id) {
        try { var mi = await supabase.from('messages').insert({ conversation_id: reserva.conversation_id, user_id: ownerId, role: 'ai', content: texto, enviado_por: 'Sistema estadia', estado_envio: 'enviando' }).select('id').single(); if (mi && mi.data) msgId = mi.data.id; } catch (eIns) {}
      }
      try {
        var salio = await enviarWhatsapp(instancia, telefono, texto, msgId);
        if (salio !== false) enviados++;
        if (reserva.conversation_id) { try { await supabase.from('conversations').update({ last_message: texto, last_role: 'ai', updated_at: new Date().toISOString() }).eq('id', reserva.conversation_id).eq('user_id', ownerId); } catch (eLm) {} }
        console.log('[estadia] ' + tipo + ' -> reserva ' + reserva.id + ' (cuenta ' + ownerId + ') salio=' + (salio !== false));
      } catch (eSend) { console.error('[estadia] envio ' + tipo + ':', eSend && eSend.message); }
      // Gap suave entre mensajes de la misma reserva (raro que haya >1 el mismo dia).
      if (i < due.length - 1) await new Promise(function (r) { setTimeout(r, 1500 + Math.floor(Math.random() * 2500)); });
    }
    return enviados;
  } catch (e) { console.error('_estadiaProcesarReserva:', e && e.message); return 0; }
}

// Envio INMEDIATO de la confirmacion al pasar una reserva a 'confirmed' (F5.2). Best-effort, NO bloquea la
// respuesta del endpoint (se llama sin await). Gateado reservas_v1 + rubro hotel. Idempotente (avisos.confirmacion).
async function _estadiaConfirmacionInline(ownerId, reservaId) {
  try {
    if (!ownerId || !reservaId) return;
    var bsr = await supabase.from('business_settings').select('rubro, reservas_v1, estadia_config, company_name, crm_pausado, eliminado_at').eq('user_id', ownerId).maybeSingle();
    var bs = bsr && bsr.data;
    if (!bs || bs.reservas_v1 !== true) return;                        // gate maestro
    if (normalizarRubro(bs.rubro) !== 'hotel_cabanas') return;         // solo hotel
    if (bs.eliminado_at || bs.crm_pausado === true) return;
    var config = _estadiaConfigMerge(bs.estadia_config);
    if (!config.confirmacion || config.confirmacion.on === false) return; // confirmacion desactivada por el cliente
    var instancia = nombreInstancia(ownerId);
    try { var conn = await instanciaConectada(instancia); if (conn !== true) return; } catch (eConn) { return; } // WA caido: lo toma el cron
    var rr = await supabase.from('hotel_reservas').select('*').eq('id', reservaId).eq('user_id', ownerId).maybeSingle();
    if (rr.error || !rr.data) return;
    await _estadiaProcesarReserva(ownerId, rr.data, config, bs.company_name || '', instancia, ['confirmacion']);
  } catch (e) { console.error('_estadiaConfirmacionInline:', e && e.message); }
}

// CRON F5.2: barre las cuentas HOTEL con reservas_v1 ON y envia los avisos de estadia que correspondan HOY.
// Idempotente (avisos jsonb). Guard de conexion por cuenta. INERTE si ninguna cuenta tiene el flag (default OFF).
async function enviarAvisosEstadia() {
  try {
    if (typeof _pausaGlobal !== 'undefined' && _pausaGlobal === true) return;
    var cuentas = [];
    try {
      var rc = await supabase.from('business_settings').select('user_id, rubro, estadia_config, company_name, crm_pausado, agente_pausado, eliminado_at').eq('reservas_v1', true);
      if (rc.error) return; // columna reservas_v1 ausente u otro error -> nada que procesar (inerte)
      cuentas = Array.isArray(rc.data) ? rc.data : [];
    } catch (eSel) { return; }
    if (!cuentas.length) return;
    var hoy = _estadiaHoyStr();
    var desdeCheckout = _estadiaAddDias(hoy, -3); // ventana: reservas vivas o que terminaron hace <=3 dias (post_checkout)
    for (var ciX = 0; ciX < cuentas.length; ciX++) {
      var bs = cuentas[ciX];
      try {
        if (normalizarRubro(bs.rubro) !== 'hotel_cabanas') continue;   // SOLO hotel
        if (bs.eliminado_at || bs.crm_pausado === true) continue;      // cuenta borrada/pausada -> no enviar
        var uid = bs.user_id;
        var instancia = nombreInstancia(uid);
        // Guard anti-baneo: si el WhatsApp del cliente esta caido, saltear la cuenta (retoma al reconectar).
        try { var conn = await instanciaConectada(instancia); if (conn !== true) continue; } catch (eConn) { continue; }
        var config = _estadiaConfigMerge(bs.estadia_config);
        var empresa = bs.company_name || '';
        var rr = await supabase.from('hotel_reservas').select('*')
          .eq('user_id', uid).in('status', ['confirmed', 'checked_in', 'checked_out'])
          .gte('check_out', desdeCheckout)
          .order('check_in', { ascending: true }).limit(2000);
        if (rr.error) continue; // tabla ausente u otro error -> saltear cuenta (defensivo)
        var reservas = rr.data || [];
        // CAP anti-baneo por cuenta y por corrida: si al activar reservas_v1 hubiera muchas reservas ya cargadas,
        // no disparamos un aluvion de WhatsApps de golpe. El resto se envia en las proximas corridas (cada 30 min).
        var CAP_ESTADIA_CUENTA = 25;
        var enviadosCuenta = 0;
        for (var riX = 0; riX < reservas.length; riX++) {
          if (enviadosCuenta >= CAP_ESTADIA_CUENTA) break;
          try { enviadosCuenta += await _estadiaProcesarReserva(uid, reservas[riX], config, empresa, instancia, null); } catch (eR) {}
        }
      } catch (eCuenta) { console.error('[estadia] cuenta ' + (bs && bs.user_id) + ':', eCuenta && eCuenta.message); }
    }
  } catch (e) { console.error('enviarAvisosEstadia:', e && e.message); }
}

// ===== SCRAPER CORREGIDO: extraccion completa por propiedad =====
// M20: alias de limpiarHTML (mismo set de entidades, unico implementador). Se mantiene el nombre por compat
// con todos los callers existentes (no se tocan). Antes era una copia byte-identica del set completo.
function limpiarHTML2(html) { return limpiarHTML(html); }
// Extrae los pares Etiqueta:Valor de la tabla de detalles (Houzez y similares)
function extraerTablaDetalles(html) {
  var pares = {};
  var re = /<strong>([^<:]{1,40}):?<\/strong>\s*([^<]{1,60})</gi;
  var m;
  while ((m = re.exec(html)) !== null) {
    var k = m[1].trim(); var v = m[2].trim();
    if (k && v && !/^\s*$/.test(v)) pares[k] = v;
  }
  return pares;
}
// Detecta el numero identificador de forma adaptativa (cada inmobiliaria lo nombra distinto)
function detectarNumeroProp(pares, titulo, plataformaId) {
  var patrones = [/propiedad\s*id/i, /property\s*id/i, /listing\s*id/i, /\bmls\b/i, /c[oa]d(igo)?\.?\s*(de\s*)?prop/i, /\bref(erencia)?\.?\b/i, /\bn[uu]mero\b/i, /\bnro\.?\b/i, /c[oa]d(igo)?\.?/i, /\bid\b/i];
  var excluir = /postal|barrio|zona|telefono|tel\.|whatsapp|a[nu]o|construc|metro|ambient|ba[nu]o|cuarto|habitacion/i;
  for (var pi = 0; pi < patrones.length; pi++) {
    for (var k in pares) {
      if (excluir.test(k)) continue;
      if (patrones[pi].test(k)) {
        var val = String(pares[k]).match(/[A-Za-z0-9][A-Za-z0-9\-\/]*/);
        if (val) return val[0];
      }
    }
  }
  if (titulo) { var mt = titulo.match(/(?:id|c[oa]d(?:igo)?|ref(?:erencia)?|#)[\s\-:.]*([A-Za-z0-9][A-Za-z0-9\-]*)/i); if (mt) return mt[1]; }
  if (plataformaId) return String(plataformaId);
  return null;
}
// Detecta operacion y devuelve flags
function detectarOperacion(estado, textoExtra) {
  var t = ((estado || '') + ' ' + (textoExtra || '')).toLowerCase();
  if (/tempora|por noche|por dia|por d.a|alquiler temporal|temporario|veraneo|diaria/.test(t)) return 'temporal';
  if (/anual|alquiler anual|alquiler permanente|todo el a.o/.test(t)) return 'anual';
  if (/alquiler|renta|rent/.test(t)) return 'anual';
  if (/venta|vende|compra|sale/.test(t)) return 'venta';
  return 'venta';
}

// M20: alias de extraerPrecioDe (misma logica de extraccion). Antes era una copia byte-identica salvo que
// usaba limpiarHTML2; como limpiarHTML2 es ahora alias de limpiarHTML, ambas funciones quedan equivalentes.
function extraerPrecio2(html) { return extraerPrecioDe(html); }
// Galeria ROBUSTA desde el HTML de una ficha WordPress (0 IA): junta las imagenes de /wp-content/uploads,
// colapsa el sufijo de tamano -WxH -> URL base (full-res), dedup y filtra el "chrome" del sitio
// (logo/favicon/overlay/factura/icon/plugins/themes). Se usa como fallback cuando el post NO tiene adjuntos
// por ?parent= (props VIEJAS de Anton, 2020/2021). Validado en vivo: Tatin -> 23 fotos, Galpon -> 13.
function _galeriaHtmlDeUploads(html) {
  if (!html || typeof html !== 'string') return [];
  var all = html.match(/https?:\/\/[^"'\s)]+\/wp-content\/uploads\/[^"'\s)]+\.(?:jpg|jpeg|png|webp)/gi) || [];
  // Descartar el "chrome" del sitio: por PATH (assets de themes/plugins) o por el NOMBRE de archivo.
  // El set de nombres es deliberadamente conservador: se sacaron 'banner'/'icono'/'watermark' porque son
  // subcadenas plausibles en el nombre de una foto REAL de una propiedad (evitar falsos positivos).
  var chromePath = /\/wp-content\/(?:themes|plugins)\//i;
  var chromeName = /(logo|favicon|factura|overlay|sprite|placeholder|avatar|loader|wpforms)/i;
  var seen = {}, limpias = [];
  for (var i = 0; i < all.length; i++) {
    var full = all[i];
    if (chromePath.test(full)) continue;
    var u = full.replace(/-\d+x\d+(\.\w+)$/, '$1'); // -1024x768.jpg -> .jpg (original)
    var name = (u.split('/').pop() || '');          // filtrar por nombre, no por la URL entera
    if (chromeName.test(name)) continue;
    if (!seen[u]) { seen[u] = 1; limpias.push(u); }
  }
  // DE-CONTAMINACION: la seccion "propiedades similares" del theme mete 1-2 fotos de OTRAS propiedades
  // (su portada) al final del HTML. La galeria real comparte la carpeta de subida AAAA/MM y aporta muchas
  // fotos; el intruso aporta 1-2. Nos quedamos con las carpetas que aportan >=3 fotos (o la mayoritaria) y
  // descartamos los intrusos. Solo se aplica si hay mas de una carpeta y algo para ganar (evita falsos).
  if (limpias.length > 3) {
    var folderDe = function (x) { var m = x.match(/\/uploads\/(\d{4}\/\d{2})\//); return m ? m[1] : '?'; };
    var cont = {};
    for (var c = 0; c < limpias.length; c++) { var f = folderDe(limpias[c]); cont[f] = (cont[f] || 0) + 1; }
    var carpetas = Object.keys(cont);
    if (carpetas.length > 1) {
      var maxN = 0; for (var k = 0; k < carpetas.length; k++) { if (cont[carpetas[k]] > maxN) maxN = cont[carpetas[k]]; }
      var filtrada = limpias.filter(function (x) { var f = folderDe(x); return cont[f] >= 3 || cont[f] === maxN; });
      if (filtrada.length >= 2 && filtrada.length < limpias.length) limpias = filtrada;
    }
  }
  return limpias.slice(0, 30);
}
// Arma la galeria COMPLETA de una propiedad WP (0 IA), en orden de preferencia:
//   1) adjuntos por ?parent=<postId> (props NUEVAS con fotos adjuntas al post)
//   2) galeria del HTML de la ficha (props VIEJAS sin adjuntos; reusa el html ya descargado)
//   3) la featured como minimo
// Devuelve un array de URLs (cap 30). Todo envuelto en try/catch: si algo falla, no rompe el scrape.
async function _armarGaleriaProp(base, postId, html, featuredUrl) {
  var fotos = [];
  try {
    if (base && postId) {
      var pm = await _resolverMediaPorParent(base, [String(postId)]);
      var arr = (pm && pm[String(postId)]) ? pm[String(postId)] : [];
      if (arr && arr.length) fotos = arr.slice();
    }
  } catch (e) { /* parent-media fallo -> probamos HTML */ }
  if (fotos.length < 2) {
    try {
      var hg = _galeriaHtmlDeUploads(html);
      if (hg.length > fotos.length) fotos = hg;
    } catch (e) { /* sin galeria HTML */ }
  }
  if (!fotos.length && featuredUrl) fotos = [featuredUrl];
  // dedup final + cap 30
  var seen = {}, out = [];
  for (var i = 0; i < fotos.length && out.length < 30; i++) {
    var u = fotos[i];
    if (u && !seen[u]) { seen[u] = 1; out.push(u); }
  }
  return out;
}
// Procesa una propiedad de la API + su ficha. Devuelve objeto con todos los campos para revision.
// PIN DEL MAPA (0 IA, 0 fetch extra): Houzez guarda la ubicacion como COORDENADAS (meta
// fave_property_location = "lat,lng,zoom", o el mapa embebido en el HTML) aunque el campo de
// direccion en TEXTO venga vacio -> es la solapa "Ubicacion" de la ficha. Reusa el HTML que ya
// se baja para el precio. ADITIVO: si no hay pin devuelve null y todo queda igual que hoy.
function _coordsHouzez(html, meta) {
  function _ok(la, ln) {
    la = Number(la); ln = Number(ln);
    if (!isFinite(la) || !isFinite(ln)) return null;
    if (la === 0 && ln === 0) return null;
    if (la < -90 || la > 90 || ln < -180 || ln > 180) return null;
    return { lat: la, lng: ln };
  }
  try {
    var m = meta || {};
    var v = m.fave_property_location || m.fave_property_map_address_location || null;
    if (Array.isArray(v)) v = v[0];
    if (v && typeof v === 'string' && v.indexOf(',') > 0) {
      var pr = v.split(',');
      var r0 = _ok(pr[0], pr[1]);
      if (r0) return r0;
    }
    var h = html || '';
    // Houzez (Anton): "property_lat":"-37.3235...","property_lng":"-57.0349..."
    var m1 = h.match(/["']property_lat["']\s*:\s*["']?(-?\d+\.\d+)["']?\s*,\s*["']property_lng["']\s*:\s*["']?(-?\d+\.\d+)["']?/i);
    if (m1) { var r1 = _ok(m1[1], m1[2]); if (r1) return r1; }
    // Otros temas/plataformas: "lat":..,"lng":.. / "latitude":..,"longitude":.. / data-lat= data-lng=
    var m2 = h.match(/["']lat(?:itude)?["']\s*:\s*["']?(-?\d+\.\d+)["']?\s*,\s*["']l(?:ng|on|ongitude)["']\s*:\s*["']?(-?\d+\.\d+)["']?/i);
    if (m2) { var r2 = _ok(m2[1], m2[2]); if (r2) return r2; }
    var m3 = h.match(/data-lat\s*=\s*["'](-?\d+\.\d+)["']/i);
    var m4 = h.match(/data-lng\s*=\s*["'](-?\d+\.\d+)["']/i);
    if (m3 && m4) { var r3 = _ok(m3[1], m4[1]); if (r3) return r3; }
  } catch (e) {}
  return null;
}

async function procesarPropiedad(p) {
  var emb = p._embedded || {};
  var terms = emb['wp:term'] || [];
  var feats = [];
  for (var a = 0; a < terms.length; a++) { var g = terms[a] || []; for (var b = 0; b < g.length; b++) { if (g[b].taxonomy === 'property_feature') feats.push(g[b].name); } }
  var media = emb['wp:featuredmedia'] || [];
  var foto = (media[0] && media[0].source_url) ? media[0].source_url : null;
  var titulo = limpiarHTML2(p.title && p.title.rendered);
  var descripcion = limpiarHTML2(p.content && p.content.rendered);
  var link = p.link || '';
  var pares = {}; var precio = null;
  try { var resp = await fetchScrape(link, { headers: { 'User-Agent': 'Mozilla/5.0 RaicesCRM' } }); if (resp.ok) { var html = await resp.text(); pares = extraerTablaDetalles(html); precio = extraerPrecio2(html); } } catch (e) {}
  var numero = detectarNumeroProp(pares, titulo, p.id);
  var operacion = detectarOperacion(pares['Estado'] || pares['Estado de la propiedad'], titulo + ' ' + descripcion.substring(0, 200));
  var ambientes = pares['Ambientes'] || pares['Habitaciones / Cuartos'] || pares['Habitaciones'] || null;
  var banos = pares['Banos'] || pares['Ba' + String.fromCharCode(241) + 'os'] || null;
  var parking = pares['Parking'] || pares['Cochera'] || pares['Garage'] || null;
  var ciudad = (pares['Ciudad/ Localidad'] || pares['Ciudad'] || pares['Localidad'] || '').split(',')[0].trim() || null;
  var zona = pares['Barrio/ Zona'] || pares['Zona'] || pares['Barrio'] || null;
  var direccion = pares['Direcci' + String.fromCharCode(243) + 'n'] || pares['Direccion'] || null;
  var entreCalles = pares['Entre calles'] || pares['Entre Calles'] || null;
  var caract = [].concat(feats);
  if (banos) caract.push('Banos: ' + banos);
  if (parking && !/no|aplica/i.test(parking)) caract.push('Cochera: ' + parking);
  // GALERIA COMPLETA (0 IA): adjuntos por ?parent (nuevas) -> HTML (viejas, reusa el `html` ya bajado
  // arriba para el precio, sin fetch extra) -> featured como minimo.
  var _base = (link || '').replace(/^(https?:\/\/[^\/]+).*/, '$1');
  var fotos = await _armarGaleriaProp(_base, p.id, (html || ''), foto);
  var _pin = _coordsHouzez((html || ''), p.property_meta || p.meta);
  return {
    numero: numero, titulo: titulo, tipo: pares['Tipo de propiedad'] || pares['Tipo'] || null,
    operacion: operacion, precio: precio, ambientes: ambientes, banos: banos,
    ciudad: ciudad, zona: zona, direccion: direccion, entre_calles: entreCalles, caracteristicas: caract.join(', '), descripcion: descripcion,
    lat: _pin ? _pin.lat : null, lng: _pin ? _pin.lng : null,
    link: link, foto: foto, fotos: fotos, postId: p.id
  };
}

async function traerListaPropiedades(sitio, limite) {
  var baseUrl = sitio.replace(/\/+$/, '');
  var props = []; var pagina = 1; var seguir = true;
  try {
    while (seguir && props.length < (limite || 9999)) {
      var url = baseUrl + '/wp-json/wp/v2/properties?per_page=50&page=' + pagina + '&_embed=1';
      var r = await fetchScrape(url, { headers: { 'User-Agent': 'Mozilla/5.0 RaicesCRM' } });
      if (!r.ok) break;
      var data = await r.json();
      if (!Array.isArray(data) || data.length === 0) break;
      for (var i = 0; i < data.length; i++) props.push(data[i]);
      if (data.length < 50) seguir = false;
      pagina++;
    }
  } catch (e) {}
  if (limite) props = props.slice(0, limite);
  return props;
}

// ============================================================================
// RESPALDO UNIVERSAL DEL CRON — SOLO INMOBILIARIA (ADITIVO)
// ============================================================================
// AGUJERO QUE TAPA: traerListaPropiedades() esta atada a /wp-json/wp/v2/properties.
// Si el sitio del cliente NO es WordPress (o no expone ese post type) devuelve 0 y la
// actualizacion automatica no hace NADA, en silencio. Eso NO se arregla tocando
// traerListaPropiedades: romperia a los clientes WordPress que hoy andan (Anton).
//
// SOLUCION: un camino NUEVO que corre SOLO donde hoy no hace nada (cuando el camino
// WordPress dio CERO). Para un sitio WordPress este codigo NUNCA se ejecuta.
//
// COSTO: reusa la MISMA cascada del import manual (POST->GET /api/scrape/lista) pero
// SOLO las vias GRATIS (Tokko -> JSON-LD -> heuristica -> sitemap generico). La IA
// (que descuenta mensajes del plan del cliente) es el ULTIMO recurso y solo si el dueno
// la habilito a mano (scraping_config.ia_habilitada). Devuelve un array de URLs (strings).
async function traerListaUniversalCron(sitio, user_id, permitirIA) {
  var items = [];
  var vistos = {};
  function _sumar(arr) {
    if (!Array.isArray(arr)) return;
    for (var i = 0; i < arr.length; i++) {
      var u = (arr[i] && typeof arr[i] === 'object') ? arr[i].url : arr[i];
      if (!u || typeof u !== 'string') continue;
      if (vistos[u]) continue;
      vistos[u] = 1;
      items.push(u);
    }
  }
  try {
    var base = String(sitio || '').trim().replace(/\/+$/, '');
    if (!base) return [];
    if (!base.startsWith('http')) base = 'https://' + base;
    // Anti-SSRF + dominio propio del tenant: MISMO gate que usa el import manual.
    var _permBase = await scrapeUrlPermitida(user_id, base);
    if (!_permBase.ok) { console.log('[cron universal] origen no permitido:', _permBase.error); return []; }
    // Material a analizar: home + rutas de listado tipicas (las mismas que /api/scrape/lista).
    var rutasListado = ['/', '/propiedades', '/propiedades/', '/listado', '/buscar', '/emprendimientos', '/venta', '/alquiler'];
    var homeHtml = '';
    var htmlsListado = [];
    for (var ri = 0; ri < rutasListado.length; ri++) {
      try {
        var rr = await fetchScrape(base + rutasListado[ri]);
        if (rr && rr.ok) { var h = await rr.text(); if (ri === 0) homeHtml = h; if (h && h.length > 500) htmlsListado.push(h); }
      } catch (eRuta) { /* seguir con la siguiente ruta */ }
    }
    if (htmlsListado.length === 0 && homeHtml) htmlsListado.push(homeHtml);

    // (1) GRATIS — Tokko Broker
    try {
      if (esSitioTokko(homeHtml) || htmlsListado.some(esSitioTokko)) {
        _sumar(await listarUrlsTokko(base, null));
        if (items.length) { console.log('[cron universal] tokko:', items.length); return items; }
      }
    } catch (eTk) { /* seguir a la siguiente estrategia */ }

    // (2) GRATIS — datos estructurados JSON-LD
    try {
      for (var hi = 0; hi < htmlsListado.length; hi++) _sumar(listarUrlsJsonLd(htmlsListado[hi], base));
      if (items.length) { console.log('[cron universal] json-ld:', items.length); return items; }
    } catch (eLd) { /* seguir */ }

    // (3) GRATIS — heuristica HTML generica. Umbral >=3 igual que el import manual:
    // con menos de 3 links es ruido (menu/destacados), no un listado -> se descarta.
    try {
      for (var hj = 0; hj < htmlsListado.length; hj++) _sumar(listarUrlsHeuristica(htmlsListado[hj], base));
      if (items.length >= 3) { console.log('[cron universal] heuristica:', items.length); return items; }
      items = []; vistos = {};
    } catch (eHe) { items = []; vistos = {}; }

    // (4) GRATIS — sitemap generico (cubre los sitios no-WP que igual publican sitemap.xml)
    try {
      _sumar(await descubrirUrlsSitemap(base, null));
      if (items.length) { console.log('[cron universal] sitemap:', items.length); return items; }
    } catch (eSm) { /* seguir */ }

    // (5) IA (PAGA) — ultimo recurso y SOLO con permiso explicito del dueno.
    if (permitirIA === true) {
      try {
        var htmlIA = homeHtml;
        for (var hk = 0; hk < htmlsListado.length; hk++) { if ((htmlsListado[hk] || '').length > (htmlIA || '').length) htmlIA = htmlsListado[hk]; }
        var iaItems = await listarUrlsIA(htmlIA, base, user_id);
        if (iaItems.length) {
          // COBRO: mismo patron exacto que /api/scrape/lista (3 mensajes por listar con IA).
          try { if (SUBSCRIPTIONS_ENABLED && user_id && await cobrarTodoV2Activo(user_id)) await registrarUsoIA(user_id, 3); } catch (eCobLista) {}
          _sumar(iaItems);
          console.log('[cron universal] IA (cobrado 3 msgs):', items.length);
          return items;
        }
      } catch (eIa) { /* nada mas que probar */ }
    }
  } catch (e) { console.error('[cron universal] traerListaUniversalCron:', e && e.message); }
  return items;
}

// Campos "duros" de una ficha: si NO hay ninguno, el parseo determinista no saco nada util.
// Mismo criterio que _wpJsonTieneDetalleUtil en /api/scrape/detalle (duplicado a proposito:
// aquella vive dentro de la ruta y no se toca). Es el gate que decide si vale gastar IA.
function _detalleTieneDatoDuroCron(campos) {
  if (!campos) return false;
  var duras = ['Precio', 'Ambientes', 'Habitaciones', 'Habitaciones / Cuartos', 'Ba' + String.fromCharCode(241) + 'os',
    'Banos', 'Parking', 'Plazas', 'Metros cubiertos', 'Metros totales', 'Tipo de propiedad', 'Propiedad ID'];
  for (var i = 0; i < duras.length; i++) { if (campos[duras[i]]) return true; }
  return false;
}

// Procesa UNA ficha a partir de su URL y devuelve el MISMO shape que procesarPropiedad(),
// para que el guardado de siempre (upsert por numero / pausa_manual / auto-pausa / fotos /
// paso GEO) lo consuma sin cambiar una linea. Devuelve null si no se pudo leer.
// Orden: helpers deterministas GRATIS -> (solo si no salio nada duro Y permitirIA) IA.
//
// ctrlIA (opcional, CANDADO B): objeto COMPARTIDO por toda la corrida del cron:
//   { usados, max, saltadas_tope_corrida, saltadas_tope_plan }
// - usados/max: contador de usos de IA de ficha en ESTA corrida (max 25). Al llegar al tope,
//   el resto de las fichas siguen SOLO por el camino determinista (que igual actualiza).
// - Ademas, ANTES de cada ficha con IA se re-chequea dentroDelTopeIA (query barata): cierra
//   el agujero de chequear el tope del plan solo al inicio de una corrida larga.
// Sin ctrlIA (llamada suelta) se comporta igual que antes.
async function procesarPropiedadURL(url, user_id, permitirIA, ctrlIA) {
  var u = String(url || '').trim();
  if (!u) return null;
  // Anti-SSRF + dominio propio del tenant ANTES de bajar nada.
  try {
    var _perm = await scrapeUrlPermitida(user_id, u);
    if (!_perm.ok) return null;
  } catch (ePerm) { return null; }
  var html = '';
  try {
    var r = await fetchScrape(u, { headers: { 'User-Agent': 'Mozilla/5.0 RaicesCRM' } });
    if (!r || !r.ok) return null;
    html = await r.text();
  } catch (eF) { return null; }
  if (!html) return null;

  var titulo = '', descripcion = '', pares = {}, precio = null;
  var esTokko = false;
  try { esTokko = esSitioTokko(html); } catch (eT) { esTokko = false; }

  if (esTokko) {
    // (1) GRATIS — Tokko tiene su propio parser, con las MISMAS claves de campos.
    try {
      var dt = parsearDetalleTokko(html, u);
      if (dt) { titulo = dt.titulo || ''; descripcion = dt.descripcion || ''; pares = dt.campos || {}; }
    } catch (eDt) {}
  } else {
    // (2) GRATIS — parser determinista de siempre (Houzez/WP y similares).
    try { pares = extraerTablaDetalles(html) || {}; } catch (eTd) { pares = {}; }
    try { precio = extraerPrecio2(html); } catch (eP) { precio = null; }
    try {
      var mT = html.match(/og:title["'][^>]*content=["']([^"']*)/i) || html.match(/content=["']([^"']*)["'][^>]*og:title/i);
      if (mT && mT[1]) titulo = _limpiarHtmlScrape(mT[1]);
      if (!titulo) { var mTt = html.match(/<title[^>]*>([\s\S]{0,200}?)<\/title>/i); if (mTt && mTt[1]) titulo = _limpiarHtmlScrape(mTt[1]); }
      var mD = html.match(/og:description["'][^>]*content=["']([^"']*)/i) || html.match(/content=["']([^"']*)["'][^>]*og:description/i);
      if (mD && mD[1]) descripcion = _limpiarHtmlScrape(mD[1]);
    } catch (eOg) {}
    // (3) GRATIS — datos estructurados (JSON-LD / microdata) si lo anterior no saco campos duros.
    if (!_detalleTieneDatoDuroCron(pares)) {
      try {
        var detEst = parsearDetalleEstructurado(html, u);
        if (detEst && detEst.campos && Object.keys(detEst.campos).length > 0) {
          pares = Object.assign({}, pares, detEst.campos);
          if (!titulo && detEst.titulo) titulo = detEst.titulo;
          if (!descripcion && detEst.descripcion) descripcion = detEst.descripcion;
        }
      } catch (eEst) {}
    }
  }

  // (4) IA (PAGA) — ULTIMO recurso: solo si lo determinista no saco NADA duro y hay permiso.
  if (!_detalleTieneDatoDuroCron(pares) && !precio && permitirIA === true) {
    // CANDADO B (tope por corrida + re-chequeo del tope del plan) — solo cuando viene ctrlIA (cron).
    var _puedeIA = true;
    if (ctrlIA && typeof ctrlIA === 'object') {
      if (ctrlIA.usados >= ctrlIA.max) {
        // Tope de la CORRIDA alcanzado: esta ficha sigue solo determinista; queda para la proxima.
        ctrlIA.saltadas_tope_corrida = (ctrlIA.saltadas_tope_corrida || 0) + 1;
        _puedeIA = false;
      } else {
        // Re-chequeo del tope del PLAN antes de CADA ficha con IA (no solo al inicio de la corrida):
        // una corrida larga puede agotar el cupo a mitad de camino. Query barata; ante duda, no gastar.
        try { _puedeIA = await dentroDelTopeIA(user_id); } catch (eTope) { _puedeIA = false; }
        if (!_puedeIA) ctrlIA.saltadas_tope_plan = (ctrlIA.saltadas_tope_plan || 0) + 1;
      }
    }
    if (_puedeIA) try {
      // El uso se cuenta al INVOCAR (los tokens se gastan aunque la IA no devuelva nada util).
      if (ctrlIA && typeof ctrlIA === 'object') ctrlIA.usados = (ctrlIA.usados || 0) + 1;
      var detIa = await parsearDetalleIA(html, u, user_id);
      if (detIa && (detIa.descripcion || (detIa.campos && Object.keys(detIa.campos).length > 0))) {
        // COBRO: mismo patron que el resto. 1 mensaje por FICHA (parsearDetalleIA usa
        // MODELO_INTERNO/Haiku y corre por propiedad; los 3 msgs del patron son el precio
        // de listar con Sonnet, que es una sola llamada por corrida).
        try { if (SUBSCRIPTIONS_ENABLED && user_id && await cobrarTodoV2Activo(user_id)) await registrarUsoIA(user_id, 1); } catch (eCobFicha) {}
        pares = Object.assign({}, pares, detIa.campos || {});
        if (detIa.titulo) titulo = detIa.titulo;
        if (detIa.descripcion) descripcion = detIa.descripcion;
      }
    } catch (eIaF) {}
  }

  // ===== MAPEO al shape de procesarPropiedad() (mismas claves, mismos fallbacks) =====
  if (!precio && pares['Precio']) precio = pares['Precio'];
  // numero: como no hay postId de WordPress, el ultimo fallback sale de la propia URL.
  var _numUrl = (u.match(/id-?(\d{2,})/i) || [])[1] || (u.match(/(\d{4,})/) || [])[1] || null;
  var numero = detectarNumeroProp(pares, titulo, _numUrl);
  var operacion = detectarOperacion(pares['Estado'] || pares['Estado de la propiedad'], titulo + ' ' + String(descripcion || '').substring(0, 200));
  var ambientes = pares['Ambientes'] || pares['Habitaciones / Cuartos'] || pares['Habitaciones'] || null;
  var banos = pares['Banos'] || pares['Ba' + String.fromCharCode(241) + 'os'] || null;
  var parking = pares['Parking'] || pares['Cochera'] || pares['Garage'] || null;
  var ciudad = (pares['Ciudad/ Localidad'] || pares['Ciudad'] || pares['Localidad'] || '').split(',')[0].trim() || null;
  var zona = pares['Barrio/ Zona'] || pares['Zona'] || pares['Barrio'] || null;
  var direccion = pares['Direcci' + String.fromCharCode(243) + 'n'] || pares['Direccion'] || null;
  var entreCalles = pares['Entre calles'] || pares['Entre Calles'] || null;
  var caract = [];
  if (banos) caract.push('Banos: ' + banos);
  if (parking && !/no|aplica/i.test(parking)) caract.push('Cochera: ' + parking);
  // FOTOS (0 IA): galeria generica del HTML -> fallback uploads/featured de WordPress -> og:image.
  var ogImg = '';
  try { var mOg = html.match(/og:image["'][^>]*content=["']([^"']*)/i) || html.match(/content=["']([^"']*)["'][^>]*og:image/i); if (mOg && mOg[1]) ogImg = mOg[1].trim(); } catch (eOi) {}
  var fotos = [];
  try { fotos = _extraerGaleriaHtml(html, u) || []; } catch (eG1) { fotos = []; }
  if (fotos.length < 2) {
    try {
      var _baseFotos = u.replace(/^(https?:\/\/[^\/]+).*/, '$1');
      var alt = await _armarGaleriaProp(_baseFotos, null, html, ogImg);
      if (alt && alt.length > fotos.length) fotos = alt;
    } catch (eG2) {}
  }
  if (!fotos.length && ogImg) fotos = [ogImg];
  // PIN DEL MAPA: mismo lector que procesarPropiedad (sin meta wp-json -> solo desde el HTML).
  var _pin = null;
  try { _pin = _coordsHouzez(html, null); } catch (ePin) { _pin = null; }

  return {
    numero: numero, titulo: titulo || 'Sin titulo', tipo: pares['Tipo de propiedad'] || pares['Tipo'] || null,
    operacion: operacion, precio: precio, ambientes: ambientes, banos: banos,
    ciudad: ciudad, zona: zona, direccion: direccion, entre_calles: entreCalles,
    caracteristicas: caract.join(', '), descripcion: descripcion || '',
    lat: _pin ? _pin.lat : null, lng: _pin ? _pin.lng : null,
    link: u, foto: (fotos.length ? fotos[0] : null), fotos: fotos, postId: null
  };
}

// Permiso de IA para la actualizacion automatica de UNA cuenta (inmobiliaria).
// DEPLOY-SAFE: si la columna ia_habilitada todavia no existe (migracion no corrida),
// cfg.ia_habilitada viene undefined -> false -> se comporta como hoy (IA apagada).
// FRENO POR TOPE: mismo precedente que el cron de hotel. Si la cuenta paso su tope de
// plan, NO se gasta IA (corre solo con las vias gratis) en vez de gastar por encima.
async function _iaPermitidaCron(cfg) {
  if (!cfg || cfg.ia_habilitada !== true) return false;
  try { return await dentroDelTopeIA(cfg.user_id); } catch (e) { return false; } // ante duda, no gastar
}

// CANDADO A: mapa de links de propiedades que el tenant YA tiene cargadas (properties.link).
// La IA de ficha del cron solo puede correr para URLs NUEVAS: una ficha cuyo link ya existe
// se actualiza SOLO con el parser determinista (gratis). Asi la primera corrida es la cara
// y las siguientes salen casi gratis. Ante error de DB devuelve {} -> NINGUN link "existe"
// -> ojo: eso permitiria IA de mas, pero el CANDADO B (max 25/corrida) acota el dano.
async function _linksExistentesTenant(user_id) {
  var mapa = {};
  try {
    var q = await supabase.from('properties').select('link').eq('user_id', user_id);
    var filas = (q && q.data) ? q.data : [];
    for (var i = 0; i < filas.length; i++) {
      var l = filas[i] && filas[i].link;
      if (l) mapa[String(l).trim().replace(/\/+$/, '')] = 1;
    }
  } catch (e) {}
  return mapa;
}
// Normaliza igual que el mapa (trim + sin barras finales) para que /ficha y /ficha/ matcheen.
function _linkYaExiste(mapa, url) {
  if (!mapa) return false;
  return !!mapa[String(url || '').trim().replace(/\/+$/, '')];
}

// Endpoint: devuelve las propiedades procesadas (para que el frontend muestre y el humano apruebe)
app.post('/api/scrape/v2', async function(req, res) {
  try {
    var user_id = await verificarUsuario(req);
    if (!user_id) return res.status(401).json({ error: 'No autorizado' });
    var sitio = (req.body.url || '').trim();
    var limite = req.body.limite ? parseInt(req.body.limite, 10) : null;
    if (!sitio) return res.status(400).json({ error: 'Falta la url del sitio' });
    if (!sitio.startsWith('http')) sitio = 'https://' + sitio;
    // restringir al dominio propio del tenant (anti-scrape de competencia / explosion de costo IA)
    const _perm = await scrapeUrlPermitida(user_id, sitio);
    if (!_perm.ok) return res.status(400).json({ error: _perm.error });
    var lista = await traerListaPropiedades(sitio, limite);
    if (!lista.length) return res.json({ ok: false, mensaje: 'No se encontraron propiedades', propiedades: [] });
    var procesadas = [];
    for (var i = 0; i < lista.length; i++) {
      try { var pr = await procesarPropiedad(lista[i]); procesadas.push(pr); } catch (e) {}
    }
    return res.json({ ok: true, total: procesadas.length, propiedades: procesadas });
  } catch (e) { return res.status(500).json({ error: e && e.message }); }
});


// ===== BANCO DE PROPIEDADES (para el chat / conversaciones) =====
// Devuelve las propiedades de la CUENTA del usuario logueado, resuelto server-side
// con la service key (que bypasea RLS). Esto arregla el bug donde un ASESOR veia
// "No hay propiedades" porque el frontend consultaba properties directo y la RLS
// lo bloqueaba (su auth.uid() != user_id del dueno de la cuenta).
// SEGURIDAD: el ownerId SIEMPRE se deriva del JWT del usuario (nunca de un
// parametro del request), asi un asesor solo ve las propiedades de SU cuenta.
app.get('/api/propiedades', async function(req, res) {
  try {
    var userId = await verificarUsuario(req);
    if (!userId) return res.status(401).json({ error: 'No autorizado: falta token valido' });
    // Resolver el OWNER de la cuenta: si el usuario es un asesor, el dueno es su admin_id;
    // si no hay fila de asesor, el usuario ES el dueno de la cuenta.
    var ownerId = userId;
    var ase = await supabase.from('asesores').select('admin_id').eq('auth_user_id', userId).maybeSingle();
    if (ase && ase.data && ase.data.admin_id) ownerId = ase.data.admin_id;
    var q = await supabase.from('properties').select('*').eq('user_id', ownerId).order('numero');
    if (q.error) return res.status(500).json({ error: q.error.message });
    return res.json({ ok: true, propiedades: q.data || [] });
  } catch (e) { return res.status(500).json({ error: e && e.message }); }
});

// ===== CITAS / AGENDA (nativo, sin Google) =====
// Account-scoped por JWT (service key bypassa RLS): el dueno ve TODAS las citas de su cuenta; el asesor comun
// solo las suyas; el asesor 'administrador' ve todas. Las crea el agente (al agendar) o se cargan a mano aca.
app.get('/api/citas', async function(req, res) {
  try {
    var userId = await verificarUsuario(req);
    if (!userId) return res.status(401).json({ error: 'No autorizado' });
    var ownerId = userId, soloAsesorId = null, esAdmin = true;
    var ase = await supabase.from('asesores').select('id, admin_id, rol, visibilidad').eq('auth_user_id', userId).maybeSingle();
    if (ase && ase.data) { if (ase.data.admin_id) ownerId = ase.data.admin_id; esAdmin = esAdministrador(ase.data); if (!esAdmin) soloAsesorId = ase.data.id; }
    var q = supabase.from('citas').select('*').eq('user_id', ownerId).order('fecha_hora', { ascending: true });
    if (soloAsesorId) q = q.eq('asesor_id', soloAsesorId);
    var r = await q;
    if (r.error) return res.status(500).json({ error: r.error.message });
    var citas = r.data || [];
    // MEJORA #4: adjuntar el NOMBRE del asesor DUEÑO (asesor_id) de cada cita para mostrarlo en la agenda.
    // Best-effort: 1 sola query batcheada por los asesor_id distintos. Si falla, las citas van sin nombre
    // (la agenda no rompe). Las citas de la IA sin dueño (asesor_id null) quedan con asesor_nombre null.
    try {
      var ids = [];
      var vistos = {};
      for (var i = 0; i < citas.length; i++) { var aid = citas[i] && citas[i].asesor_id; if (aid && !vistos[aid]) { vistos[aid] = true; ids.push(aid); } }
      if (ids.length) {
        var ra = await supabase.from('asesores').select('id, nombre').in('id', ids).eq('admin_id', ownerId);
        var nombreDe = {};
        (ra && ra.data ? ra.data : []).forEach(function(a){ if (a && a.id) nombreDe[a.id] = a.nombre || null; });
        citas.forEach(function(c){ c.asesor_nombre = (c && c.asesor_id && nombreDe[c.asesor_id]) ? nombreDe[c.asesor_id] : null; });
      }
    } catch (eNom) { /* sin nombres; la agenda funciona igual */ }
    // "Recordar a": lista de usuarios (asesores) de la cuenta para el multi-select del form. Best-effort:
    // si falla, el campo queda vacio (la agenda no rompe). Devuelve solo id+nombre (no datos sensibles).
    var asesoresLista = [];
    try {
      var ral = await supabase.from('asesores').select('id, nombre, alias').eq('admin_id', ownerId).order('created_at', { ascending: true });
      asesoresLista = (ral && ral.data ? ral.data : []).map(function(a){ return { id: a.id, nombre: a.nombre || a.alias || 'Usuario' }; });
    } catch (eAl) { /* sin lista; el form igual funciona */ }
    return res.json({ ok: true, citas: citas, esDueno: !(ase && ase.data), esAdmin: esAdmin, miAsesorId: soloAsesorId, asesores: asesoresLista });
  } catch (e) { return res.status(500).json({ error: e && e.message }); }
});
app.post('/api/citas', async function(req, res) {
  try {
    var userId = await verificarUsuario(req);
    if (!userId) return res.status(401).json({ error: 'No autorizado' });
    var ownerId = userId, asesorIdProp = null, esAsesorComun = false;
    var ase = await supabase.from('asesores').select('id, admin_id, rol, visibilidad').eq('auth_user_id', userId).maybeSingle();
    if (ase && ase.data) { if (ase.data.admin_id) ownerId = ase.data.admin_id; asesorIdProp = ase.data.id; esAsesorComun = !esAdministrador(ase.data); }
    var b = req.body || {};
    if (!b.fecha_hora) return res.status(400).json({ error: 'Falta fecha_hora' });
    var fh = new Date(b.fecha_hora);
    if (isNaN(fh.getTime())) return res.status(400).json({ error: 'fecha_hora invalida' });
    // Un asesor comun solo puede crear citas a SU nombre (no asignarlas a otro); dueno/admin pueden elegir.
    var asesorCita = esAsesorComun ? asesorIdProp : (b.asesor_id || asesorIdProp || null);
    // Tipos AMPLIADOS: ademas de visita/llamada/reunion, ahora alquiler y alquiler_temporal
    // (eventos con rango: fecha_hora = check-in, fecha_fin = check-out). ADITIVO: si b.tipo
    // no entra en la lista, cae a 'visita' (comportamiento conservador de siempre).
    var tipoCita = (_TIPOS_CITA_VALIDOS.indexOf(b.tipo) >= 0) ? b.tipo : 'otro';
    var esAlquiler = (tipoCita === 'alquiler' || tipoCita === 'alquiler_temporal');
    var fila = { user_id: ownerId, fecha_hora: fh.toISOString(), tipo: tipoCita, titulo: (b.titulo ? String(b.titulo).slice(0,160) : 'Cita'), estado: 'agendada', notas: (b.notas ? String(b.notas).slice(0,500) : null), lead_nombre: (b.lead_nombre ? String(b.lead_nombre).slice(0,120) : null), lead_telefono: (b.lead_telefono ? String(b.lead_telefono).slice(0,40) : null), asesor_id: asesorCita, contact_id: b.contact_id || null, conversation_id: b.conversation_id || null, origen: 'manual' };
    // Campos nuevos de la AGENDA NATIVA. Se agregan SOLO si vienen (defensivo: si la
    // migracion aun no corrio, igual no fuerza columnas inexistentes a valores raros).
    var fechaFinISO = null;
    if (b.fecha_fin) { var ff = new Date(b.fecha_fin); if (!isNaN(ff.getTime())) { fechaFinISO = ff.toISOString(); fila.fecha_fin = fechaFinISO; } }
    if (b.property_id) fila.property_id = b.property_id;
    if (b.unidad) fila.unidad = String(b.unidad).slice(0,120);
    if (typeof b.todo_el_dia === 'boolean') fila.todo_el_dia = b.todo_el_dia;
    else if (esAlquiler) fila.todo_el_dia = true; // alquileres son por rango de dias por defecto
    var r = await supabase.from('citas').insert(fila).select('id').single();
    if (r.error) return res.status(500).json({ error: r.error.message });
    var citaId = r.data && r.data.id;
    // "Creado por": registra QUIEN agendo la cita (auth_user_id del creador). Best-effort
    // post-insert: si la migracion de la columna aun no corrio, el update no-opea y la cita
    // YA quedo creada igual (no rompe). Las citas de la IA quedan con creado_por=null + origen='agente'.
    if (citaId) { try { await supabase.from('citas').update({ creado_por: userId }).eq('id', citaId); } catch (eCp) {} }
    // MEJORA #4: `lugar` (texto libre de donde es la cita, cuando NO hay propiedad ligada). Best-effort
    // post-insert por el MISMO motivo que creado_por: si la columna aun no existe, el update no-opea y la
    // cita YA quedo creada. Solo se setea si vino con contenido (no pisa con vacio).
    if (citaId && b.lugar && String(b.lugar).trim()) { try { await supabase.from('citas').update({ lugar: String(b.lugar).slice(0,300) }).eq('id', citaId); } catch (eLu) {} }
    // "Recordar a": lista de asesores (ids) a quienes pushear el recordatorio, ADEMAS del asesor dueno.
    // Best-effort post-insert (mismo motivo que creado_por/lugar): si la columna recordar_a aun no existe,
    // el update no-opea y la cita YA quedo creada. Se filtran a asesores validos de la cuenta y se guarda
    // como JSON de ids (lo consume enviarRecordatorioUno). Cero IA / cero tokens.
    if (citaId && Array.isArray(b.recordar_a) && b.recordar_a.length) {
      try {
        var idsRec = b.recordar_a.map(String).filter(Boolean).slice(0, 30);
        var vr = await supabase.from('asesores').select('id').eq('admin_id', ownerId).in('id', idsRec);
        var validos = (vr && vr.data ? vr.data : []).map(function(a){ return String(a.id); });
        if (validos.length) await supabase.from('citas').update({ recordar_a: JSON.stringify(validos) }).eq('id', citaId);
      } catch (eRa) { /* sin columna aun / error: la cita YA quedo creada */ }
    }
    // MOTOR DE TAREAS (cero IA): si es alquiler_temporal y tenemos check-out, generar las
    // tareas de limpieza pre/post y avisar al equipo. Best-effort: si falla, la cita YA
    // quedo creada (no se revierte) y no se devuelve error al usuario.
    if (citaId && tipoCita === 'alquiler_temporal' && fechaFinISO) {
      try { await generarTareasAlquiler(ownerId, citaId, fh.toISOString(), fechaFinISO, fila.titulo); } catch (eGen) { console.error('POST /api/citas generarTareas:', eGen && eGen.message); }
    }
    // FEATURE #21: PUSH a Google Calendar (best-effort, no bloquea ni rompe la creacion). Inerte sin Calendar conectado.
    if (citaId) { syncCitaACalendar(ownerId, citaId).catch(function(e){ console.error('POST /api/citas syncCalendar:', e && e.message); }); }
    return res.json({ ok: true, id: citaId });
  } catch (e) { return res.status(500).json({ error: e && e.message }); }
});
app.post('/api/citas/actualizar', async function(req, res) {
  try {
    var userId = await verificarUsuario(req);
    if (!userId) return res.status(401).json({ error: 'No autorizado' });
    var ownerId = userId, soloAsesorId = null;
    var ase = await supabase.from('asesores').select('id, admin_id, rol, visibilidad').eq('auth_user_id', userId).maybeSingle();
    if (ase && ase.data) { if (ase.data.admin_id) ownerId = ase.data.admin_id; if (!esAdministrador(ase.data)) soloAsesorId = ase.data.id; }
    var b = req.body || {};
    if (!b.id) return res.status(400).json({ error: 'Falta id' });
    // Traemos la fila ACTUAL (no solo el id) para poder recalcular tareas de alquiler
    // con las fechas/tipo resultantes. Defensivo: si las columnas nuevas no existen,
    // el select('*') igual trae lo que haya.
    var verq = supabase.from('citas').select('*').eq('id', b.id).eq('user_id', ownerId);
    if (soloAsesorId) verq = verq.eq('asesor_id', soloAsesorId);
    var dueno = await verq.maybeSingle();
    if (!dueno || !dueno.data) return res.status(404).json({ error: 'Cita no encontrada' });
    var actual = dueno.data;
    var upd = {};
    if (b.estado && ['agendada','confirmada','cumplida','cancelada'].indexOf(b.estado) >= 0) upd.estado = b.estado;
    if (b.fecha_hora) { var fh2 = new Date(b.fecha_hora); if (!isNaN(fh2.getTime())) { upd.fecha_hora = fh2.toISOString(); upd.recordatorio_enviado = false; } }
    if (typeof b.notas === 'string') upd.notas = b.notas.slice(0,500);
    // --- AGENDA NATIVA: campos nuevos editables ---
    // Reasignar asesor: SOLO dueno/admin (un asesor comun no puede pasar su cita a otro).
    // soloAsesorId != null => es asesor comun => se ignora b.asesor_id.
    if (!soloAsesorId && typeof b.asesor_id !== 'undefined') upd.asesor_id = b.asesor_id || null;
    if (typeof b.property_id !== 'undefined') upd.property_id = b.property_id || null;
    if (b.fecha_fin) { var ff2 = new Date(b.fecha_fin); if (!isNaN(ff2.getTime())) upd.fecha_fin = ff2.toISOString(); }
    else if (b.fecha_fin === null) upd.fecha_fin = null;
    if (typeof b.unidad === 'string') upd.unidad = b.unidad.slice(0,120);
    // MEJORA #4: `lugar` editable (texto libre). Va con el bloque de campos nuevos; si la columna aun no
    // existe, el retry defensivo de abajo lo descarta (lugar no esta en la whitelist clasica) y no rompe.
    if (typeof b.lugar === 'string') upd.lugar = b.lugar.slice(0,300);
    if (b.tipo && _TIPOS_CITA_VALIDOS.indexOf(b.tipo) >= 0) upd.tipo = b.tipo;
    if (Object.keys(upd).length === 0) return res.status(400).json({ error: 'Nada para actualizar' });
    upd.actualizado_en = new Date().toISOString();
    var updq = supabase.from('citas').update(upd).eq('id', b.id).eq('user_id', ownerId);
    if (soloAsesorId) updq = updq.eq('asesor_id', soloAsesorId);
    var r = await updq;
    if (r.error) {
      // Defensivo: si la migracion aun no corrio, columnas nuevas (asesor_id ya existe,
      // pero property_id/fecha_fin/unidad/actualizado_en podrian faltar) hacen fallar el
      // update. Reintentar SOLO con los campos clasicos para no romper la edicion vieja.
      var updSafe = {};
      ['estado','fecha_hora','recordatorio_enviado','notas','asesor_id'].forEach(function(k){ if (typeof upd[k] !== 'undefined') updSafe[k] = upd[k]; });
      if (Object.keys(updSafe).length > 0) {
        var updq2 = supabase.from('citas').update(updSafe).eq('id', b.id).eq('user_id', ownerId);
        if (soloAsesorId) updq2 = updq2.eq('asesor_id', soloAsesorId);
        var r2 = await updq2;
        if (r2.error) return res.status(500).json({ error: r2.error.message });
      } else {
        return res.status(500).json({ error: r.error.message });
      }
    }
    // MOTOR DE TAREAS (cero IA): efectos sobre las tareas del alquiler segun el cambio.
    try {
      var tipoFinal = (typeof upd.tipo !== 'undefined') ? upd.tipo : actual.tipo;
      var estadoFinal = (typeof upd.estado !== 'undefined') ? upd.estado : actual.estado;
      var ciFinal = (typeof upd.fecha_hora !== 'undefined') ? upd.fecha_hora : actual.fecha_hora;
      var coFinal = (typeof upd.fecha_fin !== 'undefined') ? upd.fecha_fin : actual.fecha_fin;
      if (estadoFinal === 'cancelada') {
        // Cancelar el alquiler => cancelar sus tareas pendientes (no avisar al equipo).
        await cancelarTareasDeEvento(ownerId, b.id);
      } else if (tipoFinal === 'alquiler_temporal' && coFinal) {
        // Cambiaron fechas/tipo de un alquiler temporal => recalcular tareas no-hechas.
        var cambioFechas = (typeof upd.fecha_hora !== 'undefined') || (typeof upd.fecha_fin !== 'undefined') || (typeof upd.tipo !== 'undefined');
        if (cambioFechas) await recalcularTareasAlquiler(ownerId, b.id, ciFinal, coFinal, actual.titulo);
      }
    } catch (eTareas) { console.error('actualizar cita motor tareas:', eTareas && eTareas.message); }
    // FEATURE #21: reflejar el cambio en Google Calendar (best-effort). Cancelada -> borrar el evento; resto -> upsert.
    try {
      var _estadoFinalCal = (typeof upd.estado !== 'undefined') ? upd.estado : actual.estado;
      if (_estadoFinalCal === 'cancelada') { borrarCitaDeCalendar(ownerId, b.id).catch(function(e){ console.error('cita cancel syncCalendar:', e && e.message); }); }
      else { syncCitaACalendar(ownerId, b.id).catch(function(e){ console.error('cita upd syncCalendar:', e && e.message); }); }
    } catch (eCal) { console.error('actualizar cita syncCalendar:', eCal && eCal.message); }
    return res.json({ ok: true });
  } catch (e) { return res.status(500).json({ error: e && e.message }); }
});

// ===== FEATURE #15: TOMAR una cita TENTATIVA (claim atomico, CERO IA) =====
// Un asesor (o el dueno) RECLAMA una cita que dejo el agente sin asignar (asesor_id=NULL, estado='agendada',
// origen='agente'). Claim ATOMICO (compare-and-set): UPDATE ... WHERE id=cita AND asesor_id IS NULL AND
// estado='agendada'. El PRIMERO gana; si otro ya la tomo (0 filas afectadas) -> 409. Aislado por tenant
// (ownerId derivado del JWT). Un asesor comun setea asesor_id=SU id; el dueno (sin fila de asesor) la
// confirma dejando asesor_id NULL pero estado='confirmada' + creado_por para dejar traza (la doble condicion
// asesor_id IS NULL + estado='agendada' hace el claim atomico igual en el caso del dueno). 0 IA.
app.post('/api/citas/tomar', async function(req, res) {
  try {
    var userId = await verificarUsuario(req);
    if (!userId) return res.status(401).json({ error: 'No autorizado' });
    var ownerId = userId, claimAsesorId = null;
    var ase = await supabase.from('asesores').select('id, admin_id').eq('auth_user_id', userId).maybeSingle();
    if (ase && ase.data) { if (ase.data.admin_id) ownerId = ase.data.admin_id; claimAsesorId = ase.data.id; }
    var b = req.body || {};
    var citaId = b.cita_id || b.id;
    if (!citaId) return res.status(400).json({ error: 'Falta cita_id' });
    // Claim ATOMICO: solo si sigue tentativa (asesor_id IS NULL) Y agendada. .select() devuelve las filas
    // afectadas: si el UPDATE no toco ninguna, ya la tomo otro (o no existe / no es de este tenant) -> 409.
    // Traemos tambien departamento_id/lead_nombre/fecha_hora para el AVISO al equipo (MEJORA #2).
    var upd = { asesor_id: claimAsesorId, estado: 'confirmada' };
    var q = supabase.from('citas').update(upd)
      .eq('id', citaId).eq('user_id', ownerId)
      .is('asesor_id', null).eq('estado', 'agendada')
      .select('id, departamento_id, lead_nombre, fecha_hora');
    var r = await q;
    if (r.error) return res.status(500).json({ error: r.error.message });
    if (!r.data || !r.data.length) {
      // 0 filas: o la tomo otro, o no existe/otro tenant. Distinguir para el mensaje (best-effort).
      var chk = await supabase.from('citas').select('id, asesor_id, estado').eq('id', citaId).eq('user_id', ownerId).maybeSingle();
      if (!chk || !chk.data) return res.status(404).json({ error: 'Cita no encontrada' });
      return res.status(409).json({ error: 'Ya la tomo otro asesor' });
    }
    // Traza de quien la tomo (best-effort; si la columna no existe, no-opea y la toma YA quedo firme).
    try { await supabase.from('citas').update({ creado_por: userId }).eq('id', citaId); } catch (eCp) {}
    // MEJORA #2: ANUNCIAR quien la tomo al canal del DEPARTAMENTO correspondiente (0 IA, texto fijo).
    // Best-effort, no bloquea la respuesta. Resuelve el nombre del que la tomo (asesor o dueño) y postea
    // "X tomó la cita ..." al mismo canal donde se aviso la cita tentativa (depto + general de fallback).
    try {
      var _cTomada = r.data[0] || {};
      var _quien = 'Alguien';
      try {
        if (claimAsesorId) { var _qa = await supabase.from('asesores').select('nombre').eq('id', claimAsesorId).eq('admin_id', ownerId).maybeSingle(); if (_qa && _qa.data && _qa.data.nombre) _quien = String(_qa.data.nombre).trim(); }
        else { _quien = 'El dueño'; } // quien toma sin fila de asesor = el dueño de la cuenta
      } catch (eQ) {}
      var _leadTxt = (_cTomada.lead_nombre && String(_cTomada.lead_nombre).trim()) ? (' de ' + String(_cTomada.lead_nombre).trim()) : '';
      var _fechaTxt = _cTomada.fecha_hora ? (' para ' + _formatearFechaCita(_cTomada.fecha_hora)) : '';
      var _txtTomada = '✅ ' + _quien + ' tomó la cita' + _leadTxt + _fechaTxt + '.';
      var _depTomada = _cTomada.departamento_id || null;
      if (_depTomada) { try { await _postearAvisoInterno(ownerId, _depTomada, _txtTomada); } catch (eAvD) {} }
      try { await _postearAvisoInterno(ownerId, 'general', _txtTomada); } catch (eAvG) {}
    } catch (eAviso) { console.error('tomar cita aviso equipo:', eAviso && eAviso.message); }
    // FEATURE #21: reflejar en Google Calendar (best-effort, inerte sin Calendar conectado).
    try { syncCitaACalendar(ownerId, citaId).catch(function(e){ console.error('tomar cita syncCalendar:', e && e.message); }); } catch (eCal) {}
    return res.json({ ok: true, id: citaId });
  } catch (e) { return res.status(500).json({ error: e && e.message }); }
});

// ===== TAREAS DE EVENTO + EQUIPO (motor de tareas, CERO IA) =====
// Mismo modelo de scoping que /api/citas: service key + filtro por user_id (ownerId).
// El asesor comun ve/edita; el aislamiento es por TENANT (no por asesor) — las tareas
// de limpieza son del negocio, no de un vendedor en particular.

// Resuelve el ownerId (tenant) a partir del JWT. Helper local para no repetir.
async function _resolverTenant(req) {
  var userId = await verificarUsuario(req);
  if (!userId) return { error: 401 };
  var ownerId = userId, asesorId = null, esAdmin = true;
  var ase = await supabase.from('asesores').select('id, admin_id, rol, visibilidad').eq('auth_user_id', userId).maybeSingle();
  if (ase && ase.data) { if (ase.data.admin_id) ownerId = ase.data.admin_id; asesorId = ase.data.id; esAdmin = esAdministrador(ase.data); }
  return { userId: userId, ownerId: ownerId, asesorId: asesorId, esAdmin: esAdmin, esDueno: !(ase && ase.data) };
}

// GET /api/citas/:id/tareas — lista las tareas de un evento del tenant.
app.get('/api/citas/:id/tareas', async function(req, res) {
  try {
    var t = await _resolverTenant(req);
    if (t.error) return res.status(401).json({ error: 'No autorizado' });
    // Verificar que el evento sea del tenant antes de exponer sus tareas.
    var cita = await supabase.from('citas').select('id').eq('id', req.params.id).eq('user_id', t.ownerId).maybeSingle();
    if (!cita || !cita.data) return res.status(404).json({ error: 'Cita no encontrada' });
    var r = await supabase.from('tareas_evento').select('*').eq('user_id', t.ownerId).eq('evento_id', req.params.id).order('fecha_hora', { ascending: true });
    if (r.error) return res.status(500).json({ error: r.error.message });
    return res.json({ ok: true, tareas: r.data || [] });
  } catch (e) { return res.status(500).json({ error: e && e.message }); }
});

// GET /api/tareas — lista tareas del tenant (filtros opcionales desde/hasta/estado/asignado_a).
app.get('/api/tareas', async function(req, res) {
  try {
    var t = await _resolverTenant(req);
    if (t.error) return res.status(401).json({ error: 'No autorizado' });
    var q = supabase.from('tareas_evento').select('*').eq('user_id', t.ownerId);
    if (req.query.desde) { var d = new Date(req.query.desde); if (!isNaN(d.getTime())) q = q.gte('fecha_hora', d.toISOString()); }
    if (req.query.hasta) { var h = new Date(req.query.hasta); if (!isNaN(h.getTime())) q = q.lte('fecha_hora', h.toISOString()); }
    if (req.query.estado) q = q.eq('estado', String(req.query.estado));
    if (req.query.asignado_a) q = q.eq('asignado_a', String(req.query.asignado_a));
    var r = await q.order('fecha_hora', { ascending: true });
    if (r.error) return res.status(500).json({ error: r.error.message });
    return res.json({ ok: true, tareas: r.data || [] });
  } catch (e) { return res.status(500).json({ error: e && e.message }); }
});

// POST /api/tareas — crear una tarea MANUAL (atada o no a un evento).
app.post('/api/tareas', async function(req, res) {
  try {
    var t = await _resolverTenant(req);
    if (t.error) return res.status(401).json({ error: 'No autorizado' });
    var b = req.body || {};
    if (!b.fecha_hora) return res.status(400).json({ error: 'Falta fecha_hora' });
    var fh = new Date(b.fecha_hora);
    if (isNaN(fh.getTime())) return res.status(400).json({ error: 'fecha_hora invalida' });
    // Si viene evento_id, verificar que el evento sea del tenant.
    if (b.evento_id) {
      var cita = await supabase.from('citas').select('id').eq('id', b.evento_id).eq('user_id', t.ownerId).maybeSingle();
      if (!cita || !cita.data) return res.status(404).json({ error: 'Cita no encontrada' });
    }
    var TIPOS_TAREA = ['limpieza','limpieza_pre','limpieza_post','mantenimiento','entrega_llaves','retiro_llaves','inventario','custom'];
    var fila = {
      user_id: t.ownerId,
      evento_id: b.evento_id || null,
      tipo: (TIPOS_TAREA.indexOf(b.tipo) >= 0 ? b.tipo : 'custom'),
      titulo: (b.titulo ? String(b.titulo).slice(0,160) : 'Tarea'),
      fecha_hora: fh.toISOString(),
      duracion_min: (typeof b.duracion_min === 'number' ? b.duracion_min : null),
      asignado_a: b.asignado_a || null,
      estado: 'pendiente',
      notas: (b.notas ? String(b.notas).slice(0,500) : null),
      origen: 'manual'
    };
    var r = await supabase.from('tareas_evento').insert(fila).select('id').single();
    if (r.error) return res.status(500).json({ error: r.error.message });
    return res.json({ ok: true, id: r.data && r.data.id });
  } catch (e) { return res.status(500).json({ error: e && e.message }); }
});

// POST /api/tareas/actualizar — cambiar estado / asignado_a / fecha_hora / notas.
app.post('/api/tareas/actualizar', async function(req, res) {
  try {
    var t = await _resolverTenant(req);
    if (t.error) return res.status(401).json({ error: 'No autorizado' });
    var b = req.body || {};
    if (!b.id) return res.status(400).json({ error: 'Falta id' });
    var dueno = await supabase.from('tareas_evento').select('id').eq('id', b.id).eq('user_id', t.ownerId).maybeSingle();
    if (!dueno || !dueno.data) return res.status(404).json({ error: 'Tarea no encontrada' });
    var upd = {};
    if (b.estado && ['pendiente','en_curso','hecha','cancelada'].indexOf(b.estado) >= 0) upd.estado = b.estado;
    if (typeof b.asignado_a !== 'undefined') upd.asignado_a = b.asignado_a || null;
    if (b.fecha_hora) { var fh3 = new Date(b.fecha_hora); if (!isNaN(fh3.getTime())) { upd.fecha_hora = fh3.toISOString(); upd.aviso_enviado = false; } }
    if (typeof b.notas === 'string') upd.notas = b.notas.slice(0,500);
    if (b.tipo && ['limpieza','limpieza_pre','limpieza_post','mantenimiento','entrega_llaves','retiro_llaves','inventario','custom'].indexOf(b.tipo) >= 0) upd.tipo = b.tipo;
    if (Object.keys(upd).length === 0) return res.status(400).json({ error: 'Nada para actualizar' });
    upd.actualizado_en = new Date().toISOString();
    var r = await supabase.from('tareas_evento').update(upd).eq('id', b.id).eq('user_id', t.ownerId);
    if (r.error) return res.status(500).json({ error: r.error.message });
    return res.json({ ok: true });
  } catch (e) { return res.status(500).json({ error: e && e.message }); }
});

