// CREDENCIALES DE ACCESO del cliente (SOLO Maestro). El mail se puede leer y cambiar; la clave NO se
// puede mostrar (Auth la guarda hasheada) -> aca solo se SETEA una nueva. updateUserById aplica al
// instante (efecto inmediato). Mandar email y/o password; al menos uno.
app.post('/api/maestro/cliente/:id/credenciales', async function(req, res){
  try{
    if (!MAESTRO_ENABLED || !maestroAuth(req)) return res.status(401).json({ error: 'No autorizado' });
    var _g = await requiereSeccion(req, 'clientes'); if (_g) return res.status(_g.status).json({ error: _g.error });
    var uid = req.params.id;
    var b = req.body || {};
    var nuevoEmail = (b.email ? String(b.email) : '').trim().toLowerCase();
    var nuevaClave = (b.password ? String(b.password) : '').trim();
    var patch = {};
    if (nuevoEmail) {
      if (!/^[^@\s]+@[^@\s]+\.[^@\s]+$/.test(nuevoEmail)) return res.status(400).json({ error: 'Email invalido' });
      patch.email = nuevoEmail; patch.email_confirm = true;
    }
    if (nuevaClave) {
      if (nuevaClave.length < 6) return res.status(400).json({ error: 'La clave debe tener al menos 6 caracteres' });
      patch.password = nuevaClave;
    }
    if (!Object.keys(patch).length) return res.status(400).json({ error: 'Nada para actualizar: manda un email nuevo y/o una clave nueva' });
    var r = await supabase.auth.admin.updateUserById(uid, patch);
    if (r.error) {
      var m = String((r.error && r.error.message) || '');
      if (/already|registered|exists|duplicate/i.test(m)) return res.status(400).json({ error: 'Ese email ya esta en uso por otra cuenta' });
      return res.status(400).json({ error: m || 'No se pudo actualizar' });
    }
    try { await supabase.from('admin_audit').insert({ accion: 'editar_credenciales', target_user_id: uid, detalle: JSON.stringify({ cambio_email: !!nuevoEmail, cambio_clave: !!nuevaClave }) }); } catch(eA){}
    return res.json({ ok: true, email: (r.data && r.data.user && r.data.user.email) || nuevoEmail || null });
  }catch(e){ return res.status(500).json({ error: e && e.message }); }
});

// Cambiar el TIPO DE COMERCIO (rubro) de un cliente. SOLO el Maestro (gateado por maestroAuth).
// El cliente NO puede cambiarlo desde su /configuracion: cambia el inventario y la estructura de
// departamentos, asi que solo se toca aca a pedido de soporte. Setea business_settings.rubro y, de
// paso, el user_metadata.rubro (lo usa el fallback de la config cuando aun no hay business_settings).
app.post('/api/maestro/cliente/:id/rubro', async function(req, res){
  try{
    if (!MAESTRO_ENABLED || !maestroAuth(req)) return res.status(401).json({ error: 'No autorizado' });
    var _g = await requiereSeccion(req, 'clientes'); if (_g) return res.status(_g.status).json({ error: _g.error });
    var uid = req.params.id;
    var rubroRaw = (req.body && req.body.rubro) ? String(req.body.rubro).trim().toLowerCase() : '';
    // Aceptamos los 3 canonicos + los legacy (compat hacia atras), pero SIEMPRE guardamos el canonico.
    var aceptados = ['inmobiliaria', 'desarrolladora', 'hotel_cabanas', 'hotel', 'cabanas', 'cabañas', 'temporario', 'hoteleria'];
    if (aceptados.indexOf(rubroRaw) === -1) return res.status(400).json({ error: 'Rubro invalido' });
    var rubro = normalizarRubro(rubroRaw);
    // Upsert por si el cliente aun no tuviera fila en business_settings (no deberia, pero defensivo).
    var up = await supabase.from('business_settings').upsert({ user_id: uid, rubro: rubro, updated_at: new Date().toISOString() }, { onConflict: 'user_id' });
    if (up && up.error) return res.status(400).json({ error: up.error.message });
    // Espejar en user_metadata (best-effort: la config usa esto como fallback). Mergeamos sobre el
    // metadata actual para NO pisar name/company. Nunca rompe la operacion.
    try {
      var cur = await supabase.auth.admin.getUserById(uid);
      var meta = (cur && cur.data && cur.data.user && cur.data.user.user_metadata) ? cur.data.user.user_metadata : {};
      await supabase.auth.admin.updateUserById(uid, { user_metadata: Object.assign({}, meta, { rubro: rubro }) });
    } catch(eMeta){}
    try { await supabase.from('admin_audit').insert({ accion: 'cambiar_rubro', target_user_id: uid, detalle: JSON.stringify({ rubro: rubro }) }); } catch(eA){}
    return res.json({ ok: true, rubro: rubro });
  }catch(e){ return res.status(500).json({ error: e && e.message }); }
});

// Prender/apagar el LOOK MODERNO (ui_moderno) de un cliente. Solo el Maestro. Antes solo se hacia por SQL manual
// (por eso quedaba OFF en clientes nuevos). Al prenderlo, tambien NORMALIZA el rubro guardado a su valor canonico
// (arregla cuentas legacy donde el menu/inventario no matcheaban 'hotel_cabanas' aunque el flag estuviera ON).
app.post('/api/maestro/cliente/:id/ui-moderno', async function(req, res){
  try{
    if (!MAESTRO_ENABLED || !maestroAuth(req)) return res.status(401).json({ error: 'No autorizado' });
    var _g = await requiereSeccion(req, 'clientes'); if (_g) return res.status(_g.status).json({ error: _g.error });
    var uid = req.params.id;
    var on = !!(req.body && req.body.on);
    var patch = { user_id: uid, ui_moderno: on, updated_at: new Date().toISOString() };
    // Normalizar el rubro guardado (best-effort): si es legacy, lo dejamos en el canonico para que labels/inventario matcheen.
    try {
      var cur = await supabase.from('business_settings').select('rubro').eq('user_id', uid).maybeSingle();
      var rubroActual = cur && cur.data && cur.data.rubro;
      if (rubroActual) patch.rubro = normalizarRubro(rubroActual);
    } catch (eR) {}
    var up = await supabase.from('business_settings').upsert(patch, { onConflict: 'user_id' });
    if (up && up.error) return res.status(400).json({ error: up.error.message });
    try { await supabase.from('admin_audit').insert({ accion: 'ui_moderno', target_user_id: uid, detalle: JSON.stringify({ on: on, rubro: patch.rubro || null }) }); } catch(eA){}
    return res.json({ ok: true, ui_moderno: on, rubro: patch.rubro || null });
  }catch(e){ return res.status(500).json({ error: e && e.message }); }
});

