// Registrar el token FCM del celular del Maestro (la app del dueno) para recibir las notificaciones por push.
app.post('/api/maestro/device-token', async function(req, res){
  try{
    if (!MAESTRO_ENABLED || !maestroAuth(req)) return res.status(401).json({ error: 'No autorizado' });
    var token = (req.body && req.body.token) ? String(req.body.token).slice(0, 4000) : '';
    var plataforma = (req.body && req.body.plataforma) ? String(req.body.plataforma).slice(0, 40) : 'android';
    if (!token) return res.status(400).json({ error: 'Falta token' });
    await supabase.from('maestro_device_tokens').upsert({ token: token, plataforma: plataforma, ultimo_uso: new Date().toISOString() }, { onConflict: 'token' });
    return res.json({ ok: true });
  }catch(e){ return res.status(500).json({ error: e && e.message }); }
});

// Registrar el token FCM del dispositivo de un ASESOR (o del dueno) para recibir push (enviarPushAsesor ~L167).
// Sin este endpoint la tabla device_tokens queda vacia y el push a asesores nunca llega. Base para iOS PWA (web push),
// app nativa y web: los tres obtienen un token FCM y lo registran aca. Auth por token de Supabase (verificarUsuario):
// el user_id se DERIVA del token (NO se confia en el body) -> nadie puede registrar tokens a nombre de otro usuario.
// device_tokens confirmado en codigo: columnas token + user_id (ver enviarPushAsesor ~L170/188). La columna plataforma
// NO esta confirmada en el esquema desde el codigo, por eso el upsert es DEFENSIVO: primero intenta con plataforma +
// ultimo_uso (como maestro_device_tokens) y, si esas columnas no existen (PGRST204/columna), reintenta con lo minimo
// (user_id + token). onConflict por 'token' (mismo criterio con que enviarPushAsesor borra por token); si no hubiera
// unique por token, se cae al camino buscar-o-insertar para no duplicar.
app.post('/api/push/registrar-token', async function(req, res){
  try{
    var uid = await verificarUsuario(req);
    if (!uid) return res.status(401).json({ error: 'No autorizado: falta token valido' });
    var token = (req.body && req.body.token) ? String(req.body.token).slice(0, 4000) : '';
    var plataforma = (req.body && req.body.plataforma) ? String(req.body.plataforma).slice(0, 40) : 'web';
    if (!token) return res.status(400).json({ error: 'Falta token' });

    // ANTI-CRUCE (exclusividad del dispositivo): un token FCM es del DISPOSITIVO, no del usuario, y NO cambia al
    // cambiar de cuenta. Si el mismo teléfono se usó antes con OTRA cuenta, ese token seguía atado a la cuenta vieja
    // y le llegaban sus push (fuga entre cuentas). Al registrar, se lo SACAMOS a cualquier otro user_id -> el push de
    // cuentas anteriores deja de llegar a este dispositivo. Best-effort: si falla, el upsert de abajo igual reasigna
    // cuando hay unique por token. Borra por token + user_id != uid (nunca toca el token del usuario actual).
    try { await supabase.from('device_tokens').delete().eq('token', token).neq('user_id', uid); } catch (eDelOtros) {}

    // Intento 1: upsert con la columna REAL `platform` (device_tokens = id, user_id, token, platform, created_at).
    // onConflict por token (requiere unique en token; si no, cae a los intentos defensivos de abajo).
    var up = await supabase.from('device_tokens').upsert(
      { user_id: uid, token: token, platform: plataforma },
      { onConflict: 'token' }
    );
    if (up && up.error) {
      // Intento 2 (DEFENSIVO): la tabla no tiene plataforma/ultimo_uso -> upsert minimo user_id + token.
      var up2 = await supabase.from('device_tokens').upsert(
        { user_id: uid, token: token },
        { onConflict: 'token' }
      );
      if (up2 && up2.error) {
        // Intento 3 (DEFENSIVO): no hay unique por token para el onConflict -> buscar-o-insertar (no duplicar).
        var ya = await supabase.from('device_tokens').select('token').eq('token', token).maybeSingle();
        if (!ya || !ya.data) {
          var ins = await supabase.from('device_tokens').insert({ user_id: uid, token: token });
          if (ins && ins.error) return res.status(500).json({ error: ins.error.message || 'No se pudo registrar el token' });
        }
      }
    }
    return res.json({ ok: true });
  }catch(e){ return res.status(500).json({ error: e && e.message }); }
});

// PRESENCIA: el front avisa que el usuario esta MIRANDO una conversacion (o que salio/oculto, visible:false).
// Se usa para NO mandarle push del chat que ya tiene abierto y visible. SOLO estado en memoria (0 DB, 0 IA).
// Fail-open: cualquier error responde ok:false y no rompe nada (el push se sigue mandando como hoy).
app.post('/api/presencia', async function(req, res){
  try{
    var uid = await verificarUsuario(req);
    if (!uid) return res.status(401).json({ error: 'No autorizado' });
    var convId = (req.body && req.body.conversation_id) ? String(req.body.conversation_id).slice(0, 100) : null;
    var visible = !(req.body && req.body.visible === false); // default true; solo false si viene explicito
    _marcarPresencia(uid, convId, visible);
    return res.json({ ok: true });
  }catch(e){ return res.status(200).json({ ok: false }); }
});

// UI-FLAGS por-cuenta (NO gated / aditivo): devuelve los flags de experiencia/apariencia del DUEÑO de la cuenta,
// resueltos con service key. Necesario porque la RLS de business_settings (unica policy own_business: auth.uid()=user_id)
// NO deja que un ASESOR lea la fila del dueño desde el frontend -> el gate composerV2/ui_moderno caia SIEMPRE a false para
// los asesores y veian la pantalla VIEJA de conversaciones. Aca resolvemos el owner (admin_id si quien pide es asesor) y
// devolvemos SOLO flags booleanos (nada sensible: ningun token). Fail-open a false ante cualquier error. 0 tokens.
// ============================================================================
// API PÚBLICA DE SINCRONIZACIÓN DE INVENTARIO (conectar el sistema/web del cliente con el CRM) — PUSH.
// Cada cliente tiene su API KEY (business_settings.inventario_api_key). Su sistema hace POST a /api/public/
// inventario/sync con su inventario (formato canónico por rubro). Auth por API KEY (header x-api-key o
// Authorization: Bearer), NO por JWT. Rutea por RUBRO y hace UPSERT por 'numero' (crea o actualiza; no borra).
// Común a los 3 mundos: auth + ruteo + upsert. Distinto por mundo: el mapeo de campos a su tabla.
// ============================================================================
const _cryptoInv = require('crypto');
function _nuevaApiKeyInv() { return 'inv_' + _cryptoInv.randomBytes(24).toString('hex'); }
function _sInvS(v){ return (v == null) ? null : (String(v).trim() || null); }
function _sInvN(v){ if (v == null || v === '') return null; var n = Number(String(v).replace(/[^0-9.\-]/g, '')); return isNaN(n) ? null : n; }
function _sInvI(v){ var n = _sInvN(v); return n == null ? null : Math.round(n); }
function _sInvB(v, def){ if (v === true) return true; if (v === false) return false; return def; }

// GET/crea la API key del inventario del dueño (autenticado por JWT). Owner-only.
app.get('/api/inventario/api-key', async function(req, res){
  try {
    var uid = await verificarUsuario(req);
    if (!uid) return res.status(401).json({ error: 'No autorizado' });
    var bs = await supabase.from('business_settings').select('inventario_api_key').eq('user_id', uid).maybeSingle();
    if (bs && bs.error) return res.status(503).json({ error: 'Falta la columna inventario_api_key (corré la migración).' });
    var key = bs && bs.data && bs.data.inventario_api_key;
    if (!key) {
      key = _nuevaApiKeyInv();
      var up = await supabase.from('business_settings').update({ inventario_api_key: key }).eq('user_id', uid);
      if (up && up.error) return res.status(503).json({ error: 'Falta la columna inventario_api_key (corré la migración).' });
    }
    return res.json({ ok: true, api_key: key });
  } catch (e) { return res.status(500).json({ error: e && e.message }); }
});

// Regenerar la API key (invalida la anterior).
app.post('/api/inventario/api-key/regenerar', async function(req, res){
  try {
    var uid = await verificarUsuario(req);
    if (!uid) return res.status(401).json({ error: 'No autorizado' });
    var key = _nuevaApiKeyInv();
    var up = await supabase.from('business_settings').update({ inventario_api_key: key }).eq('user_id', uid);
    if (up && up.error) return res.status(503).json({ error: 'Falta la columna inventario_api_key (corré la migración).' });
    return res.json({ ok: true, api_key: key });
  } catch (e) { return res.status(500).json({ error: e && e.message }); }
});

// UPSERT inmobiliaria (properties) por 'numero'.
async function _syncInvInmobiliaria(user_id, items){
  var creadas = 0, actualizadas = 0, errores = 0;
  for (var i = 0; i < items.length; i++){
    var it = items[i] || {};
    try {
      var numero = _sInvS(it.numero != null ? it.numero : it.id_externo);
      if (!numero) { errores++; continue; }
      var fila = {
        user_id: user_id, numero: numero,
        title: _sInvS(it.title != null ? it.title : it.titulo),
        type: _sInvS(it.type != null ? it.type : it.tipo),
        zone: _sInvS(it.zone != null ? it.zone : it.zona),
        description: _sInvS(it.description != null ? it.description : it.descripcion),
        rooms: _sInvI(it.rooms != null ? it.rooms : it.ambientes),
        dormitorios: _sInvI(it.dormitorios), banos: _sInvI(it.banos), cocheras: _sInvI(it.cocheras),
        amenities: _sInvS(it.amenities), link: _sInvS(it.link != null ? it.link : it.url),
        venta_activa: _sInvB(it.venta_activa, undefined), venta_precio: _sInvN(it.venta_precio),
        anual_activa: _sInvB(it.anual_activa, undefined), anual_precio: _sInvN(it.anual_precio),
        temporal_activa: _sInvB(it.temporal_activa, undefined), temporal_precio_dia: _sInvN(it.temporal_precio_dia),
        activa: _sInvB(it.activa, true)
      };
      if (Array.isArray(it.images)) fila.images = it.images;
      Object.keys(fila).forEach(function(k){ if (fila[k] === undefined) delete fila[k]; });
      var ex = await supabase.from('properties').select('id').eq('user_id', user_id).eq('numero', numero).maybeSingle();
      if (ex.data && ex.data.id) { var u = await supabase.from('properties').update(fila).eq('id', ex.data.id); if (u.error) errores++; else actualizadas++; }
      else { var ins = await supabase.from('properties').insert(fila); if (ins.error) errores++; else creadas++; }
    } catch (e) { errores++; }
  }
  return { creadas: creadas, actualizadas: actualizadas, errores: errores, total: items.length };
}

// UPSERT hotel (hotel_unidades) por 'numero' (o title si no hay numero).
async function _syncInvHotel(user_id, items){
  var creadas = 0, actualizadas = 0, errores = 0;
  for (var i = 0; i < items.length; i++){
    var it = items[i] || {};
    try {
      var numero = _sInvS(it.numero != null ? it.numero : it.id_externo);
      var title = _sInvS(it.title != null ? it.title : it.nombre) || 'Unidad';
      var fila = {
        user_id: user_id, numero: numero, title: title,
        type: _sInvS(it.type != null ? it.type : it.tipo_unidad),
        capacidad: _sInvI(it.capacidad != null ? it.capacidad : it.capacity),
        descripcion: _sInvS(it.descripcion != null ? it.descripcion : it.description),
        precio_base: _sInvN(it.precio_base != null ? it.precio_base : it.precio),
        moneda: _sInvS(it.moneda) || 'ARS',
        atributos: (it.atributos && typeof it.atributos === 'object') ? it.atributos : {},
        activa: _sInvB(it.activa, true)
      };
      Object.keys(fila).forEach(function(k){ if (fila[k] === undefined) delete fila[k]; });
      var q = supabase.from('hotel_unidades').select('id').eq('user_id', user_id);
      q = numero ? q.eq('numero', numero) : q.eq('title', title);
      var ex = await q.maybeSingle();
      if (ex.data && ex.data.id) { var u = await supabase.from('hotel_unidades').update(fila).eq('id', ex.data.id); if (u.error) errores++; else actualizadas++; }
      else { var ins = await supabase.from('hotel_unidades').insert(fila); if (ins.error) errores++; else creadas++; }
    } catch (e) { errores++; }
  }
  return { creadas: creadas, actualizadas: actualizadas, errores: errores, total: items.length };
}

// POST público de sync (auth por API key). Rutea por rubro.
app.post('/api/public/inventario/sync', async function(req, res){
  try {
    var key = (((req.headers['x-api-key'] || '') + '').trim()) || (((req.headers['authorization'] || '') + '').replace(/^Bearer\s+/i, '').trim());
    if (!key || key.length < 16) return res.status(401).json({ error: 'Falta la API key (header x-api-key)' });
    var bs = await supabase.from('business_settings').select('user_id, rubro').eq('inventario_api_key', key).maybeSingle();
    if (bs && bs.error) return res.status(503).json({ error: 'Config no disponible (¿falta la migración inventario_api_key?)' });
    if (!bs.data || !bs.data.user_id) return res.status(401).json({ error: 'API key no reconocida' });
    var user_id = bs.data.user_id;
    var rubro = normalizarRubro(bs.data.rubro || 'inmobiliaria');
    var items = Array.isArray(req.body && req.body.items) ? req.body.items : (Array.isArray(req.body) ? req.body : null);
    if (!items) return res.status(400).json({ error: 'Falta el array "items" en el body' });
    if (items.length > 2000) return res.status(400).json({ error: 'Maximo 2000 items por request' });
    var out;
    if (rubro === 'hotel_cabanas') out = await _syncInvHotel(user_id, items);
    else if (rubro === 'desarrolladora') return res.status(501).json({ error: 'Sync de desarrolladora: proxima fase (por ahora usa el import).' });
    else out = await _syncInvInmobiliaria(user_id, items);
    return res.json(Object.assign({ ok: true, rubro: rubro }, out));
  } catch (e) { return res.status(500).json({ error: e && e.message }); }
});

// ============================================================================
// ===== ETAPA 5 — SALIDAS PUBLICAS: FEED READ-ONLY + CATALOGO + CONSULTA ======
// ============================================================================
// Token PUBLICO dedicado por cuenta (business_settings.feed_token). MISMO patron que
// ical_token: NO se reusa inventario_api_key (esa da ESCRITURA). El feed es SOLO LECTURA
// del inventario activo, por rubro. La "gate" es la EXISTENCIA del token: sin token
// generado -> 404 (nada publico). El dueno genera/regenera su link desde la app.
// CERO IA / CERO tokens (solo lee inventario y sirve JSON). Rutas PLANAS (:token obligatorio).
function _nuevoFeedToken() { return 'feed_' + _cryptoInv.randomBytes(24).toString('hex'); }

// Normaliza el campo images (array de strings, o de objetos {url|src}) a array de URLs (cap).
function _feedImgs(x) {
  try {
    if (!Array.isArray(x)) return [];
    var out = [];
    for (var i = 0; i < x.length && out.length < 12; i++) {
      var it = x[i];
      if (typeof it === 'string' && it.trim()) out.push(it.trim());
      else if (it && typeof it === 'object') { var u = it.url || it.src || it.href; if (u && typeof u === 'string') out.push(u.trim()); }
    }
    return out;
  } catch (e) { return []; }
}
function _feedNum(v) { if (v == null || v === '') return null; var n = Number(v); return isNaN(n) ? null : n; }

// ---- INMOBILIARIA: properties activas -> items normalizados. Defensivo (select '*'). ----
async function _buildFeedInmobiliaria(ownerId) {
  var items = [];
  try {
    var r = await supabase.from('properties').select('*').eq('user_id', ownerId).eq('activa', true).order('numero').range(0, 499);
    if (r.error) return items;
    (r.data || []).forEach(function (p) {
      // Precio a mostrar: primera operacion activa con precio (venta > alquiler anual > temporal).
      var precio = null, moneda = 'USD', operacion = null;
      if (p.venta_activa !== false && _feedNum(p.venta_precio) != null) { precio = _feedNum(p.venta_precio); operacion = 'Venta'; }
      else if (p.anual_activa && _feedNum(p.anual_precio) != null) { precio = _feedNum(p.anual_precio); operacion = 'Alquiler'; }
      else if (p.temporal_activa && _feedNum(p.temporal_precio_dia) != null) { precio = _feedNum(p.temporal_precio_dia); operacion = 'Alquiler temporal'; moneda = 'ARS'; }
      items.push({
        tipo: 'propiedad', id: String(p.id), titulo: p.title || ('Propiedad ' + (p.numero || '')), subtipo: p.type || null,
        operacion: operacion || (p.operation || null), zona: p.zone || null,
        precio: precio, moneda: moneda, precio_texto: (precio != null ? (moneda + ' ' + precio.toLocaleString('es-AR')) : 'Consultar'),
        dormitorios: _feedNum(p.dormitorios) != null ? _feedNum(p.dormitorios) : _feedNum(p.rooms),
        banos: _feedNum(p.banos), cocheras: _feedNum(p.cocheras),
        superficie: _feedNum(p.superficie_cubierta) || _feedNum(p.superficie_total) || null,
        descripcion: p.description || p.descripcion || p.caracteristicas || null,
        fotos: _feedImgs(p.images), link: p.link || null
      });
    });
  } catch (e) { /* defensivo: si falta una tabla/columna -> feed vacio de ese rubro */ }
  return items;
}

// ---- HOTEL: hotel_unidades activas + tarifas -> items normalizados. ----
async function _buildFeedHotel(ownerId) {
  var items = [];
  try {
    var r = await supabase.from('hotel_unidades').select('*').eq('user_id', ownerId).eq('activa', true).order('title').range(0, 499);
    if (r.error) return items;
    var uds = r.data || [];
    var ids = uds.map(function (u) { return u.id; });
    var tarPorU = {};
    if (ids.length) {
      try {
        var tr = await supabase.from('hotel_tarifa').select('unidad_id, temporada, fecha_desde, fecha_hasta, precio_noche, moneda, min_noches').in('unidad_id', ids).eq('user_id', ownerId);
        if (!tr.error) (tr.data || []).forEach(function (t) { (tarPorU[t.unidad_id] = tarPorU[t.unidad_id] || []).push(t); });
      } catch (eT) {}
    }
    uds.forEach(function (u) {
      var tarifas = (tarPorU[u.id] || []).map(function (t) {
        return { temporada: t.temporada || 'Tarifa', precio: _feedNum(t.precio_noche), moneda: t.moneda || u.moneda || 'ARS', min_noches: _feedNum(t.min_noches), desde: t.fecha_desde || null, hasta: t.fecha_hasta || null };
      });
      // Precio de referencia: minima tarifa con precio, o precio_base.
      var minTar = null, minMon = u.moneda || 'ARS';
      tarifas.forEach(function (t) { if (t.precio != null && (minTar === null || t.precio < minTar)) { minTar = t.precio; minMon = t.moneda; } });
      var precio = (minTar != null) ? minTar : _feedNum(u.precio_base);
      var at = (u.atributos && typeof u.atributos === 'object') ? u.atributos : {};
      items.push({
        tipo: 'unidad', id: String(u.id), titulo: u.title || ('Unidad ' + (u.numero || '')), subtipo: u.type || null,
        capacidad: _feedNum(u.capacidad), precio: precio, moneda: minMon,
        precio_texto: (precio != null ? (minMon + ' ' + precio.toLocaleString('es-AR') + '/noche') : 'Consultar'),
        descripcion: u.descripcion || null, fotos: _feedImgs(u.images), tarifas: tarifas,
        dormitorios: _feedNum(at.dormitorios), banos: _feedNum(at.banos)
      });
    });
  } catch (e) {}
  return items;
}

// ---- DESARROLLADORA: developments activos + unidades DISPONIBLES anidadas. ----
async function _buildFeedDesarrolladora(ownerId) {
  var items = [];
  try {
    var r = await supabase.from('developments').select('*').eq('user_id', ownerId).eq('activo', true).order('nombre').range(0, 299);
    if (r.error) return items;
    var devs = r.data || [];
    var ids = devs.map(function (d) { return d.id; });
    var uPorDev = {};
    if (ids.length) {
      try {
        var ur = await supabase.from('development_units').select('*').in('development_id', ids).eq('user_id', ownerId).range(0, 999);
        if (!ur.error) (ur.data || []).forEach(function (u) { (uPorDev[u.development_id] = uPorDev[u.development_id] || []).push(u); });
      } catch (eU) {}
    }
    devs.forEach(function (d) {
      var dd = (d.dev_data && typeof d.dev_data === 'object') ? d.dev_data : {};
      var disp = (uPorDev[d.id] || []).filter(function (u) { return (u.estado || 'disponible') === 'disponible'; });
      var unidades = disp.slice(0, 200).map(function (u) {
        // Decision Diego E5: mostrar precio, salvo precio_estado='a_consultar' -> "Consultar".
        var showPrecio = (u.precio_estado !== 'a_consultar') && (_feedNum(u.precio) != null);
        return {
          id: String(u.id), numero: u.numero || null, tipologia: u.tipologia || u.tipo_producto || null,
          m2: _feedNum(u.m2_cubiertos) || _feedNum(u.m2_totales) || _feedNum(u.superficie_terreno) || null,
          precio: showPrecio ? _feedNum(u.precio) : null, moneda: u.moneda || 'USD',
          precio_texto: showPrecio ? ((u.moneda || 'USD') + ' ' + _feedNum(u.precio).toLocaleString('es-AR')) : 'Consultar'
        };
      });
      items.push({
        tipo: 'emprendimiento', id: String(d.id), titulo: d.nombre || 'Emprendimiento', subtipo: d.tipo || null,
        zona: [d.ciudad, d.zona].filter(Boolean).join(' ') || d.zona || null,
        estado_obra: d.estado_obra || null, avance_pct: _feedNum(d.avance_pct), entrega: d.fecha_entrega || null,
        descripcion: d.descripcion || null, fotos: _feedImgs(dd.images), link: d.link || null,
        disponibles: unidades.length, unidades: unidades
      });
    });
  } catch (e) {}
  return items;
}

// GET /api/inventario/feed-link — owner-only (JWT). Genera (lazy) el feed_token y
// devuelve el token + el link del feed JSON. El link del CATALOGO publico lo arma el
// front con su propio origin (/p/<token>). DEFENSIVO: si falta la columna -> 503 claro.
app.get('/api/inventario/feed-link', async function (req, res) {
  try {
    var uid = await verificarUsuario(req);
    if (!uid) return res.status(401).json({ error: 'No autorizado' });
    var ownerId = await _resolverOwnerId(uid);
    var bs = await supabase.from('business_settings').select('feed_token').eq('user_id', ownerId).maybeSingle();
    if (bs && bs.error) return res.status(503).json({ error: 'Falta la columna feed_token (corré migracion-feed-token.sql).' });
    var token = bs && bs.data && bs.data.feed_token;
    if (!token) {
      token = _nuevoFeedToken();
      var up = await supabase.from('business_settings').update({ feed_token: token }).eq('user_id', ownerId);
      if (up && up.error) return res.status(503).json({ error: 'Falta la columna feed_token (corré migracion-feed-token.sql).' });
    }
    var base = 'https://' + (req.get('host') || 'agente-inmobiliaria-production-7e1c.up.railway.app');
    return res.json({ ok: true, token: token, feed_url: base + '/api/public/feed/' + token, catalogo_path: '/p/' + token });
  } catch (e) { return res.status(500).json({ error: e && e.message }); }
});

